/* ─── LIVE CLIENT — override local ─────── */
// Edita dados do cliente localmente sem alterar o código
// Persiste em localStorage por browser (não sincroniza entre usuários)
function getLiveClient(id){
  const base=CLIENTS.find(c=>c.id===id)||{};
  try{
    const s=localStorage.getItem("pixels-live-"+id);
    if(!s)return base;
    const override=JSON.parse(s);
    return{
      ...base,
      health:override.health??base.health,
      nps:override.nps??base.nps,
      contract:override.contract??base.contract,
      meta:{...base.meta,...(override.meta||{})},
      google:{...base.google,...(override.google||{})},
      social:{...base.social,...(override.social||{})},
      goals:override.goals??base.goals,
      history:override.history??base.history,
    };
  }catch(e){return base;}
}

function saveLiveClient(id,partial){
  try{
    const existing=JSON.parse(localStorage.getItem("pixels-live-"+id)||"{}");
    const merged={...existing,...partial};
    if(partial.meta)merged.meta={...(existing.meta||{}),...partial.meta};
    if(partial.google)merged.google={...(existing.google||{}),...partial.google};
    if(partial.social)merged.social={...(existing.social||{}),...partial.social};
    localStorage.setItem("pixels-live-"+id,JSON.stringify(merged));
  }catch(e){}
}

