/* ─── SMART FORMAT TITLE — auto-formata título do card ─── */
const TITLE_STOPWORDS_PTBR = new Set([
  "de","da","do","das","dos","e","ou","a","o","as","os",
  "para","por","em","na","no","nas","nos","com","sem",
  "ao","aos","à","às","um","uma","uns","umas",
  "del","la","el","los","las","y","en","al","con","sin","un","una","unos","unas",
  "the","of","and","or","in","on","at","to","for","by","with","an"
]);
function _capitalizeFirst(word){
  if(!word)return word;
  return word.charAt(0).toLocaleUpperCase("pt-BR")+word.slice(1).toLocaleLowerCase("pt-BR");
}
function _isCamelCaseValid(word){
  if(!word||word.length<4)return false;
  return /^([a-zà-ÿ]+|[A-ZÀ-Ý][a-zà-ÿ]+)([A-ZÀ-Ý][a-zà-ÿ]{2,})+$/.test(word);
}
function _isWellFormed(word){
  if(!word)return true;
  if(/^[a-zà-ÿ0-9\-'.,!?]+$/.test(word))return true;
  if(/^[A-ZÀ-Ý][a-zà-ÿ0-9\-'.,!?]*$/.test(word))return true;
  if(/^[A-ZÀ-Ý]{2}$/.test(word))return true;
  if(_isCamelCaseValid(word))return true;
  if(/^[0-9\-'.,!?:/]+$/.test(word))return true;
  return false;
}
function stripEmojis(input){
  if(!input||typeof input!=="string")return input||"";
  let s=input;
  try{
    s=s.replace(/[\u{1F1E6}-\u{1F1FF}]/gu,"");
    s=s.replace(/[\u{1F300}-\u{1F5FF}]/gu,"");
    s=s.replace(/[\u{1F600}-\u{1F64F}]/gu,"");
    s=s.replace(/[\u{1F680}-\u{1F6FF}]/gu,"");
    s=s.replace(/[\u{1F700}-\u{1F77F}]/gu,"");
    s=s.replace(/[\u{1F780}-\u{1F7FF}]/gu,"");
    s=s.replace(/[\u{1F800}-\u{1F8FF}]/gu,"");
    s=s.replace(/[\u{1F900}-\u{1F9FF}]/gu,"");
    s=s.replace(/[\u{1FA00}-\u{1FA6F}]/gu,"");
    s=s.replace(/[\u{1FA70}-\u{1FAFF}]/gu,"");
    s=s.replace(/[\u{2600}-\u{26FF}]/gu,"");
    s=s.replace(/[\u{2700}-\u{27BF}]/gu,"");
    s=s.replace(/[\u{2300}-\u{23FF}]/gu,"");
    s=s.replace(/[\u{2B00}-\u{2BFF}]/gu,"");
    s=s.replace(/[\u{1F000}-\u{1F02F}]/gu,"");
    s=s.replace(/[\u{1F0A0}-\u{1F0FF}]/gu,"");
    s=s.replace(/[\u{1F100}-\u{1F1FF}]/gu,"");
    s=s.replace(/[\u{1F200}-\u{1F2FF}]/gu,"");
    s=s.replace(/[\u{1F3FB}-\u{1F3FF}]/gu,"");
    s=s.replace(/[\u{200D}\u{FE0F}\u{20E3}]/gu,"");
  }catch(e){
    s=s.replace(/[\uD800-\uDBFF][\uDC00-\uDFFF]/g,"");
  }
  return s.replace(/\s+/g," ").trim();
}
// Remove menções a nomes de clientes/empresas do título — o cliente já é indicado pela
// logo/badge no card. Roda como parte do smartFormatTitle.
// Variações cobertas: forma junta, com espaço, com hífen ("VetService"/"Vet Service"/"Vet-Service").
// IMPORTANTE: nomes de CIDADES (Chapecó, Toledo, Paraguay, etc) NÃO são removidos isolados —
// só quando colados ao nome da empresa (ex: "Bioter Chapecó"). Boundary manual com (?:^|[^A-Za-zÀ-ÿ0-9])
// pra funcionar com acentos (o \b nativo do JS não trata acentuação como letra).
const _B="(?:^|[^A-Za-zÀ-ÿ0-9])"; // boundary "antes"
const _E="(?:[^A-Za-zÀ-ÿ0-9]|$)"; // boundary "depois"
const _CLIENT_STRIP_PATTERNS=[
  // Bioter — variações com cidade/região vêm ANTES do "bioter" sozinho pra match mais específico primeiro
  new RegExp(_B+"grupo\\s+bioter"+_E, "gi"),
  new RegExp(_B+"bioter\\s+(?:brasil|paraguay|paraguai|chapec[oó]|toledo|castro|uberl[aâ]ndia|gl[oó]ria(?:\\s+de\\s+dourados)?)"+_E, "gi"),
  new RegExp(_B+"bioter"+_E, "gi"),
  // Construschorr
  new RegExp(_B+"construschorr"+_E, "gi"),
  // Arabutã / Arabuta — com ou sem "Pré-Moldados" depois
  new RegExp(_B+"arabut[aã](?:\\s+pr[eé]\\s*-?\\s*moldados)?"+_E, "gi"),
  // Climaves
  new RegExp(_B+"climaves"+_E, "gi"),
  // VetService — junto ou separado por espaço/hífen ("Vet Service", "Vet-Service")
  new RegExp(_B+"vet\\s*-?\\s*service"+_E, "gi"),
  // Pixels (Marketing/Agência)
  new RegExp(_B+"pixels(?:\\s+(?:marketing|ag[eê]ncia|digital))*"+_E, "gi"),
];
function stripClientNames(s){
  if(!s||typeof s!=="string")return s||"";
  let out=s;
  for(let i=0;i<_CLIENT_STRIP_PATTERNS.length;i++){
    // Repete até não casar mais — necessário porque o boundary consome um caractere
    // que pode ser o boundary de um próximo match adjacente.
    let prev;
    do {
      prev=out;
      out=out.replace(_CLIENT_STRIP_PATTERNS[i], function(m){
        // Preserva o boundary inicial (caractere não-alfanumérico) se houver
        const head=m.match(/^[^A-Za-zÀ-ÿ0-9]/)?m[0]:"";
        const tail=m.match(/[^A-Za-zÀ-ÿ0-9]$/)?m[m.length-1]:"";
        return head+tail;
      });
    } while(out!==prev);
  }
  // Limpa separadores órfãos: " - " no início/fim, "  " duplo, "- -", etc.
  out=out.replace(/\s+/g," ").trim();
  out=out.replace(/^\s*-\s*/,"").replace(/\s*-\s*$/,"");
  out=out.replace(/\s*-\s*-\s*/g," - ");
  return out.trim();
}
function smartFormatTitle(input){
  if(!input||typeof input!=="string")return input||"";
  let s=stripEmojis(input);
  if(!s)return "";
  s=stripClientNames(s);
  if(!s)return "";
  s=s.replace(/\s+/g," ").trim();
  if(!s)return "";
  s=s.replace(/\s*[–—]\s*/g," - ").replace(/\s+-\s+/g," - ");
  const parts=s.split(" - ");
  function processWord(word,idx,isTitleSegment,hasSeparator){
    if(!word)return word;
    const leadingMatch=word.match(/^[^A-Za-zÀ-ÿ0-9]+/);
    const trailingMatch=word.match(/[^A-Za-zÀ-ÿ0-9]+$/);
    const prefix=leadingMatch?leadingMatch[0]:"";
    const suffix=trailingMatch?trailingMatch[0]:"";
    if(prefix.length+suffix.length>=word.length)return word;
    const core=word.slice(prefix.length,word.length-suffix.length);
    let processed;
    if(_isCamelCaseValid(core)){processed=core;}
    else if(/^[A-ZÀ-Ý]{2,4}$/.test(core)){processed=core;} // siglas 2-4 letras (BR, ETA, CNPJ)
    else {
      const lower=core.toLocaleLowerCase("pt-BR");
      if(idx>0&&TITLE_STOPWORDS_PTBR.has(lower)){processed=lower;}
      else if(idx===0){
        if(_isWellFormed(core)&&/^[A-ZÀ-Ý]/.test(core)){processed=core;}
        else {processed=_capitalizeFirst(core);}
      }
      else if(isTitleSegment){
        if(_isWellFormed(core)){processed=core;}
        else {processed=lower;}
      }
      else {
        // Sentence segment (depois de " - "): força lowercase EXCETO em palavras
        // bem-formadas com inicial maiúscula (nomes próprios, feriados etc).
        // Ex: "Junho - Corpus Christi" → preserva "Christi" porque já vem Title Case.
        if(_isWellFormed(core)&&/^[A-ZÀ-Ý]/.test(core)){processed=core;}
        else {processed=lower;}
      }
    }
    return prefix+processed+suffix;
  }
  const hasSeparator=parts.length>1;
  const formatted=parts.map(function(part,partIdx){
    const isTitleSegment=!hasSeparator||partIdx===0;
    return part.split(" ").map(function(w,i){return processWord(w,i,isTitleSegment,hasSeparator);}).join(" ");
  });
  let result=formatted.join(" - ");
  const firstAlphaMatch=result.match(/[a-zA-ZÀ-ÿ]/);
  if(firstAlphaMatch&&/[a-zà-ÿ]/.test(firstAlphaMatch[0])){
    const wordStart=result.indexOf(firstAlphaMatch[0]);
    const wordEnd=(result.slice(wordStart).match(/^[A-Za-zÀ-ÿ0-9]+/)||[""])[0].length+wordStart;
    const firstCoreWord=result.slice(wordStart,wordEnd);
    if(!_isCamelCaseValid(firstCoreWord)){
      result=result.slice(0,wordStart)+firstAlphaMatch[0].toLocaleUpperCase("pt-BR")+result.slice(wordStart+1);
    }
  }
  return result;
}

/* ─── DESIGNER PAYMENTS ─── */
const DESIGNER_PRICES = { fotoObra: 20, arte: 30, carrossel: 45, folder: 30, video: 100, corte: 20, videoComplexo: 150, videoFeira: 50 };
// "reprovado" entra porque o material foi produzido — paga igual.
// Sócio pode reprovar quem reprova é o cliente; produção já gastou hora/recurso.
const PAID_STATUSES = ["aprovado","agendado","publicado","reprovado"];
function calcDesignerPayments(tasks, designerId, refMonth){
  const out = { fotoObra:0, arte:0, carrossel:0, folder:0, video:0, corte:0, videoComplexo:0, videoFeira:0, naoClassificado:0,
                tasksFotoObra:[], tasksArte:[], tasksCarrossel:[], tasksFolder:[], tasksVideo:[], tasksCorte:[], tasksVideoComplexo:[], tasksVideoFeira:[], tasksOutros:[] };
  (tasks||[]).forEach(t=>{
    if(!t)return;
    const assigned=t.assignee===designerId||(Array.isArray(t.assignees)&&t.assignees.includes(designerId));
    if(!assigned)return;
    if(!PAID_STATUSES.includes(t.status))return;
    // Fallback robusto: pra cards reprovados publishDate/completedAt podem ser null.
    // Cascata: referenceMonth → publishDate → completedAt → deadline → colEnteredAt → updated_at → createdAt
    function _isoMonth(v){
      if(!v)return null;
      const s=String(v);
      // ISO date "2026-06-19..." → "2026-06"
      if(/^\d{4}-\d{2}/.test(s))return s.slice(0,7);
      // BR "19/06/2026 às hh:mm" ou "19/06/2026" → "2026-06"
      const m=s.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
      if(m)return m[3]+"-"+m[2];
      // ISO datetime full
      const d=new Date(s);
      if(!isNaN(d.getTime()))return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0");
      return null;
    }
    const effectiveMonth = t.referenceMonth
      || _isoMonth(t.publishDate||t.publish_date)
      || _isoMonth(t.completedAt||t.completed_at)
      || _isoMonth(t.deadline)
      || _isoMonth(t.colEnteredAt||t.col_entered_at)
      || _isoMonth(t.updated_at||t.updatedAt)
      || _isoMonth(t.createdAt||t.created_at);
    if(refMonth&&effectiveMonth!==refMonth)return;
    if(t.contentType==="foto"){out.fotoObra++;out.tasksFotoObra.push(t);}
    else if(t.contentType==="carrossel"){out.carrossel++;out.tasksCarrossel.push(t);}
    else if(t.contentType==="folder"){out.folder++;out.tasksFolder.push(t);}
    else if(t.contentType==="arte"){out.arte++;out.tasksArte.push(t);}
    else if(t.contentType==="video"){out.video++;out.tasksVideo.push(t);}
    else if(t.contentType==="corte"){out.corte++;out.tasksCorte.push(t);}
    else if(t.contentType==="video_complexo"){out.videoComplexo++;out.tasksVideoComplexo.push(t);}
    else if(t.contentType==="video_feira"){out.videoFeira++;out.tasksVideoFeira.push(t);}
    else {out.naoClassificado++;out.tasksOutros.push(t);}
  });
  out.total = out.fotoObra*DESIGNER_PRICES.fotoObra
            + out.arte*DESIGNER_PRICES.arte
            + out.carrossel*DESIGNER_PRICES.carrossel
            + out.folder*DESIGNER_PRICES.folder
            + out.video*DESIGNER_PRICES.video
            + out.corte*DESIGNER_PRICES.corte
            + out.videoComplexo*DESIGNER_PRICES.videoComplexo
            + out.videoFeira*DESIGNER_PRICES.videoFeira;
  return out;
}
function formatRefMonth(refMonth){
  if(!refMonth) return "Todos os meses";
  const [y,m]=refMonth.split("-").map(Number);
  const meses=["jan","fev","mar","abr","mai","jun","jul","ago","set","out","nov","dez"];
  return meses[m-1]+"/"+String(y).slice(-2);
}


/* ─── FreelancerPaymentsBlock — card consolidado com pagamentos de todos os freelancers
       (André + Maria + Guilherme) por tipo de conteúdo no mês de referência selecionado.
       Reutilizado em DashPartner e em PageGestaoFinanceiro.                        ─── */
function FreelancerPaymentsBlock({tasks, setTasks, refMonth, onChangeMonth, isMob, compact}){
  const fmtBRL=function(n){return "R$ "+Number(n||0).toLocaleString("pt-BR",{minimumFractionDigits:2,maximumFractionDigits:2});};
  // Whitelist explícita pra Ocsana (estagiária com salário fixo) e qualquer outro perfil
  // que tenha pagamentoPorDemanda:true por engano em algum override não cair aqui.
  const _PAY_BY_DEMAND_IDS = ["andre","maria","guilherme"];
  const freelancers=(typeof TEAM!=="undefined"?TEAM:[]).filter(function(u){return u.pagamentoPorDemanda && _PAY_BY_DEMAND_IDS.indexOf(u.id)>=0;});
  const rows=freelancers.map(function(fr){
    const calc=calcDesignerPayments(tasks||[],fr.id,refMonth);
    return {fr:fr,calc:calc,isEditor:fr.dash==="editor"};
  });
  const total=rows.reduce(function(s,r){return s+r.calc.total;},0);
  // ── Rollover de cards pendentes pro próximo mês ────────────────────
  const [_rolModal, _setRolModal] = useState(null);
  function _abrirRollover(filterFreelancerId){
    if(!refMonth){ if(typeof pixelsToast!=="undefined") pixelsToast.warning("Selecione um mês primeiro."); return; }
    if(!setTasks){ if(typeof pixelsToast!=="undefined") pixelsToast.error("Função de atualização indisponível."); return; }
    const PAID=["aprovado","agendado","publicado","reprovado"];
    const targetIds = filterFreelancerId?[filterFreelancerId]:freelancers.map(function(f){return f.id;});
    const pendentes=(tasks||[]).filter(function(t){
      if(!t||t.deletedAt) return false;
      if(t.referenceMonth!==refMonth) return false;
      if(PAID.indexOf(t.status)>=0) return false;
      const assigned=t.assignee||(Array.isArray(t.assignees)&&t.assignees[0])||"";
      const assignees=Array.isArray(t.assignees)?t.assignees:[assigned].filter(Boolean);
      return assignees.some(function(aid){return targetIds.indexOf(aid)>=0;});
    });
    if(pendentes.length===0){ if(typeof pixelsToast!=="undefined") pixelsToast.info("Nenhum card pendente nesse mês."); return; }
    const parts=refMonth.split("-");
    let y=parseInt(parts[0]); let m=parseInt(parts[1])+1;
    if(m>12){ m=1; y++; }
    const nextMonth=y+"-"+String(m).padStart(2,"0");
    _setRolModal({cards:pendentes, nextMonth:nextMonth, filterId:filterFreelancerId||null});
  }
  function _confirmarRollover(){
    if(!_rolModal) return;
    const nextMonth=_rolModal.nextMonth;
    const ids={};
    _rolModal.cards.forEach(function(t){ ids[t.id]=true; });
    const PAID2=["aprovado","agendado","publicado","reprovado"];
    // Se o rollover foi filtrado por colaborador, marca pago só dele. Senão, todos.
    const fids=_rolModal.filterId?[_rolModal.filterId]:freelancers.map(function(f){return f.id;});
    const nowIso=new Date().toISOString();
    const paidIds={};
    (tasks||[]).forEach(function(t){
      if(!t||ids[t.id]) return;
      if(t.referenceMonth!==refMonth) return;
      if(PAID2.indexOf(t.status)<0) return;
      if(t.paidAt) return;
      const ass=Array.isArray(t.assignees)?t.assignees:[t.assignee].filter(Boolean);
      if(ass.some(function(aid){return fids.indexOf(aid)>=0;})){ paidIds[t.id]=true; }
    });
    const paidCount=Object.keys(paidIds).length;
    // Persistir paidIds também em localStorage (backup contra polling do Supabase)
    try{
      const lp=JSON.parse(localStorage.getItem("pixels-paid-tasks")||"{}");
      Object.keys(paidIds).forEach(function(k){ lp[k]=nowIso; });
      localStorage.setItem("pixels-paid-tasks",JSON.stringify(lp));
    }catch(e){}
    setTasks(function(prev){
      return (prev||[]).map(function(t){
        if(!t) return t;
        if(ids[t.id]) return Object.assign({},t,{referenceMonth:nextMonth, updated_at:nowIso});
        if(paidIds[t.id]) return Object.assign({},t,{paidAt:nowIso, updated_at:nowIso});
        return t;
      });
    });
    // Persiste no Supabase pra todos os usuários verem (Guilherme, André, etc.).
    // Dois batches: 1) tasks roladas (mudou reference_month) 2) tasks marcadas pagas em massa.
    if(window._sb){
      const rolledIds = Object.keys(ids);
      const paidIdsList = Object.keys(paidIds);
      if(rolledIds.length>0){
        window._sb.from("tasks").update({reference_month:nextMonth}).in("id",rolledIds)
          .then(function(){}).catch(function(err){console.error("rollover ref_month supabase:",err);});
      }
      if(paidIdsList.length>0){
        window._sb.from("tasks").update({paid_at:nowIso}).in("id",paidIdsList)
          .then(function(){}).catch(function(err){console.error("rollover paid_at supabase:",err);});
      }
    }
    const n=_rolModal.cards.length;
    _setRolModal(null);
    if(typeof pixelsToast!=="undefined") pixelsToast.success(n+" rolado(s) pra "+nextMonth+" | "+paidCount+" marcado(s) como pago(s)");
  }

  const ChipBreak=function(props){
    const label=props.label,count=props.count,price=props.price;
    if(!count) return null;
    return <span style={{display:"inline-flex",alignItems:"center",gap:5,background:"#f1f5f9",color:"#475569",fontSize:11,fontWeight:600,padding:"3px 9px",borderRadius:6,fontFamily:"'Inter',system-ui,sans-serif"}}>
      <strong style={{color:"#0f172a",fontWeight:800,fontFeatureSettings:"'tnum'"}}>{count}</strong>
      <span style={{color:"#94a3b8",fontSize:10}}>×</span>
      <span>{label}</span>
      <span style={{color:"#9F43F6",fontWeight:700,marginLeft:2,fontFeatureSettings:"'tnum'"}}>{fmtBRL(count*price).replace(",00","")}</span>
    </span>;
  };

  function _shiftMonth(delta){
    if(!refMonth){ onChangeMonth&&onChangeMonth(new Date().getFullYear()+"-"+String(new Date().getMonth()+1).padStart(2,"0")); return; }
    const parts=refMonth.split("-");
    let y=parseInt(parts[0]); let m=parseInt(parts[1])+delta;
    while(m<1){ m+=12; y--; }
    while(m>12){ m-=12; y++; }
    onChangeMonth&&onChangeMonth(y+"-"+String(m).padStart(2,"0"));
  }
  const _monthLabel=(function(){
    if(!refMonth) return "Selecione um mês";
    const parts=refMonth.split("-");
    if(parts.length<2) return refMonth;
    const mnames=["Janeiro","Fevereiro","Março","Abril","Maio","Junho","Julho","Agosto","Setembro","Outubro","Novembro","Dezembro"];
    return (mnames[parseInt(parts[1],10)-1]||"?")+" de "+parts[0];
  })();
  return <div style={{background:"linear-gradient(135deg,#fff 0%,#fafbfc 100%)",border:"1px solid #e5e7eb",borderRadius:16,padding:compact?"20px 22px":"24px 28px",fontFamily:"'Inter',system-ui,sans-serif",boxShadow:"0 4px 16px rgba(15,23,42,0.04),0 1px 2px rgba(15,23,42,0.025)"}}>
    {/* Header */}
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:14,marginBottom:20,flexWrap:"wrap"}}>
      <div style={{display:"flex",alignItems:"center",gap:13}}>
        <div style={{width:42,height:42,borderRadius:11,background:"linear-gradient(135deg,#7c3aed,#a855f7)",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",boxShadow:"0 4px 12px rgba(124,58,237,0.35)"}}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>
        </div>
        <div>
          <div style={{color:"#0f172a",fontWeight:800,fontSize:17,letterSpacing:-.4}}>Pagamentos por demanda</div>
          <div style={{color:"#64748b",fontSize:11.5,marginTop:2}}>Conta artes aprovadas, agendadas e publicadas no mês</div>
        </div>
      </div>
      <div style={{display:"flex",alignItems:"center",gap:14,flexWrap:"wrap"}}>
        <div style={{display:"inline-flex",alignItems:"center",background:"#fff",border:"1px solid #e5e7eb",borderRadius:11,padding:3,boxShadow:"0 1px 2px rgba(15,23,42,0.03)"}}>
          <button type="button" onClick={function(e){e.preventDefault();e.stopPropagation();_shiftMonth(-1);}} title="Mês anterior" style={{background:"transparent",border:"none",borderRadius:8,width:30,height:30,display:"inline-flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:"#64748b",transition:"all .12s"}} onMouseEnter={function(e){e.currentTarget.style.background="#f1f5f9";e.currentTarget.style.color="#0f172a";}} onMouseLeave={function(e){e.currentTarget.style.background="transparent";e.currentTarget.style.color="#64748b";}}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="15 18 9 12 15 6"/></svg>
          </button>
          <div style={{padding:"0 14px",minWidth:130,textAlign:"center",fontSize:12.5,fontWeight:700,color:"#7c3aed",letterSpacing:-.1,fontFamily:"inherit",fontFeatureSettings:"'tnum'"}}>{_monthLabel}</div>
          <button type="button" onClick={function(e){e.preventDefault();e.stopPropagation();_shiftMonth(1);}} title="Próximo mês" style={{background:"transparent",border:"none",borderRadius:8,width:30,height:30,display:"inline-flex",alignItems:"center",justifyContent:"center",cursor:"pointer",color:"#64748b",transition:"all .12s"}} onMouseEnter={function(e){e.currentTarget.style.background="#f1f5f9";e.currentTarget.style.color="#0f172a";}} onMouseLeave={function(e){e.currentTarget.style.background="transparent";e.currentTarget.style.color="#64748b";}}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"/></svg>
          </button>
        </div>
        <div style={{textAlign:"right",paddingLeft:6,borderLeft:"1px solid #e5e7eb"}}>
          <div style={{color:"#94a3b8",fontSize:9.5,fontWeight:700,textTransform:"uppercase",letterSpacing:.6}}>Total</div>
          <div style={{background:"linear-gradient(135deg,#7c3aed,#a855f7)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",backgroundClip:"text",fontWeight:900,fontSize:24,letterSpacing:-.5,fontFeatureSettings:"'tnum'",lineHeight:1.1}}>{fmtBRL(total)}</div>
        </div>
      </div>
    </div>

    {/* Cards verticais grandes — 1 por colaborador */}
    <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"repeat(auto-fit,minmax(260px,1fr))",gap:14}}>
      {rows.map(function(r){
        const fr=r.fr,c=r.calc;
        const accent=fr.color||"#7c3aed";
        const photo=(fr&&fr.profile_data&&fr.profile_data.photo)||((typeof getProfilePhoto!=="undefined")?getProfilePhoto(fr.id):null);
        const items=r.isEditor
          ?[{l:"Vídeo",n:c.video,p:DESIGNER_PRICES.video},{l:"Corte",n:c.corte,p:DESIGNER_PRICES.corte},{l:"V. dinâmico",n:c.videoComplexo,p:DESIGNER_PRICES.videoComplexo},{l:"V. básico",n:c.videoFeira,p:DESIGNER_PRICES.videoFeira}]
          :[{l:"Foto de obra",n:c.fotoObra,p:DESIGNER_PRICES.fotoObra},{l:"Arte única",n:c.arte,p:DESIGNER_PRICES.arte},{l:"Carrossel",n:c.carrossel,p:DESIGNER_PRICES.carrossel},{l:"Folder",n:c.folder,p:DESIGNER_PRICES.folder}];
        // Mostra TODOS os tipos (inclusive 0) com preço unitário visível
        const hasAny=items.some(function(it){return it.n>0;});
        return <div key={fr.id} style={{background:"linear-gradient(180deg,"+accent+"08 0%, #fff 60%)",border:"1px solid "+accent+"22",borderRadius:14,padding:0,display:"flex",flexDirection:"column",overflow:"hidden",boxShadow:"0 4px 14px "+accent+"10, 0 1px 3px rgba(15,23,42,0.04)",transition:"all .2s cubic-bezier(.4,0,.2,1)"}}
          onMouseEnter={function(e){e.currentTarget.style.borderColor=accent+"66";e.currentTarget.style.boxShadow="0 14px 32px "+accent+"22, 0 2px 6px rgba(15,23,42,0.05)";e.currentTarget.style.transform="translateY(-3px)";}}
          onMouseLeave={function(e){e.currentTarget.style.borderColor=accent+"22";e.currentTarget.style.boxShadow="0 4px 14px "+accent+"10, 0 1px 3px rgba(15,23,42,0.04)";e.currentTarget.style.transform="translateY(0)";}}>

          {/* HEADER — sóbrio, fundo branco, accent só no anel do avatar e no chip da função */}
          <div style={{padding:"22px 18px 16px",display:"flex",flexDirection:"column",alignItems:"center",gap:10,borderBottom:"1px solid "+accent+"22"}}>
            <div style={{position:"relative",width:80,height:80,borderRadius:"50%",overflow:"hidden",background:"#fff",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,boxShadow:"0 0 0 3px "+accent+", 0 4px 12px "+accent+"30"}}>
              {photo
                ?<img src={photo} alt={fr.name} style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                :<span style={{color:accent,fontWeight:900,fontSize:32,letterSpacing:-.6}}>{fr.av||(fr.name||"?")[0]}</span>}
            </div>
            <div style={{textAlign:"center"}}>
              <div style={{color:"#0f172a",fontWeight:800,fontSize:16,letterSpacing:-.3,lineHeight:1.2}}>{fr.name}</div>
              <div style={{display:"inline-block",marginTop:5,padding:"2px 10px",background:accent+"12",border:"1px solid "+accent+"22",borderRadius:99,color:accent,fontSize:10,fontWeight:700,letterSpacing:.4,textTransform:"uppercase"}}>{r.isEditor?"Edição de vídeo":"Design"}</div>
            </div>
          </div>

          {/* BREAKDOWN — sem gradiente colorido, fundo neutro */}
          <div style={{padding:"14px 14px 12px",display:"flex",flexDirection:"column",gap:5,flex:1}}>
            {items.map(function(it,i){
              const has=it.n>0;
              return <div key={i} style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8,padding:"8px 11px",background:has?accent+"0e":"transparent",border:"1px solid "+(has?accent+"22":"transparent"),borderRadius:9,opacity:has?1:0.5}}>
                <div style={{display:"flex",alignItems:"center",gap:8,minWidth:0,flex:1}}>
                  <span style={{background:has?accent:"#f1f5f9",color:has?"#fff":"#94a3b8",fontWeight:800,fontSize:11.5,padding:"2px 8px",borderRadius:6,fontFeatureSettings:"'tnum'",letterSpacing:-.2,flexShrink:0,minWidth:24,textAlign:"center"}}>{it.n}×</span>
                  <span style={{color:has?"#0f172a":"#94a3b8",fontSize:12.5,fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{it.l}</span>
                  <span style={{color:"#94a3b8",fontSize:10,fontWeight:500,fontFeatureSettings:"'tnum'",whiteSpace:"nowrap"}}>· {fmtBRL(it.p).replace(",00","")}/un</span>
                </div>
                <span style={{color:has?"#16a34a":"#cbd5e1",fontSize:12.5,fontWeight:700,fontFeatureSettings:"'tnum'",letterSpacing:-.2,flexShrink:0}}>{fmtBRL(it.n*it.p).replace(",00","")}</span>
              </div>;
            })}

            {/* Miniaturas dos cards a pagar — visual neutro, thumbs grandes (84px) */}
            {(function(){
              function _monthShortLabel(rm){
                if(!rm) return "";
                const mn=["Jan","Fev","Mar","Abr","Mai","Jun","Jul","Ago","Set","Out","Nov","Dez"];
                const parts=rm.split("-");
                return (mn[parseInt(parts[1],10)-1]||"?")+"/"+parts[0].slice(-2);
              }
              // Pega a ÚLTIMA imagem subida no card (arte final, depois de ajustes) — não a primeira nem a cover legada.
              // Ignora anotações (imagens com riscos vermelhos de revisão).
              function _thumb(t){
                const imgs=(t.files||[]).filter(function(f){
                  if(!f||!f.type||f.type.indexOf("image/")!==0) return false;
                  if(f.isAnnotation===true) return false;
                  const name=String(f.name||"").toLowerCase();
                  if(name.indexOf("annotation-")===0) return false;
                  return true;
                });
                if(imgs.length>0) return imgs[imgs.length-1].url;
                if(t.cover) return t.cover;
                return null;
              }
              // Só o mês selecionado — sem prev/next pra não confundir.
              const cc=calcDesignerPayments(tasks||[], fr.id, refMonth);
              const items=[].concat(cc.tasksFotoObra,cc.tasksArte,cc.tasksCarrossel,cc.tasksFolder,cc.tasksVideo,cc.tasksCorte,cc.tasksVideoComplexo,cc.tasksVideoFeira);
              if(items.length===0) return null;
              // Ordena ENTREGAS mais recentes primeiro.
              // Tasks vêm em camelCase do state local; snake_case usado como fallback (Supabase raw).
              // Prioridade: completedAt (entregou) → publishDate (publicou) → updated_at → deadline → colEnteredAt → createdAt
              function _ts(t){
                const cands=[
                  t.completedAt, t.completed_at,
                  t.publishDate, t.publish_date,
                  t.updated_at, t.updatedAt,
                  t.deadline,
                  t.colEnteredAt, t.col_entered_at,
                  t.createdAt, t.created_at
                ];
                for(let i=0;i<cands.length;i++){
                  const v=cands[i];
                  if(!v) continue;
                  let _v=v;
                  // formato BR ex.: "19/06/2026 às 14:30" → ISO
                  if(typeof v==="string"&&v.indexOf(" às ")>0){
                    const _m=v.match(/^(\d{2})\/(\d{2})\/(\d{4}) às (\d{1,2}):(\d{2})/);
                    if(_m)_v=_m[3]+"-"+_m[2]+"-"+_m[1]+"T"+_m[4].padStart(2,"0")+":"+_m[5];
                  }
                  const d=new Date(_v);
                  if(!isNaN(d.getTime())) return d.getTime();
                }
                return 0;
              }
              items.sort(function(a,b){
                const da=_ts(a), db=_ts(b);
                if(db!==da) return db-da;
                return String(b.id||"").localeCompare(String(a.id||""));
              });
              return <div style={{marginTop:14,paddingTop:14,borderTop:"1px solid "+accent+"22",display:"flex",flexDirection:"column",gap:10}}>
                <div style={{display:"flex",alignItems:"center",gap:8}}>
                  <div style={{color:accent,fontSize:10.5,fontWeight:800,textTransform:"uppercase",letterSpacing:.6}}>Produção mensal</div>
                  <span style={{background:accent+"15",color:accent,fontSize:10,fontWeight:800,letterSpacing:.3,textTransform:"uppercase",padding:"2px 9px",borderRadius:99,border:"1px solid "+accent+"33"}}>{_monthShortLabel(refMonth)}</span>
                  <span style={{color:"#94a3b8",fontSize:11,fontWeight:600}}>{items.length}{items.length===1?" card":" cards"}</span>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(110px,1fr))",gap:8}}>
                  {items.slice(0,8).map(function(t){
                    const url=_thumb(t);
                    const cl=(typeof CLIENTS!=="undefined"?CLIENTS:[]).find(function(x){return x.id===t.client;});
                    const tip=(t.title||"Sem título")+(cl?" · "+cl.name:"");
                    return <div key={t.id} title={tip} style={{aspectRatio:"4/5",borderRadius:11,overflow:"hidden",background:url?"#f1f5f9":(cl&&cl.color?cl.color+"15":"#f8fafc"),border:"1px solid "+accent+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,fontWeight:800,color:cl&&cl.color?cl.color:"#94a3b8",cursor:"default",transition:"all .18s",boxShadow:"0 2px 6px "+accent+"10"}}
                      onMouseEnter={function(e){e.currentTarget.style.transform="scale(1.04)";e.currentTarget.style.borderColor=accent+"66";e.currentTarget.style.boxShadow="0 6px 18px "+accent+"22";}}
                      onMouseLeave={function(e){e.currentTarget.style.transform="scale(1)";e.currentTarget.style.borderColor=accent+"22";e.currentTarget.style.boxShadow="0 2px 6px "+accent+"10";}}>
                      {url
                        ? <img src={url} alt="" referrerPolicy="no-referrer" loading="lazy" style={{width:"100%",height:"100%",objectFit:"cover"}} onError={function(e){e.currentTarget.style.display="none";}}/>
                        : (cl?cl.name.slice(0,2).toUpperCase():"?")
                      }
                    </div>;
                  })}
                  {items.length>8 && <div title={(items.length-8)+" cards a mais"} style={{aspectRatio:"4/5",borderRadius:11,background:accent+"08",border:"1px dashed "+accent+"55",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,fontWeight:800,color:accent}}>+{items.length-8}</div>}
                </div>
              </div>;
            })()}
          </div>

          {/* TOTAL — separador limpo */}
          <div style={{padding:"14px 18px",background:"linear-gradient(180deg,"+accent+"08, "+accent+"14)",borderTop:"1px solid "+accent+"22",display:"flex",alignItems:"center",justifyContent:"space-between",gap:8}}>
            <span style={{color:accent,fontSize:10.5,fontWeight:800,textTransform:"uppercase",letterSpacing:.5}}>Total</span>
            <div style={{color:c.total>0?"#16a34a":"#94a3b8",fontWeight:800,fontSize:18,fontFeatureSettings:"'tnum'",letterSpacing:-.4,lineHeight:1}}>{fmtBRL(c.total)}</div>
          </div>

          {/* ROLAR — ghost discreto */}
          <button type="button" onClick={function(){_abrirRollover(fr.id);}} title={"Rolar pendentes do "+fr.name+" pro próximo mês"} style={{background:"#fff",color:"#64748b",border:"none",borderTop:"1px solid #f1f5f9",padding:"11px 12px",fontSize:11.5,fontWeight:600,cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",justifyContent:"center",gap:6,transition:"all .15s"}}
            onMouseEnter={function(e){e.currentTarget.style.background="#f8fafc";e.currentTarget.style.color=accent;}}
            onMouseLeave={function(e){e.currentTarget.style.background="#fff";e.currentTarget.style.color="#64748b";}}>⟳ Rolar pendentes do {fr.name.split(" ")[0]}</button>
        </div>;
      })}
    </div>
    {_rolModal&&<div onClick={function(){_setRolModal(null);}} style={{position:"fixed",inset:0,background:"rgba(15,23,42,0.55)",zIndex:10000,display:"flex",alignItems:"center",justifyContent:"center",padding:20,fontFamily:"'Inter',system-ui,sans-serif"}}>
      <div onClick={function(e){e.stopPropagation();}} style={{background:"#fff",borderRadius:14,padding:"22px 24px",maxWidth:480,width:"100%",maxHeight:"80vh",overflow:"auto",boxShadow:"0 20px 60px rgba(0,0,0,0.3)"}}>
        <div style={{color:"#0f172a",fontWeight:800,fontSize:17,letterSpacing:-.3,marginBottom:6}}>Rolar pendentes pro próximo mês</div>
        <div style={{color:"#64748b",fontSize:12.5,marginBottom:16,lineHeight:1.5}}><strong style={{color:"#a16207"}}>{_rolModal.cards.length} card(s)</strong> serão movidos de <strong>{refMonth}</strong> → <strong>{_rolModal.nextMonth}</strong>. Apenas cards NÃO aprovados/publicados são considerados.</div>
        <div style={{background:"#fafbfc",border:"1px solid #f1f5f9",borderRadius:9,padding:"10px 12px",maxHeight:240,overflow:"auto",marginBottom:18}}>
          {_rolModal.cards.map(function(t){
            const a=Array.isArray(t.assignees)?t.assignees[0]:t.assignee;
            const u=(typeof TEAM!=="undefined"?TEAM:[]).find(function(x){return x.id===a;});
            return <div key={t.id} style={{display:"flex",alignItems:"center",gap:8,padding:"5px 0",borderBottom:"1px dashed #e5e7eb",fontSize:12}}>
              <span style={{color:"#0f172a",fontWeight:600,flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.title||"Sem título"}</span>
              <span style={{color:"#94a3b8",fontSize:11,whiteSpace:"nowrap"}}>{u?u.name:(a||"—")}</span>
            </div>;
          })}
        </div>
        <div style={{display:"flex",justifyContent:"flex-end",gap:8}}>
          <button type="button" onClick={function(){_setRolModal(null);}} style={{background:"#fff",color:"#64748b",border:"1px solid #e5e7eb",borderRadius:9,padding:"9px 16px",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>Cancelar</button>
          <button type="button" onClick={_confirmarRollover} style={{background:"#a16207",color:"#fff",border:"none",borderRadius:9,padding:"9px 18px",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>Confirmar — mover pra {_rolModal.nextMonth}</button>
        </div>
      </div>
    </div>}
  </div>;
}

/* ─── SAFE STORAGE — wrapper localStorage com quota check ─── */
// Captura QuotaExceededError automaticamente. Tenta limpar caches antigos.
const safeStorage={
  get(key,fallback=null){
    try{const v=localStorage.getItem(key);return v===null?fallback:v;}
    catch(e){console.warn("[safeStorage] get failed:",key,e?.message);return fallback;}
  },
  set(key,value){
    try{localStorage.setItem(key,typeof value==="string"?value:JSON.stringify(value));return true;}
    catch(e){
      // Quota cheia → tenta limpar caches antigos (chaves "pixels-cache-*" ou similares)
      if(e?.name==="QuotaExceededError"||e?.code===22){
        try{
          const keys=Object.keys(localStorage);
          const oldCaches=keys.filter(k=>k.startsWith("pixels-thumb-")||k.startsWith("pixels-cache-"));
          oldCaches.forEach(k=>localStorage.removeItem(k));
          // Tenta de novo após limpar
          localStorage.setItem(key,typeof value==="string"?value:JSON.stringify(value));
          return true;
        }catch{
          console.warn("[safeStorage] localStorage cheio. Não foi possível salvar:",key);
          return false;
        }
      }
      console.warn("[safeStorage] set failed:",key,e?.message);
      return false;
    }
  },
  remove(key){try{localStorage.removeItem(key);}catch(e){console.warn("[safeStorage] remove failed:",e?.message);}},
  getJSON(key,fallback=null){
    try{const v=localStorage.getItem(key);return v===null?fallback:JSON.parse(v);}
    catch(e){console.warn("[safeStorage] getJSON failed:",key,e?.message);return fallback;}
  },
};

/* ─── TOAST/NOTIFICATION SYSTEM — substituto pro alert() ───
   Uso:
     pixelsToast.success("Salvo!");
     pixelsToast.error("Falhou");
     pixelsToast.info("Aviso");
     pixelsToast.warning("Atenção");
   Modal de confirmação:
     pixelsConfirm("Tem certeza?").then(yes=>{ if(yes) ... });
*/
const _toastQueue=[];
let _toastContainer=null;
function _ensureToastContainer(){
  if(_toastContainer)return _toastContainer;
  if(typeof document==="undefined")return null;
  const div=document.createElement("div");
  div.id="pixels-toast-container";
  Object.assign(div.style,{
    position:"fixed",top:"max(20px,env(safe-area-inset-top))",right:"20px",
    zIndex:"99999",display:"flex",flexDirection:"column",gap:"8px",
    pointerEvents:"none",maxWidth:"360px",
  });
  document.body.appendChild(div);
  _toastContainer=div;
  return div;
}
function _showToast(type,msg,duration=3500){
  const container=_ensureToastContainer();
  if(!container){console.log(`[${type}] ${msg}`);return;}
  const colors={
    success:{bg:"#16a34a",icon:"✓"},
    error:{bg:"#dc2626",icon:"✕"},
    info:{bg:"#2563eb",icon:"ℹ"},
    warning:{bg:"#f59e0b",icon:"⚠"},
  };
  const c=colors[type]||colors.info;
  const toast=document.createElement("div");
  Object.assign(toast.style,{
    background:c.bg,color:"#fff",padding:"12px 16px",borderRadius:"10px",
    boxShadow:"0 8px 32px rgba(0,0,0,0.18)",fontSize:"13px",fontWeight:"600",
    display:"flex",alignItems:"center",gap:"10px",pointerEvents:"auto",
    cursor:"pointer",fontFamily:"'Outfit',system-ui,sans-serif",
    transform:"translateX(100%)",opacity:"0",
    transition:"all .25s cubic-bezier(.22,1,.36,1)",
  });
  toast.innerHTML=`<span style="font-size:16px;flex-shrink:0">${c.icon}</span><span style="line-height:1.4"></span>`;
  toast.children[1].textContent=msg; // safe text
  toast.onclick=()=>_dismissToast(toast);
  container.appendChild(toast);
  requestAnimationFrame(()=>{toast.style.transform="translateX(0)";toast.style.opacity="1";});
  setTimeout(()=>_dismissToast(toast),duration);
}
function _dismissToast(toast){
  if(!toast.parentNode)return;
  toast.style.transform="translateX(100%)";toast.style.opacity="0";
  setTimeout(()=>{try{toast.remove();}catch{}},250);
}
const pixelsToast={
  success:(m,d)=>_showToast("success",m,d),
  error:(m,d)=>_showToast("error",m,d||5000),
  info:(m,d)=>_showToast("info",m,d),
  warning:(m,d)=>_showToast("warning",m,d||4500),
};

// Modal de input custom (substitui prompt())
function pixelsPrompt(message,opts={}){
  return new Promise(resolve=>{
    if(typeof document==="undefined")return resolve(window.prompt(message,opts.defaultValue||""));
    const overlay=document.createElement("div");
    Object.assign(overlay.style,{
      position:"fixed",inset:"0",background:"rgba(15,23,42,0.6)",zIndex:"99998",
      display:"flex",alignItems:"center",justifyContent:"center",padding:"20px",
      animation:"fadeIn .15s ease",backdropFilter:"blur(4px)",
    });
    const box=document.createElement("div");
    Object.assign(box.style,{
      background:"#fff",borderRadius:"16px",padding:"22px 24px",maxWidth:"440px",width:"100%",
      boxShadow:"0 20px 60px rgba(0,0,0,0.3)",fontFamily:"'Outfit',system-ui,sans-serif",
      animation:"slideInUp .2s ease",
    });
    const title=document.createElement("div");
    Object.assign(title.style,{color:"#0f172a",fontSize:"15px",fontWeight:"700",marginBottom:"14px",lineHeight:"1.4"});
    title.textContent=message;
    box.appendChild(title);
    const input=document.createElement("input");
    input.type=opts.inputType||"text";
    input.placeholder=opts.placeholder||"";
    input.value=opts.defaultValue||"";
    Object.assign(input.style,{width:"100%",padding:"10px 14px",border:"1px solid #cbd5e1",borderRadius:"10px",fontSize:"14px",outline:"none",fontFamily:"inherit",marginBottom:"16px",boxSizing:"border-box"});
    box.appendChild(input);
    const btns=document.createElement("div");
    Object.assign(btns.style,{display:"flex",gap:"8px",justifyContent:"flex-end"});
    const close=(val)=>{document.body.removeChild(overlay);resolve(val);};
    const cancel=document.createElement("button");
    cancel.textContent=opts.cancelText||"Cancelar";
    Object.assign(cancel.style,{background:"#f1f5f9",border:"none",color:"#475569",padding:"10px 20px",borderRadius:"10px",fontSize:"13px",fontWeight:"700",cursor:"pointer",fontFamily:"inherit"});
    cancel.onclick=()=>close(null);
    const ok=document.createElement("button");
    ok.textContent=opts.okText||"OK";
    Object.assign(ok.style,{background:"#2563eb",border:"none",color:"#fff",padding:"10px 20px",borderRadius:"10px",fontSize:"13px",fontWeight:"700",cursor:"pointer",fontFamily:"inherit"});
    ok.onclick=()=>close(input.value);
    input.onkeydown=(e)=>{if(e.key==="Enter")close(input.value);if(e.key==="Escape")close(null);};
    btns.appendChild(cancel);btns.appendChild(ok);
    box.appendChild(btns);
    overlay.appendChild(box);
    overlay.onclick=(e)=>{if(e.target===overlay)close(null);};
    document.body.appendChild(overlay);
    setTimeout(()=>input.focus(),50);
  });
}

// Modal de confirmação custom (substitui confirm())
function pixelsConfirm(message,opts={}){
  return new Promise(resolve=>{
    if(typeof document==="undefined")return resolve(window.confirm(message));
    const isDanger=!!opts.danger;
    const overlay=document.createElement("div");
    Object.assign(overlay.style,{position:"fixed",inset:"0",background:"rgba(15,23,42,0.55)",zIndex:"99998",display:"flex",alignItems:"center",justifyContent:"center",padding:"20px",animation:"fadeIn .15s ease",backdropFilter:"blur(6px)"});
    const box=document.createElement("div");
    Object.assign(box.style,{background:"#fff",borderRadius:"18px",padding:"26px 28px 22px",maxWidth:"440px",width:"100%",boxShadow:"0 30px 70px rgba(15,23,42,0.22)",border:"1px solid #f1f5f9",fontFamily:"'Inter',system-ui,sans-serif",animation:"slideInUp .18s ease"});
    const header=document.createElement("div");
    Object.assign(header.style,{display:"flex",alignItems:"flex-start",gap:"14px",marginBottom:"18px"});
    const icoWrap=document.createElement("div");
    Object.assign(icoWrap.style,{width:"40px",height:"40px",borderRadius:"12px",flexShrink:"0",background:isDanger?"#fee2e2":"#dbeafe",color:isDanger?"#dc2626":"#2563eb",display:"flex",alignItems:"center",justifyContent:"center"});
    icoWrap.innerHTML=isDanger?'<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/></svg>':'<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>';
    const titleBox=document.createElement("div");
    Object.assign(titleBox.style,{flex:"1",minWidth:"0"});
    const titleEl=document.createElement("div");
    Object.assign(titleEl.style,{color:"#0f172a",fontSize:"16px",fontWeight:"700",letterSpacing:"-0.3px",lineHeight:"1.3",marginBottom:"4px"});
    titleEl.textContent=opts.title||(isDanger?"Confirmar exclusão":"Confirmação");
    const msgEl=document.createElement("div");
    Object.assign(msgEl.style,{color:"#64748b",fontSize:"13px",lineHeight:"1.55",fontWeight:"500"});
    msgEl.textContent=message;
    titleBox.appendChild(titleEl);titleBox.appendChild(msgEl);
    header.appendChild(icoWrap);header.appendChild(titleBox);
    box.appendChild(header);
    const btns=document.createElement("div");
    Object.assign(btns.style,{display:"flex",gap:"8px",justifyContent:"flex-end",marginTop:"6px"});
    const cancel=document.createElement("button");
    cancel.textContent=opts.cancelText||"Cancelar";
    Object.assign(cancel.style,{background:"#f1f5f9",border:"none",color:"#475569",padding:"10px 18px",borderRadius:"10px",fontSize:"13px",fontWeight:"700",cursor:"pointer",fontFamily:"inherit",transition:"background .12s"});
    cancel.onmouseenter=()=>{cancel.style.background="#e2e8f0";};
    cancel.onmouseleave=()=>{cancel.style.background="#f1f5f9";};
    function _close(val){try{document.body.removeChild(overlay);}catch(_){};document.removeEventListener("keydown",onKey);resolve(val);}
    cancel.onclick=()=>_close(false);
    const ok=document.createElement("button");
    ok.textContent=opts.okText||"Confirmar";
    Object.assign(ok.style,{background:isDanger?"#dc2626":"#2563eb",border:"none",color:"#fff",padding:"10px 18px",borderRadius:"10px",fontSize:"13px",fontWeight:"700",cursor:"pointer",fontFamily:"inherit",boxShadow:isDanger?"0 6px 16px rgba(220,38,38,0.30)":"0 6px 16px rgba(37,99,235,0.30)",transition:"transform .12s, box-shadow .12s"});
    ok.onmouseenter=()=>{ok.style.transform="translateY(-1px)";};
    ok.onmouseleave=()=>{ok.style.transform="";};
    ok.onclick=()=>_close(true);
    btns.appendChild(cancel);btns.appendChild(ok);
    box.appendChild(btns);
    overlay.appendChild(box);
    overlay.onclick=(e)=>{if(e.target===overlay)_close(false);};
    function onKey(e){if(e.key==="Escape")_close(false);else if(e.key==="Enter")_close(true);}
    document.addEventListener("keydown",onKey);
    document.body.appendChild(overlay);
    setTimeout(()=>ok.focus(),50);
  });
}

/* ─── UTILS ──────────────────────────────── */
const mkId=()=>Math.floor(Date.now()+Math.random()*999999);
const daysLeft=d=>{const e=new Date(d),n=new Date();n.setHours(0,0,0,0);return Math.ceil((e-n)/86400000);};

/* ─── SLA HELPERS — Prazo de entrega com dias úteis ─── */
// Opções de SLA (em horas)
const SLA_OPTIONS=[
  {label:"12 horas",hours:12,emoji:"⚡"},
  {label:"1 dia útil",hours:24,emoji:"🔥"},
  {label:"2 dias úteis",hours:48,emoji:"⏱"},
  {label:"3 dias úteis",hours:72,emoji:"⏰"},
  {label:"4 dias úteis",hours:96,emoji:"📅"},
  {label:"5 dias úteis",hours:120,emoji:"🗓"},
];

// Checa se uma data (Date) é dia útil (não sábado nem domingo)
function isBusinessDay(d){const dow=d.getDay();return dow!==0&&dow!==6;}

// Adiciona N horas a uma data, PULANDO fins de semana
function addBusinessHours(startDate,hours){
  const d=new Date(startDate);
  let remaining=hours;
  while(remaining>0){
    d.setHours(d.getHours()+1);
    // Se caiu em fim de semana, pula pra próxima segunda 09:00
    if(!isBusinessDay(d)){
      while(!isBusinessDay(d)){d.setDate(d.getDate()+1);}
      d.setHours(9,0,0,0);
      continue;
    }
    remaining--;
  }
  return d;
}

// Calcula quando o SLA vai vencer com base em slaStartAt + slaHours + pausas
function calcSlaDeadline(task){
  if(!task.slaHours||!task.slaStartAt)return null;
  const startMs=new Date(task.slaStartAt).getTime();
  const pausedMs=(task.slaPausedDuration||0)*1000;
  // Se está pausado agora, soma o tempo desde slaPausedAt
  let adjustedStart=startMs+pausedMs;
  if(task.slaPausedAt){
    adjustedStart+=(Date.now()-new Date(task.slaPausedAt).getTime());
  }
  return addBusinessHours(new Date(adjustedStart),task.slaHours);
}

// Retorna status do SLA: {deadline, msLeft, status: "ok"|"soon"|"overdue"|"paused"|"none"}
function getSlaStatus(task){
  if(!task||!task.slaHours||!task.slaStartAt)return{status:"none"};
  if(task.slaPausedAt)return{status:"paused",pausedSince:task.slaPausedAt};
  const deadline=calcSlaDeadline(task);
  if(!deadline)return{status:"none"};
  const msLeft=deadline.getTime()-Date.now();
  const hoursLeft=msLeft/(1000*60*60);
  let status="ok";
  if(msLeft<0)status="overdue";
  else if(hoursLeft<24)status="soon"; // menos de 1 dia
  else if(hoursLeft<2)status="urgent"; // menos de 2h
  return{status,deadline,msLeft,hoursLeft};
}

// Formato amigável do tempo restante ou atrasado
function fmtSlaTime(msLeft){
  const abs=Math.abs(msLeft);
  const h=Math.floor(abs/(1000*60*60));
  const m=Math.floor((abs%(1000*60*60))/(1000*60));
  if(h>=24){const d=Math.floor(h/24);return d+"d "+(h%24)+"h";}
  if(h>0)return h+"h "+m+"m";
  return m+"m";
}

/* ─── SLA Hourglass — componente visual de contagem regressiva ─── */
function SlaHourglass({task,compact}){
  const [tick,setTick]=useState(0);
  useEffect(()=>{const i=setInterval(()=>setTick(t=>t+1),30000);return()=>clearInterval(i);},[]);
  const s=getSlaStatus(task);
  if(s.status==="none")return null;
  const colors={
    ok:{bg:"#16a34a",label:"No prazo",icon:"⏳"},
    soon:{bg:"#eab308",label:"Atenção",icon:"⚠"},
    urgent:{bg:"#ea580c",label:"Urgente",icon:"🔥"},
    overdue:{bg:"#dc2626",label:"Atrasado",icon:"🚨"},
    paused:{bg:"#64748b",label:"Pausado",icon:"⏸"},
  };
  const c=colors[s.status]||colors.ok;
  if(s.status==="paused"){
    return <span style={{background:c.bg,color:"#fff",borderRadius:6,padding:compact?"2px 6px":"4px 10px",fontSize:compact?9:10,fontWeight:800,display:"inline-flex",alignItems:"center",gap:4}}>{c.icon} {c.label}</span>;
  }
  const shouldPulse=s.status==="urgent"||s.status==="overdue";
  return <span style={{
      background:c.bg,color:"#fff",borderRadius:6,
      padding:compact?"2px 6px":"4px 10px",
      fontSize:compact?9:10,fontWeight:800,
      display:"inline-flex",alignItems:"center",gap:4,
      animation:shouldPulse?"slaPulse 1.5s ease-in-out infinite":"none",
      whiteSpace:"nowrap",
    }}>
    {c.icon} {s.status==="overdue"?`${fmtSlaTime(s.msLeft)} atrasado`:fmtSlaTime(s.msLeft)}
  </span>;
}
const pct=(a,b)=>b>0?Math.round((a/b)*100):0;
const dlLabel=d=>d<0?Math.abs(d)+"d atraso":d===0?"Hoje":d===1?"Amanhã":d+"d";
const dlColor=d=>d<0?"#e53e3e":d<=2?"#dd6b20":d<=5?"#d69e2e":"#94a3b8";
const fmtDate=iso=>iso?new Date(iso).toLocaleDateString("pt-BR",{day:"2-digit",month:"2-digit"}):"—";
const f$=v=>"R$ "+v.toLocaleString("pt-BR");
const fN=v=>v>=1000?(v/1000).toFixed(1)+"k":String(v);
const hc=h=>h>=80?C.gr:h>=60?C.yw:C.rd;

