/* ─── USER AVATAR GLOBAL ──────────────────────
 * Componente que mostra a FOTO real do usuário se existir, com fallback pra letra colorida.
 * Usa getProfilePhoto (já existente — lê pixels-selfprofile-{id} do localStorage).
 * Re-renderiza instantâneo quando dispara event "pixels:photo-updated".
 */
function UserAvatar({user, size=18, fontWeight=600, border=true, style:extraStyle, title}){
  const u=typeof user==="string"?(TEAM.find(t=>t.id===user)||{id:user,name:user,av:"?",color:"#94a3b8"}):user;
  const [photo,setPhoto]=useState(()=>getProfilePhoto(u.id));
  const [broken,setBroken]=useState(false);
  useEffect(function(){
    const handler=function(e){
      if(!e||!e.detail||!e.detail.userId||e.detail.userId===u.id){
        setPhoto(getProfilePhoto(u.id));
        setBroken(false);
      }
    };
    window.addEventListener("pixels:photo-updated",handler);
    return function(){window.removeEventListener("pixels:photo-updated",handler);};
  },[u.id]);
  const base={
    width:size,height:size,borderRadius:"50%",
    border:border?"1.5px solid #fff":"none",
    boxShadow:"0 1px 2px rgba(0,0,0,0.1)",
    flexShrink:0,overflow:"hidden",display:"inline-flex",alignItems:"center",justifyContent:"center"
  };
  const merged=Object.assign({},base,extraStyle||{});
  const safePhoto = photo ? (typeof fixLegacyUrl==="function" ? fixLegacyUrl(photo) : photo) : null;
  if(safePhoto && !broken){
    return <img src={safePhoto} alt={u.name||""} title={title||u.name||""} loading="lazy"
      style={Object.assign({},merged,{objectFit:"cover"})}
      onError={function(){
        setBroken(true);
        try{
          if(window._sb){
            window._sb.from("profiles").select("profile_data").eq("team_id",u.id).single().then(function(r){
              if(r&&r.data&&r.data.profile_data&&r.data.profile_data.photo){
                const fresh=r.data.profile_data.photo;
                try{
                  const cur=localStorage.getItem("pixels-selfprofile-"+u.id);
                  const parsed=cur?JSON.parse(cur):{};
                  parsed.photo=fresh;
                  localStorage.setItem("pixels-selfprofile-"+u.id,JSON.stringify(parsed));
                  window.dispatchEvent(new CustomEvent("pixels:photo-updated",{detail:{userId:u.id}}));
                }catch(e){}
              }
            }).catch(function(){});
          }
        }catch(e){}
      }}/>;
  }
  return <div title={title||u.name||""} style={Object.assign({},merged,{
    background:u.color||"#94a3b8",
    color:"#fff",fontWeight:fontWeight,
    fontSize:Math.max(8,Math.round(size*0.45))
  })}>{u.av||(u.name||"?").charAt(0).toUpperCase()}</div>;
}

/* ─── HOOK: useEscToClose ──────────────────── */
// Captura Esc enquanto a condição `active` é verdadeira e dispara `onClose`.
// Padrão pra TODO modal/overlay do app — usar assim:
//   useEscToClose(!!isOpen, ()=>setIsOpen(false));
// Stop propagation pra que múltiplos modais sobrepostos só fechem o topo.
function useEscToClose(active, onClose){
  useEffect(function(){
    if(!active)return undefined;
    function handler(e){
      if(e.key==="Escape"){
        e.stopPropagation();
        if(typeof onClose==="function")onClose();
      }
    }
    window.addEventListener("keydown",handler);
    return function(){window.removeEventListener("keydown",handler);};
  },[active,onClose]);
}

/* ─── HOOK: useOpenCardSync ─────────────────── */
// Mantém o card aberto sincronizado com a versão mais recente de tasks.
// IMPORTANTE: NÃO fecha o cartão automaticamente — se o cartão sumir do array
// (ex: race do polling ao voltar de aba minimizada), só fica esperando voltar.
// O usuário fecha manualmente pelo X. Evita o bug "minimizei e fechou".
function useOpenCardSync(openCard, setOpenCard, tasks){
  useEffect(()=>{
    if(!openCard)return;
    if(!tasks||tasks.length===0)return; // tasks ainda não carregou — mantém o card aberto
    const updated=tasks.find(t=>String(t.id)===String(openCard.id));
    if(updated&&updated!==openCard){
      setOpenCard(updated); // sincroniza referência (atualizações de outras sessões)
    }
    // NÃO chama setOpenCard(null) mesmo se não achar — evita fechar em race condition
  },[tasks]); // eslint-disable-line react-hooks/exhaustive-deps
}

/* ─── URGÊNCIA DE TAREFAS ────────────────────── */
// Retorna nível de urgência: 0=atrasado | 1=urgente | 2=atenção | 3=no prazo
function taskUrgencyLevel(t){
  if(!t||["aprovado","agendado","publicado","pausado","reprovado"].includes(t.status))return 3;
  const d=t.deadline?daysLeft(t.deadline):null;
  if(d===null)return 3;
  if(d<0)return 0;   // atrasado
  if(d<=1)return 1;  // urgente (hoje ou amanhã)
  if(d<=3)return 2;  // atenção
  return 3;          // no prazo
}

// Cor correspondente ao nível de urgência
function getUrgencyColor(level){
  return(["#e53e3e","#f97316",C.yw,C.gr])[level]??C.gr;
}

// Cor determinística por hash do nome da tag — pílulas coloridas Trello-like
const TAG_PALETTE=[
  {bg:"#fef2f2",fg:"#991b1b"}, // red
  {bg:"#fff7ed",fg:"#9a3412"}, // orange
  {bg:"#fefce8",fg:"#854d0e"}, // yellow
  {bg:"#f0fdf4",fg:"#15803d"}, // green
  {bg:"#ecfeff",fg:"#155e75"}, // cyan
  {bg:"#eff6ff",fg:"#1e40af"}, // blue
  {bg:"#faf5ff",fg:"#7c3aed"}, // purple (Pixels)
  {bg:"#fdf4ff",fg:"#86198f"}, // pink
  {bg:"#f8fafc",fg:"#475569"}, // slate
];
function tagColor(tag){
  if(!tag)return TAG_PALETTE[8];
  let hash=0;
  for(let i=0;i<tag.length;i++)hash=(hash*31+tag.charCodeAt(i))|0;
  return TAG_PALETTE[Math.abs(hash)%TAG_PALETTE.length];
}

/* ─── PRESENCE / STATUS ONLINE ───────────────
   Calcula status baseado no último heartbeat.
   - online: ativo nos últimos 10 min
   - ausente: 10 min a 2h sem atividade
   - offline: mais de 2h ou nunca acessou
*/
function getPresenceStatus(lastSeenAt){
  if(!lastSeenAt)return{status:"offline",label:"Offline",color:"#94a3b8"};
  const now=Date.now();
  const last=new Date(lastSeenAt).getTime();
  if(isNaN(last))return{status:"offline",label:"Offline",color:"#94a3b8"};
  const diffMin=(now-last)/60000;
  if(diffMin<=10)return{status:"online",label:"Online",color:"#16a34a"};
  if(diffMin<=120)return{status:"ausente",label:"Ausente",color:"#eab308"};
  return{status:"offline",label:"Offline",color:"#94a3b8"};
}

// Formata "última atividade às XX:XX do dia DD/MM/YY"
function fmtLastSeen(lastSeenAt){
  if(!lastSeenAt)return"Nunca acessou o app";
  const d=new Date(lastSeenAt);
  if(isNaN(d.getTime()))return"Sem registro";
  const today=new Date();today.setHours(0,0,0,0);
  const ds=new Date(d);ds.setHours(0,0,0,0);
  const time=d.toLocaleTimeString("pt-BR",{hour:"2-digit",minute:"2-digit"});
  if(ds.getTime()===today.getTime())return`Última atividade às ${time} de hoje`;
  const yesterday=new Date(today);yesterday.setDate(today.getDate()-1);
  if(ds.getTime()===yesterday.getTime())return`Última atividade às ${time} de ontem`;
  return`Última atividade às ${time} do dia ${d.toLocaleDateString("pt-BR")}`;
}

/* ─── HELPER: getProfilePhoto ───────────────── */
// Busca foto do localStorage para qualquer userId
function getProfilePhoto(uid){
  if(!uid) return null;
  try{
    const s=localStorage.getItem("pixels-selfprofile-"+uid);
    if(!s) return null;
    const p=JSON.parse(s);
    return p?.photo||null;
  }catch(e){return null;}
}

/* ─── FUNÇÃO: trashDaysLeft ─────────────────── */
// Retorna quantos dias restam antes de um card na lixeira ser excluído (30 dias)
function trashDaysLeft(t){
  if(!t?.deletedAt) return 30;
  const deleted=new Date(t.deletedAt);
  const expires=new Date(deleted.getTime()+30*24*60*60*1000);
  return Math.max(0,Math.ceil((expires-new Date())/86400000));
}

