// Barra de progresso simples
const Bar=({v,color,h=6})=>(
  <div style={{width:"100%",height:h,background:C.b1,borderRadius:99,overflow:"hidden"}}>
    <div style={{width:`${Math.min(100,Math.max(0,v))}%`,height:"100%",background:color||C.a,borderRadius:99,transition:"width .4s ease"}}/>
  </div>
);

/* ─── DASHBOARD ADMIN PREMIUM (Vinicius, Gustavo) ───
   Nível V4/G4: visão executiva completa com foco OPERACIONAL primeiro
   Estrutura:
   1. Banner de AÇÕES URGENTES (portal, atrasos, publicações, aprovações)
   2. Pipeline Operacional (3 fluxos lado a lado)
   3. Andamento de CADA Colaborador (tabela rica)
   4. Aprovações Pendentes (copys + artes)
   5. Publicações (hoje/semana/atrasadas)
   6. Solicitações do Portal
   7. KPIs Financeiros (MRR, ROAS, LTV, Churn, NPS)
   8. Top Clientes + Clientes em Risco
   9. Panorama completo dos Clientes
   10. Pagamentos em Atraso + Demandas Atrasadas
*/
function DashPartner({user,isViewing,tasks:propTasks,setTasks:propSetTasks,notifs,isMob}){
  const [openCard,setOpenCard]=useState(null);
  // ═══ TAB ATIVA ═══ (alerta | demandas | metricas | metas)
  const [activeTab,setActiveTab]=useState(()=>{
    try{return localStorage.getItem("pixels-dash-tab")||"alerta";}catch{return "alerta";}
  });
  // ═══ Mês selecionado pro card de Pagamento por Demanda (default: mês corrente) ═══
  const [payMonth,setPayMonth]=useState(()=>{
    try{
      const saved=localStorage.getItem("pixels-pay-month");
      if(saved)return saved;
    }catch(e){}
    const now=new Date();
    return now.getFullYear()+"-"+String(now.getMonth()+1).padStart(2,"0");
  });
  useEffect(()=>{try{localStorage.setItem("pixels-pay-month",payMonth);}catch(e){}},[payMonth]);
  useEffect(()=>{try{localStorage.setItem("pixels-dash-tab",activeTab);}catch(e){}},[activeTab]);
  const setTasks=propSetTasks||(()=>{});
  const adminCardPerms=(()=>{try{const s=localStorage.getItem("pixels-perms-"+(CURRENT_USER).id);return s?{...DEFAULT_PERMS,...JSON.parse(s)}:DEFAULT_PERMS;}catch{return DEFAULT_PERMS;}})();
  const allTasks=propTasks||[];
  const active=allTasks.filter(t=>!t.deletedAt);
  const ativas=active.filter(t=>t.status!=="aprovado"&&t.status!=="publicado"&&t.status!=="pausado");
  const hojeStr=(()=>{const d=new Date();return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0");})();
  const hoje=new Date();hoje.setHours(0,0,0,0);
  const ha7d=new Date(hoje);ha7d.setDate(hoje.getDate()-7);
  const ha30d=new Date(hoje);ha30d.setDate(hoje.getDate()-30);
  const daqui7d=new Date(hoje);daqui7d.setDate(hoje.getDate()+7);

  // ═══ Demandas CLIENTES (kanban normal) ═══
  const clientStatuses=["demanda","recebida","execucao","avaliacao","aprovado","agendado","publicado","pausado","reprovado"];
  const clientTasks=active.filter(t=>clientStatuses.includes(t.status));
  const clientAtivas=clientTasks.filter(t=>t.status!=="aprovado"&&t.status!=="publicado"&&t.status!=="pausado");

  // ═══ Demandas INTERNAS ═══
  const internStatuses=["interno_demanda","interno_execucao","interno_avaliacao","interno_aprovado","interno_executado"];
  const internTasks=active.filter(t=>internStatuses.includes(t.status));
  const internAtivas=internTasks.filter(t=>t.status!=="interno_aprovado"&&t.status!=="interno_executado");

  // ═══ Solicitações do PORTAL (origem=portal) ═══
  const portalRequests=active.filter(t=>t.origem==="portal");
  const portalPendentes=portalRequests.filter(t=>t.status==="interno_demanda"||(t.assignees||[]).length===0);
  const portalRecentes=portalRequests.filter(t=>t.createdAt&&new Date(t.createdAt)>=ha7d);

  // ═══ KPIs Executivos ═══
  const mrr=CLIENTS.reduce((a,c)=>a+c.contract,0);
  const avgRoas=(CLIENTS.reduce((a,c)=>a+(c.meta?.roas||0),0)/CLIENTS.length).toFixed(1);
  const totalLeads=CLIENTS.reduce((a,c)=>a+(c.meta?.leads||0)+(c.google?.leads||0),0);
  const avgHealth=Math.round(CLIENTS.reduce((a,c)=>a+c.health,0)/CLIENTS.length);
  const avgNps=Math.round(CLIENTS.reduce((a,c)=>a+(c.nps||0),0)/CLIENTS.length);
  const atrasadas=ativas.filter(t=>{const d=daysLeft(t.deadline);return d!==null&&d<0;});
  const noPrazoCount=ativas.length-atrasadas.length;
  const noPrazoPct=ativas.length>0?Math.round((noPrazoCount/ativas.length)*100):100;
  const ltvMedio=Math.round(CLIENTS.reduce((a,c)=>a+(c.contract*24),0)/CLIENTS.length); // LTV = 24 meses médios
  const clientesAtivos=CLIENTS.length;

  // ═══ Riscos críticos (exigem ação agora) ═══
  const riscosCriticos=[];
  CLIENTS.forEach(c=>{
    if(c.health<60)riscosCriticos.push({type:"saude",client:c,msg:`Saúde em ${c.health}%`,color:"#dc2626"});
    if(c.payment&&c.payment.status==="atrasado")riscosCriticos.push({type:"pag",client:c,msg:"Pagamento atrasado",color:"#dc2626"});
    if(c.lastMeeting){
      const p=c.lastMeeting.split("/");
      const diasSemReuniao=Math.floor((new Date()-new Date(p[2]+"-"+p[1]+"-"+p[0]))/(1000*60*60*24));
      if(diasSemReuniao>30)riscosCriticos.push({type:"reuniao",client:c,msg:`Reunião há ${diasSemReuniao}d`,color:"#ea580c"});
    }
  });
  TEAM.filter(u=>u.level>1).forEach(u=>{
    const uTasks=ativas.filter(t=>t.assignee===u.id||(t.assignees||[]).includes(u.id));
    if(uTasks.length>=10)riscosCriticos.push({type:"sobrecarga",user:u,msg:`Sobrecarga: ${uTasks.length} demandas ativas`,color:"#ea580c"});
  });

  // ═══ Pipeline (funil) ═══
  const pipeline=[
    {label:"Copys",status:"demanda",color:"#a140ff",icon:"📝"},
    {label:"Recebidas",status:"recebida",color:"#ec4899",icon:"📥"},
    {label:"Execução",status:"execucao",color:"#eab308",icon:"⚙"},
    {label:"Avaliação",status:"avaliacao",color:"#f97316",icon:"👀"},
    {label:"Aprovadas",status:"aprovado",color:"#16a34a",icon:"✅"},
    {label:"Agendadas",status:"agendado",color:"#2563eb",icon:"📅"},
  ].map(s=>({...s,count:active.filter(t=>t.status===s.status).length}));
  const pipelineMax=Math.max(...pipeline.map(p=>p.count),1);

  // ═══ Top Clientes por MRR ═══
  const topClientes=[...CLIENTS].sort((a,b)=>b.contract-a.contract).slice(0,5);

  // ═══ Clientes em risco ═══
  const clientesRisco=CLIENTS.filter(c=>c.health<60||(c.payment&&c.payment.status==="atrasado"))
    .sort((a,b)=>a.health-b.health);

  // ═══ Produtividade da equipe (últimos 30d) — reusa hoje/ha30d já declarados acima
  const equipeStats=TEAM.filter(u=>u.level>1).map(u=>{
    const done30d=active.filter(t=>{
      if(t.status!=="aprovado"||!t.completedAt)return false;
      if(t.assignee!==u.id&&!(t.assignees||[]).includes(u.id))return false;
      return new Date(t.completedAt)>=ha30d;
    }).length;
    const activeNow=ativas.filter(t=>t.assignee===u.id||(t.assignees||[]).includes(u.id)).length;
    const lateNow=atrasadas.filter(t=>t.assignee===u.id||(t.assignees||[]).includes(u.id)).length;
    return {user:u,done30d,activeNow,lateNow};
  }).sort((a,b)=>b.done30d-a.done30d);
  const maxDone=Math.max(...equipeStats.map(e=>e.done30d),1);

  // ═══ Histórico de produção da agência (mini-charts + chart evolutivo) ═══
  const agencyCompletedSeries=(()=>{
    const compute=(days)=>{
      const today=new Date();today.setHours(0,0,0,0);
      const arr=Array(days).fill(0);
      (allTasks||[]).forEach(t=>{
        if(!t.completedAt)return;
        const d=new Date(t.completedAt);d.setHours(0,0,0,0);
        const diff=Math.floor((today-d)/86400000);
        if(diff>=0&&diff<days)arr[days-1-diff]++;
      });
      return arr;
    };
    return{"7d":compute(7),"30d":compute(30),"90d":compute(90)};
  })();
  const last6AgencyCompletions=agencyCompletedSeries["7d"].slice(-6);

  // ═══ Pagamentos atrasados ═══
  const pagAtras=CLIENTS.filter(c=>c.payment&&c.payment.status==="atrasado");

  // ═══ Minhas Demandas (card grande + 5 laterais) — tanto clientes quanto internas ═══
  const myTasks=active.filter(t=>{
    const isMine=t.assignee===user.id||(t.assignees||[]).includes(user.id);
    if(!isMine)return false;
    // Ignora concluídas/publicadas/pausadas
    if(["aprovado","publicado","pausado","interno_aprovado","interno_executado"].includes(t.status))return false;
    return true;
  });
  // Usa o sortByPriority do 12_dashboard.jsx (disponível no bundle)
  const mySorted=typeof sortByPriority==="function"?sortByPriority(myTasks):myTasks;
  const myMain=mySorted[0]||null;
  const myNext=mySorted.slice(1,6);
  const myMainPrio=myMain&&typeof getDemandPriority==="function"?getDemandPriority(myMain):null;
  const myMainCl=myMain?CLIENTS.find(c=>c.id===myMain.client):null;

  // ═══ Publicações ═══
  const agendadas=active.filter(t=>t.status==="agendado");
  const pubHoje=agendadas.filter(t=>t.publishDate===hojeStr);
  const pubAtrasadas=agendadas.filter(t=>t.publishDate&&t.publishDate<hojeStr);
  const pubSemana=agendadas.filter(t=>{
    if(!t.publishDate)return false;
    const pd=new Date(t.publishDate);
    return pd>=hoje&&pd<=daqui7d;
  });

  // ═══ Aprovações pendentes ═══
  const copysPendentes=clientTasks.filter(t=>t.status==="demanda"&&!t.ajustar);
  const artesPendentes=clientTasks.filter(t=>t.status==="avaliacao");
  const aprovacoesInternas=internTasks.filter(t=>t.status==="interno_avaliacao");

  // ═══ Andamento detalhado por colaborador ═══
  const equipeDetalhe=TEAM.filter(u=>u.level>1).map(u=>{
    const todas=active.filter(t=>t.assignee===u.id||(t.assignees||[]).includes(u.id));
    const emAtv=todas.filter(t=>!["aprovado","publicado","pausado","interno_aprovado","interno_executado"].includes(t.status));
    const emExec=emAtv.filter(t=>t.status==="execucao"||t.status==="interno_execucao");
    const emAval=emAtv.filter(t=>t.status==="avaliacao"||t.status==="interno_avaliacao");
    const atras=emAtv.filter(t=>{const d=daysLeft(t.deadline);return d!==null&&d<0;});
    const urg=emAtv.filter(t=>{const d=daysLeft(t.deadline);return d===0;});
    const done30d=todas.filter(t=>{
      if(t.status!=="aprovado"&&t.status!=="interno_aprovado"&&t.status!=="interno_executado"&&t.status!=="publicado")return false;
      if(!t.completedAt)return false;
      return new Date(t.completedAt)>=ha30d;
    }).length;
    const prazoPct=emAtv.length>0?Math.round(((emAtv.length-atras.length-urg.length)/emAtv.length)*100):100;
    const saudeC=prazoPct>=80?"#16a34a":prazoPct>=60?"#eab308":"#dc2626";
    return {user:u,emAtv:emAtv.length,emExec:emExec.length,emAval:emAval.length,atras:atras.length,urg:urg.length,done30d,prazoPct,saudeC};
  }).sort((a,b)=>b.done30d-a.done30d);

  // ═══ Ações urgentes (tudo que precisa atenção AGORA) ═══
  const acoesUrgentes=[];
  if(portalPendentes.length>0)acoesUrgentes.push({type:"portal",count:portalPendentes.length,label:"Nova(s) solicitação(ões) do portal",color:"#2563eb",icon:"📩"});
  if(pubAtrasadas.length>0)acoesUrgentes.push({type:"pubatras",count:pubAtrasadas.length,label:"Publicação(ões) atrasada(s)",color:"#dc2626",icon:"📤"});
  if(atrasadas.length>0)acoesUrgentes.push({type:"atras",count:atrasadas.length,label:"Demanda(s) atrasada(s)",color:"#dc2626",icon:"🔥"});
  if(copysPendentes.length>0)acoesUrgentes.push({type:"copys",count:copysPendentes.length,label:"Copy(s) aguardando aprovação",color:"#7c3aed",icon:"📝"});
  if(artesPendentes.length>0)acoesUrgentes.push({type:"artes",count:artesPendentes.length,label:"Arte(s) aguardando aprovação",color:"#16a34a",icon:"🎨"});
  if(pubHoje.length>0)acoesUrgentes.push({type:"pubhoje",count:pubHoje.length,label:"Publicação(ões) hoje",color:"#2563eb",icon:"🚀"});
  if(pagAtras.length>0)acoesUrgentes.push({type:"pag",count:pagAtras.length,label:"Pagamento(s) atrasado(s)",color:"#dc2626",icon:"💸"});

  // ═══ NOVAS COMPUTAÇÕES PARA AS TABS ═══

  // Brief do Dia — narrativa que sintetiza ações urgentes em texto
  const briefParts=[];
  if(atrasadas.length>0)briefParts.push(`${atrasadas.length} demanda${atrasadas.length>1?"s atrasadas":" atrasada"}`);
  if(pagAtras.length>0)briefParts.push(`${pagAtras.length} pagamento${pagAtras.length>1?"s vencidos":" vencido"}`);
  if(pubAtrasadas.length>0)briefParts.push(`${pubAtrasadas.length} publicação${pubAtrasadas.length>1?"ões atrasadas":" atrasada"}`);
  if(pubHoje.length>0)briefParts.push(`${pubHoje.length} publicação${pubHoje.length>1?"ões hoje":" hoje"}`);
  const aprovTotal=copysPendentes.length+artesPendentes.length;
  if(aprovTotal>0)briefParts.push(`${aprovTotal} aprovação${aprovTotal>1?"ões pendentes":" pendente"}`);

  // Total de alertas para badge na tab
  const alertaCount=atrasadas.length+pagAtras.length+pubAtrasadas.length+clientesRisco.length;

  // Tab Demandas — KPIs operacionais
  const emProducao=active.filter(t=>t.status==="execucao"||t.status==="interno_execucao").length;
  const emAvaliacao=active.filter(t=>t.status==="avaliacao"||t.status==="interno_avaliacao").length;
  const aprovadasTotal=active.filter(t=>t.status==="aprovado"||t.status==="interno_aprovado").length;
  const publicadasMes=active.filter(t=>{
    if(t.status!=="publicado"||!t.completedAt)return false;
    const d=new Date(t.completedAt);
    return d.getFullYear()===hoje.getFullYear()&&d.getMonth()===hoje.getMonth();
  }).length;

  // Carga por pessoa (avatar + barra horizontal)
  const cargaPorPessoa=TEAM.filter(u=>u.level>1).map(u=>{
    const count=ativas.filter(t=>t.assignee===u.id||(t.assignees||[]).includes(u.id)).length;
    return {user:u,count};
  }).sort((a,b)=>b.count-a.count);
  const maxCarga=Math.max(...cargaPorPessoa.map(c=>c.count),1);

  // Velocity — entregas por semana (4 últimas semanas)
  const velocity=[3,2,1,0].map(weeksAgo=>{
    const start=new Date(hoje);start.setDate(hoje.getDate()-(weeksAgo+1)*7);
    const end=new Date(hoje);end.setDate(hoje.getDate()-weeksAgo*7);
    return active.filter(t=>{
      if(t.status!=="aprovado"&&t.status!=="publicado"&&t.status!=="interno_aprovado"&&t.status!=="interno_executado")return false;
      if(!t.completedAt)return false;
      const d=new Date(t.completedAt);
      return d>=start&&d<end;
    }).length;
  });
  const velocityMax=Math.max(...velocity,1);
  const velocityAvg=(velocity.reduce((a,b)=>a+b,0)/velocity.length).toFixed(1);
  const velocityTrend=velocity[3]>velocity[0]?"↑":velocity[3]<velocity[0]?"↓":"→";

  // Gargalos detectados — coluna com cards parados há 4+ dias
  const gargalos=pipeline.map(p=>{
    const stuck=active.filter(t=>{
      if(t.status!==p.status||!t.colEnteredAt)return false;
      const days=Math.floor((new Date()-new Date(t.colEnteredAt))/(1000*60*60*24));
      return days>=4;
    }).length;
    return {label:p.label,color:p.color,stuck};
  }).filter(g=>g.stuck>0);

  // Tab Métricas — 4 hero numbers
  const spendTotal=CLIENTS.reduce((a,c)=>a+(c.meta?.spend||0)+(c.google?.spend||0),0);
  const followersTotal=CLIENTS.reduce((a,c)=>a+(c.social?.followers||0),0);
  // totalLeads e avgRoas já calculados acima

  // Top 5 ROAS / Bottom (alerta)
  const top5Roas=[...CLIENTS].filter(c=>(c.meta?.roas||0)>0).sort((a,b)=>(b.meta?.roas||0)-(a.meta?.roas||0)).slice(0,5);
  const bottomRoas=CLIENTS.filter(c=>(c.meta?.roas||0)>0&&(c.meta?.roas||0)<2).sort((a,b)=>(a.meta?.roas||0)-(b.meta?.roas||0));

  // Tab Metas — metas hardcoded (depois cria tela editável)
  const METAS={mrr:75000,novosClientesMes:3,nps:90,churn:3};
  const novosClientesMes=CLIENTS.filter(c=>{
    if(!c.since)return false;
    // since formato "Mar 2025" — comparação simplificada com mês atual
    const meses=["Jan","Fev","Mar","Abr","Mai","Jun","Jul","Ago","Set","Out","Nov","Dez"];
    const atual=meses[hoje.getMonth()]+" "+hoje.getFullYear();
    return c.since===atual;
  }).length;
  const churnPct=0; // placeholder — sem tracking real ainda

  // Health Score composto da agência (0-100)
  const slaScore=noPrazoPct;
  const npsScore=avgNps;
  const churnScore=Math.max(0,100-churnPct*20);
  const growthScore=80; // placeholder — depois conectar com histórico real
  const healthScore=Math.round(slaScore*0.3+npsScore*0.3+churnScore*0.2+growthScore*0.2);

  // Receita histórica 12 meses — placeholder com dados sintéticos crescentes
  const receita12m=Array.from({length:12},(_,i)=>{
    const fator=0.55+i*0.04; // crescimento simulado
    return Math.round(mrr*fator);
  });
  const receita12mMax=Math.max(...receita12m);

  // ── Auto-normalizar títulos antigos ─────────────────────────
  // Roda silenciosamente uma vez por navegador (flag em localStorage).
  // Só sócios disparam (level 1) — pra evitar problemas de RLS com colaboradores.
  // smartFormatTitle é idempotente, então rodar de novo sem flag não causa nenhum efeito.
  const _migratedRef=useRef(false);
  useEffect(()=>{
    if(_migratedRef.current)return;
    if(!user||user.level!==1)return;
    if(!allTasks||allTasks.length===0)return;
    const FLAG_KEY="pixels-title-migration-v8";
    try{if(localStorage.getItem(FLAG_KEY))return;}catch(e){}
    const candidates=allTasks.filter(t=>{
      if(!t||!t.title||t.deletedAt)return false;
      return smartFormatTitle(t.title)!==t.title;
    });
    if(candidates.length>0){
      setTasks(prev=>prev.map(t=>{
        if(!t||!t.title)return t;
        const newTitle=smartFormatTitle(t.title);
        return newTitle===t.title?t:{...t,title:newTitle};
      }));
      pixelsToast.info(`${candidates.length} título(s) padronizado(s) automaticamente.`,5000);
    }
    try{localStorage.setItem(FLAG_KEY,"1");}catch(e){}
    _migratedRef.current=true;
  },[allTasks.length]);

  return <div style={{display:"flex",flexDirection:"column",gap:16,maxWidth:1600,margin:"0 auto",width:"100%",padding:isMob?"0 4px":0}}>
    {openCard&&<CardModal task={openCard} tasks={allTasks} setTasks={setTasks} onClose={()=>setOpenCard(null)} currentUser={CURRENT_USER} cardPerms={adminCardPerms}/>}
    {isViewing&&<div style={{background:"#a140ff",borderRadius:10,padding:"8px 14px",color:"#fff",fontSize:12,fontWeight:700,display:"flex",alignItems:"center",gap:8}}>
      👁 Visualizando dashboard de <strong>{user.name}</strong>
    </div>}

    {/* ═══ PAGAMENTO POR DEMANDA — Bloco consolidado (André + Maria + Guilherme) ═══ */}
    <FreelancerPaymentsBlock tasks={allTasks} refMonth={payMonth} onChangeMonth={setPayMonth} isMob={isMob}/>

    {/* ═══ HEADER FIXO — MINHAS DEMANDAS ═══ */}
    {myTasks.length>0&&(
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"minmax(0,1fr) 280px",gap:12}}>
        {/* CARD GRANDE — prioridade máxima */}
        {myMain&&(
          <div onClick={()=>setOpenCard(myMain)}
            style={{background:"#fff",border:"0.5px solid #e5e7eb",borderLeft:`5px solid ${myMainPrio?.bg||"#16a34a"}`,borderRadius:12,padding:"18px 20px",cursor:"pointer",display:"flex",flexDirection:"column",gap:12,transition:"all .12s"}}
            onMouseEnter={e=>{e.currentTarget.style.borderColor="#a140ff";}}
            onMouseLeave={e=>{e.currentTarget.style.borderColor="#e5e7eb";}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:10}}>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                {myMainPrio&&<span style={{background:myMainPrio.bg,color:"#fff",borderRadius:5,padding:"2px 8px",fontSize:9,fontWeight:600,letterSpacing:.5}}>
                  {myMainPrio.level===0?"ALTERAÇÃO":myMainPrio.level===1?"ATRASADO":myMainPrio.level===2?"URGENTE":"NO PRAZO"}
                </span>}
                <span style={{color:"#64748b",fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:.4}}>Minha próxima demanda</span>
              </div>
              {myMainCl&&<span style={{background:"#f1f5f9",color:"#475569",borderRadius:5,padding:"2px 8px",fontSize:10,fontWeight:700}}>{myMainCl.abbr}</span>}
            </div>
            <div style={{color:"#0f172a",fontWeight:700,fontSize:18,lineHeight:1.3,letterSpacing:-.3}}>{myMain.title}</div>
            {myMain.desc&&<div style={{color:"#64748b",fontSize:12,lineHeight:1.6}}>{myMain.desc.replace(/<[^>]*>/g,"").slice(0,120)}{myMain.desc.length>120?"...":""}</div>}
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",paddingTop:10,borderTop:"0.5px solid #f1f5f9",marginTop:"auto"}}>
              <span style={{color:myMainPrio?.bg||"#16a34a",fontSize:11,fontWeight:700}}>
                {myMainPrio?.icon&&myMainPrio.icon+" "}{myMainPrio?.label||"No prazo"}
              </span>
              <span style={{color:"#2563eb",fontSize:12,fontWeight:600}}>Abrir →</span>
            </div>
          </div>
        )}

        {/* 5 CARDS LATERAIS — próximas */}
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {myNext.length===0&&<div style={{background:"#f8fafc",border:"0.5px solid #e5e7eb",borderRadius:10,padding:"18px",textAlign:"center"}}>
            <div style={{fontSize:24,marginBottom:6}}>🎉</div>
            <div style={{color:"#64748b",fontSize:11,fontWeight:600}}>Só a principal por enquanto</div>
          </div>}
          {myNext.map(t=>{
            const prio=typeof getDemandPriority==="function"?getDemandPriority(t):{bg:"#94a3b8",label:"",icon:""};
            const cl=CLIENTS.find(c=>c.id===t.client);
            const dl=typeof daysLeft==="function"?daysLeft(t.deadline):null;
            return <div key={t.id} onClick={()=>setOpenCard(t)}
              style={{background:"#fff",border:"0.5px solid #e5e7eb",borderLeft:`3px solid ${prio.bg}`,borderRadius:8,padding:"10px 12px",cursor:"pointer",display:"flex",alignItems:"center",gap:10,transition:"all .1s"}}
              onMouseEnter={e=>{e.currentTarget.style.transform="translateX(2px)";e.currentTarget.style.borderColor="#cbd5e1";}}
              onMouseLeave={e=>{e.currentTarget.style.transform="";e.currentTarget.style.borderColor="#e5e7eb";}}>
              <div style={{flex:1,minWidth:0}}>
                <div style={{color:"#0f172a",fontWeight:600,fontSize:12,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.title}</div>
                <div style={{color:"#94a3b8",fontSize:10,marginTop:2}}>{cl?.abbr||(t.status?.startsWith("interno_")?"Interna":"—")}</div>
              </div>
              <span style={{color:prio.bg,fontWeight:700,fontSize:10,flexShrink:0}}>
                {prio.level<=1?prio.label:dl===null?"—":dl===0?"Hoje":dl+"d"}
              </span>
            </div>;
          })}
          {/* Mini totais */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,marginTop:2}}>
            <div style={{background:"#f8fafc",border:"0.5px solid #e5e7eb",borderRadius:8,padding:"8px",textAlign:"center"}}>
              <div style={{color:"#0f172a",fontWeight:600,fontSize:16}}>{myTasks.length}</div>
              <div style={{color:"#94a3b8",fontSize:9,fontWeight:600,textTransform:"uppercase"}}>Minhas</div>
            </div>
            <div style={{background:"#f8fafc",border:"0.5px solid #e5e7eb",borderRadius:8,padding:"8px",textAlign:"center"}}>
              <div style={{color:"#dc2626",fontWeight:600,fontSize:16}}>{myTasks.filter(t=>{const d=daysLeft(t.deadline);return d!==null&&d<0;}).length}</div>
              <div style={{color:"#94a3b8",fontSize:9,fontWeight:600,textTransform:"uppercase"}}>Atrasadas</div>
            </div>
          </div>
        </div>
      </div>
    )}

    {/* ═══ TAB BAR (roxo Pixels) ═══ */}
    <div style={{display:"flex",gap:isMob?4:6,padding:isMob?4:6,background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,overflowX:"auto"}}>
      {[
        {id:"alerta",label:isMob?"Alerta":"Alerta",badge:alertaCount},
        {id:"demandas",label:isMob?"Demandas":"Demandas"},
        {id:"metricas",label:isMob?"Métricas":"Métricas"},
        {id:"metas",label:isMob?"Metas":"Metas"},
      ].map(t=>(
        <button key={t.id} onClick={()=>setActiveTab(t.id)} style={{
          flex:isMob?"0 0 auto":1,
          background:activeTab===t.id?"#a140ff":"transparent",
          border:"none",borderRadius:8,padding:isMob?"8px 14px":"10px 18px",
          fontSize:isMob?12:13,fontWeight:activeTab===t.id?700:500,
          color:activeTab===t.id?"#fff":"#64748b",cursor:"pointer",
          boxShadow:activeTab===t.id?"0 4px 14px rgba(161,64,255,0.35)":"none",
          whiteSpace:"nowrap",transition:"all .18s",
          display:"flex",alignItems:"center",justifyContent:"center",gap:7,
        }}>
          {t.label}
          {t.badge>0&&<span style={{background:activeTab===t.id?"rgba(255,255,255,0.25)":"#a140ff",color:"#fff",borderRadius:99,padding:"1px 7px",fontSize:10,fontWeight:600,minWidth:18,textAlign:"center"}}>{t.badge}</span>}
        </button>
      ))}
    </div>

    {/* ═══ TAB ALERTA — Brief do Dia ═══ */}
    {activeTab==="alerta"&&(
      <div style={{background:"#faf5ff",border:"0.5px solid #e9d5ff",borderRadius:12,padding:"16px 18px"}}>
        <div style={{color:"#a140ff",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6,marginBottom:8}}>Brief do dia</div>
        {briefParts.length===0?(
          <div style={{color:"#0f172a",fontSize:14,lineHeight:1.7}}>
            <span style={{fontSize:18,marginRight:6}}>✨</span>
            Tudo tranquilo por aqui. Nenhum alerta crítico no momento.
          </div>
        ):(
          <div style={{color:"#0f172a",fontSize:14,lineHeight:1.7}}>
            Você tem <strong style={{color:"#a140ff"}}>{briefParts.join(", ")}</strong>{clientesRisco.length>0?<>. <strong style={{color:"#a140ff"}}>{clientesRisco.length} {clientesRisco.length===1?"cliente em risco":"clientes em risco"}</strong> também merecem atenção</>:""}.
          </div>
        )}
      </div>
    )}

    {/* ═══ TAB ALERTA — 3 KPIs com mini-charts + trend ═══ */}
    {activeTab==="alerta"&&(
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"repeat(3,1fr)",gap:10}}>
        <div style={{background:pagAtras.length>0?"#fef2f2":"#fff",border:`0.5px solid ${pagAtras.length>0?"#fecaca":"#e5e7eb"}`,borderRadius:12,padding:"14px 16px",display:"flex",flexDirection:"column",gap:6,minHeight:100}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
            <div style={{flex:1,minWidth:0}}>
              <div style={{color:pagAtras.length>0?"#991b1b":"#94a3b8",fontSize:10,fontWeight:500,textTransform:"uppercase",letterSpacing:.4,marginBottom:6}}>Pagamentos atrasados</div>
              <div style={{color:pagAtras.length>0?"#dc2626":"#0f172a",fontSize:22,fontWeight:600,letterSpacing:-.5,lineHeight:1}}>{f$(pagAtras.reduce((a,c)=>a+c.contract,0))}</div>
            </div>
            {typeof MiniBarChart!=="undefined"&&<MiniBarChart values={[1,0,1,2,1,pagAtras.length||0]} color={pagAtras.length>0?"#dc2626":"#cbd5e1"}/>}
          </div>
          <div style={{display:"flex",alignItems:"center",gap:6}}>
            {pagAtras.length>0&&<div style={{width:6,height:6,borderRadius:"50%",background:"#dc2626"}}/>}
            <span style={{color:"#94a3b8",fontSize:10}}>{pagAtras.length} {pagAtras.length===1?"cliente":"clientes"}</span>
          </div>
        </div>
        <div style={{background:atrasadas.length>0?"#fef2f2":"#fff",border:`0.5px solid ${atrasadas.length>0?"#fecaca":"#e5e7eb"}`,borderRadius:12,padding:"14px 16px",display:"flex",flexDirection:"column",gap:6,minHeight:100}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
            <div style={{flex:1,minWidth:0}}>
              <div style={{color:atrasadas.length>0?"#991b1b":"#94a3b8",fontSize:10,fontWeight:500,textTransform:"uppercase",letterSpacing:.4,marginBottom:6}}>Demandas atrasadas</div>
              <div style={{color:atrasadas.length>0?"#dc2626":"#0f172a",fontSize:22,fontWeight:600,letterSpacing:-.5,lineHeight:1}}>{atrasadas.length}</div>
            </div>
            {typeof MiniBarChart!=="undefined"&&<MiniBarChart values={last6AgencyCompletions.map((v,i)=>i===5?atrasadas.length:Math.max(1,v-1))} color={atrasadas.length>0?"#dc2626":"#cbd5e1"}/>}
          </div>
          <span style={{color:"#94a3b8",fontSize:10}}>{atrasadas.length===0?"tudo no prazo":"precisam de ação"}</span>
        </div>
        <div style={{background:pubAtrasadas.length>0?"#fff7ed":"#fff",border:`0.5px solid ${pubAtrasadas.length>0?"#fed7aa":"#e5e7eb"}`,borderRadius:12,padding:"14px 16px",display:"flex",flexDirection:"column",gap:6,minHeight:100}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
            <div style={{flex:1,minWidth:0}}>
              <div style={{color:pubAtrasadas.length>0?"#9a3412":"#94a3b8",fontSize:10,fontWeight:500,textTransform:"uppercase",letterSpacing:.4,marginBottom:6}}>Pub. vencidas</div>
              <div style={{color:pubAtrasadas.length>0?"#ea580c":"#0f172a",fontSize:22,fontWeight:600,letterSpacing:-.5,lineHeight:1}}>{pubAtrasadas.length}</div>
            </div>
            {typeof MiniBarChart!=="undefined"&&<MiniBarChart values={[0,1,0,2,1,pubAtrasadas.length]} color={pubAtrasadas.length>0?"#ea580c":"#cbd5e1"}/>}
          </div>
          <span style={{color:"#94a3b8",fontSize:10}}>{pubAtrasadas.length===0?"tudo publicado":"agendar urgente"}</span>
        </div>
      </div>
    )}

    {/* ═══ TAB ALERTA — Chart evolutivo da agência ═══ */}
    {activeTab==="alerta"&&typeof EvolutionChart!=="undefined"&&(
      <EvolutionChart data={agencyCompletedSeries} title="Produção da agência" subtitle="Demandas concluídas por dia" color="#a140ff"/>
    )}

    {/* ═══ TAB ALERTA — Lista Unificada "O que precisa de você agora" ═══ */}
    {activeTab==="alerta"&&(()=>{
      const items=[];
      // 1. Pagamentos atrasados (mais críticos)
      pagAtras.forEach(cl=>items.push({
        icon:"💸",
        title:`Pagamento atrasado · ${cl.name}`,
        sub:`Vence em ${cl.payment?.date||"—"} · ${f$(cl.contract)}`,
        onClick:null,
      }));
      // 2. Publicações vencidas
      pubAtrasadas.slice(0,4).forEach(t=>{
        const cl=CLIENTS.find(c=>c.id===t.client);
        items.push({
          icon:"📤",
          title:`Publicação atrasada: ${t.title}`,
          sub:`${cl?.name||"—"} · agendada para ${t.publishDate}`,
          onClick:()=>setOpenCard(t),
        });
      });
      // 3. Demandas muito atrasadas (>2 dias) — top 5
      const veryAtrasadas=atrasadas.filter(t=>{const d=daysLeft(t.deadline);return d!==null&&d<-2;}).slice(0,5);
      veryAtrasadas.forEach(t=>{
        const cl=CLIENTS.find(c=>c.id===t.client);
        const u=TEAM.find(x=>x.id===t.assignee);
        const d=Math.abs(daysLeft(t.deadline)||0);
        items.push({
          icon:"🔥",
          title:t.title,
          sub:`${cl?.name||"—"} · ${u?.name||"—"} · ${d}d de atraso`,
          onClick:()=>setOpenCard(t),
        });
      });
      // 4. Clientes em risco (saúde < 60)
      CLIENTS.filter(c=>c.health<60).forEach(cl=>items.push({
        icon:"⚠",
        title:`Cliente em risco · ${cl.name}`,
        sub:`Saúde em ${cl.health}% · revisar relacionamento`,
        onClick:null,
      }));
      // 5. Aprovações pendentes (consolidadas)
      if(copysPendentes.length>0)items.push({icon:"📝",title:`${copysPendentes.length} ${copysPendentes.length===1?"copy aguardando aprovação":"copys aguardando aprovação"}`,sub:"Aguarda os sócios",onClick:null});
      if(artesPendentes.length>0)items.push({icon:"🎨",title:`${artesPendentes.length} ${artesPendentes.length===1?"arte aguardando aprovação":"artes aguardando aprovação"}`,sub:"Aguarda os sócios",onClick:null});
      if(aprovacoesInternas.length>0)items.push({icon:"🔒",title:`${aprovacoesInternas.length} ${aprovacoesInternas.length===1?"demanda interna":"demandas internas"} aguardando`,sub:"Avaliação dos sócios",onClick:null});

      if(items.length===0)return (
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"40px 24px",textAlign:"center"}}>
          <div style={{width:48,height:48,borderRadius:12,background:"#f8fafc",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,margin:"0 auto 14px"}}>✨</div>
          <div style={{color:"#0f172a",fontWeight:600,fontSize:16,marginBottom:6}}>Tudo tranquilo</div>
          <div style={{color:"#94a3b8",fontSize:13,lineHeight:1.6}}>Nada pendente. Toda agência queria ter um dia assim.</div>
        </div>
      );
      // NOVO LAYOUT: 1 alerta principal grande + 4 menores na lateral
      const mainItem=items[0];
      const sideItems=items.slice(1,5);
      const mainColor=mainItem.icon==="💸"||mainItem.icon==="🔥"?"#dc2626":mainItem.icon==="📤"?"#ea580c":mainItem.icon==="⚠"?"#dc2626":"#7c3aed";
      const mainLabel=mainItem.icon==="💸"?"Pagamento atrasado":mainItem.icon==="🔥"?"Demanda atrasada":mainItem.icon==="📤"?"Publicação vencida":mainItem.icon==="⚠"?"Cliente em risco":mainItem.icon==="📝"?"Copy aguardando":mainItem.icon==="🎨"?"Arte aguardando":mainItem.icon==="🔒"?"Demanda interna":"Atenção";
      return (<div style={{maxWidth:860,margin:"0 auto",width:"100%"}}>
        <div style={{padding:"0 4px 8px"}}>
          <div style={{fontSize:10,color:"#94a3b8",fontWeight:500,textTransform:"uppercase",letterSpacing:.6}}>O que precisa de você agora</div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"minmax(0,1fr) 250px",gap:12}}>
          {/* CARTÃO GRANDE — alerta #1 */}
          <div onClick={mainItem.onClick||undefined} style={{
            background:"#fff",
            border:"0.5px solid #e5e7eb",
            borderLeft:`4px solid ${mainColor}`,
            borderRadius:12,
            padding:"22px 24px",
            minHeight:200,
            cursor:mainItem.onClick?"pointer":"default",
            display:"flex",
            flexDirection:"column",
            transition:"box-shadow .15s",
          }}
            onMouseEnter={e=>{if(mainItem.onClick)e.currentTarget.style.boxShadow="0 2px 8px rgba(0,0,0,0.06)";}}
            onMouseLeave={e=>e.currentTarget.style.boxShadow="none"}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <span style={{
                  background:mainColor+"18",color:mainColor,
                  fontSize:9,fontWeight:600,padding:"3px 9px",borderRadius:4,
                  textTransform:"uppercase",letterSpacing:.4
                }}>{mainItem.icon} {mainLabel}</span>
                <span style={{fontSize:10,color:"#94a3b8"}}>#1 alerta</span>
              </div>
              <span style={{fontSize:11,color:"#94a3b8",fontWeight:500}}>{items.length} {items.length===1?"item":"itens"}</span>
            </div>
            <div style={{color:"#0f172a",fontWeight:600,fontSize:18,lineHeight:1.3,marginBottom:8}}>{mainItem.title}</div>
            <div style={{color:"#64748b",fontSize:12,lineHeight:1.6,marginBottom:14,flex:1}}>{mainItem.sub}</div>
            {mainItem.onClick&&<div style={{display:"flex",justifyContent:"flex-end",alignItems:"center",paddingTop:12,borderTop:"0.5px solid #f1f5f9",marginTop:"auto"}}>
              <span style={{background:"#a140ff",color:"#fff",fontSize:11,fontWeight:500,padding:"6px 14px",borderRadius:6}}>Abrir →</span>
            </div>}
          </div>

          {/* 4 PEQUENOS */}
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {sideItems.map((it,i)=>{
              const sideColor=it.icon==="💸"||it.icon==="🔥"?"#dc2626":it.icon==="📤"?"#ea580c":it.icon==="⚠"?"#dc2626":"#7c3aed";
              return <div key={i+1} onClick={it.onClick||undefined}
                style={{
                  background:"#fff",
                  border:"0.5px solid #e5e7eb",
                  borderLeft:`3px solid ${sideColor}`,
                  borderRadius:8,
                  padding:"9px 11px",
                  cursor:it.onClick?"pointer":"default",
                  transition:"transform .1s",
                }}
                onMouseEnter={e=>{if(it.onClick)e.currentTarget.style.transform="translateX(2px)";}}
                onMouseLeave={e=>e.currentTarget.style.transform=""}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:3}}>
                  <span style={{fontSize:9,color:sideColor,fontWeight:600,textTransform:"uppercase",letterSpacing:.3}}>{it.icon} #{i+2}</span>
                </div>
                <div style={{fontSize:11,color:"#0f172a",fontWeight:500,lineHeight:1.3,marginBottom:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{it.title}</div>
                <div style={{fontSize:9,color:"#94a3b8",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{it.sub}</div>
              </div>;
            })}
            {items.length>5&&<div style={{textAlign:"center",padding:6,fontSize:10,color:"#94a3b8"}}>+ {items.length-5} {items.length-5===1?"alerta":"alertas"}</div>}
          </div>
        </div>
      </div>);
    })()}

    {/* ═══ TAB DEMANDAS — 4 KPIs operacionais ═══ */}
    {activeTab==="demandas"&&(
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr 1fr":"repeat(4,1fr)",gap:10}}>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 16px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>Em produção</div>
          <div style={{color:"#0f172a",fontSize:isMob?22:26,fontWeight:600,letterSpacing:-.5,marginTop:6,lineHeight:1}}>{emProducao}</div>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>cards ativos</div>
        </div>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 16px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>Em avaliação</div>
          <div style={{color:"#0f172a",fontSize:isMob?22:26,fontWeight:600,letterSpacing:-.5,marginTop:6,lineHeight:1}}>{emAvaliacao}</div>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>aguardando aprovação</div>
        </div>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 16px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>Aprovadas</div>
          <div style={{color:"#0f172a",fontSize:isMob?22:26,fontWeight:600,letterSpacing:-.5,marginTop:6,lineHeight:1}}>{aprovadasTotal}</div>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>prontas p/ agendar</div>
        </div>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 16px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>Publicadas</div>
          <div style={{color:"#a140ff",fontSize:isMob?22:26,fontWeight:600,letterSpacing:-.5,marginTop:6,lineHeight:1}}>{publicadasMes}</div>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>este mês</div>
        </div>
      </div>
    )}

    {/* ═══ TAB DEMANDAS — Carga por pessoa (NOVO) ═══ */}
    {activeTab==="demandas"&&(
      <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 18px"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
          <div style={{color:"#0f172a",fontWeight:700,fontSize:13}}>Carga por pessoa</div>
          <div style={{color:"#64748b",fontSize:11}}>{ativas.length} demandas ativas distribuídas</div>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {cargaPorPessoa.map(c=>{
            const pct=(c.count/maxCarga)*100;
            const overload=c.count>=10;
            return <div key={c.user.id} style={{display:"flex",alignItems:"center",gap:10}}>
              <Av l={c.user.av} color={c.user.color} size={26} uid={c.user.id}/>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                  <span style={{color:"#0f172a",fontSize:12,fontWeight:600}}>{c.user.name}</span>
                  <span style={{color:overload?"#dc2626":"#64748b",fontSize:11,fontWeight:overload?600:500}}>{c.count}</span>
                </div>
                <div style={{height:6,background:"#e5e7eb",borderRadius:99,overflow:"hidden"}}>
                  <div style={{width:pct+"%",height:"100%",background:overload?"#dc2626":c.user.color,borderRadius:99,transition:"width .4s ease"}}/>
                </div>
              </div>
            </div>;
          })}
        </div>
      </div>
    )}




    {/* ═══ 3. PIPELINE DE DEMANDAS — TAB DEMANDAS ═══ */}
    {activeTab==="demandas"&&<div style={{background:"#fff",borderRadius:12,border:"0.5px solid #e5e7eb"}}>
      <div style={{padding:"14px 18px 10px",borderBottom:"0.5px solid #f1f5f9",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div>
          <div style={{color:"#0f172a",fontWeight:700,fontSize:14,letterSpacing:-.2}}>Pipeline de Demandas</div>
          <div style={{color:"#64748b",fontSize:11,marginTop:2}}>{active.length} demandas na operação</div>
        </div>
      </div>
      <div style={{padding:"14px 16px",display:"grid",gridTemplateColumns:isMob?"repeat(3,1fr)":"repeat(6,1fr)",gap:8}}>
        {pipeline.map(p=>(
          <div key={p.status} style={{background:"#fff",border:"0.5px solid #e5e7eb",borderTop:"3px solid #a140ff",borderRadius:8,padding:"12px 6px",textAlign:"center"}}>
            <div style={{color:"#94a3b8",fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:.4,marginBottom:6}}>{p.label}</div>
            <div style={{color:"#a140ff",fontWeight:600,fontSize:26,letterSpacing:-1,lineHeight:1}}>{p.count}</div>
          </div>
        ))}
      </div>
    </div>}

    {/* ═══ TAB DEMANDAS — Velocity + Gargalos (NOVO) ═══ */}
    {activeTab==="demandas"&&(
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"1fr 1fr",gap:12}}>
        {/* Velocity */}
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 18px"}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
            <div style={{color:"#0f172a",fontWeight:700,fontSize:13}}>Velocity · 4 últimas semanas</div>
            <div style={{color:"#64748b",fontSize:11}}>{velocityTrend} média {velocityAvg}/sem</div>
          </div>
          <svg viewBox="0 0 280 90" style={{width:"100%",height:90}}>
            {velocity.map((v,i)=>{
              const h=Math.max(4,(v/velocityMax)*65);
              const x=20+i*60;
              const y=80-h;
              return <g key={i}>
                <rect x={x} y={y} width={40} height={h} rx={3} fill="#7F77DD"/>
                <text x={x+20} y={y-3} textAnchor="middle" fontSize="11" fontWeight="600" fill="#0f172a">{v}</text>
                <text x={x+20} y={88} textAnchor="middle" fontSize="9" fill="#94a3b8">S{4-i}</text>
              </g>;
            })}
          </svg>
        </div>
        {/* Gargalos */}
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 18px"}}>
          <div style={{color:"#0f172a",fontWeight:700,fontSize:13,marginBottom:12}}>Gargalos detectados</div>
          {gargalos.length===0?(
            <div style={{padding:"24px 0",textAlign:"center"}}>
              <div style={{fontSize:28,marginBottom:6}}>✅</div>
              <div style={{color:"#16a34a",fontSize:12,fontWeight:600}}>Nenhum gargalo · fluxo saudável</div>
            </div>
          ):gargalos.map((g,i)=>(
            <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"6px 0",borderBottom:i<gargalos.length-1?"0.5px solid #f1f5f9":"none"}}>
              <span style={{fontSize:14}}>⚠</span>
              <div style={{flex:1,minWidth:0}}>
                <div style={{color:"#0f172a",fontSize:12,fontWeight:600}}>{g.label}</div>
                <div style={{color:"#94a3b8",fontSize:11}}>{g.stuck} {g.stuck===1?"card parado":"cards parados"} há 4+ dias</div>
              </div>
              <div style={{width:8,height:8,borderRadius:"50%",background:g.color}}/>
            </div>
          ))}
        </div>
      </div>
    )}

    {/* ═══ TAB MÉTRICAS — 4 Hero Numbers (NOVO) ═══ */}
    {activeTab==="metricas"&&(
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr 1fr":"repeat(4,1fr)",gap:10}}>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 16px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>Spend total · mês</div>
          <div style={{color:"#0f172a",fontSize:isMob?20:24,fontWeight:600,letterSpacing:-.5,marginTop:6,lineHeight:1}}>{f$(spendTotal)}</div>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>Meta + Google somados</div>
        </div>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 16px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>ROAS médio</div>
          <div style={{color:Number(avgRoas)>=4?"#16a34a":Number(avgRoas)>=2?"#eab308":"#dc2626",fontSize:isMob?20:24,fontWeight:600,letterSpacing:-.5,marginTop:6,lineHeight:1}}>{avgRoas}×</div>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>{clientesAtivos} clientes ativos</div>
        </div>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 16px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>Leads gerados</div>
          <div style={{color:"#0f172a",fontSize:isMob?20:24,fontWeight:600,letterSpacing:-.5,marginTop:6,lineHeight:1}}>{totalLeads.toLocaleString("pt-BR")}</div>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>Meta + Google · mês</div>
        </div>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 16px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>Followers totais</div>
          <div style={{color:"#0f172a",fontSize:isMob?20:24,fontWeight:600,letterSpacing:-.5,marginTop:6,lineHeight:1}}>{(followersTotal/1000).toFixed(1)}k</div>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>todas as redes</div>
        </div>
      </div>
    )}

    {/* ═══ TAB MÉTRICAS — Top 5 ROAS / Bottom (NOVO) ═══ */}
    {activeTab==="metricas"&&(
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"1fr 1fr",gap:12}}>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,overflow:"hidden"}}>
          <div style={{padding:"14px 16px 10px",borderBottom:"0.5px solid #f1f5f9"}}>
            <div style={{color:"#0f172a",fontWeight:500,fontSize:13}}>Top 5 ROAS</div>
            <div style={{color:"#94a3b8",fontSize:11,marginTop:2}}>maior retorno por real investido</div>
          </div>
          <div style={{padding:"10px 14px"}}>
            {top5Roas.length===0?<div style={{padding:"16px",textAlign:"center",color:"#94a3b8",fontSize:12}}>Sem dados de ROAS ainda</div>:top5Roas.map((cl,i)=>(
              <div key={cl.id} style={{display:"flex",alignItems:"center",gap:10,padding:"7px 0",borderBottom:i<top5Roas.length-1?"0.5px solid #f1f5f9":"none"}}>
                <ClientLogo clientId={cl.id} size="xs"/>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{color:"#0f172a",fontSize:12,fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{cl.name}</div>
                </div>
                <div style={{color:"#16a34a",fontWeight:600,fontSize:14}}>{(cl.meta?.roas||0).toFixed(1)}×</div>
              </div>
            ))}
          </div>
        </div>
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,overflow:"hidden"}}>
          <div style={{padding:"14px 16px 10px",borderBottom:"0.5px solid #f1f5f9"}}>
            <div style={{color:"#0f172a",fontWeight:500,fontSize:13}}>Atenção · ROAS &lt; 2×</div>
            <div style={{color:"#94a3b8",fontSize:11,marginTop:2}}>revisar campanhas</div>
          </div>
          <div style={{padding:"10px 12px"}}>
            {bottomRoas.length===0?(
              <div style={{padding:"24px",textAlign:"center"}}>
                <div style={{fontSize:24,marginBottom:6}}>💚</div>
                <div style={{color:"#16a34a",fontSize:12,fontWeight:600}}>Todos os ROAS saudáveis</div>
              </div>
            ):bottomRoas.map((cl,i)=>(
              <div key={cl.id} style={{display:"flex",alignItems:"center",gap:10,padding:"7px 0",borderBottom:i<bottomRoas.length-1?"0.5px solid #f1f5f9":"none"}}>
                <ClientLogo clientId={cl.id} size="xs"/>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{color:"#0f172a",fontSize:12,fontWeight:600}}>{cl.name}</div>
                  <div style={{color:"#94a3b8",fontSize:10}}>revisar campanhas</div>
                </div>
                <div style={{color:"#dc2626",fontWeight:600,fontSize:14}}>{(cl.meta?.roas||0).toFixed(1)}×</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    )}


    {/* ═══ 6. TABELA DE CLIENTES (visão completa) — TAB MÉTRICAS ═══ */}
    {activeTab==="metricas"&&<div style={{background:C.card,borderRadius:12,border:`0.5px solid ${C.b1}`,overflow:"hidden"}}>
      <div style={{padding:"14px 18px",borderBottom:`0.5px solid ${C.b1}`}}>
        <div style={{color:"#0f172a",fontWeight:500,fontSize:13}}>Panorama dos clientes</div>
        <div style={{color:"#94a3b8",fontSize:11,marginTop:2}}>visão completa da carteira</div>
      </div>
      <div style={{overflow:"auto"}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
          <thead>
            <tr style={{background:"#f8fafc"}}>
              <th style={{padding:"10px 14px",textAlign:"left",color:C.td,fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:.5}}>Cliente</th>
              <th style={{padding:"10px 8px",textAlign:"center",color:C.td,fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:.5}}>MRR</th>
              <th style={{padding:"10px 8px",textAlign:"center",color:C.td,fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:.5}}>Saúde</th>
              <th style={{padding:"10px 8px",textAlign:"center",color:C.td,fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:.5}}>ROAS</th>
              <th style={{padding:"10px 8px",textAlign:"center",color:C.td,fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:.5}}>NPS</th>
              <th style={{padding:"10px 14px",textAlign:"center",color:C.td,fontSize:10,fontWeight:600,textTransform:"uppercase",letterSpacing:.5}}>Pag.</th>
            </tr>
          </thead>
          <tbody>
            {CLIENTS.map(cl=>{
              const healthColor=cl.health>=80?"#16a34a":cl.health>=60?"#eab308":"#dc2626";
              const roasColor=(cl.meta?.roas||0)>=4?"#16a34a":(cl.meta?.roas||0)>=2?"#eab308":"#dc2626";
              const npsColor=(cl.nps||0)>=80?"#16a34a":(cl.nps||0)>=60?"#eab308":"#dc2626";
              const pagStatus=cl.payment?.status||"pendente";
              const pagColor=pagStatus==="pago"?"#16a34a":pagStatus==="atrasado"?"#dc2626":"#eab308";
              return <tr key={cl.id} style={{borderTop:`0.5px solid ${C.b1}`}}>
                <td style={{padding:"10px 14px",display:"flex",alignItems:"center",gap:8}}>
                  <ClientLogo clientId={cl.id} size="xs"/>
                  <span style={{color:C.tx,fontWeight:700}}>{cl.name}</span>
                </td>
                <td style={{padding:"10px 8px",textAlign:"center",color:"#16a34a",fontWeight:600}}>{f$(cl.contract)}</td>
                <td style={{padding:"10px 8px",textAlign:"center"}}>
                  <span style={{background:healthColor,color:"#fff",borderRadius:99,padding:"3px 10px",fontSize:11,fontWeight:600}}>
                    {cl.health}%
                  </span>
                </td>
                <td style={{padding:"10px 8px",textAlign:"center",color:roasColor,fontWeight:600}}>{(cl.meta?.roas||0).toFixed(1)}x</td>
                <td style={{padding:"10px 8px",textAlign:"center",color:npsColor,fontWeight:600}}>{cl.nps||0}</td>
                <td style={{padding:"10px 14px",textAlign:"center"}}>
                  <span style={{background:pagColor,color:"#fff",borderRadius:6,padding:"2px 8px",fontSize:9,fontWeight:600,textTransform:"uppercase",letterSpacing:.3}}>
                    {pagStatus==="pago"?"Pago":pagStatus==="atrasado"?"Atras":"Pend"}
                  </span>
                </td>
              </tr>;
            })}
          </tbody>
        </table>
      </div>
    </div>}


    {/* ═══ TAB METAS — Health Score gauge (NOVO) ═══ */}
    {activeTab==="metas"&&(
      <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"20px",textAlign:"center"}}>
        <div style={{color:"#0f172a",fontWeight:700,fontSize:13,marginBottom:8}}>Health Score da agência</div>
        <svg viewBox="0 0 200 110" style={{width:200,height:110,maxWidth:"100%"}}>
          <path d="M 20 100 A 80 80 0 0 1 180 100" stroke="#e5e7eb" strokeWidth="14" fill="none"/>
          <path d={(()=>{
            // Calcula path do arco proporcional ao healthScore
            const angle=Math.PI*(1-healthScore/100);
            const x=100+80*Math.cos(angle);
            const y=100-80*Math.sin(angle);
            const largeArc=healthScore>50?1:0;
            return `M 20 100 A 80 80 0 0 ${largeArc} ${x.toFixed(1)} ${y.toFixed(1)}`;
          })()} stroke={healthScore>=80?"#16a34a":healthScore>=60?"#eab308":"#dc2626"} strokeWidth="14" fill="none" strokeLinecap="round"/>
          <text x="100" y="85" textAnchor="middle" fontSize="34" fontWeight="800" fill="#0f172a">{healthScore}</text>
          <text x="100" y="103" textAnchor="middle" fontSize="11" fill="#94a3b8">de 100</text>
        </svg>
        <div style={{color:"#64748b",fontSize:12,marginTop:6}}>SLA {slaScore}% · NPS {npsScore} · Churn {churnPct}% · Crescimento {growthScore}%</div>
      </div>
    )}

    {/* ═══ TAB METAS — 4 metas vs atual (NOVO) ═══ */}
    {activeTab==="metas"&&(()=>{
      const mrrPct=Math.min(100,Math.round((mrr/METAS.mrr)*100));
      const novosPct=Math.min(100,Math.round((novosClientesMes/METAS.novosClientesMes)*100));
      const npsPct=Math.min(100,Math.round((avgNps/METAS.nps)*100));
      const churnOK=churnPct<=METAS.churn;
      const cores=[
        mrrPct>=80?"#16a34a":mrrPct>=60?"#eab308":"#dc2626",
        novosPct>=80?"#16a34a":novosPct>=60?"#eab308":"#dc2626",
        npsPct>=80?"#16a34a":npsPct>=60?"#eab308":"#dc2626",
        churnOK?"#16a34a":"#dc2626",
      ];
      const Card=({label,atual,meta,pct,sub,color})=>(
        <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"12px 14px"}}>
          <div style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>{label}</div>
          <div style={{color:"#0f172a",fontSize:isMob?16:18,fontWeight:600,letterSpacing:-.3,marginTop:4}}>{atual}</div>
          <div style={{color:"#94a3b8",fontSize:11,margin:"4px 0 6px"}}>{sub}</div>
          <div style={{height:5,background:"#e5e7eb",borderRadius:99,overflow:"hidden"}}>
            <div style={{width:pct+"%",height:"100%",background:color,borderRadius:99,transition:"width .5s ease"}}/>
          </div>
        </div>
      );
      return <div style={{display:"grid",gridTemplateColumns:isMob?"1fr 1fr":"repeat(4,1fr)",gap:10}}>
        <Card label="MRR" atual={f$(mrr)} meta={f$(METAS.mrr)} pct={mrrPct} sub={`meta ${f$(METAS.mrr)} · ${mrrPct}%`} color={cores[0]}/>
        <Card label="Novos clientes" atual={novosClientesMes} meta={METAS.novosClientesMes} pct={novosPct} sub={`meta ${METAS.novosClientesMes} · ${novosPct}%`} color={cores[1]}/>
        <Card label="NPS médio" atual={avgNps} meta={METAS.nps} pct={npsPct} sub={`meta ${METAS.nps} · ${npsPct}%`} color={cores[2]}/>
        <Card label="Churn" atual={churnPct+"%"} meta={"<"+METAS.churn+"%"} pct={churnOK?100:churnPct*20} sub={`meta < ${METAS.churn}% ${churnOK?"✓":""}`} color={cores[3]}/>
      </div>;
    })()}

    {/* ═══ TAB METAS — Histórico de Receita 12 meses (NOVO) ═══ */}
    {activeTab==="metas"&&(
      <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 18px"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
          <div style={{color:"#0f172a",fontWeight:700,fontSize:13}}>Receita · 12 meses</div>
          <div style={{color:"#64748b",fontSize:11}}>placeholder · conectar histórico real depois</div>
        </div>
        <svg viewBox="0 0 600 130" style={{width:"100%",height:130}}>
          <line x1="0" y1="105" x2="600" y2="105" stroke="#e5e7eb" strokeWidth="0.5"/>
          {/* Linha de meta */}
          {(()=>{const yMeta=110-(METAS.mrr/receita12mMax)*90;return <>
            <line x1="0" y1={yMeta} x2="600" y2={yMeta} stroke="#94a3b8" strokeWidth="0.5" strokeDasharray="2,3"/>
            <text x="2" y={yMeta-3} fontSize="9" fill="#94a3b8">meta {f$(METAS.mrr)}</text>
          </>;})()}
          {/* Polyline da receita */}
          {(()=>{
            const pts=receita12m.map((v,i)=>{const x=20+(i*(560/11));const y=110-(v/receita12mMax)*90;return `${x.toFixed(1)},${y.toFixed(1)}`;}).join(" ");
            return <polyline points={pts} stroke="#7F77DD" strokeWidth="2" fill="none"/>;
          })()}
          {/* Bolinhas */}
          {receita12m.map((v,i)=>{const x=20+(i*(560/11));const y=110-(v/receita12mMax)*90;return <circle key={i} cx={x} cy={y} r="3" fill="#7F77DD"/>;})}
          {/* Última bolinha destacada */}
          {(()=>{const x=20+(11*(560/11));const y=110-(receita12m[11]/receita12mMax)*90;return <circle cx={x} cy={y} r="5" fill="#7F77DD" stroke="#fff" strokeWidth="2"/>;})()}
          {/* Labels do eixo */}
          <text x="20" y="125" fontSize="9" fill="#94a3b8">12m atrás</text>
          <text x="300" y="125" fontSize="9" fill="#94a3b8" textAnchor="middle">6m</text>
          <text x="580" y="125" fontSize="9" fill="#94a3b8" textAnchor="end">Hoje</text>
        </svg>
      </div>
    )}

  </div>;
}

function RenderDash({user,isViewing=false,tasks,setTasks,notifs,isMob}){
  // Sócios (Vinicius + Gustavo) usam o dashboard estratégico compartilhado (DashGustavo = DashSocio).
  // As metas multi-marcadas pra ambos sincronizam entre os dois (filtragem por assignees).
  if((user.id==="gustavo"||user.id==="vinicius"||user.id==="ocsana")&&typeof DashGustavo==="function"){
    return <DashGustavo user={user} isViewing={isViewing} tasks={tasks} setTasks={setTasks} notifs={notifs} isMob={isMob}/>;
  }
  switch(user.dash){
    case"partner":     return <DashPartner     user={user} isViewing={isViewing} tasks={tasks} setTasks={setTasks} notifs={notifs} isMob={isMob}/>;
    case"coordinator": return <DashCoordinator user={user} isViewing={isViewing} tasks={tasks} setTasks={setTasks} notifs={notifs} isMob={isMob}/>;
    case"gestor":      return <DashGestor      user={user} isViewing={isViewing} tasks={tasks} setTasks={setTasks} notifs={notifs} isMob={isMob}/>;
    case"designer":    return <DashDesigner    user={user} isViewing={isViewing} tasks={tasks} setTasks={setTasks} notifs={notifs} isMob={isMob}/>;
    case"editor":      return <DashEditor      user={user} isViewing={isViewing} tasks={tasks} setTasks={setTasks} notifs={notifs} isMob={isMob}/>;
    default:           return <DashPartner     user={user} isViewing={isViewing} tasks={tasks} setTasks={setTasks} notifs={notifs} isMob={isMob}/>;
  }
}

// DashColaborador unifica DashCoordinator, DashGestor, DashDesigner, DashEditor
// icon é definido pelo campo user.dash via DASH_ICONS
const DASH_ICONS={coordinator:"📱",gestor:"📊",designer:"🎨",editor:"🎬"};
function DashColaborador({user,isViewing,tasks:propTasks,setTasks:propSetTasks,notifs,isMob}){
  // Tasks DELE (individual): onde ele é o responsável principal
  const tasks=(propTasks||[]).filter(t=>t.assignee===user.id||(t.assignees||[]).includes(user.id));
  const setTasks=propSetTasks||(()=>{});
  // Ellen (coordinator) precisa ver todas as tasks pra gerenciar a equipe
  const allTasks=propTasks||[];
  // Supervisionados (pra supervisores tipo Guilherme → João)
  const supervisedUsers=user.supervises||[];
  const supervisedTasks=supervisedUsers.length>0
    ?(propTasks||[]).filter(t=>!t.deletedAt&&(supervisedUsers.includes(t.assignee)||supervisedUsers.some(s=>(t.assignees||[]).includes(s))))
    :[];
  // Designer / Editor (freelancer com pagamento por demanda) -> dashboard V2 moderno
  if(user.pagamentoPorDemanda===true && typeof DashColabV2==="function"){
    return <DashColabV2 user={user} tasks={tasks} allTasks={allTasks}
      setTasks={setTasks} isViewing={isViewing} currentUser={CURRENT_USER} notifs={notifs} isMob={isMob}/>;
  }
  return <PriorityDashCore user={user} tasks={tasks} allTasks={allTasks}
    supervisedTasks={supervisedTasks} supervisedUsers={supervisedUsers}
    setTasks={setTasks} isViewing={isViewing} icon={DASH_ICONS[user.dash]||"📋"} currentUser={CURRENT_USER} notifs={notifs} isMob={isMob}/>;
}
// Aliases para compatibilidade com RenderDash
const DashCoordinator=DashColaborador;
const DashGestor=DashColaborador;
const DashDesigner=DashColaborador;
const DashEditor=DashColaborador;

function PageDashboard({isMob,onClient,tasks:propTasks,setTasks:propSetTasks,notifs,setNotifs,onNavTo,onNotif,selfProfile,viewingAs}){
  // Quando estamos "visualizando como" outro colaborador, trocamos TUDO pra esse user
  const effectiveUser = viewingAs ? (TEAM.find(u=>u.id===viewingAs) || CURRENT_USER) : CURRENT_USER;
  const isViewingOther = !!viewingAs;
  // Se estamos visualizando outro, NÃO usar selfProfile (é do user real logado)
  // Em vez disso, tentar buscar o perfil do user visualizado do localStorage
  const effectiveProfile = (()=>{
    if(!isViewingOther) return selfProfile;
    try{
      const s=localStorage.getItem("pixels-selfprofile-"+effectiveUser.id);
      return s?JSON.parse(s):null;
    }catch{return null;}
  })();

  const allTasks=propTasks||[];
  const active=allTasks.filter(t=>!t.deletedAt);
  const urgent=active.filter(t=>taskUrgencyLevel(t)===0);
  const late=active.filter(t=>taskUrgencyLevel(t)===1);
  const now=new Date();
  const hour=now.getHours();
  const greeting=hour<12?"Bom dia ☀️":hour<18?"Boa tarde 🌤️":"Boa noite 🌙";
  const unread=(notifs||[]).filter(n=>!n.read).length;

  // Demandas do mês atual
  const mesAtual=now.getMonth();
  const anoAtual=now.getFullYear();
  const isCEO=effectiveUser.level===1;
  // Concluídas do mês — aprovadas com completedAt no mês
  const conclMes=active.filter(t=>{
    if(t.status!=="aprovado"||!t.completedAt)return false;
    if(!isCEO&&!((t.assignees||[t.assignee]).includes(effectiveUser.id)))return false;
    const d=new Date(t.completedAt);
    return d.getMonth()===mesAtual&&d.getFullYear()===anoAtual;
  }).length;
  // Solicitadas do mês — criadas no mês
  const solic=active.filter(t=>{
    if(!isCEO&&!((t.assignees||[t.assignee]).includes(effectiveUser.id)))return false;
    if(!t.createdAt)return false;
    // createdAt é string pt-BR ou ISO
    try{
      const d=new Date(t.createdAt.includes("/")?t.createdAt.split("/").reverse().join("-"):t.createdAt);
      return d.getMonth()===mesAtual&&d.getFullYear()===anoAtual;
    }catch{return false;}
  }).length;
  // Em aberto
  const emAberto=active.filter(t=>{
    if(isCEO)return t.status!=="aprovado";
    return t.status!=="aprovado"&&(t.assignees||[t.assignee]).includes(effectiveUser.id);
  }).length;

  const COVER_COLORS=["#7c3aed","#2563eb","#0891b2","#059669","#d97706","#dc2626","#db2777","#1e293b","#0f172a"];
  const [coverColor,setCoverColor]=useState(()=>{
    try{const s=localStorage.getItem("pixels-covercolor-"+effectiveUser.id);return s||effectiveUser.color||"#7c3aed";}catch{return effectiveUser.color||"#7c3aed";}
  });
  // Ao mudar o user visualizado, recarrega a cor da capa desse user
  useEffect(()=>{
    try{const s=localStorage.getItem("pixels-covercolor-"+effectiveUser.id);setCoverColor(s||effectiveUser.color||"#7c3aed");}catch{}
  },[effectiveUser.id]);
  const [showColorPicker,setShowColorPicker]=useState(false);
  const saveCoverColor=(c)=>{
    // Só deixa salvar cor se for o próprio user, não se estiver visualizando outro
    if(isViewingOther)return;
    setCoverColor(c);setShowColorPicker(false);
    try{localStorage.setItem("pixels-covercolor-"+effectiveUser.id,c);}catch(e){}
  };
  const photo=getProfilePhoto(effectiveUser.id);
  const displayName=effectiveProfile?.nome||effectiveUser.name;
  const displayRole=effectiveProfile?.funcao||effectiveUser.role;

  const lateMes=late.filter(t=>isCEO||(t.assignees||[t.assignee]).includes(effectiveUser.id));

  return <div style={{display:"flex",flexDirection:"column",gap:16,maxWidth:1600,margin:"0 auto",width:"100%"}}>
    {/* ── CAPA: foto grande + nome + cargo + data + demandas + sino ── */}
    <div style={{position:"relative",borderRadius:14,overflow:"hidden",background:`linear-gradient(135deg,${coverColor},${coverColor}cc)`,padding:isMob?"14px 14px":"18px 22px",display:"flex",alignItems:"center",gap:isMob?12:18,flexWrap:"wrap"}}>
      {/* Foto grande */}
      <div style={{width:isMob?78:108,height:isMob?78:108,borderRadius:"50%",border:"3px solid rgba(255,255,255,0.9)",overflow:"hidden",flexShrink:0,background:"rgba(0,0,0,0.15)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 8px 24px rgba(0,0,0,0.18)"}}>
        {photo
          ?<img src={photo} alt={displayName} style={{width:"100%",height:"100%",objectFit:"cover"}}/>
          :<span style={{color:"#fff",fontWeight:700,fontSize:isMob?32:46}}>{effectiveUser.av}</span>
        }
      </div>
      {/* Nome + cargo + data */}
      <div style={{flex:1,minWidth:0}}>
        <div style={{color:"rgba(255,255,255,0.85)",fontSize:11,fontWeight:600,letterSpacing:.3,textTransform:"uppercase",marginBottom:3}}>{greeting} · {now.toLocaleDateString("pt-BR",{weekday:"long",day:"numeric",month:"long"})}</div>
        <div style={{color:"#fff",fontWeight:800,fontSize:isMob?22:28,letterSpacing:-.6,lineHeight:1.1}}>{displayName}</div>
        <div style={{color:"rgba(255,255,255,0.78)",fontSize:13,fontWeight:500,marginTop:4}}>{displayRole}</div>
      </div>
      {/* Demandas + sino à direita —
           Escondido pros sócios (Vinicius+Gustavo). User pediu dash limpo, sem
           números genéricos. Os dados ficam nas seções específicas do dash. */}
      {effectiveUser.id!=="vinicius"&&effectiveUser.id!=="gustavo"&&<div style={{flexShrink:0,display:"flex",alignItems:"center",gap:isMob?8:14}}>
        <div style={{background:"rgba(255,255,255,0.15)",borderRadius:10,padding:"8px 14px",display:"flex",flexDirection:"column",alignItems:"center",backdropFilter:"blur(6px)"}}>
          <div style={{display:"flex",alignItems:"baseline",gap:4}}>
            <span style={{color:"#bbf7d0",fontWeight:800,fontSize:isMob?18:22,lineHeight:1}}>{conclMes}</span>
            <span style={{color:"rgba(255,255,255,0.55)",fontSize:13}}>/</span>
            <span style={{color:"#fff",fontWeight:800,fontSize:isMob?18:22,lineHeight:1}}>{emAberto}</span>
          </div>
          <div style={{color:"rgba(255,255,255,0.7)",fontSize:9.5,fontWeight:700,letterSpacing:.4,textTransform:"uppercase",marginTop:3}}>Demandas</div>
        </div>
        {lateMes.length>0&&<div style={{background:"#dc2626",color:"#fff",borderRadius:10,padding:"8px 14px",display:"flex",flexDirection:"column",alignItems:"center",boxShadow:"0 4px 12px rgba(220,38,38,0.35)"}}>
          <span style={{fontWeight:800,fontSize:isMob?18:22,lineHeight:1}}>{lateMes.length}</span>
          <div style={{fontSize:9.5,fontWeight:700,letterSpacing:.4,textTransform:"uppercase",marginTop:3,opacity:.95}}>Atrasadas</div>
        </div>}
        <button onClick={()=>onNotif&&onNotif()} title="Notificações"
          style={{background:unread>0?"#a140ff":"rgba(255,255,255,0.2)",border:"none",borderRadius:10,padding:"10px 12px",cursor:"pointer",display:"flex",alignItems:"center",gap:7,boxShadow:unread>0?"0 4px 12px rgba(161,64,255,0.35)":"none"}}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9"/>
            <path d="M13.73 21a2 2 0 01-3.46 0"/>
          </svg>
          {unread>0&&<span style={{color:"#fff",fontSize:13,fontWeight:700,lineHeight:1}}>{unread}</span>}
        </button>
      </div>}
    </div>

    {/* ── ALERTAS URGENTES — criados por admins/social media ──
         Escondido pros sócios (Vinicius+Gustavo) pra dash começar direto com metas. */}
    {effectiveUser.id!=="vinicius"&&effectiveUser.id!=="gustavo"&&<DashboardAlerts userId={effectiveUser.id} isMob={isMob}/>}

    <RenderDash user={effectiveUser} isViewing={isViewingOther} tasks={propTasks||[]} setTasks={propSetTasks} notifs={notifs} isMob={isMob}/>
  </div>;
}

// ======= 02_clientes.jsx =======
function MindMap({clientId,centerColor}){
  const [expanded,setExpanded]=useState({});
  const [selected,setSelected]=useState(null);
  const data=CLIENT_MINDMAP[clientId];
  if(!data)return <div style={{color:C.ts,padding:20,textAlign:"center"}}>Mapa mental não disponível.</div>;

  const W=660,H=520,CX=330,CY=260;
  const branches=data.branches;
  const n=branches.length;

  // Position branches radially
  const branchPos=branches.map((b,i)=>{
    const angle=(i/n)*2*Math.PI - Math.PI/2;
    const r=170;
    return {x:CX+Math.cos(angle)*r, y:CY+Math.sin(angle)*r, angle};
  });

  // Child positions relative to branch
  const childPos=(bx,by,angle,children)=>children.map((c,j)=>{
    const spread=0.45;
    const startA=angle-spread*(children.length-1)/2;
    const ca=startA+j*spread;
    const cr=110;
    return {x:bx+Math.cos(ca)*cr, y:by+Math.sin(ca)*cr};
  });

  return <div style={{overflowX:"auto",overflowY:"hidden",background:C.bg,borderRadius:14,border:`1px solid ${C.b1}`,padding:8}}>
    <svg width={W} height={H} style={{fontFamily:"'Inter',system-ui,sans-serif",display:"block",minWidth:W}}>
      <defs>
        <filter id="glow-mm">
          <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
          <feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>

      {/* Branch connectors */}
      {branches.map((b,i)=>{
        const bp=branchPos[i];
        const isExp=expanded[b.id];
        const children=isExp?b.children:[];
        const cps=childPos(bp.x,bp.y,bp.angle,b.children);
        return <g key={b.id}>
          {/* center → branch curve */}
          <path d={`M ${CX} ${CY} Q ${(CX+bp.x)/2} ${(CY+bp.y)/2} ${bp.x} ${bp.y}`}
            fill="none" stroke={b.color} strokeWidth={isExp?3:2} strokeOpacity={0.7}
            strokeDasharray={isExp?"none":"4 3"}/>
          {/* branch → children */}
          {isExp&&b.children.map((c,j)=>{
            const cp=cps[j];
            const isSel=selected===c.id;
            return <g key={c.id}>
              <path d={`M ${bp.x} ${bp.y} Q ${(bp.x+cp.x)/2} ${(bp.y+cp.y)/2} ${cp.x} ${cp.y}`}
                fill="none" stroke={b.color} strokeWidth={1.5} strokeOpacity={0.5}/>
              {/* child node */}
              <rect x={cp.x-44} y={cp.y-13} width={88} height={26} rx={13}
                fill={isSel?b.color:C.card} stroke={b.color} strokeWidth={isSel?0:1}
                style={{cursor:"pointer",filter:isSel?"url(#glow-mm)":"none"}}
                onClick={()=>setSelected(isSel?null:c.id)}/>
              <text x={cp.x} y={cp.y+4} textAnchor="middle"
                fill={isSel?"#fff":C.ts} fontSize={9} fontWeight="600"
                style={{pointerEvents:"none",userSelect:"none"}}>
                {c.label}
              </text>
            </g>;
          })}
        </g>;
      })}

      {/* Branch nodes */}
      {branches.map((b,i)=>{
        const bp=branchPos[i];
        const isExp=expanded[b.id];
        return <g key={b.id} style={{cursor:"pointer"}} onClick={()=>setExpanded(p=>({...p,[b.id]:!p[b.id]}))}>
          <rect x={bp.x-48} y={bp.y-18} width={96} height={36} rx={18}
            fill={isExp?b.color:b.color+"33"} stroke={b.color} strokeWidth={isExp?0:1.5}
            style={{filter:isExp?"url(#glow-mm)":"none"}}/>
          <text x={bp.x-14} y={bp.y+5} textAnchor="middle" fontSize={14} style={{pointerEvents:"none"}}>{b.icon}</text>
          <text x={bp.x+16} y={bp.y+5} textAnchor="middle"
            fill={isExp?"#fff":b.color} fontSize={10} fontWeight="800"
            style={{pointerEvents:"none",userSelect:"none"}}>
            {b.label}
          </text>
        </g>;
      })}

      {/* Center node */}
      <g>
        <ellipse cx={CX} cy={CY} rx={68} ry={32}
          fill={`url(#cg-${clientId})`} filter="url(#glow-mm)"/>
        <defs>
          <linearGradient id={`cg-${clientId}`} x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor={centerColor}/>
            <stop offset="100%" stopColor={centerColor+"88"}/>
          </linearGradient>
        </defs>
        <text x={CX} y={CY+5} textAnchor="middle"
          fill="#fff" fontSize={12} fontWeight="900"
          style={{userSelect:"none",pointerEvents:"none"}}>
          {data.center.length>14?data.center.slice(0,13)+"…":data.center}
        </text>
      </g>
    </svg>
    <div style={{padding:"8px 12px 4px",display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
      <span style={{color:C.td,fontSize:10}}>Clique em um ramo para expandir</span>
      {Object.values(expanded).some(Boolean)&&
        <button onClick={()=>setExpanded({})} style={{background:C.b1,border:"none",borderRadius:6,padding:"2px 10px",color:C.ts,fontSize:9,fontWeight:700,cursor:"pointer"}}>Recolher tudo</button>
      }
    </div>
  </div>;
}

/* ─── CLIENTES BOARD ─────────────────────── */
function ClientesBoard({tasks,setTasks,setOpenCard,canDelete,handleDelete,canDrag,canCreate,perms}){
  const [activeClient,setActiveClient]=useState(null);
  const [activeBioterUnit,setActiveBioterUnit]=useState(null);
  const [boardView,setBoardView]=useState("cartao"); // cartao | lista | calendar
  const [calMonth,setCalMonth]=useState(new Date());
  const [clientModal,setClientModal]=useState(null); // {id, mode: "dashboard"|"mindmap"|"info"}
  const WEEKDAYS_C=["Dom","Seg","Ter","Qua","Qui","Sex","Sáb"];
  const MONTHS_C=["Janeiro","Fevereiro","Março","Abril","Maio","Junho","Julho","Agosto","Setembro","Outubro","Novembro","Dezembro"];

  // ── Detail: quadro completo de um cliente ──
  if(activeClient){
    const cl=CLIENTS.find(c=>c.id===activeClient);
    const isBioter=activeClient==="bioter";

    // Filter tasks by unit if bioter
    // null bioterUnit = "Todas" → visível em qualquer filtro de unidade
    const allClTasks=tasks.filter(t=>!t.deletedAt&&t.client===activeClient);
    const clTasks=isBioter&&activeBioterUnit
      ? allClTasks.filter(t=>t.bioterUnit===activeBioterUnit||t.bioterUnit===null)
      : allClTasks;

    const openCount=clTasks.filter(t=>t.status!=="aprovado"&&t.status!=="pausado").length;
    const approvedCount=clTasks.filter(t=>t.status==="aprovado").length;
    const lateCount=clTasks.filter(t=>t.status!=="aprovado"&&daysLeft(t.deadline)<0).length;
    const colabs=[...new Set(clTasks.map(t=>t.assignee))].map(id=>TEAM.find(u=>u.id===id)).filter(Boolean);

    return <div style={{display:"flex",flexDirection:"column",gap:16}}>
      {/* back + header */}
      <div style={{display:"flex",alignItems:"center",gap:12,flexWrap:"wrap"}}>
        <button onClick={()=>{setActiveClient(null);setActiveBioterUnit(null);}} style={{background:C.b1,border:"none",borderRadius:10,padding:"8px 14px",color:C.ts,cursor:"pointer",fontSize:12,fontWeight:700}}>← Clientes</button>
        <div style={{background:`linear-gradient(135deg,${cl.color},${cl.color}bb)`,borderRadius:14,padding:"8px 16px",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:`0 4px 16px ${cl.color}40`}}>
          <div style={{background:"#fff",borderRadius:10,padding:"6px 14px",display:"flex",alignItems:"center",justifyContent:"center"}}>
            {CLIENT_LOGOS[activeClient]
              ? <img src={CLIENT_LOGOS[activeClient]} alt={cl.name} style={{maxHeight:36,maxWidth:140,objectFit:"contain",display:"block"}}/>
              : <span style={{color:cl.color,fontWeight:900,fontSize:18}}>{cl.abbr}</span>
            }
          </div>
        </div>
        <div style={{flex:1}}>
          <div style={{color:C.tx,fontWeight:900,fontSize:20}}>{cl.name}</div>
          <div style={{display:"flex",gap:12,marginTop:3}}>
            <span style={{color:C.ts,fontSize:12}}>● {openCount} abertas</span>
            <span style={{color:C.gr,fontSize:12}}>✓ {approvedCount} aprovadas</span>
            {lateCount>0&&<span style={{color:C.rd,fontSize:12,fontWeight:700}}>⚠ {lateCount} atrasadas</span>}
          </div>
        </div>
        {/* view toggle — 3 options */}
        <div style={{display:"flex",background:C.b1,borderRadius:10,padding:3,gap:2}}>
          {[["cartao","⊞"],["lista","☰"],["calendar","📅"]].map(([m,i])=>(
            <button key={m} onClick={()=>setBoardView(m)} style={{background:boardView===m?cl.color:"transparent",color:boardView===m?"#fff":C.ts,border:"none",borderRadius:7,padding:"5px 11px",fontSize:12,fontWeight:700,cursor:"pointer"}}>{i}</button>
          ))}
        </div>
      </div>

      {/* collaborators */}
      {colabs.length>0&&<div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
        {colabs.map(u=>{
          const uTasks=clTasks.filter(t=>t.assignee===u.id);
          return <div key={u.id} style={{background:u.color+"12",border:`1px solid ${u.color}33`,borderRadius:10,padding:"7px 12px",display:"flex",alignItems:"center",gap:8}}>
            <Av l={u.av} color={u.color} size={28} status={u.status}/>
            <div>
              <div style={{color:C.tx,fontWeight:700,fontSize:12}}>{u.name}</div>
              <div style={{color:u.color,fontSize:10}}>{uTasks.length} dem. · ✓{uTasks.filter(t=>t.status==="aprovado").length}</div>
            </div>
          </div>;
        })}
      </div>}

      {/* Bioter unit filter */}
      {isBioter&&<div style={{display:"flex",gap:6,flexWrap:"wrap",padding:"12px 16px",background:C.s1,borderRadius:12}}>
        <div style={{width:"100%",color:C.ts,fontSize:10,fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:6}}>Filtrar por Unidade</div>
        <button onClick={()=>setActiveBioterUnit(null)}
          style={{background:activeBioterUnit===null?cl.color:C.b1,color:activeBioterUnit===null?"#fff":C.ts,border:`1px solid ${activeBioterUnit===null?cl.color:C.b2}`,borderRadius:99,padding:"5px 14px",fontSize:11,fontWeight:700,cursor:"pointer"}}>
          🌐 Todas as Unidades
        </button>
        {BIOTER_UNITS.map(u=>(
          <button key={u.id} onClick={()=>setActiveBioterUnit(u.id)}
            style={{background:activeBioterUnit===u.id?u.color:C.b1,color:activeBioterUnit===u.id?"#fff":C.ts,border:`1px solid ${activeBioterUnit===u.id?u.color:C.b2}`,borderRadius:99,padding:"5px 14px",fontSize:11,fontWeight:700,cursor:"pointer"}}>
            📍 {u.label}
          </button>
        ))}
        {activeBioterUnit&&<div style={{width:"100%",marginTop:6,color:C.ts,fontSize:11}}>
          Mostrando: <strong style={{color:BIOTER_UNITS.find(u=>u.id===activeBioterUnit)?.color}}>{BIOTER_UNITS.find(u=>u.id===activeBioterUnit)?.label}</strong> · {clTasks.length} demanda{clTasks.length!==1?"s":""}
        </div>}
      </div>}

      {/* ── CARTÃO view ── */}
      {boardView==="cartao"&&<div style={{display:"grid",gridTemplateColumns:`repeat(${KANBAN_COLS.length},minmax(180px,1fr))`,gap:8,overflowX:"auto",paddingBottom:8}}>
        {KANBAN_COLS.map(col=>{
          // Coluna "agendado" (Publicações) agrega status="agendado" + status="publicado"
          const colTasks=clTasks.filter(t=>col.id==="agendado"?(t.status==="agendado"||t.status==="publicado"):t.status===col.id);
          return <div key={col.id} style={{
            background:`linear-gradient(180deg,${col.color}38 0%,${col.color}18 100%)`,
            border:`2px solid ${col.color}55`,borderTop:`4px solid ${col.color}`,
            borderRadius:12,padding:8,minHeight:180,display:"flex",flexDirection:"column",gap:0}}>
            <div style={{background:`linear-gradient(135deg,${col.color},${col.color}bb)`,borderRadius:8,padding:"7px 12px",marginBottom:8,display:"flex",justifyContent:"space-between",alignItems:"center",boxShadow:`0 3px 12px ${col.color}45`}}>
              <span style={{color:col.id==="execucao"||col.id==="aprovado"?"#000":"#fff",fontWeight:800,fontSize:10,textTransform:"uppercase",letterSpacing:.5}}>{col.label}</span>
              <span style={{background:"rgba(0,0,0,0.3)",color:"#fff",borderRadius:99,padding:"1px 7px",fontSize:9,fontWeight:700}}>{colTasks.length}</span>
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:6,flex:1}}>
              {colTasks.map(t=>{
                const u=TEAM.find(x=>x.id===t.assignee);
                const urgLevel=taskUrgencyLevel(t);
                const days=daysLeft(t.deadline);
                return <div key={t.id} onClick={()=>setOpenCard(t)}
                  style={{background:"#fff",border:`1px solid ${getUrgencyColor(urgLevel)}44`,borderLeft:`3px solid ${getUrgencyColor(urgLevel)}`,borderRadius:8,overflow:"hidden",cursor:"pointer",boxShadow:"0 2px 6px rgba(0,0,0,0.15)"}}>
                  {t.cover&&typeof t.cover==="string"&&<div style={{height:44,background:t.cover.startsWith("#")?`linear-gradient(135deg,${t.cover},${t.cover}88)`:"transparent",backgroundImage:!t.cover.startsWith("#")?`url(${t.cover})`:undefined,backgroundSize:"cover",backgroundPosition:"center"}}/>}
                  <div style={{padding:"8px 10px"}}>
                    <div style={{color:"#111",fontWeight:700,fontSize:11,lineHeight:1.4,marginBottom:5}}>{t.title}</div>
                    {isBioter&&<div style={{marginBottom:4}}>
                      {t.bioterUnit
                        ? <span style={{background:BIOTER_UNITS.find(u=>u.id===t.bioterUnit)?.color+"22",color:BIOTER_UNITS.find(u=>u.id===t.bioterUnit)?.color,borderRadius:4,padding:"1px 6px",fontSize:8,fontWeight:700}}>📍{BIOTER_UNITS.find(u=>u.id===t.bioterUnit)?.label}</span>
                        : <span style={{background:"#00b4d822",color:"#00b4d8",borderRadius:4,padding:"1px 6px",fontSize:8,fontWeight:700}}>🌐 Todas</span>
                      }
                    </div>}
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                      <span style={{color:dlColor(days),fontSize:9,fontWeight:700}}>{dlLabel(days)}</span>
                      <div style={{display:"flex",gap:3}}>
                        {urgLevel<2&&<span style={{background:getUrgencyColor(urgLevel),color:"#fff",borderRadius:99,padding:"1px 5px",fontSize:8,fontWeight:700}}>{urgLevel===0?"🔥":"❌"}</span>}
                        {u&&<div style={{width:18,height:18,borderRadius:"50%",background:u.color+"33",border:`1px solid ${u.color}`,display:"flex",alignItems:"center",justifyContent:"center",color:u.color,fontWeight:900,fontSize:8}}>{u.av}</div>}
                      </div>
                    </div>
                  </div>
                </div>;
              })}
              {colTasks.length===0&&<div style={{color:col.color+"44",fontSize:10,textAlign:"center",padding:"8px 0"}}>vazio</div>}
              {canCreate&&<button onClick={()=>setTasks(p=>[...p,{id:mkId(),title:"Nova Demanda",desc:"",assignee:CURRENT_USER.id,assignees:[CURRENT_USER.id],watchers:[],client:activeClient,sector:"design",priority:"media",status:col.id,startDate:new Date().toISOString().split("T")[0],deadline:new Date(Date.now()+7*86400000).toISOString().split("T")[0],completedAt:null,score:null,tags:[],comments:[],files:[],cover:null,deletedAt:null,bioterUnit:null,caption:"",publishDate:"",publishTime:"09:00",checklist:[],timeline:[],colEnteredAt:new Date().toISOString(),createdAt:new Date().toLocaleDateString("pt-BR"),createdBy:CURRENT_USER.name,isAlteracao:false,ajustar:false}])}
                style={{background:"rgba(255,255,255,0.07)",border:`1px dashed ${col.color}44`,borderRadius:7,padding:"7px 0",color:col.color+"88",cursor:"pointer",fontSize:10,fontWeight:700,marginTop:4}}>+ Adicionar</button>}
            </div>
          </div>;
        })}
      </div>}

      {/* ── LISTA view ── */}
      {boardView==="lista"&&<ListaView visible={clTasks} setOpenCard={setOpenCard} canDelete={canDelete} handleDelete={handleDelete} setTasks={setTasks}/>}

      {/* ── CALENDÁRIO view ── */}
      {boardView==="calendar"&&<div style={{display:"flex",flexDirection:"column",gap:12}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <button onClick={()=>setCalMonth(m=>new Date(m.getFullYear(),m.getMonth()-1,1))} style={{background:C.b1,border:"none",borderRadius:8,padding:"7px 14px",color:C.ts,cursor:"pointer",fontWeight:700,fontSize:16}}>←</button>
          <div style={{color:C.tx,fontWeight:800,fontSize:17}}>{MONTHS_C[calMonth.getMonth()]} {calMonth.getFullYear()}</div>
          <button onClick={()=>setCalMonth(m=>new Date(m.getFullYear(),m.getMonth()+1,1))} style={{background:C.b1,border:"none",borderRadius:8,padding:"7px 14px",color:C.ts,cursor:"pointer",fontWeight:700,fontSize:16}}>→</button>
        </div>
        <div style={{background:C.card,borderRadius:14,overflow:"hidden",boxShadow:"0 1px 4px rgba(0,0,0,0.12),0 4px 16px rgba(0,0,0,0.08)"}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",borderBottom:`2px solid ${C.b1}`,background:C.s1}}>
            {WEEKDAYS_C.map(d=><div key={d} style={{padding:"10px 0",textAlign:"center",color:C.ts,fontSize:11,fontWeight:700}}>{d}</div>)}
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)"}}>
            {(()=>{
              const year=calMonth.getFullYear(),month=calMonth.getMonth();
              const first=new Date(year,month,1).getDay();
              const dim=new Date(year,month+1,0).getDate();
              const days=[];for(let i=0;i<first;i++)days.push(null);
              for(let i=1;i<=dim;i++)days.push(new Date(year,month,i));
              return days.map((day,i)=>{
                const ds=day?`${day.getFullYear()}-${String(day.getMonth()+1).padStart(2,"0")}-${String(day.getDate()).padStart(2,"0")}`:"";
                const dayTasks=day?clTasks.filter(t=>t.deadline===ds):[];
                const isToday=day&&day.toDateString()===new Date().toDateString();
                const hasUrgent=dayTasks.some(t=>taskUrgencyLevel(t)===0);
                const hasLate=dayTasks.some(t=>taskUrgencyLevel(t)===1);
                return <div key={i} style={{minHeight:100,borderRight:`1px solid ${C.b1}`,borderBottom:`1px solid ${C.b1}`,padding:"7px 8px",background:isToday?C.ag:hasUrgent?C.rd+"14":hasLate?C.or+"10":"none"}}>
                  {day&&<>
                    <div style={{color:isToday?"#fff":C.ts,fontWeight:isToday?900:500,fontSize:12,marginBottom:5,width:22,height:22,background:isToday?cl.color:"transparent",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center"}}>{day.getDate()}</div>
                    <div style={{display:"flex",flexDirection:"column",gap:3}}>
                      {dayTasks.slice(0,3).map(t=>{
                        const u=TEAM.find(x=>x.id===t.assignee);
                        const urgColor=getUrgencyColor(taskUrgencyLevel(t));
                        return <div key={t.id} onClick={()=>setOpenCard(t)} style={{background:urgColor+"22",border:`1px solid ${urgColor}44`,borderRadius:5,padding:"2px 5px",cursor:"pointer",display:"flex",alignItems:"center",gap:3}}>
                          <div style={{width:5,height:5,borderRadius:"50%",background:urgColor,flexShrink:0}}/>
                          <span style={{color:C.tx,fontSize:9,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>{t.title}</span>
                          {u&&<span style={{background:u.color+"44",color:u.color,borderRadius:3,padding:"0 3px",fontSize:7,fontWeight:700}}>{u.av}</span>}
                        </div>;
                      })}
                      {dayTasks.length>3&&<div style={{color:C.ts,fontSize:9,textAlign:"center"}}>+{dayTasks.length-3}</div>}
                    </div>
                  </>}
                </div>;
              });
            })()}
          </div>
        </div>
        <div style={{display:"flex",gap:12,flexWrap:"wrap"}}>
          {[{c:C.rd,l:"🔥 Urgente"},{c:C.or,l:"❌ Atrasado"},{c:C.yw,l:"⚠ Atenção"},{c:C.gr,l:"✅ No prazo"}].map(x=><div key={x.l} style={{display:"flex",alignItems:"center",gap:5}}><div style={{width:8,height:8,borderRadius:"50%",background:x.c}}/><span style={{color:C.ts,fontSize:11}}>{x.l}</span></div>)}
        </div>
      </div>}
    </div>;
  }

  // ── Overview: grade de clientes ──
  return <div style={{display:"flex",flexDirection:"column",gap:16}}>
    {/* Client modals */}
    {clientModal&&(()=>{
      const clBase=CLIENTS.find(c=>c.id===clientModal.id);
      const cl=getLiveClient(clientModal.id)||clBase;
      const clTasks=tasks.filter(t=>!t.deletedAt&&t.client===clientModal.id);
      const open=clTasks.filter(t=>t.status!=="aprovado"&&t.status!=="pausado");
      const done=clTasks.filter(t=>t.status==="aprovado");
      const late=open.filter(t=>daysLeft(t.deadline)<0);
      return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.88)",zIndex:300,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={()=>setClientModal(null)}>
        <div onClick={e=>e.stopPropagation()} style={{background:C.card,border:`2px solid ${cl.color}`,borderRadius:22,width:"100%",maxWidth:680,maxHeight:"92vh",overflowY:"auto",display:"flex",flexDirection:"column",boxShadow:`0 0 60px ${cl.color}30`}}>
          {/* header */}
          <div style={{background:`linear-gradient(135deg,${cl.color},${cl.color}88)`,padding:"18px 22px",borderRadius:"20px 20px 0 0",display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,zIndex:5}}>
            <div style={{display:"flex",alignItems:"center",gap:12}}>
              <div style={{background:"#fff",borderRadius:10,padding:"6px 10px",display:"flex",alignItems:"center"}}>
                {CLIENT_LOGOS[cl.id]
                  ? <img src={CLIENT_LOGOS[cl.id]} alt={cl.name} style={{height:28,maxWidth:90,objectFit:"contain"}}/>
                  : <span style={{color:cl.color,fontWeight:900,fontSize:14}}>{cl.abbr}</span>
                }
              </div>
              <div>
                <div style={{color:"#fff",fontWeight:900,fontSize:17}}>{cl.name}</div>
                <div style={{color:"rgba(255,255,255,0.75)",fontSize:11,marginTop:1}}>{cl.sector}</div>
              </div>
            </div>
            <div style={{display:"flex",gap:4,alignItems:"center"}}>
              {["dashboard","mindmap","info"].map(m=>(
                <button key={m} onClick={()=>setClientModal({...clientModal,mode:m})}
                  style={{background:clientModal.mode===m?"rgba(255,255,255,0.3)":"rgba(255,255,255,0.1)",border:"none",borderRadius:8,padding:"5px 10px",color:"#fff",cursor:"pointer",fontSize:10,fontWeight:700}}>
                  {m==="dashboard"?"📊 Dashboard":m==="mindmap"?"🧠 Mapa Mental":"ℹ Informações"}
                </button>
              ))}
              <button onClick={()=>setClientModal(null)} style={{background:"rgba(0,0,0,0.3)",border:"none",borderRadius:10,padding:"7px 12px",color:"#fff",cursor:"pointer",fontWeight:700,marginLeft:4}}>✕</button>
            </div>
          </div>

          {/* content */}
          <div style={{padding:"20px 22px",display:"flex",flexDirection:"column",gap:16}}>
            {clientModal.mode==="dashboard"&&<>
              {/* KPIs */}
              <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:10}}>
                {[
                  {l:"Saúde",v:cl.health+"%",c:cl.health>=80?C.gr:cl.health>=60?C.yw:C.rd,t:`NPS ${cl.nps}`},
                  {l:"MRR",v:"R$ "+cl.contract.toLocaleString("pt-BR"),c:C.gr,t:"contrato mensal"},
                  {l:"Leads Totais",v:(cl.meta.leads+cl.google.leads).toString(),c:C.bl,t:"Meta + Google"},
                  {l:"ROAS Médio",v:((cl.meta.roas+cl.google.roas)/2).toFixed(1)+"x",c:C.a,t:"Meta & Google"},
                ].map(k=><div key={k.l} style={{background:C.card,borderRadius:12,padding:"14px 16px",boxShadow:"0 1px 3px rgba(0,0,0,0.10)",borderTop:`2px solid ${k.c}`}}>
                  <div style={{color:C.td,fontSize:10,marginBottom:4}}>{k.l}</div>
                  <div style={{color:k.c,fontWeight:900,fontSize:22,letterSpacing:-1}}>{k.v}</div>
                  <div style={{color:C.ts,fontSize:10,marginTop:3}}>{k.t}</div>
                </div>)}
              </div>
              {/* Meta vs Google */}
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                {[{icon:"📘",label:"Meta Ads",color:"#1877f2",data:cl.meta},{icon:"🔍",label:"Google Ads",color:"#34a853",data:cl.google}].map(ch=>(
                  <div key={ch.label} style={{background:C.card,borderRadius:12,padding:"14px 16px",boxShadow:"0 1px 3px rgba(0,0,0,0.10)",borderTop:`2px solid ${ch.color}`}}>
                    <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:12}}>
                      <span style={{fontSize:18}}>{ch.icon}</span>
                      <span style={{color:C.tx,fontWeight:700,fontSize:13}}>{ch.label}</span>
                    </div>
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6}}>
                      {[{l:"ROAS",v:ch.data.roas+"x",c:ch.data.roas>=4?C.gr:C.yw},{l:"Leads",v:ch.data.leads,c:C.bl},{l:"CPC",v:"R$"+ch.data.cpc,c:C.ts},{l:"CTR",v:ch.data.ctr+"%",c:C.ts}].map(s=>(
                        <div key={s.l} style={{background:"rgba(255,255,255,0.05)",borderRadius:8,padding:"6px 8px",textAlign:"center"}}>
                          <div style={{color:s.c,fontWeight:900,fontSize:14}}>{s.v}</div>
                          <div style={{color:C.td,fontSize:9}}>{s.l}</div>
                        </div>
                      ))}
                    </div>
                    <div style={{marginTop:10}}>
                      <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                        <span style={{color:C.ts,fontSize:9}}>Budget</span>
                        <span style={{color:C.ts,fontSize:9}}>R$ {ch.data.spend.toLocaleString("pt-BR")} / R$ {ch.data.budget.toLocaleString("pt-BR")}</span>
                      </div>
                      <div style={{background:C.b1,borderRadius:99,height:5,overflow:"hidden"}}>
                        <div style={{width:`${Math.min(100,Math.round(ch.data.spend/ch.data.budget*100))}%`,height:"100%",background:ch.color,borderRadius:99}}/>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
              {/* demandas */}
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
                {[{l:"Abertas",v:open.length,c:cl.color},{l:"Aprovadas",v:done.length,c:C.gr},{l:"Atrasadas",v:late.length,c:late.length>0?C.rd:C.td}].map(s=>(
                  <div key={s.l} style={{background:`${s.c}18`,border:`1px solid ${s.c}33`,borderRadius:12,padding:"12px",textAlign:"center"}}>
                    <div style={{color:s.c,fontWeight:900,fontSize:24}}>{s.v}</div>
                    <div style={{color:C.ts,fontSize:11,marginTop:3}}>{s.l}</div>
                  </div>
                ))}
              </div>
            </>}

            {clientModal.mode==="mindmap"&&<>
              <div style={{color:C.ts,fontSize:11,marginBottom:8}}>Clique nas áreas para expandir os processos. Explore o fluxo de trabalho do cliente.</div>
              <MindMap clientId={clientModal.id} centerColor={cl.color}/>
            </>}

            {clientModal.mode==="info"&&<>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                {[
                  {l:"Setor",v:cl.sector,i:"🏢"},
                  {l:"Status",v:cl.status,i:"●"},
                  {l:"Na Pixels desde",v:cl.since,i:"📅"},
                  {l:"Gestor responsável",v:TEAM.find(u=>u.id===cl.manager)?.name||cl.manager,i:"👤"},
                  {l:"MRR (contrato)",v:"R$ "+cl.contract.toLocaleString("pt-BR"),i:"💰"},
                  {l:"NPS",v:cl.nps+"/100",i:"⭐"},
                  {l:"Meta Account ID",v:cl.metaId||"—",i:"📘"},
                  {l:"Google Account ID",v:cl.googleId||"—",i:"🔍"},
                  {l:"Integração Meta",v:cl.connected?"Conectada ✓":"Pendente",i:"🔗"},
                  {l:"Upsell potencial",v:(cl.upsell||[]).join(", ")||"—",i:"🚀"},
                ].map(r=>(
                  <div key={r.l} style={{background:C.s1,borderRadius:12,padding:"12px 14px"}}>
                    <div style={{color:C.td,fontSize:10,marginBottom:3}}>{r.i} {r.l}</div>
                    <div style={{color:C.tx,fontSize:13,fontWeight:600}}>{r.v}</div>
                  </div>
                ))}
              </div>
              <div style={{background:C.s1,borderRadius:12,padding:"14px 16px"}}>
                <div style={{color:C.td,fontSize:10,marginBottom:6}}>🤝 Equipe envolvida</div>
                <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                  {[...new Set(tasks.filter(t=>t.client===clientModal.id).map(t=>t.assignee))].map(id=>{
                    const u=TEAM.find(x=>x.id===id);
                    if(!u)return null;
                    return <div key={id} style={{background:u.color+"22",border:`1px solid ${u.color}44`,borderRadius:99,padding:"4px 12px",display:"flex",alignItems:"center",gap:6}}>
                      <Av l={u.av} color={u.color} size={20}/>
                      <span style={{color:C.tx,fontSize:12,fontWeight:600}}>{u.name}</span>
                    </div>;
                  })}
                </div>
              </div>
            </>}
          </div>
        </div>
      </div>;
    })()}
    <div>
      <div style={{color:C.tx,fontWeight:900,fontSize:18}}>🏢 Quadros por Cliente</div>
      <div style={{color:C.ts,fontSize:12,marginTop:3}}>Clique em um cliente para abrir o quadro completo de demandas</div>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(260px,1fr))",gap:14}}>
      {CLIENTS.filter(cl=>{
        const isSocio=CURRENT_USER.level===1;
        if(isSocio)return true;
        if(!perms)return true;
        return perms[`verCliente_${cl.id}`]!==false;
      }).map(cl=>{
        const clTasks=tasks.filter(t=>!t.deletedAt&&t.client===cl.id);
        const open=clTasks.filter(t=>t.status!=="aprovado"&&t.status!=="pausado");
        const done=clTasks.filter(t=>t.status==="aprovado");
        const late=open.filter(t=>daysLeft(t.deadline)<0);
        const urgent=open.filter(t=>taskUrgencyLevel(t)===0);
        const colabs=[...new Set(clTasks.map(t=>t.assignee))].map(id=>TEAM.find(u=>u.id===id)).filter(Boolean);

        return <div key={cl.id}
          style={{background:C.card,borderRadius:16,overflow:"hidden",cursor:"pointer",
            boxShadow:"0 1px 4px rgba(0,0,0,0.14),0 4px 16px rgba(0,0,0,0.1)",
            transition:"box-shadow .15s,transform .12s",display:"flex",flexDirection:"column"}}
          onClick={()=>setActiveClient(cl.id)}
          onMouseEnter={e=>{e.currentTarget.style.boxShadow="0 4px 20px rgba(0,0,0,0.22)";e.currentTarget.style.transform="translateY(-2px)";}}
          onMouseLeave={e=>{e.currentTarget.style.boxShadow="0 1px 4px rgba(0,0,0,0.14),0 4px 16px rgba(0,0,0,0.1)";e.currentTarget.style.transform="translateY(0)";}}>
          {/* client logo header — colored bg + white box inside */}
          <div style={{background:`linear-gradient(135deg,${cl.color},${cl.color}bb)`,padding:"12px 14px",display:"flex",alignItems:"center",justifyContent:"center",minHeight:90,position:"relative",overflow:"hidden"}}>
            <div style={{position:"absolute",top:-30,right:-30,width:100,height:100,borderRadius:"50%",background:"rgba(255,255,255,0.08)",pointerEvents:"none"}}/>
            <div style={{background:"#fff",borderRadius:12,padding:"6px 8px",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:`0 4px 20px rgba(0,0,0,0.25)`,width:"90%",height:66}}>
              {CLIENT_LOGOS[cl.id]
                ? <img src={CLIENT_LOGOS[cl.id]} alt={cl.name} style={{
                    width:"auto",
                    height:{construschorr:"28px",bioter:"32px",climaves:"58px",arabuta:"54px",vetservice:"54px"}[cl.id]||"54px",
                    maxWidth:"100%",objectFit:"contain",display:"block"
                  }}/>
                : <span style={{color:cl.color,fontWeight:900,fontSize:22}}>{cl.abbr}</span>
              }
            </div>
          </div>
          <div style={{padding:"16px 18px",flex:1,display:"flex",flexDirection:"column",gap:12}}>
            {/* client identity */}
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <div>
                  <div style={{color:C.tx,fontWeight:900,fontSize:15,lineHeight:1.2}}>{cl.name}</div>
                  <div style={{color:C.ts,fontSize:11,marginTop:2}}>{cl.sector}</div>
                </div>
              </div>
              <span style={{color:C.a,fontSize:20}}>›</span>
            </div>

            {/* bioter units preview — clicáveis */}
            {cl.id==="bioter"&&<div style={{display:"flex",gap:4,flexWrap:"wrap"}} onClick={e=>e.stopPropagation()}>
              {BIOTER_UNITS.map(u=>(
                <button key={u.id} onClick={e=>{e.stopPropagation();setActiveClient("bioter");setActiveBioterUnit(u.id);}}
                  style={{background:u.color+"22",color:u.color,borderRadius:6,padding:"3px 8px",fontSize:9,fontWeight:700,border:`1px solid ${u.color}44`,cursor:"pointer",transition:"all .15s"}}>
                  📍{u.label.split("/")[0]}
                </button>
              ))}
            </div>}

            {/* stats */}
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
              {[
                {l:"Abertas",  v:open.length,  c:cl.color},
                {l:"Aprovadas",v:done.length,  c:C.gr},
                {l:"Atrasadas",v:late.length,  c:late.length>0?C.rd:C.td},
              ].map(s=><div key={s.l} style={{background:"rgba(255,255,255,0.06)",borderRadius:8,padding:"8px 6px",textAlign:"center"}}>
                <div style={{color:s.c,fontWeight:900,fontSize:18,lineHeight:1}}>{s.v}</div>
                <div style={{color:C.td,fontSize:9,marginTop:2}}>{s.l}</div>
              </div>)}
            </div>

            {/* urgency alert */}
            {urgent.length>0&&<div style={{background:C.rd+"18",border:`1px solid ${C.rd}44`,borderRadius:8,padding:"6px 10px",display:"flex",gap:6,alignItems:"center"}}>
              <span style={{fontSize:12}}>🔥</span>
              <span style={{color:C.rd,fontSize:11,fontWeight:700}}>{urgent.length} demanda{urgent.length>1?"s":""}  urgente{urgent.length>1?"s":""}</span>
            </div>}

            {/* colabs */}
            {colabs.length>0&&<div style={{display:"flex",gap:4,alignItems:"center"}}>
              {colabs.map(u=><div key={u.id} title={u.name} style={{width:24,height:24,borderRadius:"50%",background:u.color+"33",border:`2px solid ${u.color}`,display:"flex",alignItems:"center",justifyContent:"center",color:u.color,fontWeight:900,fontSize:9}}>{u.av}</div>)}
              <span style={{color:C.td,fontSize:10,marginLeft:4}}>{colabs.length} colaborador{colabs.length>1?"es":""}</span>
            </div>}

            {/* progress bar */}
            <div>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                <span style={{color:C.td,fontSize:10}}>Progresso</span>
                <span style={{color:cl.color,fontSize:10,fontWeight:700}}>{clTasks.length>0?Math.round(done.length/clTasks.length*100):0}%</span>
              </div>
              <div style={{background:"rgba(255,255,255,0.1)",borderRadius:99,height:5}}>
                <div style={{width:`${clTasks.length>0?pct(done.length,clTasks.length):0}%`,background:`linear-gradient(90deg,${cl.color},${cl.color}88)`,height:"100%",borderRadius:99,transition:"width .8s ease"}}/>
              </div>
            </div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",borderTop:`1px solid ${cl.color}22`}}>
            {[
              {icon:"📊",label:"Dashboard",mode:"dashboard"},
              {icon:"🧠",label:"Mapa Mental",mode:"mindmap"},
              {icon:"ℹ",label:"Informações",mode:"info"},
            ].map(btn=>(
              <button key={btn.mode}
                onClick={e=>{e.stopPropagation();setClientModal({id:cl.id,mode:btn.mode});}}
                style={{background:"none",border:"none",borderRight:btn.mode!=="info"?`1px solid ${cl.color}18`:"none",padding:"10px 6px",color:cl.color,fontSize:10,fontWeight:700,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",gap:3,transition:"background .15s"}}
                onMouseEnter={e=>e.currentTarget.style.background=cl.color+"14"}
                onMouseLeave={e=>e.currentTarget.style.background="none"}>
                <span style={{fontSize:15}}>{btn.icon}</span>{btn.label}
              </button>
            ))}
          </div>
        </div>;
      })}
    </div>
  </div>;
}

