    {trend&&<div style={{color:trend.startsWith("+")?C.gr:C.rd,fontSize:11,fontWeight:600,marginTop:6,display:"flex",alignItems:"center",gap:3}}>
      <span style={{fontSize:8}}>{trend.startsWith("+")?"▲":"▼"}</span>{trend}
    </div>}
