/* ═══════════════════════════════════════════════════════════════
   SISTEMA DE ALERTAS URGENTES (sócios + social media criam, todos recebem)
   Armazenado em localStorage na chave "pixels-alerts".
   Cada alerta: {id, forUid|"all", fromUid, message, level, createdAt, resolvedAt?}
   ═══════════════════════════════════════════════════════════════ */

const ALERTS_KEY="pixels-alerts";

function loadAllAlerts(){
  try{const s=localStorage.getItem(ALERTS_KEY);if(s)return JSON.parse(s);}catch(e){}
  return [];
}
function saveAllAlerts(alerts){
  try{localStorage.setItem(ALERTS_KEY,JSON.stringify(alerts));
    // Dispara evento pro dashboard ouvir
    window.dispatchEvent(new Event("pixels-alerts-changed"));
  }catch(e){}
}
function loadActiveAlertsFor(uid){
  return loadAllAlerts()
    .filter(a=>(a.forUid===uid||a.forUid==="all")&&!a.resolvedAt)
    .sort((a,b)=>{
      // Urgente > Atenção > Lembrete; depois mais recente primeiro
      const lv={urgente:0,atencao:1,lembrete:2};
      if(lv[a.level]!==lv[b.level])return lv[a.level]-lv[b.level];
      return new Date(b.createdAt)-new Date(a.createdAt);
    });
}
function createAlert({forUid,fromUid,message,level}){
  const alerts=loadAllAlerts();
  alerts.push({
    id:"alert-"+Date.now()+"-"+Math.random().toString(36).slice(2,7),
    forUid,fromUid,message,level:level||"atencao",
    createdAt:new Date().toISOString(),
  });
  saveAllAlerts(alerts);
}
function resolveAlert(id){
  const alerts=loadAllAlerts();
  const idx=alerts.findIndex(a=>a.id===id);
  if(idx>=0){alerts[idx].resolvedAt=new Date().toISOString();saveAllAlerts(alerts);}
}
function deleteAlertForever(id){
  saveAllAlerts(loadAllAlerts().filter(a=>a.id!==id));
}
function timeAgoBR(iso){
  const diff=Date.now()-new Date(iso).getTime();
  const m=Math.floor(diff/60000);
  if(m<1)return"agora";
  if(m<60)return m+"min";
  const h=Math.floor(m/60);
  if(h<24)return h+"h";
  const d=Math.floor(h/24);
  return d+"d";
}

// Metadados de cada nível de urgência
const ALERT_LEVELS={
  urgente:{label:"URGENTE",icon:"🚨",color:"#dc2626",bg:"#fef2f2",border:"#fecaca"},
  atencao:{label:"ATENÇÃO",icon:"⚠",color:"#ea580c",bg:"#fff7ed",border:"#fed7aa"},
  lembrete:{label:"LEMBRETE",icon:"📌",color:"#2563eb",bg:"#eff6ff",border:"#bfdbfe"},
};

// Timestamp da última vez que o user viu os alertas
const alertSeenKey=(uid)=>"pixels-alerts-seen-"+uid;
function getLastSeen(uid){
  try{const s=localStorage.getItem(alertSeenKey(uid));return s?new Date(s).getTime():0;}catch{return 0;}
}
function markAlertsAsSeen(uid){
  try{localStorage.setItem(alertSeenKey(uid),new Date().toISOString());}catch{}
}

// Som de sino (2 tons, Web Audio API — funciona em qualquer navegador)
function playBellSound(){
  try{
    const Ctx=window.AudioContext||window.webkitAudioContext;
    if(!Ctx)return;
    const ctx=new Ctx();
    const notes=[880,659]; // A5 + E5 (acorde de sino)
    notes.forEach((freq,i)=>{
      const osc=ctx.createOscillator();
      const gain=ctx.createGain();
      osc.type="sine";
      osc.frequency.value=freq;
      osc.connect(gain);
      gain.connect(ctx.destination);
      const start=ctx.currentTime+i*0.18;
      gain.gain.setValueAtTime(0.35,start);
      gain.gain.exponentialRampToValueAtTime(0.01,start+0.8);
      osc.start(start);
      osc.stop(start+0.8);
    });
    // Fecha contexto depois pra liberar memória
    setTimeout(()=>{try{ctx.close();}catch{}},2000);
  }catch(e){/* silently fail */}
}

/* ─── COMPONENTE: DashboardAlerts ─── (usado no Dashboard de cada user) */
function DashboardAlerts({userId,isMob}){
  const [alerts,setAlerts]=useState(()=>loadActiveAlertsFor(userId));
  const [welcomeModalAlerts,setWelcomeModalAlerts]=useState([]);
  const prevAlertIdsRef=useRef(new Set(alerts.map(a=>a.id)));

  // Recarrega alertas quando mudam (via evento)
  useEffect(()=>{
    const refresh=()=>{
      const newList=loadActiveAlertsFor(userId);
      // Detecta novos alertas (ID que não estava antes)
      const prevIds=prevAlertIdsRef.current;
      const newOnes=newList.filter(a=>!prevIds.has(a.id));
      if(newOnes.length>0){
        playBellSound();
      }
      prevAlertIdsRef.current=new Set(newList.map(a=>a.id));
      setAlerts(newList);
    };
    window.addEventListener("pixels-alerts-changed",refresh);
    window.addEventListener("storage",refresh);
    return()=>{
      window.removeEventListener("pixels-alerts-changed",refresh);
      window.removeEventListener("storage",refresh);
    };
  },[userId]);

  // Recarrega quando muda o userId (view as) + checa "boas-vindas" com alertas pendentes
  useEffect(()=>{
    const list=loadActiveAlertsFor(userId);
    setAlerts(list);
    prevAlertIdsRef.current=new Set(list.map(a=>a.id));

    // Ao entrar no dashboard: se tiver alertas CRIADOS DEPOIS da última vez que viu, mostra modal
    const lastSeen=getLastSeen(userId);
    const unseenAlerts=list.filter(a=>new Date(a.createdAt).getTime()>lastSeen);
    if(unseenAlerts.length>0){
      setWelcomeModalAlerts(unseenAlerts);
      // Tentar tocar som — pode falhar se o user ainda não interagiu
      playBellSound();
    }
  },[userId]);

  const closeWelcomeModal=()=>{
    markAlertsAsSeen(userId);
    setWelcomeModalAlerts([]);
  };

  const shown=alerts.slice(0,2);

  // Modal de "boas-vindas" com alertas pendentes
  const welcomeModal=welcomeModalAlerts.length>0&&(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.75)",zIndex:300,
        display:"flex",alignItems:"center",justifyContent:"center",padding:20,
        animation:"fadeIn .2s ease"}}
        onClick={closeWelcomeModal}>
      <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:20,
          padding:0,width:"100%",maxWidth:560,overflow:"hidden",
          boxShadow:"0 20px 60px rgba(0,0,0,0.3)",
          animation:"slideInUp .3s ease"}}>
        {/* Header vermelho chamativo */}
        <div style={{background:"#dc2626",padding:"22px 28px",color:"#fff",textAlign:"center"}}>
          <div style={{fontSize:40,marginBottom:8}}>🔔</div>
          <div style={{fontWeight:900,fontSize:20,letterSpacing:-.3}}>
            Você tem {welcomeModalAlerts.length} alerta{welcomeModalAlerts.length>1?"s":""} pendente{welcomeModalAlerts.length>1?"s":""}!
          </div>
          <div style={{fontSize:12,marginTop:4,opacity:0.9}}>
            Leia com atenção antes de começar o dia
          </div>
        </div>
        {/* Lista de alertas */}
        <div style={{padding:"18px 22px",maxHeight:"50vh",overflowY:"auto",display:"flex",flexDirection:"column",gap:10}}>
          {welcomeModalAlerts.map(a=>{
            const lv=ALERT_LEVELS[a.level]||ALERT_LEVELS.atencao;
            const from=TEAM.find(u=>u.id===a.fromUid);
            return <div key={a.id} style={{background:lv.bg,border:`2px solid ${lv.border}`,
                borderLeft:`6px solid ${lv.color}`,borderRadius:10,padding:"12px 14px",
                display:"flex",alignItems:"flex-start",gap:10}}>
              <div style={{width:38,height:38,borderRadius:10,background:lv.color,
                  display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,
                  flexShrink:0,boxShadow:`0 2px 6px ${lv.color}55`}}>
                {lv.icon}
              </div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:3,flexWrap:"wrap"}}>
                  <span style={{background:lv.color,color:"#fff",borderRadius:5,padding:"2px 7px",fontSize:9,fontWeight:800,letterSpacing:.5}}>
                    {lv.label}
                  </span>
                  {from&&<span style={{color:lv.color,fontSize:11,fontWeight:700}}>{from.name.split(" ")[0]}</span>}
                  <span style={{color:"#94a3b8",fontSize:10}}>· há {timeAgoBR(a.createdAt)}</span>
                </div>
                <div style={{color:"#1e293b",fontSize:13,fontWeight:600,lineHeight:1.4}}>
                  {a.message}
                </div>
              </div>
            </div>;
          })}
        </div>
        {/* Footer — botão fechar */}
        <div style={{padding:"14px 22px 18px",borderTop:"1px solid #e5e7eb",
            display:"flex",gap:10,justifyContent:"flex-end"}}>
          <button onClick={closeWelcomeModal}
              style={{background:"#dc2626",color:"#fff",border:"none",borderRadius:10,
                  padding:"11px 24px",fontWeight:800,fontSize:13,cursor:"pointer",
                  display:"flex",alignItems:"center",gap:6}}>
            ✓ Entendi, bora trabalhar!
          </button>
        </div>
      </div>
    </div>
  );

  // Estado vazio — card pequeno e discreto
  if(shown.length===0){
    return <>{welcomeModal}<div style={{background:"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:14,
        padding:"14px 18px",display:"flex",alignItems:"center",gap:12,
        maxWidth:860,margin:"0 auto",width:"100%"}}>
      <div style={{width:36,height:36,borderRadius:10,background:"#16a34a",
          display:"flex",alignItems:"center",justifyContent:"center",fontSize:18}}>✅</div>
      <div>
        <div style={{color:"#166534",fontWeight:800,fontSize:13}}>Tudo tranquilo!</div>
        <div style={{color:"#15803d",fontSize:11,marginTop:1}}>
          Você não tem alertas urgentes no momento.
        </div>
      </div>
    </div></>;
  }

  return <>{welcomeModal}<div style={{display:"flex",flexDirection:"column",gap:8,
      maxWidth:860,margin:"0 auto",width:"100%"}}>
    {shown.map(alert=>{
      const lv=ALERT_LEVELS[alert.level]||ALERT_LEVELS.atencao;
      const from=TEAM.find(u=>u.id===alert.fromUid);
      return <div key={alert.id} style={{
          background:lv.bg,
          border:`2px solid ${lv.border}`,
          borderLeft:`6px solid ${lv.color}`,
          borderRadius:12,
          padding:"12px 16px",
          display:"flex",
          alignItems:"center",
          gap:12,
          boxShadow:alert.level==="urgente"?`0 0 0 3px ${lv.color}22`:"none",
          animation:alert.level==="urgente"?"pulse 2s ease-in-out infinite":"none",
        }}>
        {/* Ícone urgência */}
        <div style={{width:44,height:44,borderRadius:12,background:lv.color,
            display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,
            flexShrink:0,boxShadow:`0 2px 6px ${lv.color}55`}}>
          {lv.icon}
        </div>
        {/* Conteúdo */}
        <div style={{flex:1,minWidth:0}}>
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:3,flexWrap:"wrap"}}>
            <span style={{background:lv.color,color:"#fff",borderRadius:6,padding:"2px 8px",
                fontSize:9,fontWeight:800,letterSpacing:.6}}>
              {lv.label}
            </span>
            {from&&<span style={{color:lv.color,fontSize:11,fontWeight:700}}>
              {from.name.split(" ")[0]}
            </span>}
            <span style={{color:"#94a3b8",fontSize:10,fontWeight:600}}>
              · há {timeAgoBR(alert.createdAt)}
            </span>
          </div>
          <div style={{color:"#1e293b",fontSize:13,fontWeight:600,lineHeight:1.4}}>
            {alert.message}
          </div>
        </div>
        {/* Botão resolver */}
        <button
          onClick={()=>{resolveAlert(alert.id);setAlerts(loadActiveAlertsFor(userId));}}
          title="Marcar como resolvido"
          style={{background:"#fff",border:`1px solid ${lv.color}`,borderRadius:8,
              padding:"6px 12px",color:lv.color,fontSize:10,fontWeight:800,
              cursor:"pointer",flexShrink:0,whiteSpace:"nowrap"}}
          onMouseEnter={e=>{e.currentTarget.style.background=lv.color;e.currentTarget.style.color="#fff";}}
          onMouseLeave={e=>{e.currentTarget.style.background="#fff";e.currentTarget.style.color=lv.color;}}>
          ✓ Li e resolvi
        </button>
      </div>;
    })}
    {alerts.length>2&&<div style={{color:"#94a3b8",fontSize:10,fontWeight:600,textAlign:"center"}}>
      +{alerts.length-2} alerta{alerts.length-2>1?"s":""} na página de Notificações
    </div>}
  </div></>;
}

/* SEED_NOTIFS removido — usuários veem apenas notificações reais */
const SEED_NOTIFS=[];

function PageNotificacoes({isMob, notifs, setNotifs}){
  const [expanded,setExpanded]=useState({}); // which panels show "ver mais"
  const markRead=(id)=>{if(setNotifs)setNotifs(p=>p.map(n=>n.id===id?{...n,read:true}:n));};
  const markAllCat=(cat)=>{if(setNotifs)setNotifs(p=>p.map(n=>n.category===cat?{...n,read:true}:n));};

  // ═══ Alertas: gerenciado via perm "criarAlerta". Sócios e coordenadores sempre podem (fallback). ═══
  const _alertPerms=(typeof ACCESS_STORE!=="undefined"?(ACCESS_STORE[CURRENT_USER.id]||{}):{});
  const canCreateAlerts=CURRENT_USER.level===1||CURRENT_USER.dash==="coordinator"||_alertPerms.criarAlerta===true;
  const [allAlerts,setAllAlerts]=useState(()=>loadAllAlerts());
  const [alertMsg,setAlertMsg]=useState("");
  const [alertTarget,setAlertTarget]=useState("all");
  const [alertLevel,setAlertLevel]=useState("atencao");
  const refreshAlerts=()=>setAllAlerts(loadAllAlerts());
  useEffect(()=>{
    const h=()=>refreshAlerts();
    window.addEventListener("pixels-alerts-changed",h);
    return()=>window.removeEventListener("pixels-alerts-changed",h);
  },[]);
  const handleCreateAlert=()=>{
    if(!alertMsg.trim()){pixelsToast.warning("Digite a mensagem do alerta.");return;}
    createAlert({
      forUid:alertTarget,
      fromUid:CURRENT_USER.id,
      message:alertMsg.trim(),
      level:alertLevel,
    });
    setAlertMsg("");
    refreshAlerts();
  };
  const activeAlerts=allAlerts.filter(a=>!a.resolvedAt).sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));

  // Seed data by category
  // FIX: respeita targetUsers — só mostra notif pro usuário atual se ele está no array
  // (ou se o array não existe / está vazio, pra manter broadcast como default)
  const _isForMe=(nt)=>{
    if(!nt.targetUsers||!Array.isArray(nt.targetUsers)||nt.targetUsers.length===0)return true;
    return nt.targetUsers.indexOf(CURRENT_USER.id)>=0;
  };
  const ALL_NOTIFS=[...(notifs||[]),...SEED_NOTIFS].filter(_isForMe);

  const PANELS=[
    {
      id:"demanda",label:"Demandas",icon:"📋",color:"#64748b",
      desc:"Quando demandas entram em execução ou são recebidas",
    },
    {
      id:"pendencia",label:"Pendências",icon:"🔄",color:"#f97316",
      desc:"Alterações de artes, vídeos e materiais em aprovação",
    },
    {
      id:"chat",label:"Chat",icon:"💬",color:"#00e5a0",
      desc:"Menções e mensagens diretas para você",
    },
    {
      id:"recado",label:"Recados da Empresa",icon:"📢",color:C.a,
      desc:"Comunicados e avisos da agência para a equipe",
    },
  ];

  const totalUnread=ALL_NOTIFS.filter(n=>!n.read).length;

  return <div style={{display:"flex",flexDirection:"column",gap:0}}>
    {/* Page header */}
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
      <div>
        <div style={{color:C.tx,fontWeight:900,fontSize:isMob?17:22}}>Notificações</div>
        <div style={{color:C.ts,fontSize:12,marginTop:2}}>
          {totalUnread>0?`${totalUnread} não lida${totalUnread>1?"s":""}  · `:""}{ALL_NOTIFS.length} no total
        </div>
      </div>
      {totalUnread>0&&<button
        onClick={()=>setNotifs&&setNotifs(p=>p.map(n=>({...n,read:true})))}
        style={{background:"none",border:`1px solid ${C.b1}`,borderRadius:8,padding:"6px 14px",color:C.ts,fontSize:11,fontWeight:600,cursor:"pointer"}}>
        ✓ Marcar todas como lidas
      </button>}
    </div>

    {/* ═══ SEÇÃO CRIAR ALERTA — só admins + social media ═══ */}
    {canCreateAlerts&&(
      <div style={{background:"#fff",borderRadius:14,border:"1px solid #e5e7eb",
          marginBottom:20,overflow:"hidden",boxShadow:"0 2px 6px rgba(0,0,0,0.06)"}}>
        {/* Header */}
        <div style={{background:"#dc2626",padding:"14px 18px",display:"flex",
            alignItems:"center",gap:10}}>
          <div style={{width:36,height:36,borderRadius:10,background:"#fff",
              display:"flex",alignItems:"center",justifyContent:"center",fontSize:18}}>⚡</div>
          <div>
            <div style={{color:"#fff",fontWeight:800,fontSize:14}}>Criar Alerta para Colaborador</div>
            <div style={{color:"#fff",fontSize:10,marginTop:1,opacity:0.9}}>
              aparece em destaque no dashboard do colaborador
            </div>
          </div>
        </div>
        {/* Form */}
        <div style={{padding:"16px 18px",display:"grid",gridTemplateColumns:isMob?"1fr":"1fr 1fr",gap:12}}>
          {/* Colaborador alvo */}
          <div>
            <label style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6,marginBottom:6,display:"block"}}>Enviar para</label>
            <select value={alertTarget} onChange={e=>setAlertTarget(e.target.value)}
                style={{width:"100%",padding:"9px 12px",border:"1px solid #e5e7eb",
                    borderRadius:8,fontSize:13,background:"#fff",color:"#1e293b",fontWeight:600}}>
              <option value="all">🌐 Todos os colaboradores</option>
              {TEAM.filter(u=>u.id!==CURRENT_USER.id).map(u=>(
                <option key={u.id} value={u.id}>{u.name} — {u.role}</option>
              ))}
            </select>
          </div>
          {/* Nível */}
          <div>
            <label style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6,marginBottom:6,display:"block"}}>Nível de urgência</label>
            <div style={{display:"flex",gap:6}}>
              {Object.entries(ALERT_LEVELS).map(([key,lv])=>(
                <button key={key} onClick={()=>setAlertLevel(key)}
                    style={{flex:1,padding:"9px 0",border:"none",borderRadius:8,
                        background:alertLevel===key?lv.color:"#f1f5f9",
                        color:alertLevel===key?"#fff":"#64748b",
                        fontSize:11,fontWeight:800,cursor:"pointer",
                        display:"flex",alignItems:"center",justifyContent:"center",gap:4,
                        transition:"all .12s"}}>
                  <span>{lv.icon}</span>
                  <span>{lv.label}</span>
                </button>
              ))}
            </div>
          </div>
          {/* Mensagem */}
          <div style={{gridColumn:isMob?"1":"1 / -1"}}>
            <label style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6,marginBottom:6,display:"block"}}>Mensagem do alerta</label>
            <textarea value={alertMsg} onChange={e=>setAlertMsg(e.target.value)}
                placeholder="Ex: Terminar o vídeo da Bioter até 18h hoje!"
                rows={2}
                style={{width:"100%",padding:"10px 12px",border:"1px solid #e5e7eb",
                    borderRadius:8,fontSize:13,color:"#1e293b",resize:"vertical",fontFamily:"inherit"}}/>
          </div>
          {/* Botão criar */}
          <div style={{gridColumn:isMob?"1":"1 / -1"}}>
            <button onClick={handleCreateAlert}
                disabled={!alertMsg.trim()}
                style={{width:"100%",padding:"11px 0",
                    background:alertMsg.trim()?"#dc2626":"#e5e7eb",
                    color:alertMsg.trim()?"#fff":"#94a3b8",
                    border:"none",borderRadius:10,fontSize:13,fontWeight:800,
                    cursor:alertMsg.trim()?"pointer":"not-allowed",
                    display:"flex",alignItems:"center",justifyContent:"center",gap:8,
                    transition:"transform .1s"}}>
              ⚡ Criar alerta
            </button>
          </div>
        </div>

        {/* Lista de alertas ATIVOS (criados por qualquer um) */}
        {activeAlerts.length>0&&<div style={{borderTop:"1px solid #e5e7eb",background:"#f8fafc"}}>
          <div style={{padding:"10px 18px",color:"#475569",fontSize:11,fontWeight:800,
              textTransform:"uppercase",letterSpacing:.6,display:"flex",alignItems:"center",gap:6}}>
            <span>📋 Alertas Ativos</span>
            <span style={{background:"#dc2626",color:"#fff",borderRadius:99,padding:"1px 8px",fontSize:10,fontWeight:800}}>{activeAlerts.length}</span>
          </div>
          <div style={{padding:"0 12px 12px",display:"flex",flexDirection:"column",gap:6}}>
            {activeAlerts.map(a=>{
              const lv=ALERT_LEVELS[a.level]||ALERT_LEVELS.atencao;
              const from=TEAM.find(u=>u.id===a.fromUid);
              const target=a.forUid==="all"?"Todos":(TEAM.find(u=>u.id===a.forUid)?.name||a.forUid);
              return <div key={a.id} style={{background:"#fff",border:`1px solid #e5e7eb`,
                  borderLeft:`4px solid ${lv.color}`,borderRadius:8,padding:"10px 12px",
                  display:"flex",alignItems:"center",gap:10}}>
                <div style={{width:28,height:28,borderRadius:7,background:lv.bg,
                    display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,flexShrink:0}}>
                  {lv.icon}
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2,flexWrap:"wrap"}}>
                    <span style={{background:lv.color,color:"#fff",borderRadius:4,padding:"1px 6px",fontSize:8,fontWeight:800,letterSpacing:.4}}>
                      {lv.label}
                    </span>
                    <span style={{color:"#475569",fontSize:10,fontWeight:700}}>→ {target}</span>
                    <span style={{color:"#94a3b8",fontSize:9}}>· {from?.name.split(" ")[0]||"?"} · há {timeAgoBR(a.createdAt)}</span>
                  </div>
                  <div style={{color:"#1e293b",fontSize:12,fontWeight:500,lineHeight:1.4}}>{a.message}</div>
                </div>
                <button onClick={async()=>{if(await pixelsConfirm("Remover este alerta?",{okText:"Remover",danger:true})){deleteAlertForever(a.id);refreshAlerts();}}}
                    title="Remover alerta"
                    style={{background:"none",border:"1px solid #e5e7eb",borderRadius:6,
                        padding:"5px 9px",color:"#94a3b8",fontSize:10,cursor:"pointer",flexShrink:0}}
                    onMouseEnter={e=>{e.currentTarget.style.background="#dc2626";e.currentTarget.style.color="#fff";e.currentTarget.style.borderColor="#dc2626";}}
                    onMouseLeave={e=>{e.currentTarget.style.background="none";e.currentTarget.style.color="#94a3b8";e.currentTarget.style.borderColor="#e5e7eb";}}>
                  🗑
                </button>
              </div>;
            })}
          </div>
        </div>}
      </div>
    )}

    {/* 4 panels grid */}
    <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"1fr 1fr",gap:14}}>
      {PANELS.map(panel=>{
        const items=ALL_NOTIFS.filter(n=>n.category===panel.id);
        const unread=items.filter(n=>!n.read).length;
        const isExpanded=expanded[panel.id];
        const visible=isExpanded?items:items.slice(0,10);
        const hasMore=items.length>10;

        return <div key={panel.id} style={{background:C.card,borderRadius:14,overflow:"hidden",boxShadow:"0 1px 4px rgba(0,0,0,0.12),0 4px 14px rgba(0,0,0,0.08)",display:"flex",flexDirection:"column"}}>

          {/* Colored header strip */}
          <div style={{background:panel.color,padding:"14px 16px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <div style={{width:34,height:34,borderRadius:9,background:"rgba(255,255,255,0.2)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:17}}>
                {panel.icon}
              </div>
              <div>
                <div style={{color:"#fff",fontWeight:800,fontSize:13}}>{panel.label}</div>
                <div style={{color:"rgba(255,255,255,0.75)",fontSize:10,marginTop:1}}>{panel.desc}</div>
              </div>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:7}}>
              {unread>0&&<div style={{background:"rgba(0,0,0,0.2)",color:"#fff",borderRadius:99,padding:"2px 9px",fontSize:11,fontWeight:800}}>{unread}</div>}
              {unread>0&&<button onClick={()=>markAllCat(panel.id)}
                style={{background:"rgba(255,255,255,0.2)",border:"none",borderRadius:6,padding:"4px 10px",color:"#fff",fontSize:10,cursor:"pointer",fontWeight:600}}>
                Limpar
              </button>}
            </div>
          </div>

          {/* White notifications list */}
          <div style={{flex:1,overflowY:"auto",maxHeight:340}}>
            {items.length===0
              ?<div style={{padding:"32px 16px",textAlign:"center"}}>
                <div style={{fontSize:28,marginBottom:8}}>✅</div>
                <div style={{color:C.ts,fontSize:12}}>Tudo em dia por aqui!</div>
              </div>
              :<>
                {visible.map(n=><div key={n.id} onClick={()=>markRead(n.id)}
                  style={{display:"flex",gap:10,alignItems:"flex-start",padding:"11px 14px",borderBottom:`1px solid ${C.b1}`,cursor:"pointer",background:n.read?"transparent":panel.color+"0d",transition:"background .1s"}}
                  onMouseEnter={e=>e.currentTarget.style.background=C.b1}
                  onMouseLeave={e=>e.currentTarget.style.background=n.read?"transparent":panel.color+"0d"}>
                  <div style={{width:30,height:30,borderRadius:8,background:panel.color+"18",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,flexShrink:0}}>{n.icon}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:6}}>
                      <span style={{color:C.tx,fontWeight:n.read?500:700,fontSize:12,lineHeight:1.3}}>{n.title}</span>
                      {!n.read&&<div style={{width:7,height:7,borderRadius:"50%",background:panel.color,flexShrink:0,marginTop:3}}/>}
                    </div>
                    <div style={{color:C.ts,fontSize:11,marginTop:3,lineHeight:1.5}}>{n.body}</div>
                    <div style={{color:C.td,fontSize:10,marginTop:4}}>{n.at} · {n.user}</div>
                  </div>
                </div>)}
                {hasMore&&<button
                  onClick={()=>setExpanded(p=>({...p,[panel.id]:!p[panel.id]}))}
                  style={{width:"100%",padding:"10px 14px",background:"none",border:"none",color:panel.color,fontSize:12,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:6,borderTop:`1px solid ${C.b1}`}}>
                  {isExpanded?"▲ Recolher":<>Ver mais <span style={{background:panel.color+"22",color:panel.color,borderRadius:99,padding:"1px 7px",fontSize:10,fontWeight:800}}>{items.length-10}</span></>}
                </button>}
              </>
            }
          </div>
        </div>;
      })}
    </div>
  </div>;
}

// Aba Financeiro — visão consolidada de receita da Pixels.
// Mostra SÓ o que já é contrato/receita/projeto vendido/projeção/cobrança.
// NUNCA mostra prospects ou oportunidades em aberto — isso é Comercial.

const FIN_CONTRATO_STATUS = [
  {id:"ativo",     label:"Ativo",     color:"#16a34a", bg:"#dcfce7"},
  {id:"pausado",   label:"Pausado",   color:"#64748b", bg:"#f1f5f9"},
  {id:"encerrado", label:"Encerrado", color:"#dc2626", bg:"#fee2e2"},
];
const FIN_PAGAMENTO_STATUS = [
  {id:"em_dia",    label:"Em dia",   color:"#16a34a", bg:"#dcfce7"},
  {id:"em_aberto", label:"Em aberto",color:"#ca8a04", bg:"#fef9c3"},
  {id:"atrasado",  label:"Atrasado", color:"#dc2626", bg:"#fee2e2"},
  {id:"pago",      label:"Pago",     color:"#0284c7", bg:"#e0f2fe"},
];
const FIN_PROJETO_STATUS = [
  {id:"proposta",    label:"Proposta",    color:"#64748b", bg:"#f1f5f9"},
  {id:"aprovado",    label:"Aprovado",    color:"#0284c7", bg:"#e0f2fe"},
  {id:"em_producao", label:"Em produção", color:"#ca8a04", bg:"#fef9c3"},
  {id:"entregue",    label:"Entregue",    color:"#16a34a", bg:"#dcfce7"},
  {id:"cancelado",   label:"Cancelado",   color:"#dc2626", bg:"#fee2e2"},
];
const FIN_TIPOS_PROJETO = ["Landing Page","Site","Google Perfil de Empresa","Apresentação Comercial","Catálogo Digital","Campanha de Feira","Automação WhatsApp/CRM","Relatório Premium","Edição Extra de Vídeos","Pacote Extra de Posts","Setup Pixel/Tag","CRM/Funil","Outro"];

const FIN_STORE_KEY = "pixels-financeiro-v1";

function _finInitial(){
  const contratos=[];
  if(typeof BIOTER_GROUP_UNITS!=="undefined"){
    BIOTER_GROUP_UNITS.forEach(function(u){
      if(u.mrr>0)contratos.push({id:"c_"+u.id,clienteId:u.id,clienteNome:u.name,grupo:"bioter",unidade:u.cidade||"",valorMensal:u.mrr,servicos:"Social media · Meta Ads · Google Ads",dataInicio:"2024-01-01",dataRevisao:"",statusContrato:"ativo",statusPagamento:"em_dia",responsavel:"gustavo",custoEstimado:0,margem:0,observacoes:""});
    });
  }
  if(typeof CLIENT_PROFILES!=="undefined"){
    ["construschorr","arabuta","climaves","vetservice"].forEach(function(id){
      const p=CLIENT_PROFILES[id];
      if(p&&p.mrr>0)contratos.push({id:"c_"+id,clienteId:id,clienteNome:p.name,grupo:"",unidade:"",valorMensal:p.mrr,servicos:p.servicos||"",dataInicio:"2024-01-01",dataRevisao:"",statusContrato:"ativo",statusPagamento:"em_dia",responsavel:p.responsavel_interno||"vinicius",custoEstimado:0,margem:0,observacoes:""});
    });
  }
  return {contratos:contratos,pontuais:[],cobrancas:[]};
}
function _finLoad(){
  try{const raw=localStorage.getItem(FIN_STORE_KEY);if(!raw){const init=_finInitial();_finSave(init);return init;}const p=JSON.parse(raw);return Object.assign(_finInitial(),p||{});}catch(e){return _finInitial();}
}
function _finSave(s){try{localStorage.setItem(FIN_STORE_KEY,JSON.stringify(s));}catch(e){}}
function useFinanceiroStore(){
  const [store,setStore]=useState(_finLoad);
  const update=useCallback(function(updater){setStore(function(prev){const next=typeof updater==="function"?updater(prev):updater;_finSave(next);return next;});},[]);
  return {store,update};
}

const _FIN_CARD={background:"#fff",border:"1px solid #e2e8f0",borderRadius:14,padding:18,fontFamily:"'Inter',system-ui,sans-serif"};
const _FIN_LBL={color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.7,marginBottom:5};
const _FIN_INP={width:"100%",background:"#f8fafc",border:"1px solid #e2e8f0",borderRadius:9,padding:"8px 12px",color:"#0f172a",fontSize:13,fontWeight:500,outline:"none",fontFamily:"'Inter',system-ui,sans-serif",boxSizing:"border-box"};

function _finFmtBRL(n){return "R$ "+(Number(n)||0).toLocaleString("pt-BR",{minimumFractionDigits:0,maximumFractionDigits:0});}
function _finFmtDateBR(ds){if(!ds)return "—";try{const d=new Date((ds+"").length===10?ds+"T12:00:00":ds);if(isNaN(d.getTime()))return ds;return d.toLocaleDateString("pt-BR",{day:"2-digit",month:"2-digit",year:"2-digit"});}catch(e){return ds;}}
function _finFindCfg(arr,id){return arr.find(function(x){return x.id===id;})||arr[0];}

function FinModal({title,subtitle,children,onClose,maxWidth}){
  if(typeof useEscToClose==="function")useEscToClose(true,onClose);
  return <div onMouseDown={function(e){if(e.target===e.currentTarget)onClose&&onClose();}}
    style={{position:"fixed",inset:0,background:"rgba(15,23,42,0.55)",backdropFilter:"blur(4px)",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center",padding:16,fontFamily:"'Inter',system-ui,sans-serif"}}>
    <div onMouseDown={function(e){e.stopPropagation();}}
      style={{background:"#fff",borderRadius:16,width:"100%",maxWidth:maxWidth||560,maxHeight:"92vh",overflow:"auto",boxShadow:"0 24px 64px rgba(15,23,42,0.28)"}}>
      <div style={{padding:"18px 22px 14px",borderBottom:"1px solid #f1f5f9",display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:12}}>
        <div>
          <div style={{color:"#0f172a",fontWeight:700,fontSize:16,letterSpacing:-.3}}>{title}</div>
          {subtitle&&<div style={{color:"#64748b",fontSize:12,marginTop:3}}>{subtitle}</div>}
        </div>
        <button onClick={onClose} style={{background:"#f1f5f9",border:"none",borderRadius:8,width:30,height:30,color:"#64748b",cursor:"pointer",fontSize:13}}>✕</button>
      </div>
      <div style={{padding:22}}>{children}</div>
    </div>
  </div>;
}

function PageFinanceiro({isMob,perms,effectiveUser}){
  const {store,update}=useFinanceiroStore();
  const [tab,setTab]=useState("mrr");
  const isSocio=(effectiveUser||(typeof CURRENT_USER!=="undefined"?CURRENT_USER:null))?.level===1;
  const canEdit=isSocio||(perms&&perms.editarFinanceiro);

  const contratosAtivos=(store.contratos||[]).filter(function(c){return c.statusContrato==="ativo";});
  const mrrAtual=contratosAtivos.reduce(function(s,c){return s+(c.valorMensal||0);},0);
  const proj12=mrrAtual*12;
  const pontualMes=(store.pontuais||[]).filter(function(p){if(p.status==="cancelado")return false;if(!p.dataVenda)return false;const d=new Date(p.dataVenda);const now=new Date();return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();}).reduce(function(s,p){return s+(p.valor||0);},0);
  const receitaTotalMes=mrrAtual+pontualMes;
  const clientesAtivos=new Set(contratosAtivos.map(function(c){return c.grupo||c.clienteId;})).size;
  const ticketMedio=contratosAtivos.length>0?(mrrAtual/contratosAtivos.length):0;
  const porGrupo={};
  contratosAtivos.forEach(function(c){const k=c.grupo||c.clienteNome;porGrupo[k]=(porGrupo[k]||0)+(c.valorMensal||0);});
  const concentracao=Object.entries(porGrupo).sort(function(a,b){return b[1]-a[1];})[0];
  const concentracaoNome=concentracao?(concentracao[0]==="bioter"?"Grupo Bioter":concentracao[0]):"—";
  const concentracaoValor=concentracao?concentracao[1]:0;
  const concentracaoPct=mrrAtual>0?Math.round((concentracaoValor/mrrAtual)*100):0;
  const contasAbertas=(store.cobrancas||[]).filter(function(c){return c.statusPagamento==="em_aberto";});
  const contasAtrasadas=(store.cobrancas||[]).filter(function(c){return c.statusPagamento==="atrasado";});
  const ltvTotal=contratosAtivos.reduce(function(s,c){if(!c.dataInicio)return s+(c.valorMensal||0);const start=new Date(c.dataInicio);const meses=Math.max(1,Math.round((Date.now()-start.getTime())/(30*86400000)));return s+meses*(c.valorMensal||0);},0);

  const KPIS=[
    {label:"MRR atual",value:_finFmtBRL(mrrAtual),accent:"#16a34a"},
    {label:"Receita projetada (12m)",value:_finFmtBRL(proj12)},
    {label:"Receita pontual do mês",value:_finFmtBRL(pontualMes)},
    {label:"Receita total do mês",value:_finFmtBRL(receitaTotalMes)},
    {label:"Contratos ativos",value:contratosAtivos.length},
    {label:"Clientes ativos",value:clientesAtivos},
    {label:"Ticket médio",value:_finFmtBRL(ticketMedio)},
    {label:"LTV total acumulado",value:_finFmtBRL(ltvTotal)},
    {label:"Contas em aberto",value:contasAbertas.length,accent:contasAbertas.length>0?"#ca8a04":undefined},
    {label:"Contas atrasadas",value:contasAtrasadas.length,accent:contasAtrasadas.length>0?"#dc2626":undefined},
    {label:"Maior concentração",value:concentracaoNome,small:_finFmtBRL(concentracaoValor)+" · "+concentracaoPct+"%"},
  ];
  const SUBTABS=[{id:"mrr",label:"MRR & Contratos"},{id:"pontual",label:"Receita pontual"},{id:"ltv",label:"LTV por cliente"},{id:"projecao",label:"Projeção"},{id:"status",label:"Status financeiro"}];

  return <div style={{display:"flex",flexDirection:"column",gap:18,fontFamily:"'Inter',system-ui,sans-serif"}}>
    <div>
      <div style={{color:"#0f172a",fontWeight:800,fontSize:24,letterSpacing:-.5}}>Financeiro</div>
      <div style={{color:"#64748b",fontSize:12,marginTop:3,fontWeight:500}}>Receita recorrente, pontual, projeção e status financeiro da Pixels.</div>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(190px,1fr))",gap:10}}>
      {KPIS.map(function(k,i){return <div key={i} style={Object.assign({},_FIN_CARD,{padding:"14px 16px"})}>
        <div style={_FIN_LBL}>{k.label}</div>
        <div style={{color:k.accent||"#0f172a",fontWeight:800,fontSize:k.small?17:20,marginTop:4,letterSpacing:-.3}}>{k.value}</div>
        {k.small&&<div style={{color:"#94a3b8",fontSize:10.5,marginTop:3,fontWeight:600}}>{k.small}</div>}
      </div>;})}
    </div>
    <div style={{display:"flex",gap:4,borderBottom:"1px solid #e2e8f0",overflowX:"auto"}}>
      {SUBTABS.map(function(s){const active=tab===s.id;return <button key={s.id} onClick={function(){setTab(s.id);}}
        style={{background:"none",border:"none",borderBottom:active?"2px solid #0f172a":"2px solid transparent",padding:"10px 16px",color:active?"#0f172a":"#64748b",fontWeight:active?700:500,fontSize:13,cursor:"pointer",fontFamily:"inherit",marginBottom:-1,whiteSpace:"nowrap"}}>{s.label}</button>;})}
    </div>
    {tab==="mrr"&&<FinMRRContratos store={store} update={update} canEdit={canEdit}/>}
    {tab==="pontual"&&<FinReceitaPontual store={store} update={update} canEdit={canEdit}/>}
    {tab==="ltv"&&<FinLTV store={store}/>}
    {tab==="projecao"&&<FinProjecao store={store} mrrAtual={mrrAtual} proj12={proj12}/>}
    {tab==="status"&&<FinStatus store={store} update={update} canEdit={canEdit}/>}
  </div>;
}

function FinMRRContratos({store,update,canEdit}){
  const [editing,setEditing]=useState(null);
  const contratos=store.contratos||[];
  const groups={};
  contratos.forEach(function(c){if(c.grupo==="bioter"){if(!groups.bioter)groups.bioter={name:"Grupo Bioter",total:0,items:[]};groups.bioter.total+=(c.valorMensal||0);groups.bioter.items.push(c);}});
  const semGrupo=contratos.filter(function(c){return !c.grupo;});

  function newContrato(){setEditing({id:"c"+Date.now()+"-"+Math.random().toString(36).slice(2,5),clienteId:"",clienteNome:"",grupo:"",unidade:"",valorMensal:0,servicos:"",dataInicio:new Date().toISOString().slice(0,10),dataRevisao:"",statusContrato:"ativo",statusPagamento:"em_dia",responsavel:"",custoEstimado:0,margem:0,observacoes:""});}
  function saveContrato(c){const exists=(store.contratos||[]).some(function(x){return x.id===c.id;});update(function(prev){const arr=prev.contratos||[];return Object.assign({},prev,{contratos:exists?arr.map(function(x){return x.id===c.id?c:x;}):[c].concat(arr)});});setEditing(null);}
  function delContrato(id){if(!window.confirm("Excluir esse contrato?"))return;update(function(prev){return Object.assign({},prev,{contratos:(prev.contratos||[]).filter(function(c){return c.id!==id;})});});}

  function renderRow(c){
    const stC=_finFindCfg(FIN_CONTRATO_STATUS,c.statusContrato),stP=_finFindCfg(FIN_PAGAMENTO_STATUS,c.statusPagamento);
    return <div key={c.id} style={{display:"grid",gridTemplateColumns:"2fr 0.9fr 0.9fr 1fr 1fr 70px",padding:"12px 14px",borderBottom:"1px solid #f1f5f9",gap:10,alignItems:"center",cursor:canEdit?"pointer":"default"}} onClick={function(){canEdit&&setEditing(c);}}>
      <div><div style={{color:"#0f172a",fontWeight:600,fontSize:13}}>{c.clienteNome}</div><div style={{color:"#64748b",fontSize:11,marginTop:2}}>{c.servicos||"—"}</div></div>
      <div style={{color:"#0f172a",fontWeight:700,fontSize:13}}>{_finFmtBRL(c.valorMensal)}</div>
      <div style={{color:"#475569",fontSize:11}}>{_finFmtDateBR(c.dataInicio)}</div>
      <div><span style={{background:stC.bg,color:stC.color,fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:99}}>{stC.label}</span></div>
      <div><span style={{background:stP.bg,color:stP.color,fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:99}}>{stP.label}</span></div>
      {canEdit&&<button onClick={function(e){e.stopPropagation();delContrato(c.id);}} style={{background:"transparent",border:"none",color:"#cbd5e1",cursor:"pointer",fontSize:14,padding:6}}>✕</button>}
    </div>;
  }

  return <div style={{display:"flex",flexDirection:"column",gap:14}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:12,flexWrap:"wrap"}}>
      <div style={{color:"#64748b",fontSize:13}}>{contratos.length} contrato{contratos.length!==1?"s":""}</div>
      {canEdit&&<button onClick={newContrato} style={{background:"#0f172a",color:"#fff",border:"none",borderRadius:10,padding:"9px 16px",fontWeight:700,fontSize:12.5,cursor:"pointer",fontFamily:"inherit"}}>+ Novo contrato</button>}
    </div>
    <div style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:14,overflow:"hidden"}}>
      <div style={{display:"grid",gridTemplateColumns:"2fr 0.9fr 0.9fr 1fr 1fr 70px",padding:"12px 14px",background:"#f8fafc",borderBottom:"1px solid #e2e8f0",gap:10}}>
        {["Cliente / serviços","Mensal","Início","Contrato","Pagamento",""].map(function(h,i){return <div key={i} style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6}}>{h}</div>;})}
      </div>
      {groups.bioter&&<div>
        <div style={{padding:"10px 14px",background:"#f5f3ff",borderBottom:"1px solid #e2e8f0",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div style={{color:"#7c3aed",fontSize:11,fontWeight:800,textTransform:"uppercase",letterSpacing:.6,display:"flex",alignItems:"center",gap:8}}>Grupo Bioter <span style={{background:"#7c3aed",color:"#fff",borderRadius:99,padding:"1px 7px",fontSize:9,fontWeight:700}}>{groups.bioter.items.length} unidades</span></div>
          <div style={{color:"#7c3aed",fontWeight:800,fontSize:13}}>{_finFmtBRL(groups.bioter.total)}/mês</div>
        </div>
        {groups.bioter.items.map(renderRow)}
      </div>}
      {semGrupo.map(renderRow)}
      {contratos.length===0&&<div style={{padding:36,textAlign:"center",color:"#94a3b8",fontSize:13}}>Nenhum contrato cadastrado.</div>}
    </div>
    {editing&&<FinContratoModal c={editing} onClose={function(){setEditing(null);}} onSave={saveContrato}/>}
  </div>;
}

function FinContratoModal({c,onClose,onSave}){
  const [f,setF]=useState(c);const set=function(k,v){setF(Object.assign({},f,{[k]:v}));};
  return <FinModal title={c.clienteNome?"Editar contrato":"Novo contrato"} onClose={onClose} maxWidth={640}>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Cliente</div><input value={f.clienteNome||""} onChange={function(e){set("clienteNome",e.target.value);}} style={_FIN_INP} autoFocus/></div>
      <div><div style={_FIN_LBL}>Grupo econômico (opcional)</div><input value={f.grupo||""} onChange={function(e){set("grupo",e.target.value);}} style={_FIN_INP} placeholder="Ex: bioter"/></div>
      <div><div style={_FIN_LBL}>Unidade / filial</div><input value={f.unidade||""} onChange={function(e){set("unidade",e.target.value);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Valor mensal (R$)</div><input type="number" value={f.valorMensal||0} onChange={function(e){set("valorMensal",Number(e.target.value)||0);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Custo estimado (R$)</div><input type="number" value={f.custoEstimado||0} onChange={function(e){set("custoEstimado",Number(e.target.value)||0);}} style={_FIN_INP}/></div>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Serviços contratados</div><textarea rows={2} value={f.servicos||""} onChange={function(e){set("servicos",e.target.value);}} style={Object.assign({},_FIN_INP,{resize:"vertical",minHeight:50})}/></div>
      <div><div style={_FIN_LBL}>Data de início</div><input type="date" value={f.dataInicio||""} onChange={function(e){set("dataInicio",e.target.value);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Data de revisão</div><input type="date" value={f.dataRevisao||""} onChange={function(e){set("dataRevisao",e.target.value);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Status do contrato</div><select value={f.statusContrato||"ativo"} onChange={function(e){set("statusContrato",e.target.value);}} style={_FIN_INP}>{FIN_CONTRATO_STATUS.map(function(s){return <option key={s.id} value={s.id}>{s.label}</option>;})}</select></div>
      <div><div style={_FIN_LBL}>Status do pagamento</div><select value={f.statusPagamento||"em_dia"} onChange={function(e){set("statusPagamento",e.target.value);}} style={_FIN_INP}>{FIN_PAGAMENTO_STATUS.map(function(s){return <option key={s.id} value={s.id}>{s.label}</option>;})}</select></div>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Responsável interno</div><select value={f.responsavel||""} onChange={function(e){set("responsavel",e.target.value);}} style={_FIN_INP}><option value="">—</option>{(typeof TEAM!=="undefined"?TEAM:[]).map(function(u){return <option key={u.id} value={u.id}>{u.name}</option>;})}</select></div>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Observações</div><textarea rows={3} value={f.observacoes||""} onChange={function(e){set("observacoes",e.target.value);}} style={Object.assign({},_FIN_INP,{resize:"vertical",minHeight:60})}/></div>
    </div>
    <div style={{display:"flex",justifyContent:"flex-end",gap:8,marginTop:18}}>
      <button onClick={onClose} style={{background:"#f1f5f9",color:"#64748b",border:"none",borderRadius:10,padding:"10px 18px",fontWeight:600,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>Cancelar</button>
      <button onClick={function(){onSave(f);}} style={{background:"#7c3aed",color:"#fff",border:"none",borderRadius:10,padding:"10px 22px",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>Salvar</button>
    </div>
  </FinModal>;
}

function FinReceitaPontual({store,update,canEdit}){
  const [editing,setEditing]=useState(null);
  const pontuais=store.pontuais||[];
  const total=pontuais.filter(function(p){return p.status!=="cancelado";}).reduce(function(s,p){return s+(p.valor||0);},0);
  function newProj(){setEditing({id:"p"+Date.now()+"-"+Math.random().toString(36).slice(2,5),projeto:"",cliente:"",tipo:"Landing Page",valor:0,custoEstimado:0,margem:0,status:"proposta",dataVenda:new Date().toISOString().slice(0,10),dataEntrega:"",responsavel:"",observacoes:""});}
  function saveProj(p){const exists=(store.pontuais||[]).some(function(x){return x.id===p.id;});update(function(prev){const arr=prev.pontuais||[];return Object.assign({},prev,{pontuais:exists?arr.map(function(x){return x.id===p.id?p:x;}):[p].concat(arr)});});setEditing(null);}
  return <div style={{display:"flex",flexDirection:"column",gap:14}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:12,flexWrap:"wrap"}}>
      <div style={{color:"#64748b",fontSize:13}}>{pontuais.length} projeto{pontuais.length!==1?"s":""} · receita total {_finFmtBRL(total)}</div>
      {canEdit&&<button onClick={newProj} style={{background:"#0f172a",color:"#fff",border:"none",borderRadius:10,padding:"9px 16px",fontWeight:700,fontSize:12.5,cursor:"pointer",fontFamily:"inherit"}}>+ Novo projeto</button>}
    </div>
    <div style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:14,overflow:"hidden"}}>
      <div style={{display:"grid",gridTemplateColumns:"2fr 1.5fr 1fr 1fr 1.2fr",padding:"12px 14px",background:"#f8fafc",borderBottom:"1px solid #e2e8f0",gap:10}}>
        {["Projeto","Cliente / tipo","Valor","Venda","Status"].map(function(h,i){return <div key={i} style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6}}>{h}</div>;})}
      </div>
      {pontuais.length===0&&<div style={{padding:36,textAlign:"center",color:"#94a3b8",fontSize:13}}>Nenhum projeto pontual cadastrado.</div>}
      {pontuais.map(function(p){const stCfg=_finFindCfg(FIN_PROJETO_STATUS,p.status);return <div key={p.id} style={{display:"grid",gridTemplateColumns:"2fr 1.5fr 1fr 1fr 1.2fr",padding:"12px 14px",borderBottom:"1px solid #f1f5f9",gap:10,alignItems:"center",cursor:canEdit?"pointer":"default"}} onClick={function(){canEdit&&setEditing(p);}}>
        <div style={{color:"#0f172a",fontWeight:600,fontSize:13}}>{p.projeto||"(sem nome)"}</div>
        <div><div style={{color:"#475569",fontSize:12}}>{p.cliente||"—"}</div><div style={{color:"#94a3b8",fontSize:10.5,marginTop:1}}>{p.tipo}</div></div>
        <div style={{color:"#0f172a",fontWeight:700,fontSize:13}}>{_finFmtBRL(p.valor)}</div>
        <div style={{color:"#475569",fontSize:11}}>{_finFmtDateBR(p.dataVenda)}</div>
        <div><span style={{background:stCfg.bg,color:stCfg.color,fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:99}}>{stCfg.label}</span></div>
      </div>;})}
    </div>
    {editing&&<FinPontualModal p={editing} onClose={function(){setEditing(null);}} onSave={saveProj}/>}
  </div>;
}

function FinPontualModal({p,onClose,onSave}){
  const [f,setF]=useState(p);const set=function(k,v){setF(Object.assign({},f,{[k]:v}));};
  return <FinModal title={p.projeto?"Editar projeto":"Novo projeto pontual"} onClose={onClose} maxWidth={640}>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Nome do projeto</div><input value={f.projeto||""} onChange={function(e){set("projeto",e.target.value);}} style={_FIN_INP} autoFocus/></div>
      <div><div style={_FIN_LBL}>Cliente</div><input value={f.cliente||""} onChange={function(e){set("cliente",e.target.value);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Tipo</div><select value={f.tipo||"Landing Page"} onChange={function(e){set("tipo",e.target.value);}} style={_FIN_INP}>{FIN_TIPOS_PROJETO.map(function(t){return <option key={t} value={t}>{t}</option>;})}</select></div>
      <div><div style={_FIN_LBL}>Valor (R$)</div><input type="number" value={f.valor||0} onChange={function(e){set("valor",Number(e.target.value)||0);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Custo estimado (R$)</div><input type="number" value={f.custoEstimado||0} onChange={function(e){set("custoEstimado",Number(e.target.value)||0);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Status</div><select value={f.status||"proposta"} onChange={function(e){set("status",e.target.value);}} style={_FIN_INP}>{FIN_PROJETO_STATUS.map(function(s){return <option key={s.id} value={s.id}>{s.label}</option>;})}</select></div>
      <div><div style={_FIN_LBL}>Data da venda</div><input type="date" value={f.dataVenda||""} onChange={function(e){set("dataVenda",e.target.value);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Data prevista de entrega</div><input type="date" value={f.dataEntrega||""} onChange={function(e){set("dataEntrega",e.target.value);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Responsável</div><select value={f.responsavel||""} onChange={function(e){set("responsavel",e.target.value);}} style={_FIN_INP}><option value="">—</option>{(typeof TEAM!=="undefined"?TEAM:[]).map(function(u){return <option key={u.id} value={u.id}>{u.name}</option>;})}</select></div>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Observações</div><textarea rows={3} value={f.observacoes||""} onChange={function(e){set("observacoes",e.target.value);}} style={Object.assign({},_FIN_INP,{resize:"vertical",minHeight:60})}/></div>
    </div>
    <div style={{display:"flex",justifyContent:"flex-end",gap:8,marginTop:18}}>
      <button onClick={onClose} style={{background:"#f1f5f9",color:"#64748b",border:"none",borderRadius:10,padding:"10px 18px",fontWeight:600,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>Cancelar</button>
      <button onClick={function(){onSave(f);}} style={{background:"#7c3aed",color:"#fff",border:"none",borderRadius:10,padding:"10px 22px",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>Salvar</button>
    </div>
  </FinModal>;
}

function FinLTV({store}){
  const contratos=store.contratos||[];const byClient={};
  contratos.forEach(function(c){const key=c.grupo||c.clienteNome;if(!byClient[key])byClient[key]={nome:key,grupo:c.grupo||"",mrr:0,mesesAtivos:0,inicio:c.dataInicio,unidades:[]};byClient[key].mrr+=(c.valorMensal||0);byClient[key].unidades.push(c);if(c.dataInicio&&(!byClient[key].inicio||c.dataInicio<byClient[key].inicio))byClient[key].inicio=c.dataInicio;});
  Object.values(byClient).forEach(function(b){if(b.inicio){const start=new Date(b.inicio);b.mesesAtivos=Math.max(1,Math.round((Date.now()-start.getTime())/(30*86400000)));}b.acumulado=b.mrr*b.mesesAtivos;b.projetada=b.mrr*12;});
  const sorted=Object.values(byClient).sort(function(a,b){return b.acumulado-a.acumulado;});
  return <div style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:14,overflow:"hidden"}}>
    <div style={{display:"grid",gridTemplateColumns:"2fr 1fr 1fr 1.2fr 1.2fr",padding:"12px 14px",background:"#f8fafc",borderBottom:"1px solid #e2e8f0",gap:10}}>
      {["Cliente / grupo","MRR","Tempo (m)","Acumulado","Projetada 12m"].map(function(h,i){return <div key={i} style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6}}>{h}</div>;})}
    </div>
    {sorted.length===0&&<div style={{padding:36,textAlign:"center",color:"#94a3b8",fontSize:13}}>Sem contratos pra calcular.</div>}
    {sorted.map(function(b){return <div key={b.nome} style={{display:"grid",gridTemplateColumns:"2fr 1fr 1fr 1.2fr 1.2fr",padding:"12px 14px",borderBottom:"1px solid #f1f5f9",gap:10,alignItems:"center"}}>
      <div><div style={{color:"#0f172a",fontWeight:600,fontSize:13}}>{b.grupo==="bioter"?"Grupo Bioter":b.nome}</div>{b.unidades.length>1&&<div style={{color:"#94a3b8",fontSize:10.5,marginTop:1}}>{b.unidades.length} unidades</div>}</div>
      <div style={{color:"#0f172a",fontWeight:700,fontSize:13}}>{_finFmtBRL(b.mrr)}</div>
      <div style={{color:"#475569",fontSize:12}}>{b.mesesAtivos}</div>
      <div style={{color:"#16a34a",fontWeight:700,fontSize:13}}>{_finFmtBRL(b.acumulado)}</div>
      <div style={{color:"#7c3aed",fontWeight:700,fontSize:13}}>{_finFmtBRL(b.projetada)}</div>
    </div>;})}
  </div>;
}

function FinProjecao({store,mrrAtual,proj12}){
  const proj3=mrrAtual*3,proj6=mrrAtual*6;
  const pontualPrev=(store.pontuais||[]).filter(function(p){return p.status==="aprovado"||p.status==="em_producao";}).reduce(function(s,p){return s+(p.valor||0);},0);
  const contratosRisco=(store.contratos||[]).filter(function(c){return c.statusPagamento==="atrasado";});
  const hoje=Date.now();
  const renovacao=(store.contratos||[]).filter(function(c){if(!c.dataRevisao)return false;const d=new Date(c.dataRevisao).getTime();return d>hoje&&d<hoje+90*86400000;});
  return <div style={{display:"flex",flexDirection:"column",gap:14}}>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:10}}>
      <div style={Object.assign({},_FIN_CARD,{padding:"14px 16px"})}><div style={_FIN_LBL}>Receita projetada (3 meses)</div><div style={{color:"#0f172a",fontWeight:800,fontSize:20,marginTop:4}}>{_finFmtBRL(proj3)}</div></div>
      <div style={Object.assign({},_FIN_CARD,{padding:"14px 16px"})}><div style={_FIN_LBL}>Receita projetada (6 meses)</div><div style={{color:"#0f172a",fontWeight:800,fontSize:20,marginTop:4}}>{_finFmtBRL(proj6)}</div></div>
      <div style={Object.assign({},_FIN_CARD,{padding:"14px 16px"})}><div style={_FIN_LBL}>Receita projetada (12 meses)</div><div style={{color:"#0f172a",fontWeight:800,fontSize:20,marginTop:4}}>{_finFmtBRL(proj12)}</div></div>
      <div style={Object.assign({},_FIN_CARD,{padding:"14px 16px"})}><div style={_FIN_LBL}>Receita pontual prevista</div><div style={{color:"#0f172a",fontWeight:800,fontSize:20,marginTop:4}}>{_finFmtBRL(pontualPrev)}</div></div>
    </div>
    <div style={_FIN_CARD}>
      <div style={{color:"#0f172a",fontWeight:700,fontSize:14,marginBottom:10}}>Contratos em risco</div>
      {contratosRisco.length===0&&<div style={{color:"#94a3b8",fontSize:12}}>Nenhum contrato em risco no momento.</div>}
      {contratosRisco.map(function(c){return <div key={c.id} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid #f1f5f9"}}>
        <span style={{color:"#0f172a",fontSize:13,fontWeight:600}}>{c.clienteNome}</span>
        <span style={{color:"#dc2626",fontSize:12,fontWeight:700}}>{_finFmtBRL(c.valorMensal)}/mês · pagamento atrasado</span>
      </div>;})}
    </div>
    <div style={_FIN_CARD}>
      <div style={{color:"#0f172a",fontWeight:700,fontSize:14,marginBottom:10}}>Renovação próxima (90 dias)</div>
      {renovacao.length===0&&<div style={{color:"#94a3b8",fontSize:12}}>Nenhuma renovação prevista.</div>}
      {renovacao.map(function(c){return <div key={c.id} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid #f1f5f9"}}>
        <span style={{color:"#0f172a",fontSize:13,fontWeight:600}}>{c.clienteNome}</span>
        <span style={{color:"#ca8a04",fontSize:12,fontWeight:700}}>Revisão em {_finFmtDateBR(c.dataRevisao)}</span>
      </div>;})}
    </div>
  </div>;
}

function FinStatus({store,update,canEdit}){
  const [editing,setEditing]=useState(null);
  const cobrancas=store.cobrancas||[];
  function newCob(){setEditing({id:"cb"+Date.now()+"-"+Math.random().toString(36).slice(2,5),cliente:"",valor:0,vencimento:new Date().toISOString().slice(0,10),statusPagamento:"em_aberto",tipo:"recorrente",observacoes:"",responsavelCobranca:""});}
  function saveCob(c){const exists=(store.cobrancas||[]).some(function(x){return x.id===c.id;});update(function(prev){const arr=prev.cobrancas||[];return Object.assign({},prev,{cobrancas:exists?arr.map(function(x){return x.id===c.id?c:x;}):[c].concat(arr)});});setEditing(null);}
  return <div style={{display:"flex",flexDirection:"column",gap:14}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:12,flexWrap:"wrap"}}>
      <div style={{color:"#64748b",fontSize:13}}>{cobrancas.length} cobrança{cobrancas.length!==1?"s":""}</div>
      {canEdit&&<button onClick={newCob} style={{background:"#0f172a",color:"#fff",border:"none",borderRadius:10,padding:"9px 16px",fontWeight:700,fontSize:12.5,cursor:"pointer",fontFamily:"inherit"}}>+ Nova cobrança</button>}
    </div>
    <div style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:14,overflow:"hidden"}}>
      <div style={{display:"grid",gridTemplateColumns:"2fr 1fr 1fr 1fr 1fr",padding:"12px 14px",background:"#f8fafc",borderBottom:"1px solid #e2e8f0",gap:10}}>
        {["Cliente","Valor","Vencimento","Tipo","Status"].map(function(h,i){return <div key={i} style={{color:"#64748b",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6}}>{h}</div>;})}
      </div>
      {cobrancas.length===0&&<div style={{padding:36,textAlign:"center",color:"#94a3b8",fontSize:13}}>Nenhuma cobrança registrada.</div>}
      {cobrancas.map(function(c){const stCfg=_finFindCfg(FIN_PAGAMENTO_STATUS,c.statusPagamento);return <div key={c.id} style={{display:"grid",gridTemplateColumns:"2fr 1fr 1fr 1fr 1fr",padding:"12px 14px",borderBottom:"1px solid #f1f5f9",gap:10,alignItems:"center",cursor:canEdit?"pointer":"default"}} onClick={function(){canEdit&&setEditing(c);}}>
        <div style={{color:"#0f172a",fontWeight:600,fontSize:13}}>{c.cliente||"—"}</div>
        <div style={{color:"#0f172a",fontWeight:700,fontSize:13}}>{_finFmtBRL(c.valor)}</div>
        <div style={{color:"#475569",fontSize:12}}>{_finFmtDateBR(c.vencimento)}</div>
        <div style={{color:"#64748b",fontSize:11,textTransform:"capitalize"}}>{c.tipo}</div>
        <div><span style={{background:stCfg.bg,color:stCfg.color,fontSize:10,fontWeight:700,padding:"3px 9px",borderRadius:99}}>{stCfg.label}</span></div>
      </div>;})}
    </div>
    {editing&&<FinCobrancaModal c={editing} onClose={function(){setEditing(null);}} onSave={saveCob}/>}
  </div>;
}

function FinCobrancaModal({c,onClose,onSave}){
  const [f,setF]=useState(c);const set=function(k,v){setF(Object.assign({},f,{[k]:v}));};
  return <FinModal title={c.cliente?"Editar cobrança":"Nova cobrança"} onClose={onClose}>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Cliente</div><input value={f.cliente||""} onChange={function(e){set("cliente",e.target.value);}} style={_FIN_INP} autoFocus/></div>
      <div><div style={_FIN_LBL}>Valor (R$)</div><input type="number" value={f.valor||0} onChange={function(e){set("valor",Number(e.target.value)||0);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Vencimento</div><input type="date" value={f.vencimento||""} onChange={function(e){set("vencimento",e.target.value);}} style={_FIN_INP}/></div>
      <div><div style={_FIN_LBL}>Tipo</div><select value={f.tipo||"recorrente"} onChange={function(e){set("tipo",e.target.value);}} style={_FIN_INP}><option value="recorrente">Recorrente</option><option value="pontual">Pontual</option></select></div>
      <div><div style={_FIN_LBL}>Status</div><select value={f.statusPagamento||"em_aberto"} onChange={function(e){set("statusPagamento",e.target.value);}} style={_FIN_INP}>{FIN_PAGAMENTO_STATUS.map(function(s){return <option key={s.id} value={s.id}>{s.label}</option>;})}</select></div>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Responsável pela cobrança</div><select value={f.responsavelCobranca||""} onChange={function(e){set("responsavelCobranca",e.target.value);}} style={_FIN_INP}><option value="">—</option>{(typeof TEAM!=="undefined"?TEAM:[]).map(function(u){return <option key={u.id} value={u.id}>{u.name}</option>;})}</select></div>
      <div style={{gridColumn:"span 2"}}><div style={_FIN_LBL}>Observações</div><textarea rows={3} value={f.observacoes||""} onChange={function(e){set("observacoes",e.target.value);}} style={Object.assign({},_FIN_INP,{resize:"vertical",minHeight:60})}/></div>
    </div>
    <div style={{display:"flex",justifyContent:"flex-end",gap:8,marginTop:18}}>
      <button onClick={onClose} style={{background:"#f1f5f9",color:"#64748b",border:"none",borderRadius:10,padding:"10px 18px",fontWeight:600,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>Cancelar</button>
      <button onClick={function(){onSave(f);}} style={{background:"#7c3aed",color:"#fff",border:"none",borderRadius:10,padding:"10px 22px",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>Salvar</button>
    </div>
  </FinModal>;
}


/* ═══════════════════════════════════════════════════════════════════
   PAGE GESTÃO FINANCEIRO — dashboard executivo premium da agência
   9 blocos grandes: Cabeçalho · Receita · Custos · Sócios · Resultado ·
                     Meta de margem · Contratos
═══════════════════════════════════════════════════════════════════ */

// Contratos por grupo econômico
const GF_CONTRATOS = [
  {
    grupo:"Bioter", grupoEcon:true, cor:"#166534",
    unidades:[
      {nome:"Chapecó",            valor:3000},
      {nome:"Toledo",             valor:2000},
      {nome:"Castro",             valor:2500},
      {nome:"Glória de Dourados", valor:500},
      {nome:"Uberlândia",         valor:500},
      {nome:"Paraguay",           valor:0},
    ],
  },
  {grupo:"Construschorr",        cor:"#dc2626", valor:4000},
  {grupo:"Arabutã Pré-Moldados", cor:"#d97706", valor:4500},
  {grupo:"Climaves",             cor:"#0284c7", valor:2500},
];

// Custo Fixo — agrupado por categoria
const GF_CUSTO_FIXO = {
  Contabilidade: [
    {label:"Contabilidade", valor:430},
  ],
  "Pró-labore": [
    {label:"Pró-labore Gustavo",  valor:2225},
    {label:"Pró-labore Vinicius", valor:2225},
    {label:"INSS pró-labore",     valor:550},
  ],
  "Softwares e licenças": [
    {label:"Canva",                valor:47},
    {label:"Adobe",                valor:189},
    {label:"Google Workspace",     valor:81.80},
    {label:"Google Workspace pixels", valor:81.80},
    {label:"Asana",                valor:120},
    {label:"Lovable",              valor:150},
    {label:"ChatGPT",              valor:110},
    {label:"Anthropic + IOF",      valor:50},
    {label:"Claude AI + IOF",      valor:600},
  ],
  Treinamentos: [
    {label:"Hotmart / Sobral",     valor:113.86},
  ],
};

// Custo de Servir — só áreas de valor fixo mensal (Estratégia + Gestão de mídia).
// Design e Edição de vídeo agora são calculados por demanda via FreelancerPaymentsBlock.
const GF_CUSTO_SERVIR = {
  "Estratégia":        [{label:"Hellen Benning",     valor:2500}],
  "Gestão de mídia":   [{label:"Erick Soares",       valor:2400}],
};

// Impostos
const GF_IMPOSTOS_VALOR = 1500;

// Sócios — pró-labore (já dentro do custo fixo) + distribuição de lucros (separada)
const GF_SOCIOS = {
  prolabore: [
    {nome:"Gustavo",  valor:2225},
    {nome:"Vinicius", valor:2225},
  ],
  lucros: [
    {nome:"Gustavo",  valor:2775},
    {nome:"Vinicius", valor:2775},
  ],
};

// Reserva de caixa — 10% do MRR vai pra RDB Nubank (caixinhas)
const GF_RESERVA_CAIXA_PCT = 0.10;

// Meta de margem (configurável)
const GF_META_MARGEM_PCT = 0.50;

function PageGestaoFinanceiro({isMob,tasks,setTasks}){
  const [payMonth,setPayMonth]=useState(function(){const d=new Date();return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0");});
  const [contratosExpand,setContratosExpand]=useState({Bioter:true});
  const _brl=function(n){return "R$ "+Number(n||0).toLocaleString("pt-BR",{minimumFractionDigits:0,maximumFractionDigits:0});};
  const _brlF=function(n){return "R$ "+Number(n||0).toLocaleString("pt-BR",{minimumFractionDigits:2,maximumFractionDigits:2});};
  const _pct=function(n){return Number(n||0).toLocaleString("pt-BR",{minimumFractionDigits:2,maximumFractionDigits:2})+"%";};

  // ── Cálculos ──
  const flatContratos=GF_CONTRATOS.flatMap(function(c){
    if(c.unidades)return c.unidades.map(function(u){return {grupo:c.grupo,valor:u.valor};});
    return [{grupo:c.grupo,valor:c.valor}];
  });
  const ativos=flatContratos.filter(function(x){return x.valor>0;});
  const mrr=ativos.reduce(function(s,x){return s+x.valor;},0);
  const projecao12m=mrr*12;
  const unidadesFaturadas=ativos.length;
  const clientesAtivos=GF_CONTRATOS.length;
  const ticketCliente=clientesAtivos>0?mrr/clientesAtivos:0;
  const ticketUnidade=unidadesFaturadas>0?mrr/unidadesFaturadas:0;

  // Custos
  const sumGroup=function(g){return Object.values(g).reduce(function(s,arr){return s+arr.reduce(function(t,it){return t+it.valor;},0);},0);};
  const custoFixoTotal=sumGroup(GF_CUSTO_FIXO);
  const custoServirFixoTotal=sumGroup(GF_CUSTO_SERVIR);
  // Total dinâmico dos freelancers (pagos por demanda) no payMonth
  const freelancersTotal=(typeof TEAM!=="undefined"?TEAM:[]).filter(function(u){return u.pagamentoPorDemanda;}).reduce(function(s,u){
    const c=(typeof calcDesignerPayments==="function")?calcDesignerPayments(tasks||[],u.id,payMonth):{total:0};
    return s+(c.total||0);
  },0);
  const custoServirTotal=custoServirFixoTotal+freelancersTotal;
  const custoOperacional=custoFixoTotal+custoServirTotal;

  // Impostos
  const imposto=GF_IMPOSTOS_VALOR;
  const impostoPctAtual=mrr>0?imposto/mrr:0;

  // Reserva de caixa (10% do MRR → RDB Nubank / caixinhas)
  const reservaCaixa=mrr*GF_RESERVA_CAIXA_PCT;

  // Sócios
  const prolaboreTotal=GF_SOCIOS.prolabore.reduce(function(s,p){return s+p.valor;},0);
  const lucrosTotal=GF_SOCIOS.lucros.reduce(function(s,p){return s+p.valor;},0);

  // Resultado operacional (já descontando reserva de caixa)
  const resultadoOp=mrr-imposto-custoServirTotal-custoFixoTotal-reservaCaixa;
  const margemAntesImpostos=mrr>0?(mrr-custoServirTotal-custoFixoTotal)/mrr:0;
  const margemApos=mrr>0?resultadoOp/mrr:0;

  // Meta de margem (50%) — solve for receita necessária
  // (R - R*i - CS - CF - R*reserva) / R = 0.5
  // 1 - i - reserva - (CS+CF)/R = 0.5
  // (CS+CF)/R = 0.5 - i - reserva
  // R = (CS+CF) / (0.5 - i - reserva)
  // OBS: i é constante atual; reserva é porcentagem fixa
  const denomMeta=1-GF_META_MARGEM_PCT-impostoPctAtual-GF_RESERVA_CAIXA_PCT; // 1 - 0.5 - 0.0769 - 0.10 = 0.3231
  const mrrNecessario=denomMeta>0?(custoFixoTotal+custoServirTotal)/denomMeta:0;
  const faltaVender=mrrNecessario-mrr;
  const gapMargem=(GF_META_MARGEM_PCT-margemApos)*100;
  const clientesAdic=ticketCliente>0?Math.ceil(faltaVender/ticketCliente):0;

  // ── Helpers visuais ──
  const Block=function(props){
    return <section style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:14,padding:"14px 18px",display:"flex",flexDirection:"column",gap:10,...(props.style||{})}}>
      {props.children}
    </section>;
  };
  const BlockHeader=function(props){
    return <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:10,flexWrap:"wrap"}}>
      <div style={{display:"flex",alignItems:"center",gap:10}}>
        {props.ico&&<div style={{width:34,height:34,borderRadius:9,background:props.color+"15",display:"flex",alignItems:"center",justifyContent:"center"}}>
          <Ico n={props.ico} size={17} color={props.color}/>
        </div>}
        <div>
          <div style={{color:"#0f172a",fontWeight:800,fontSize:15,letterSpacing:-.2}}>{props.title}</div>
          {props.subtitle&&<div style={{color:"#64748b",fontSize:11.5,marginTop:1}}>{props.subtitle}</div>}
        </div>
      </div>
      {props.right}
    </div>;
  };
  // Big stat (usado em vários lugares)
  const BigStat=function(props){
    return <div style={{display:"flex",flexDirection:"column",gap:3,...(props.style||{})}}>
      <div style={{color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>{props.label}</div>
      <div style={{color:props.color||"#0f172a",fontWeight:800,fontSize:props.size||22,letterSpacing:-.6,fontFeatureSettings:"'tnum'",lineHeight:1.15}}>{props.value}</div>
      {props.hint&&<div style={{color:"#94a3b8",fontSize:10.5}}>{props.hint}</div>}
    </div>;
  };

  return <div style={{display:"flex",flexDirection:"column",gap:12,fontFamily:"'Inter',system-ui,sans-serif",width:"100%"}}>

    {/* Header simples */}
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:12,flexWrap:"wrap"}}>
      <div style={{display:"flex",alignItems:"center",gap:11}}>
        <div style={{width:42,height:42,borderRadius:11,background:"#16a34a15",display:"flex",alignItems:"center",justifyContent:"center"}}>
          <Ico n="wallet" size={22} color="#16a34a"/>
        </div>
        <div>
          <div style={{color:"#0f172a",fontWeight:800,fontSize:22,letterSpacing:-.5}}>Financeiro</div>
          <div style={{color:"#64748b",fontSize:13,marginTop:2}}>Visão executiva da saúde financeira da Pixels.</div>
        </div>
      </div>
    </div>

    {/* ════ 1. CABEÇALHO EXECUTIVO — bloco grande com KPIs principais ════ */}
    <div style={{background:"linear-gradient(135deg,#0f172a,#1e293b)",borderRadius:18,padding:"26px 30px",color:"#fff",boxShadow:"0 12px 36px rgba(15,23,42,0.25)"}}>
      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:14,flexWrap:"wrap",marginBottom:22}}>
        <div>
          <div style={{fontSize:11,fontWeight:700,letterSpacing:.7,textTransform:"uppercase",opacity:.7,marginBottom:6}}>MRR atual</div>
          <div style={{fontSize:42,fontWeight:800,letterSpacing:-1.4,lineHeight:1,fontFeatureSettings:"'tnum'"}}>{_brl(mrr)}<span style={{fontSize:15,fontWeight:600,opacity:.7,marginLeft:8}}>/mês</span></div>
          <div style={{fontSize:13,opacity:.75,marginTop:8}}>Receita projetada em 12 meses: <strong style={{opacity:1}}>{_brl(projecao12m)}</strong></div>
        </div>
        <div style={{display:"flex",alignItems:"flex-end",gap:6}}>
          <span style={{background:margemApos>=GF_META_MARGEM_PCT?"#22c55e22":"#fbbf2422",color:margemApos>=GF_META_MARGEM_PCT?"#86efac":"#fde047",borderRadius:99,padding:"5px 14px",fontSize:11,fontWeight:800,letterSpacing:.3,textTransform:"uppercase",border:"1px solid "+(margemApos>=GF_META_MARGEM_PCT?"#22c55e44":"#fbbf2444")}}>
            Margem {_pct(margemApos*100)}
          </span>
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr 1fr":"repeat(2,1fr)",gap:18,paddingTop:18,borderTop:"1px solid rgba(255,255,255,0.1)"}}>
        <BigStat label="Clientes ativos" value={clientesAtivos}      size={22} color="#fff" style={{color:"#fff"}}/>
        <BigStat label="Ticket médio"    value={_brl(ticketCliente)} size={22} color="#fff" style={{color:"#fff"}}/>
      </div>
    </div>

    {/* ════ 2. RECEITA E CARTEIRA ════ */}
    <Block>
      <BlockHeader ico="chart" color="#16a34a" title="Receita e carteira" subtitle="Recorrência, projeção e qualidade do faturamento"/>
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr 1fr":"repeat(3,1fr)",gap:14}}>
        <BigStat label="MRR atual"       value={_brl(mrr)}        color="#16a34a"/>
        <BigStat label="Receita do mês"  value={_brl(mrr)}        color="#0d9488"/>
        <BigStat label="Projeção 12m"    value={_brl(projecao12m)} color="#7c3aed"/>
      </div>
    </Block>

    {/* ════ 3. CUSTO FIXO / ESTRUTURA ════ */}
    <Block>
      <BlockHeader ico="layers" color="#475569" title="Custo fixo / Estrutura" subtitle="Despesas que não variam com o número de clientes"
        right={<div style={{textAlign:"right"}}>
          <div style={{color:"#475569",fontWeight:800,fontSize:22,fontFeatureSettings:"'tnum'",letterSpacing:-.4}}>{_brlF(custoFixoTotal)}</div>
          <div style={{color:"#94a3b8",fontSize:11}}>{_brlF(custoFixoTotal/clientesAtivos)} por cliente</div>
        </div>}/>
      <div style={{display:"flex",flexDirection:"column"}}>
        {Object.entries(GF_CUSTO_FIXO).map(function(arr,idx){
          const [cat,items]=arr;
          const subtotal=items.reduce(function(s,it){return s+it.valor;},0);
          return <div key={cat} style={{marginTop:idx===0?0:18}}>
            {/* Cabeçalho discreto da categoria */}
            <div style={{display:"flex",alignItems:"baseline",justifyContent:"space-between",gap:8,marginBottom:6,paddingBottom:4,borderBottom:"1px solid #f1f5f9"}}>
              <div style={{color:"#475569",fontWeight:700,fontSize:10.5,letterSpacing:.5,textTransform:"uppercase"}}>{cat}</div>
              <div style={{color:"#94a3b8",fontWeight:600,fontSize:11,fontFeatureSettings:"'tnum'"}}>{_brlF(subtotal)}</div>
            </div>
            {/* Linhas plain — 2 colunas em desktop */}
            <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"1fr 1fr",columnGap:32,rowGap:0}}>
              {items.map(function(it,i){
                return <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",padding:"5px 0",borderBottom:i<items.length-1?"1px dashed #f1f5f9":"none"}}>
                  <span style={{color:"#475569",fontSize:12.5,fontWeight:500}}>{it.label}</span>
                  <span style={{color:"#0f172a",fontSize:12.5,fontWeight:600,fontFeatureSettings:"'tnum'"}}>{_brlF(it.valor)}</span>
                </div>;
              })}
            </div>
          </div>;
        })}
      </div>
    </Block>

    {/* ════ 4. CUSTO DE SERVIR (valor fixo: Estratégia + Gestão de mídia) ════ */}
    <Block>
      <BlockHeader ico="users" color="#0891b2" title="Custo de servir (fixo)" subtitle="Áreas com pagamento mensal fixo"
        right={<div style={{textAlign:"right"}}>
          <div style={{color:"#0891b2",fontWeight:800,fontSize:22,fontFeatureSettings:"'tnum'",letterSpacing:-.4}}>{_brlF(custoServirFixoTotal)}</div>
          <div style={{color:"#94a3b8",fontSize:11}}>{_brlF(custoServirFixoTotal/clientesAtivos)} por cliente</div>
        </div>}/>
      <div style={{display:"flex",flexDirection:"column"}}>
        {Object.entries(GF_CUSTO_SERVIR).map(function(arr,idx){
          const [area,items]=arr;
          const subtotal=items.reduce(function(s,it){return s+it.valor;},0);
          return <div key={area} style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",padding:"7px 0",borderBottom:idx<Object.keys(GF_CUSTO_SERVIR).length-1?"1px dashed #f1f5f9":"none"}}>
            <div style={{display:"flex",flexDirection:"column",gap:2}}>
              <span style={{color:"#0891b2",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5}}>{area}</span>
              <span style={{color:"#475569",fontSize:12.5,fontWeight:500}}>{items.map(function(i){return i.label;}).join(", ")}</span>
            </div>
            <span style={{color:"#0f172a",fontSize:13,fontWeight:700,fontFeatureSettings:"'tnum'"}}>{_brlF(subtotal)}</span>
          </div>;
        })}
      </div>
    </Block>

    {/* ════ 4b. PAGAMENTOS POR DEMANDA — Design + Edição de vídeo (cálculo auto) ════ */}
    <Block>
      <FreelancerPaymentsBlock tasks={tasks||[]} setTasks={setTasks} refMonth={payMonth} onChangeMonth={setPayMonth} isMob={isMob}/>
    </Block>

    {/* ════ 4c. TABELA DE PREÇOS POR TIPO DE CONTEÚDO (referência pros sócios) ════ */}
    <Block>
      <BlockHeader ico="dollar" color="#7c3aed" title="Tabela de preços por tipo de conteúdo" subtitle="Valor pago por demanda aprovada — referência única do que vai no cálculo dos freelancers"/>
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr 1fr":"repeat(auto-fill,minmax(180px,1fr))",gap:8}}>
        {[
          {label:"Arte única",       sub:"feed + story",        valor:(typeof DESIGNER_PRICES!=="undefined")?DESIGNER_PRICES.arte:30,           area:"Design"},
          {label:"Carrossel",        sub:"feed + story",        valor:(typeof DESIGNER_PRICES!=="undefined")?DESIGNER_PRICES.carrossel:45,      area:"Design"},
          {label:"Folder",           sub:"PDF / impresso",      valor:(typeof DESIGNER_PRICES!=="undefined")?DESIGNER_PRICES.folder:30,         area:"Design"},
          {label:"Foto de obra",     sub:"ajuste de template",  valor:(typeof DESIGNER_PRICES!=="undefined")?DESIGNER_PRICES.fotoObra:20,       area:"Design"},
          {label:"Vídeo",            sub:"edição padrão",       valor:(typeof DESIGNER_PRICES!=="undefined")?DESIGNER_PRICES.video:100,         area:"Edição"},
          {label:"Vídeo dinâmico",   sub:"motion / complexo",   valor:(typeof DESIGNER_PRICES!=="undefined")?DESIGNER_PRICES.videoComplexo:150, area:"Edição"},
          {label:"Vídeo básico",   sub:"vídeo curto / loop",  valor:(typeof DESIGNER_PRICES!=="undefined")?DESIGNER_PRICES.videoFeira:50,     area:"Edição"},
          {label:"Corte de vídeo",   sub:"shorts / reels",      valor:(typeof DESIGNER_PRICES!=="undefined")?DESIGNER_PRICES.corte:20,          area:"Edição"},
        ].map(function(t,i){
          const isDesign = t.area==="Design";
          const accent = isDesign?"#ec4899":"#0ea5e9";
          return <div key={i} style={{background:"#fafbfc",border:"1px solid #f1f5f9",borderRadius:9,padding:"10px 12px",display:"flex",flexDirection:"column",gap:3,position:"relative"}}>
            <span style={{background:accent+"14",color:accent,fontSize:9,fontWeight:700,padding:"2px 7px",borderRadius:5,letterSpacing:.4,textTransform:"uppercase",alignSelf:"flex-start"}}>{t.area}</span>
            <div style={{color:"#0f172a",fontSize:12.5,fontWeight:700,marginTop:3,letterSpacing:-.1}}>{t.label}</div>
            <div style={{color:"#94a3b8",fontSize:10.5,fontWeight:500}}>{t.sub}</div>
            <div style={{color:"#0f172a",fontSize:17,fontWeight:800,fontFeatureSettings:"'tnum'",letterSpacing:-.4,marginTop:4}}>{_brl(t.valor)}<span style={{color:"#94a3b8",fontSize:10,fontWeight:600,marginLeft:3}}>/demanda</span></div>
          </div>;
        })}
      </div>
      <div style={{color:"#94a3b8",fontSize:11,marginTop:8,lineHeight:1.5}}>Valores referenciados em <code style={{background:"#f1f5f9",padding:"1px 6px",borderRadius:4,fontSize:10,color:"#475569"}}>DESIGNER_PRICES</code> (00_globals.jsx). Ajuste lá pra atualizar o cálculo dos freelancers e esta tabela automaticamente.</div>
    </Block>

    {/* ════ 5. CUSTO OPERACIONAL TOTAL — destacado com custo por cliente ════ */}
    <div style={{background:"linear-gradient(135deg,#0f172a,#1e293b 60%,#334155)",borderRadius:14,padding:"18px 22px",color:"#fff",position:"relative",overflow:"hidden"}}>
      {/* Decoração: anel atrás */}
      <div style={{position:"absolute",top:-40,right:-40,width:180,height:180,borderRadius:"50%",background:"radial-gradient(circle at 30% 30%,rgba(159,67,246,0.25),transparent 70%)",pointerEvents:"none"}}/>
      <div style={{position:"relative",display:"grid",gridTemplateColumns:isMob?"1fr 1fr":"2fr 1fr 1fr 1fr",gap:20,alignItems:"center"}}>
        {/* Total */}
        <div>
          <div style={{fontSize:10.5,fontWeight:700,letterSpacing:.6,textTransform:"uppercase",opacity:.7}}>Custo operacional total</div>
          <div style={{fontSize:32,fontWeight:900,letterSpacing:-1,lineHeight:1.05,fontFeatureSettings:"'tnum'",marginTop:4}}>{_brlF(custoOperacional)}<span style={{fontSize:13,fontWeight:600,opacity:.6,marginLeft:6}}>/mês</span></div>
          <div style={{fontSize:11,opacity:.65,marginTop:6,letterSpacing:.1}}>{_brlF(custoFixoTotal)} fixo + {_brlF(custoServirTotal)} servir</div>
        </div>
        {/* Por cliente */}
        <div style={{background:"rgba(255,255,255,0.06)",borderRadius:10,padding:"10px 12px",border:"1px solid rgba(255,255,255,0.08)"}}>
          <div style={{fontSize:9.5,fontWeight:700,letterSpacing:.5,textTransform:"uppercase",opacity:.6}}>Custo por cliente</div>
          <div style={{fontSize:18,fontWeight:800,fontFeatureSettings:"'tnum'",letterSpacing:-.4,marginTop:3}}>{_brlF(custoOperacional/clientesAtivos)}</div>
          <div style={{fontSize:10,opacity:.55,marginTop:3}}>fixo + servir ÷ {clientesAtivos}</div>
        </div>
        {/* % receita */}
        <div style={{background:"rgba(255,255,255,0.06)",borderRadius:10,padding:"10px 12px",border:"1px solid rgba(255,255,255,0.08)"}}>
          <div style={{fontSize:9.5,fontWeight:700,letterSpacing:.5,textTransform:"uppercase",opacity:.6}}>% da receita</div>
          <div style={{fontSize:18,fontWeight:800,fontFeatureSettings:"'tnum'",letterSpacing:-.4,marginTop:3,color:mrr>0&&(custoOperacional/mrr)>0.7?"#fecaca":"#fff"}}>{mrr>0?_pct((custoOperacional/mrr)*100):"—"}</div>
          <div style={{fontSize:10,opacity:.55,marginTop:3}}>do MRR</div>
        </div>
        {/* Reserva sobrando */}
        <div style={{background:"rgba(255,255,255,0.06)",borderRadius:10,padding:"10px 12px",border:"1px solid rgba(255,255,255,0.08)"}}>
          <div style={{fontSize:9.5,fontWeight:700,letterSpacing:.5,textTransform:"uppercase",opacity:.6}}>Sobra mensal</div>
          <div style={{fontSize:18,fontWeight:800,fontFeatureSettings:"'tnum'",letterSpacing:-.4,marginTop:3,color:(mrr-custoOperacional)>=0?"#86efac":"#fca5a5"}}>{_brlF(mrr-custoOperacional)}</div>
          <div style={{fontSize:10,opacity:.55,marginTop:3}}>antes de impostos</div>
        </div>
      </div>
    </div>

    {/* ════ 6. SÓCIOS, IMPOSTOS, RESERVA E RETIRADAS ════ */}
    <Block>
      <BlockHeader ico="users" color="#7c3aed" title="Sócios, impostos e reservas" subtitle="Pró-labore (custo fixo) · Lucros (separada) · Impostos · Reserva de caixa 10%"/>
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"repeat(4,1fr)",gap:12}}>
        {/* A) Pró-labore */}
        <div style={{background:"#faf5ff",border:"1px solid #e9d5ff",borderRadius:10,padding:"14px 16px"}}>
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10}}>
            <div style={{width:6,height:18,borderRadius:3,background:"#7c3aed"}}/>
            <div style={{color:"#0f172a",fontWeight:800,fontSize:12.5}}>A · Pró-labore</div>
            <span style={{background:"#ede9fe",color:"#7c3aed",fontSize:9,fontWeight:700,padding:"2px 7px",borderRadius:99,letterSpacing:.3,textTransform:"uppercase",marginLeft:"auto"}}>Custo fixo</span>
          </div>
          {GF_SOCIOS.prolabore.map(function(p,i){
            return <div key={i} style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:5}}>
              <span style={{color:"#475569"}}>{p.nome}</span>
              <span style={{color:"#0f172a",fontWeight:700,fontFeatureSettings:"'tnum'"}}>{_brlF(p.valor)}</span>
            </div>;
          })}
          <div style={{display:"flex",justifyContent:"space-between",fontSize:13,marginTop:8,paddingTop:8,borderTop:"1px solid #e9d5ff"}}>
            <span style={{color:"#0f172a",fontWeight:700}}>Total</span>
            <span style={{color:"#7c3aed",fontWeight:800,fontFeatureSettings:"'tnum'"}}>{_brlF(prolaboreTotal)}</span>
          </div>
        </div>
        {/* B) Distribuição de lucros */}
        <div style={{background:"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:10,padding:"14px 16px"}}>
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10}}>
            <div style={{width:6,height:18,borderRadius:3,background:"#16a34a"}}/>
            <div style={{color:"#0f172a",fontWeight:800,fontSize:12.5}}>B · Distribuição de lucros</div>
            <span style={{background:"#dcfce7",color:"#15803d",fontSize:9,fontWeight:700,padding:"2px 7px",borderRadius:99,letterSpacing:.3,textTransform:"uppercase",marginLeft:"auto"}}>Separado</span>
          </div>
          {GF_SOCIOS.lucros.map(function(p,i){
            return <div key={i} style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:5}}>
              <span style={{color:"#475569"}}>{p.nome}</span>
              <span style={{color:"#0f172a",fontWeight:700,fontFeatureSettings:"'tnum'"}}>{_brlF(p.valor)}</span>
            </div>;
          })}
          <div style={{display:"flex",justifyContent:"space-between",fontSize:13,marginTop:8,paddingTop:8,borderTop:"1px solid #bbf7d0"}}>
            <span style={{color:"#0f172a",fontWeight:700}}>Total</span>
            <span style={{color:"#16a34a",fontWeight:800,fontFeatureSettings:"'tnum'"}}>{_brlF(lucrosTotal)}</span>
          </div>
        </div>
        {/* C) Impostos */}
        <div style={{background:"#fef2f2",border:"1px solid #fecaca",borderRadius:10,padding:"14px 16px"}}>
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10}}>
            <div style={{width:6,height:18,borderRadius:3,background:"#dc2626"}}/>
            <div style={{color:"#0f172a",fontWeight:800,fontSize:12.5}}>C · Impostos</div>
            <span style={{background:"#fee2e2",color:"#b91c1c",fontSize:9,fontWeight:700,padding:"2px 7px",borderRadius:99,letterSpacing:.3,textTransform:"uppercase",marginLeft:"auto"}}>{_pct(impostoPctAtual*100)} da receita</span>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:5}}>
            <span style={{color:"#475569"}}>Simples Nacional / ISS</span>
            <span style={{color:"#0f172a",fontWeight:700,fontFeatureSettings:"'tnum'"}}>{_brlF(imposto)}</span>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:13,marginTop:8,paddingTop:8,borderTop:"1px solid #fecaca"}}>
            <span style={{color:"#0f172a",fontWeight:700}}>Total</span>
            <span style={{color:"#dc2626",fontWeight:800,fontFeatureSettings:"'tnum'"}}>{_brlF(imposto)}</span>
          </div>
        </div>
        {/* D) Reserva de caixa */}
        <div style={{background:"#eff6ff",border:"1px solid #bfdbfe",borderRadius:10,padding:"14px 16px"}}>
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10}}>
            <div style={{width:6,height:18,borderRadius:3,background:"#2563eb"}}/>
            <div style={{color:"#0f172a",fontWeight:800,fontSize:12.5}}>D · Reserva de caixa</div>
            <span style={{background:"#dbeafe",color:"#1d4ed8",fontSize:9,fontWeight:700,padding:"2px 7px",borderRadius:99,letterSpacing:.3,textTransform:"uppercase",marginLeft:"auto"}}>{_pct(GF_RESERVA_CAIXA_PCT*100)} da receita</span>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:5}}>
            <span style={{color:"#475569"}}>RDB Nubank · caixinhas</span>
            <span style={{color:"#0f172a",fontWeight:700,fontFeatureSettings:"'tnum'"}}>{_brlF(reservaCaixa)}</span>
          </div>
          <div style={{color:"#64748b",fontSize:10.5,marginTop:6,marginBottom:2}}>Acumula 12m: <strong style={{color:"#0f172a"}}>{_brl(reservaCaixa*12)}</strong></div>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:13,marginTop:6,paddingTop:8,borderTop:"1px solid #bfdbfe"}}>
            <span style={{color:"#0f172a",fontWeight:700}}>Total</span>
            <span style={{color:"#2563eb",fontWeight:800,fontFeatureSettings:"'tnum'"}}>{_brlF(reservaCaixa)}</span>
          </div>
        </div>
      </div>
    </Block>

    {/* ════ 7. RESULTADO OPERACIONAL ════ */}
    <Block>
      <BlockHeader ico="funnel" color="#0d9488" title="Resultado operacional" subtitle="Receita − impostos − custos − reserva de caixa = sobra para sócios"/>
      <div style={{display:"flex",flexDirection:"column",gap:0}}>
        {[
          {label:"Receita total",     v:mrr,             op:"",  cor:"#16a34a"},
          {label:"Impostos",          v:imposto,         op:"−", cor:"#dc2626"},
          {label:"Custo de servir",   v:custoServirTotal,op:"−", cor:"#0891b2"},
          {label:"Custo fixo",        v:custoFixoTotal,  op:"−", cor:"#475569"},
          {label:"Reserva de caixa",  v:reservaCaixa,    op:"−", cor:"#2563eb"},
        ].map(function(r,i){
          return <div key={i} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid #f1f5f9"}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <span style={{color:r.cor,fontWeight:800,fontSize:18,width:18}}>{r.op||""}</span>
              <span style={{color:"#0f172a",fontSize:13,fontWeight:600}}>{r.label}</span>
            </div>
            <span style={{color:"#0f172a",fontWeight:700,fontSize:14,fontFeatureSettings:"'tnum'"}}>{_brlF(r.v)}</span>
          </div>;
        })}
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 0 6px",background:"linear-gradient(90deg,transparent,#f0fdf4,transparent)",borderRadius:9,paddingLeft:10,paddingRight:10,marginTop:6}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <span style={{color:"#16a34a",fontWeight:800,fontSize:18,width:18}}>=</span>
            <span style={{color:"#0f172a",fontSize:14,fontWeight:800,letterSpacing:-.2}}>Resultado operacional</span>
          </div>
          <span style={{color:resultadoOp>=0?"#15803d":"#b91c1c",fontWeight:800,fontSize:22,fontFeatureSettings:"'tnum'",letterSpacing:-.5}}>{_brlF(resultadoOp)}</span>
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginTop:4}}>
        <div style={{background:"#fafbfc",borderRadius:9,padding:"10px 14px"}}>
          <div style={{color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.4}}>Margem antes de impostos</div>
          <div style={{color:"#0f172a",fontWeight:800,fontSize:18,fontFeatureSettings:"'tnum'",marginTop:2}}>{_pct(margemAntesImpostos*100)}</div>
        </div>
        <div style={{background:"#fafbfc",borderRadius:9,padding:"10px 14px"}}>
          <div style={{color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.4}}>Margem após impostos</div>
          <div style={{color:"#0f172a",fontWeight:800,fontSize:18,fontFeatureSettings:"'tnum'",marginTop:2}}>{_pct(margemApos*100)}</div>
        </div>
      </div>
    </Block>

    {/* ════ 8. META DE MARGEM 50% — bloco destaque clean ════ */}
    <section style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:14,padding:"22px 26px",display:"flex",flexDirection:"column",gap:20,position:"relative",overflow:"hidden"}}>
      {/* Acento sutil no canto */}
      <div style={{position:"absolute",top:-40,right:-40,width:180,height:180,borderRadius:"50%",background:"radial-gradient(circle,#ede9fe,transparent 70%)",pointerEvents:"none"}}/>

      {/* Header */}
      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:14,flexWrap:"wrap",position:"relative"}}>
        <div style={{display:"flex",alignItems:"center",gap:11}}>
          <div style={{width:38,height:38,borderRadius:10,background:"linear-gradient(135deg,#7c3aed,#a855f7)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 12px rgba(124,58,237,0.25)"}}>
            <Ico n="sparkles" size={18} color="#fff"/>
          </div>
          <div>
            <div style={{color:"#0f172a",fontWeight:800,fontSize:15,letterSpacing:-.2}}>Meta de margem 50%</div>
            <div style={{color:"#64748b",fontSize:11.5,marginTop:1}}>Quanto faturar pra chegar lá sem mexer nos custos atuais</div>
          </div>
        </div>
        <span style={{background:margemApos>=GF_META_MARGEM_PCT?"#dcfce7":"#fef3c7",color:margemApos>=GF_META_MARGEM_PCT?"#15803d":"#a16207",padding:"5px 12px",borderRadius:99,fontSize:10.5,fontWeight:800,letterSpacing:.4,textTransform:"uppercase",border:"1px solid "+(margemApos>=GF_META_MARGEM_PCT?"#86efac":"#fde047")}}>
          {margemApos>=GF_META_MARGEM_PCT?"Meta batida":"Em construção"}
        </span>
      </div>

      {/* Visualização principal: Atual vs Meta */}
      <div style={{display:"flex",alignItems:"flex-end",gap:18,padding:"14px 4px 0",position:"relative"}}>
        <div style={{flex:1}}>
          <div style={{color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>Margem atual</div>
          <div style={{color:"#7c3aed",fontWeight:800,fontSize:36,letterSpacing:-1.2,lineHeight:1,fontFeatureSettings:"'tnum'"}}>{_pct(margemApos*100)}</div>
        </div>
        <div style={{flex:"0 0 auto",display:"flex",alignItems:"center",gap:6,paddingBottom:8}}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#cbd5e1" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>
        </div>
        <div style={{flex:1,textAlign:"right"}}>
          <div style={{color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>Meta</div>
          <div style={{color:"#0f172a",fontWeight:800,fontSize:36,letterSpacing:-1.2,lineHeight:1,fontFeatureSettings:"'tnum'"}}>{_pct(GF_META_MARGEM_PCT*100)}</div>
        </div>
      </div>

      {/* Barra de progresso elegante */}
      <div style={{position:"relative"}}>
        <div style={{background:"#f1f5f9",borderRadius:99,height:8,overflow:"hidden"}}>
          <div style={{width:Math.min(100,Math.max(2,(margemApos/GF_META_MARGEM_PCT)*100))+"%",height:"100%",background:"linear-gradient(90deg,#a855f7,#7c3aed)",borderRadius:99,transition:"width .3s",boxShadow:"0 1px 4px rgba(124,58,237,0.4)"}}/>
        </div>
        <div style={{display:"flex",justifyContent:"space-between",marginTop:6,fontSize:10.5,color:"#94a3b8",fontWeight:600}}>
          <span>{Math.round((margemApos/GF_META_MARGEM_PCT)*100)}% do caminho</span>
          <span>Gap: <strong style={{color:"#7c3aed"}}>{gapMargem.toFixed(1)} pp</strong></span>
        </div>
      </div>

      {/* 3 KPIs em cards limpos */}
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"repeat(3,1fr)",gap:12,position:"relative"}}>
        <div style={{background:"#fafbfc",border:"1px solid #f1f5f9",borderRadius:11,padding:"14px 16px"}}>
          <div style={{color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>MRR necessário</div>
          <div style={{color:"#0f172a",fontWeight:800,fontSize:22,letterSpacing:-.5,fontFeatureSettings:"'tnum'",lineHeight:1.1}}>{_brl(mrrNecessario)}</div>
          <div style={{color:"#64748b",fontSize:10.5,marginTop:3}}>por mês</div>
        </div>
        <div style={{background:"#fafbfc",border:"1px solid #f1f5f9",borderRadius:11,padding:"14px 16px"}}>
          <div style={{color:"#94a3b8",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>Falta vender</div>
          <div style={{color:"#7c3aed",fontWeight:800,fontSize:22,letterSpacing:-.5,fontFeatureSettings:"'tnum'",lineHeight:1.1}}>{_brl(faltaVender)}</div>
          <div style={{color:"#64748b",fontSize:10.5,marginTop:3}}>por mês</div>
        </div>
        <div style={{background:"linear-gradient(135deg,#faf5ff,#f3e8ff)",border:"1px solid #e9d5ff",borderRadius:11,padding:"14px 16px"}}>
          <div style={{color:"#7c3aed",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5,marginBottom:4,display:"flex",alignItems:"center",gap:5}}>
            <Ico n="users" size={11} color="#7c3aed"/> Clientes a vender
          </div>
          <div style={{color:"#7c3aed",fontWeight:800,fontSize:22,letterSpacing:-.5,fontFeatureSettings:"'tnum'",lineHeight:1.1}}>+{clientesAdic}</div>
          <div style={{color:"#64748b",fontSize:10.5,marginTop:3}}>ticket médio {_brl(ticketCliente)}</div>
        </div>
      </div>
    </section>

    {/* ════ 9. CONTRATOS ATIVOS — cards grandes coloridos com logo ════ */}
    <Block>
      <BlockHeader ico="fileText" color="#475569" title="Contratos ativos" subtitle={clientesAtivos+" clientes · MRR consolidado "+_brl(mrr)}/>
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"repeat(auto-fill,minmax(280px,1fr))",gap:12}}>
        {GF_CONTRATOS.map(function(c,idx){
          // Resolve cliente real pra pegar logo
          const clKey=(c.grupo||"").toLowerCase().split(" ")[0];
          const realCl=(typeof CLIENTS!=="undefined"?CLIENTS:[]).find(function(x){return x.id===clKey||(x.name||"").toLowerCase().startsWith(clKey);});
          const logoUrl=realCl&&typeof CLIENT_LOGOS!=="undefined"?CLIENT_LOGOS[realCl.id]:null;

          if(c.grupoEcon&&c.unidades){
            const totalGrupo=c.unidades.reduce(function(s,u){return s+u.valor;},0);
            const ativosGrupo=c.unidades.filter(function(u){return u.valor>0;}).length;
            const expanded=contratosExpand[c.grupo]!==false;
            return <div key={idx} style={{background:"linear-gradient(135deg,"+c.cor+"06,"+c.cor+"12)",border:"1px solid "+c.cor+"33",borderRadius:14,overflow:"hidden",display:"flex",flexDirection:"column",transition:"transform .15s, box-shadow .15s"}}
              onMouseEnter={function(e){e.currentTarget.style.transform="translateY(-1px)";e.currentTarget.style.boxShadow="0 6px 20px "+c.cor+"22";}}
              onMouseLeave={function(e){e.currentTarget.style.transform="none";e.currentTarget.style.boxShadow="none";}}>
              <div onClick={function(){setContratosExpand(function(p){return Object.assign({},p,{[c.grupo]:!expanded});});}}
                style={{padding:"14px 16px",cursor:"pointer",display:"flex",flexDirection:"column",gap:10}}>
                {/* Linha topo: logo + nome + chevron */}
                <div style={{display:"flex",alignItems:"center",gap:11}}>
                  <div style={{width:48,height:48,borderRadius:12,background:"#fff",border:"1px solid "+c.cor+"22",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,overflow:"hidden",boxShadow:"0 1px 4px rgba(15,23,42,0.06)"}}>
                    {logoUrl?<img src={logoUrl} alt={c.grupo} style={{maxWidth:38,maxHeight:38,objectFit:"contain"}}/>:<span style={{color:c.cor,fontWeight:900,fontSize:18,letterSpacing:-.4}}>{c.grupo.charAt(0)}</span>}
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{color:"#0f172a",fontWeight:800,fontSize:15,letterSpacing:-.2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{c.grupo}</div>
                    <div style={{color:c.cor,fontSize:10.5,fontWeight:700,marginTop:1,textTransform:"uppercase",letterSpacing:.4}}>Grupo · {ativosGrupo} unidades</div>
                  </div>
                  <span style={{color:c.cor,fontSize:14,fontWeight:800,transform:expanded?"rotate(90deg)":"rotate(0)",transition:"transform .2s"}}>›</span>
                </div>
                {/* MRR grande */}
                <div style={{display:"flex",alignItems:"baseline",gap:6,paddingTop:6,borderTop:"1px solid "+c.cor+"1c"}}>
                  <span style={{color:c.cor,fontWeight:900,fontSize:22,letterSpacing:-.6,fontFeatureSettings:"'tnum'",lineHeight:1}}>{_brl(totalGrupo)}</span>
                  <span style={{color:"#64748b",fontSize:11,fontWeight:600}}>/mês</span>
                </div>
              </div>
              {expanded&&<div style={{padding:"4px 16px 12px",background:"rgba(255,255,255,0.6)"}}>
                {c.unidades.map(function(u,j){
                  return <div key={j} style={{padding:"7px 0",borderBottom:j<c.unidades.length-1?"1px dashed "+c.cor+"22":"none",display:"flex",alignItems:"center",justifyContent:"space-between",gap:10}}>
                    <div style={{display:"flex",alignItems:"center",gap:8,minWidth:0}}>
                      <div style={{width:6,height:6,borderRadius:"50%",background:u.valor>0?c.cor:"#cbd5e1",flexShrink:0}}/>
                      <span style={{color:"#0f172a",fontSize:12,fontWeight:600}}>{u.nome}</span>
                      {u.valor===0&&<span style={{background:"#f1f5f9",color:"#94a3b8",fontSize:9,fontWeight:700,padding:"1px 6px",borderRadius:99,letterSpacing:.3,textTransform:"uppercase"}}>—</span>}
                    </div>
                    <div style={{color:u.valor>0?"#0f172a":"#94a3b8",fontWeight:700,fontSize:12,fontFeatureSettings:"'tnum'"}}>{u.valor>0?_brl(u.valor):"—"}</div>
                  </div>;
                })}
              </div>}
            </div>;
          }
          // Cliente individual (sem unidades)
          return <div key={idx} style={{background:"linear-gradient(135deg,"+c.cor+"06,"+c.cor+"12)",border:"1px solid "+c.cor+"33",borderRadius:14,padding:"14px 16px",display:"flex",flexDirection:"column",gap:10,transition:"transform .15s, box-shadow .15s"}}
            onMouseEnter={function(e){e.currentTarget.style.transform="translateY(-1px)";e.currentTarget.style.boxShadow="0 6px 20px "+c.cor+"22";}}
            onMouseLeave={function(e){e.currentTarget.style.transform="none";e.currentTarget.style.boxShadow="none";}}>
            <div style={{display:"flex",alignItems:"center",gap:11}}>
              <div style={{width:48,height:48,borderRadius:12,background:"#fff",border:"1px solid "+c.cor+"22",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,overflow:"hidden",boxShadow:"0 1px 4px rgba(15,23,42,0.06)"}}>
                {logoUrl?<img src={logoUrl} alt={c.grupo} style={{maxWidth:38,maxHeight:38,objectFit:"contain"}}/>:<span style={{color:c.cor,fontWeight:900,fontSize:18,letterSpacing:-.4}}>{c.grupo.charAt(0)}</span>}
              </div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{color:"#0f172a",fontWeight:800,fontSize:15,letterSpacing:-.2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{c.grupo}</div>
                <div style={{color:c.cor,fontSize:10.5,fontWeight:700,marginTop:1,textTransform:"uppercase",letterSpacing:.4}}>Cliente único</div>
              </div>
            </div>
            <div style={{display:"flex",alignItems:"baseline",gap:6,paddingTop:6,borderTop:"1px solid "+c.cor+"1c"}}>
              <span style={{color:c.cor,fontWeight:900,fontSize:22,letterSpacing:-.6,fontFeatureSettings:"'tnum'",lineHeight:1}}>{_brl(c.valor)}</span>
              <span style={{color:"#64748b",fontSize:11,fontWeight:600}}>/mês</span>
            </div>
          </div>;
        })}
      </div>
    </Block>

  </div>;
}

