/* ── CALENDÁRIO COM FILTROS ────────────────── */
function CalendarioInterno({tasks}){
  const safeTasks = tasks || [];
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDay, setSelectedDay] = useState(null);
  const [activeFilters, setActiveFilters] = useState(["aniversario_equipe","aniversario_cliente","demanda","interna","solicitacao"]);
  const [allNotes, setAllNotes] = useState([]);

  useEffect(()=>{
    const loadNotes = () => {
      let all = [];
      CLIENTS.forEach(cl=>{
        try{
          const s = localStorage.getItem("pixels-notes-"+cl.id);
          if(s){
            const notes = JSON.parse(s);
            notes.forEach(note=>{
              (note.tasks||[]).forEach(t=>{
                if(!t.done && t.deadline){
                  all.push({...t, clientId:cl.id, clientName:cl.name, clientColor:cl.color,
                    noteId:note.id, noteDate:note.date, noteType:note.type, type:"interna"});
                }
              });
              // Solicitacoes do cliente (type=demanda in notes)
              if(note.type==="demanda"&&note.tasks&&note.tasks.length===0&&note.text){
                // treat the note itself as a solicitation event if it has a date
                if(note.date){
                  const p=note.date.split("/");
                  const ds=p.length===3?p[2]+"-"+p[1].padStart(2,"0")+"-"+p[0].padStart(2,"0"):note.date;
                  all.push({id:"sol_"+note.id, title:note.text.slice(0,60)+(note.text.length>60?"...":""),
                    date:ds, type:"solicitacao", clientName:cl.name, clientColor:cl.color});
                }
              }
            });
          }
        }catch(e){}
      });
      setAllNotes(all);
    };
    loadNotes();
    window.addEventListener("pixels-notes-updated", loadNotes);
    return () => window.removeEventListener("pixels-notes-updated", loadNotes);
  }, []);

  const teamBirthdays = TEAM.map((u, i)=>{
    return {type:"aniversario_equipe", title:"Aniversário — "+u.name,
      date:currentDate.getFullYear()+"-"+BDAY_MONTHS[i%BDAY_MONTHS.length]+"-"+BDAY_DAYS[i%BDAY_DAYS.length],
      color:u.color, av:u.av, id:"bday_team_"+u.id};
  });

  const clientBirthdays = [];
  CLIENTS.forEach(cl=>{
    try{
      const s=localStorage.getItem("pixels-contacts-"+cl.id);
      const contacts=s?JSON.parse(s):(cl.contacts||[]);
      contacts.forEach(c=>{
        if(c.birthday){
          const parts=c.birthday.split("/");
          if(parts.length>=2){
            const ds=currentDate.getFullYear()+"-"+parts[1].padStart(2,"0")+"-"+parts[0].padStart(2,"0");
            clientBirthdays.push({type:"aniversario_cliente",title:"Aniversário — "+c.name+" ("+cl.name+")",
              date:ds,color:cl.color,clientId:cl.id,id:"bday_client_"+cl.id+"_"+c.name});
          }
        }
      });
    }catch(e){}
  });

  const taskDeadlines = safeTasks.filter(t=>t.deadline&&!t.deletedAt&&t.status!=="aprovado").map(t=>{
    const cl=CLIENTS.find(c=>c.id===t.client);
    const u=TEAM.find(u=>u.id===t.assignee);
    return {type:"demanda",title:t.title,date:t.deadline,color:u?u.color:C.a,
      clientColor:cl?cl.color:C.a,clientName:cl?cl.name:"—",assigneeName:u?u.name:"—",
      priority:t.priority,id:"task_"+t.id};
  });

  const internalDeadlines = allNotes.filter(t=>t.type==="interna").map(t=>{
    let ds=t.deadline;
    if(ds&&ds.includes("/")){const p=ds.split("/");if(p.length===3)ds=p[2]+"-"+p[1].padStart(2,"0")+"-"+p[0].padStart(2,"0");}
    return {...t, date:ds, title:t.title+(t.clientName?" ("+t.clientName+")":"")};
  });

  const solicitacoes = allNotes.filter(t=>t.type==="solicitacao");

  const allEvents = [
    ...teamBirthdays, ...clientBirthdays, ...taskDeadlines,
    ...internalDeadlines, ...solicitacoes,
  ];

  const toggleFilter = (type) => {
    setActiveFilters(prev => prev.includes(type) ? prev.filter(x=>x!==type) : [...prev, type]);
  };

  const filteredEvents = allEvents.filter(ev=>activeFilters.includes(ev.type));
  const getEventsForDate = (ds) => filteredEvents.filter(ev=>ev.date&&ev.date.startsWith(ds.slice(0,10)));

  const year=currentDate.getFullYear(), month=currentDate.getMonth();
  const firstDay=new Date(year,month,1).getDay(), daysInMonth=new Date(year,month+1,0).getDate();
  const today=new Date();
  const todayStr=today.getFullYear()+"-"+(today.getMonth()+1).toString().padStart(2,"0")+"-"+today.getDate().toString().padStart(2,"0");

  const selectedDateStr=selectedDay?year+"-"+(month+1).toString().padStart(2,"0")+"-"+selectedDay.toString().padStart(2,"0"):null;
  const selectedEvents=selectedDateStr?getEventsForDate(selectedDateStr):[];
  const upcoming=filteredEvents.filter(ev=>{
    if(!ev.date)return false;
    const diff=Math.ceil((new Date(ev.date)-today)/86400000);
    return diff>=0&&diff<=7;
  }).sort((a,b)=>new Date(a.date)-new Date(b.date));

  return(<div style={{display:"flex",flexDirection:"column",gap:14}}>

    {/* Filter pills */}
    <div style={{display:"flex",gap:6,flexWrap:"wrap",alignItems:"center"}}>
      <span style={{color:C.td,fontSize:10,fontWeight:700}}>Filtros:</span>
      {Object.entries(TYPE_COLORS).map(([k,v])=>{
        const on=activeFilters.includes(k);
        return(<button key={k} onClick={()=>toggleFilter(k)}
          style={{display:"flex",alignItems:"center",gap:5,background:on?v.color+"18":"transparent",
            border:"1px solid "+(on?v.color+"55":C.b1),borderRadius:99,padding:"5px 12px",
            fontSize:10,fontWeight:on?700:400,color:on?v.color:C.td,cursor:"pointer",transition:"all .15s"}}>
          <span style={{fontSize:12}}>{v.icon}</span>{v.label}
          {!on&&<span style={{fontSize:9,opacity:.6}}>(off)</span>}
        </button>);
      })}
      <button onClick={()=>setActiveFilters(Object.keys(TYPE_COLORS))}
        style={{background:"none",border:"1px solid "+C.b1,borderRadius:99,padding:"4px 10px",fontSize:10,color:C.td,cursor:"pointer"}}>
        Todos
      </button>
    </div>

    <div style={{display:"grid",gridTemplateColumns:"1fr 300px",gap:16}}>
      <div style={{background:C.card,borderRadius:16,border:"1px solid "+C.b1,overflow:"hidden"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"14px 18px",borderBottom:"1px solid "+C.b1}}>
          <button onClick={()=>setCurrentDate(new Date(year,month-1,1))} style={{background:C.s1,border:"1px solid "+C.b1,borderRadius:8,width:32,height:32,cursor:"pointer",color:C.ts,fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}}>‹</button>
          <div style={{color:C.tx,fontWeight:800,fontSize:15}}>{INT_MONTHS[month]} {year}</div>
          <button onClick={()=>setCurrentDate(new Date(year,month+1,1))} style={{background:C.s1,border:"1px solid "+C.b1,borderRadius:8,width:32,height:32,cursor:"pointer",color:C.ts,fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}}>›</button>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",borderBottom:"1px solid "+C.b1}}>
          {DAYS_LABELS.map(d=><div key={d} style={{padding:"8px 0",textAlign:"center",color:C.td,fontSize:10,fontWeight:700,textTransform:"uppercase"}}>{d}</div>)}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)"}}>
          {Array.from({length:firstDay}).map((_,i)=><div key={"e"+i} style={{minHeight:70,borderRight:"1px solid "+C.b1+"44",borderBottom:"1px solid "+C.b1+"44"}}/>)}
          {Array.from({length:daysInMonth}).map((_,i)=>{
            const day=i+1, col=(firstDay+i)%7;
            const ds=year+"-"+(month+1).toString().padStart(2,"0")+"-"+day.toString().padStart(2,"0");
            const evs=getEventsForDate(ds);
            const isToday=ds===todayStr, isSel=selectedDay===day, isWeekend=col===0||col===6;
            return(<div key={day} onClick={()=>setSelectedDay(day===selectedDay?null:day)}
              style={{minHeight:70,borderRight:"1px solid "+C.b1+"44",borderBottom:"1px solid "+C.b1+"44",padding:"6px 6px 4px",cursor:"pointer",
                background:isSel?C.a+"18":isToday?C.a+"08":isWeekend?C.s1+"88":"transparent",transition:"background .1s"}}
              onMouseEnter={e=>{if(!isSel)e.currentTarget.style.background=C.s1;}}
              onMouseLeave={e=>{e.currentTarget.style.background=isSel?C.a+"18":isToday?C.a+"08":isWeekend?C.s1+"88":"transparent";}}>
              <div style={{display:"flex",alignItems:"center",justifyContent:"center",width:22,height:22,borderRadius:"50%",
                background:isToday?C.a:"transparent",color:isToday?"#fff":C.tx,fontWeight:isToday?900:400,fontSize:11,marginBottom:3}}>
                {day}
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:2}}>
                {evs.slice(0,3).map((ev,ei)=>{
                  const tc=TYPE_COLORS[ev.type]||{color:C.a,icon:"●"};
                  return(<div key={ei} style={{background:tc.color+"22",border:"1px solid "+tc.color+"44",borderRadius:4,padding:"1px 4px",fontSize:9,fontWeight:700,color:tc.color,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
                    {tc.icon} {ev.title.slice(0,16)}{ev.title.length>16?"...":""}
                  </div>);
                })}
                {evs.length>3&&<div style={{color:C.td,fontSize:8,textAlign:"center"}}>+{evs.length-3}</div>}
              </div>
            </div>);
          })}
        </div>
      </div>

      <div style={{display:"flex",flexDirection:"column",gap:12}}>
        {selectedDay&&(<div style={{background:C.card,borderRadius:14,border:"1px solid "+C.b1,overflow:"hidden"}}>
          <div style={{padding:"12px 16px",borderBottom:"1px solid "+C.b1,color:C.tx,fontWeight:700,fontSize:13}}>
            {selectedDay} de {INT_MONTHS[month]}
          </div>
          <div style={{padding:"10px 12px",maxHeight:280,overflowY:"auto"}}>
            {selectedEvents.length===0&&<div style={{color:C.td,fontSize:12,textAlign:"center",padding:"16px 0"}}>Nenhum evento</div>}
            {selectedEvents.map((ev,i)=>{
              const tc=TYPE_COLORS[ev.type]||{color:C.a,icon:"●",label:"Evento"};
              return(<div key={i} style={{background:tc.color+"10",border:"1px solid "+tc.color+"33",borderRadius:9,padding:"8px 12px",marginBottom:6}}>
                <div style={{display:"flex",alignItems:"center",gap:5,marginBottom:3}}>
                  <span style={{fontSize:12}}>{tc.icon}</span>
                  <span style={{background:tc.color+"18",color:tc.color,borderRadius:99,padding:"1px 6px",fontSize:8,fontWeight:700}}>{tc.label}</span>
                </div>
                <div style={{color:C.tx,fontWeight:600,fontSize:12}}>{ev.title}</div>
                {ev.clientName&&<div style={{color:C.td,fontSize:10,marginTop:2}}>{ev.clientName}</div>}
              </div>);
            })}
          </div>
        </div>)}
        <div style={{background:C.card,borderRadius:14,border:"1px solid "+C.b1,overflow:"hidden"}}>
          <div style={{padding:"12px 16px",borderBottom:"1px solid "+C.b1,color:C.tx,fontWeight:700,fontSize:13}}>Próximos 7 dias</div>
          <div style={{maxHeight:360,overflowY:"auto"}}>
            {upcoming.length===0&&<div style={{color:C.td,fontSize:12,textAlign:"center",padding:"20px"}}>Nenhum evento nos próximos 7 dias</div>}
            {upcoming.map((ev,i)=>{
              const tc=TYPE_COLORS[ev.type]||{color:C.a,icon:"●"};
              const d=new Date(ev.date), diff=Math.ceil((d-today)/(1000*60*60*24));
              const diffLabel=diff===0?"Hoje":diff===1?"Amanhã":"em "+diff+"d";
              return(<div key={i} style={{display:"flex",gap:8,alignItems:"flex-start",padding:"9px 14px",borderBottom:i<upcoming.length-1?"1px solid "+C.b1+"33":"none"}}>
                <div style={{width:32,height:32,borderRadius:9,background:tc.color+"18",border:"1px solid "+tc.color+"33",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,flexShrink:0}}>{tc.icon}</div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{color:C.tx,fontSize:11,fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{ev.title}</div>
                  <div style={{color:C.td,fontSize:9,marginTop:1}}>{d.toLocaleDateString("pt-BR",{day:"2-digit",month:"short"})}{ev.clientName?" · "+ev.clientName:""}</div>
                </div>
                <span style={{color:diff===0?C.rd:diff<=2?C.yw:C.td,fontSize:9,fontWeight:700,flexShrink:0,whiteSpace:"nowrap"}}>{diffLabel}</span>
              </div>);
            })}
          </div>
        </div>
      </div>
    </div>

  </div>);
}

/* ── CONEXÃO E CONTAS ─────────────────────── */
function PageConexoes({isMob}){
  const [show,setShow]=useState({});
  const [creds,setCreds]=useState(()=>{
    try{const s=localStorage.getItem("pixels-creds");if(s)return JSON.parse(s);}catch(e){}
    return [
      {id:1,n:"Meta Business Suite",  l:"agencia@pixels.com.br",    pw:"Pixels@Meta25",  cat:"Meta",    c:"#1877f2"},
      {id:2,n:"Google Ads MCC",       l:"ads@pixels.com.br",        pw:"Pixels@Google25",cat:"Google",  c:"#34a853"},
      {id:3,n:"Canva Pro",            l:"design@pixels.com.br",     pw:"Canva@Pixels",   cat:"Design",  c:"#7c3aed"},
      {id:4,n:"Notion",               l:"admin@pixels.com.br",      pw:"Notion@2025",    cat:"Ferram",  c:"#000"},
      {id:5,n:"RD Station",           l:"crm@pixels.com.br",        pw:"RD@Pixels25",    cat:"CRM",     c:"#e50000"},
      {id:6,n:"Google Analytics",     l:"analytics@pixels.com.br",  pw:"GA4@Pixels",     cat:"Google",  c:"#e37400"},
    ];
  });
  const [links,setLinks]=useState(()=>{
    try{const s=localStorage.getItem("pixels-links-intern");if(s)return JSON.parse(s);}catch(e){}
    return [
      {id:1,l:"Google Drive Principal",url:"#",c:"#1877f2",icon:"📁"},
      {id:2,l:"Planilha Financeira",   url:"#",c:"#34a853",icon:"📊"},
      {id:3,l:"Modelo de Proposta",    url:"#",c:C.a,      icon:"📋"},
      {id:4,l:"Calendário Editorial",  url:"#",c:"#8b5cf6", icon:"📅"},
    ];
  });
  const [tab,setTab]=useState("credenciais");
  const [adding,setAdding]=useState(false);
  const [form,setForm]=useState({n:"",l:"",pw:"",cat:"",c:"#a140ff"});

  const saveCreds=(list)=>{setCreds(list);try{localStorage.setItem("pixels-creds",JSON.stringify(list));}catch(e){}
    if(window._sb)window._sb.from("content_library").upsert({tipo:"creds",dados:list,updated_by:CURRENT_USER.name},{onConflict:"tipo"}).then(()=>{}).catch(()=>{});
  };
  useEffect(()=>{
    if(!window._sb)return;
    window._sb.from("content_library").select("dados").eq("tipo","creds").single()
      .then(({data})=>{
        if(data?.dados&&Array.isArray(data.dados)&&data.dados.length){
          setCreds(data.dados);
          try{localStorage.setItem("pixels-creds",JSON.stringify(data.dados));}catch(e){}
        }
      }).catch(()=>{});
  },[]);
  const addCred=()=>{if(!form.n.trim())return;saveCreds([...creds,{...form,id:Date.now()}]);setForm({n:"",l:"",pw:"",cat:"",c:"#a140ff"});setAdding(false);};
  const inp={background:C.s1,border:"1px solid "+C.b1,borderRadius:9,padding:"8px 10px",color:C.tx,fontSize:12,outline:"none",width:"100%",boxSizing:"border-box",fontFamily:"inherit"};

  return(<div style={{display:"flex",flexDirection:"column",gap:16}}>
    <div style={{color:C.tx,fontWeight:900,fontSize:isMob?17:20}}>Conexão e Contas</div>

    <div style={{display:"flex",gap:4,borderBottom:"1px solid "+C.b1,marginBottom:4}}>
      {CONEXOES_TABS.map(([id,lbl])=>(
        <button key={id} onClick={()=>setTab(id)} style={{background:"none",border:"none",borderBottom:tab===id?"2px solid "+C.a:"2px solid transparent",padding:"9px 16px",color:tab===id?C.a:C.ts,fontWeight:tab===id?700:400,fontSize:12,cursor:"pointer",marginBottom:-1}}>{lbl}</button>
      ))}
    </div>

    {tab==="credenciais"&&(<div style={{background:C.card,borderRadius:16,border:"1px solid "+C.b1,overflow:"hidden"}}>
      <div style={{padding:"14px 18px",borderBottom:"1px solid "+C.b1,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <span style={{color:C.tx,fontWeight:700}}>Credenciais da Agência</span>
        <button onClick={()=>setAdding(true)} style={{background:C.a+"18",color:C.a,border:"1px solid "+C.a+"33",borderRadius:8,padding:"5px 12px",fontSize:11,fontWeight:700,cursor:"pointer"}}>+ Adicionar</button>
      </div>
      {adding&&(<div style={{padding:"14px 18px",borderBottom:"1px solid "+C.b1,display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
        {CRED_FIELDS.map(f=>(
          <div key={f.k}><div style={{color:C.td,fontSize:10,marginBottom:3}}>{f.p}</div>
            <input value={form[f.k]} onChange={e=>setForm(prev=>({...prev,[f.k]:e.target.value}))} style={inp}/></div>
        ))}
        <div style={{gridColumn:"1/-1",display:"flex",gap:8,justifyContent:"flex-end"}}>
          <button onClick={()=>setAdding(false)} style={{background:C.s1,border:"1px solid "+C.b1,borderRadius:9,padding:"7px 14px",color:C.ts,fontSize:12,cursor:"pointer"}}>Cancelar</button>
          <button onClick={addCred} style={{background:C.a,color:"#fff",border:"none",borderRadius:9,padding:"7px 16px",fontWeight:700,fontSize:12,cursor:"pointer"}}>Salvar</button>
        </div>
      </div>)}
      {creds.map((cr,i)=>(
        <div key={cr.id||i} style={{padding:"13px 18px",borderBottom:i<creds.length-1?"1px solid "+C.b1:"none",display:"flex",justifyContent:"space-between",alignItems:"center",gap:12}}>
          <div style={{display:"flex",gap:10,alignItems:"center"}}>
            <span style={{background:cr.c+"22",color:cr.c,borderRadius:99,padding:"2px 8px",fontSize:9,fontWeight:700}}>{cr.cat||"—"}</span>
            <div>
              <div style={{color:C.tx,fontWeight:600,fontSize:13}}>{cr.n}</div>
              <div style={{color:C.ts,fontSize:11}}>{cr.l}</div>
            </div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            {show[cr.id||i]&&<span style={{color:C.gr,fontSize:11,fontFamily:"monospace",background:C.s1,borderRadius:6,padding:"2px 8px"}}>{cr.pw}</span>}
            <button onClick={()=>setShow(s=>({...s,[cr.id||i]:!s[cr.id||i]}))}
              style={{background:C.s1,border:"1px solid "+C.b1,borderRadius:8,padding:"5px 10px",color:C.ts,cursor:"pointer",fontSize:10,fontWeight:700}}>
              {show[cr.id||i]?"🙈 Ocultar":"👁 Ver"}
            </button>
            <button onClick={()=>saveCreds(creds.filter((_,j)=>j!==i))} style={{background:"none",border:"none",color:C.td,cursor:"pointer",fontSize:13,padding:2}}>×</button>
          </div>
        </div>
      ))}
    </div>)}

    {tab==="links"&&(<div style={{background:C.card,borderRadius:16,border:"1px solid "+C.b1,overflow:"hidden"}}>
      <div style={{padding:"14px 18px",borderBottom:"1px solid "+C.b1,color:C.tx,fontWeight:700}}>Links Rápidos</div>
      {links.map((lk,i)=>(
        <div key={lk.id||i} style={{padding:"12px 18px",borderBottom:i<links.length-1?"1px solid "+C.b1:"none",display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:16}}>{lk.icon||"🔗"}</span>
          <a href={lk.url} target="_blank" rel="noopener noreferrer" style={{color:lk.c||C.a,fontSize:13,fontWeight:700,textDecoration:"none",flex:1}}>{lk.l} ↗</a>
        </div>
      ))}
    </div>)}
  </div>);
}

/* ── BarChart — fora do componente para evitar remount ── */
function BarChartV({items,colorKey="valor"}){
  const max=Math.max(...items.map(i=>i[colorKey]),1);
  return(<div style={{display:"flex",flexDirection:"column",gap:5}}>
    {[...items].sort((a,b)=>b[colorKey]-a[colorKey]).slice(0,6).map((item,i)=>{
      const pct=Math.round((item[colorKey]/max)*100);
      const col=pct>=70?"#15803d":pct>=40?"#22c55e":"#86efac";
      return(<div key={i}>
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
          <span style={{color:C.tx,fontSize:11,fontWeight:500}}>{item.cidade||item.estado||item.pais}</span>
          <span style={{color:col,fontSize:11,fontWeight:700}}>
            {colorKey==="valor"?"R$"+(item[colorKey]/1000).toFixed(0)+"k":item[colorKey]}
          </span>
        </div>
        <div style={{background:C.b1,borderRadius:99,height:5,overflow:"hidden"}}>
          <div style={{width:pct+"%",height:"100%",background:col,borderRadius:99,transition:"width .6s ease"}}/>
        </div>
      </div>);
    })}
  </div>);
}

/* ── ROI constants — fora do componente ── */
const VALOR_POR_TAREFA=150;
const SALARIOS={vinicius:5000,gustavo:5000,ellen:3200,erick:3500,andre:3000,guilherme:2800};

/* ── MAPEAMENTO DE VENDAS ─────────────────── */
function PageMapeamento(){
  /* ── DATA ── */
  const [entries,setEntries]=useState(()=>{
    try{const s=localStorage.getItem("pixels-mapa-vendas");if(s)return JSON.parse(s);}catch(e){}
    return[
      {id:1,client:"construschorr",pais:"Brasil",estado:"SC",cidade:"Chapecó",    lat:-27.10,lng:-52.62,vendas:42,valor:187000,semana:"2026-W12"},
      {id:2,client:"construschorr",pais:"Brasil",estado:"SC",cidade:"Xanxerê",   lat:-26.88,lng:-52.40,vendas:18,valor:82000, semana:"2026-W12"},
      {id:3,client:"bioter",       pais:"Brasil",estado:"PR",cidade:"Toledo",     lat:-24.72,lng:-53.74,vendas:67,valor:340000,semana:"2026-W12"},
      {id:4,client:"bioter",       pais:"Brasil",estado:"MS",cidade:"Dourados",   lat:-22.22,lng:-54.81,vendas:31,valor:158000,semana:"2026-W12"},
      {id:5,client:"vetservice",   pais:"Brasil",estado:"SC",cidade:"Concórdia",  lat:-27.23,lng:-52.03,vendas:28,valor:94000, semana:"2026-W12"},
      {id:6,client:"arabuta",      pais:"Brasil",estado:"SC",cidade:"Seara",      lat:-27.15,lng:-52.32,vendas:15,valor:67000, semana:"2026-W12"},
      {id:7,client:"climaves",     pais:"Brasil",estado:"SC",cidade:"Chapecó",    lat:-27.10,lng:-52.62,vendas:22,valor:110000,semana:"2026-W12"},
      {id:8,client:"bioter",       pais:"Brasil",estado:"GO",cidade:"Goiânia",    lat:-16.69,lng:-49.26,vendas:45,valor:225000,semana:"2026-W12"},
      {id:9,client:"construschorr",pais:"Argentina",estado:"Buenos Aires",cidade:"Buenos Aires",lat:-34.61,lng:-58.43,vendas:12,valor:55000,semana:"2026-W12"},
      {id:10,client:"bioter",      pais:"Paraguai", estado:"Alto Paraná",cidade:"Ciudad del Este",lat:-25.51,lng:-54.61,vendas:8,valor:38000,semana:"2026-W12"},
    ];
  });
  const saveEntries=list=>{setEntries(list);try{localStorage.setItem("pixels-mapa-vendas",JSON.stringify(list));}catch(e){}};

  /* ── MAP STATE ── */
  const [countries,setCountries]=useState(null);
  const [brStates, setBrStates] =useState(null);
  const [loading,  setLoading]  =useState(true);
  const [hoverId,  setHoverId]  =useState(null);
  const [selected, setSelected] =useState(null); // {type:'country'|'state', name, data}
  const [tooltip,  setTooltip]  =useState(null);
  const [zoom,     setZoom]     =useState(1);
  const [pan,      setPan]      =useState({x:0,y:0});
  const [dragging, setDragging] =useState(false);
  const [dragStart,setDragStart]=useState(null);
  const [filterClient,setFilterClient]=useState("todos");
  const [showAdd,  setShowAdd]  =useState(false);
  const [form,setForm]=useState({client:"",pais:"Brasil",estado:"",cidade:"",lat:"",lng:"",vendas:"",valor:"",semana:""});

  /* ── PROJECTION (Mercator, SA bounds) ── */
  const project=([lng,lat])=>{
    const x=(lng-LNG0)/(LNG1-LNG0)*MAP_W;
    const m=d=>Math.log(Math.tan(Math.PI/4+d*Math.PI/360));
    const y=(1-(m(lat)-m(LAT1))/(m(LAT0)-m(LAT1)))*MAP_H;
    return[x,y];
  };
  const geomPath=geom=>{
    if(!geom)return"";
    const polys=geom.type==="Polygon"?[geom.coordinates]:geom.type==="MultiPolygon"?geom.coordinates:[];
    return polys.map(poly=>poly.map(ring=>{
      const pts=ring.map(project);
      return"M"+pts.map((p,i)=>(i?`L${p[0].toFixed(1)},${p[1].toFixed(1)}`:`${p[0].toFixed(1)},${p[1].toFixed(1)}`)).join("")+"Z";
    }).join(" ")).join(" ");
  };

  /* ── LOAD GEOJSON ── */
  useEffect(()=>{
    fetch("https://raw.githubusercontent.com/nvkelso/natural-earth-vector/master/geojson/ne_110m_admin_0_countries.geojson")
      .then(r=>r.json()).then(d=>{
        setCountries(d.features.filter(f=>SA_CODES.includes(f.properties.ADM0_A3)));
        setLoading(false);
      }).catch(()=>setLoading(false));
  },[]);

  useEffect(()=>{
    if(selected?.name==="Brazil"||selected?.name==="Brasil"){
      fetch("https://raw.githubusercontent.com/codeforamerica/click_that_hood/master/public/data/brazil-states.geojson")
        .then(r=>r.json()).then(d=>setBrStates(d.features)).catch(()=>{});
    } else setBrStates(null);
  },[selected]);

  /* ── DATA AGGREGATION ── */
  const filtered=entries.filter(e=>filterClient==="todos"||e.client===filterClient);
  const byPais={}, byEstado={};
  filtered.forEach(e=>{
    byPais[e.pais]=(byPais[e.pais]||{pais:e.pais,vendas:0,valor:0,estados:{}});
    byPais[e.pais].vendas+=e.vendas; byPais[e.pais].valor+=e.valor;
    const ek=e.estado;
    if(!byEstado[ek])byEstado[ek]={estado:ek,pais:e.pais,vendas:0,valor:0,cidades:[]};
    byEstado[ek].vendas+=e.vendas; byEstado[ek].valor+=e.valor;
    if(!byEstado[ek].cidades.find(c=>c.cidade===e.cidade))
      byEstado[ek].cidades.push({cidade:e.cidade,vendas:0,valor:0,lat:+e.lat,lng:+e.lng});
    const c=byEstado[ek].cidades.find(c=>c.cidade===e.cidade);
    c.vendas+=e.vendas; c.valor+=e.valor;
  });

  const maxPV=Math.max(...Object.values(byPais).map(p=>p.valor),1);
  const maxEV=Math.max(...Object.values(byEstado).map(e=>e.valor),1);

  const paisColor=name=>{
    const ptBR=PAIS_PT[name]||name;
    const d=byPais[ptBR]||byPais[name];
    if(!d||d.valor===0)return"#f8fafc";
    const t=d.valor/maxPV;
    return t>=.7?"#15803d":t>=.4?"#22c55e":t>=.1?"#86efac":"#dcfce7";
  };
  const estadoColor=nome=>{
    const d=byEstado[nome];
    if(!d||d.valor===0)return"#f1f5f9";
    const t=d.valor/maxEV;
    return t>=.7?"#15803d":t>=.4?"#22c55e":t>=.1?"#86efac":"#dcfce7";
  };

  /* ── INTERACTIONS ── */
  const handleWheel=e=>{e.preventDefault();setZoom(z=>Math.max(.7,Math.min(10,z*(e.deltaY>0?.87:1.15))));};
  const onMD=e=>{if(e.button)return;setDragging(true);setDragStart({x:e.clientX-pan.x,y:e.clientY-pan.y});};
  const onMM=e=>{if(dragging&&dragStart)setPan({x:e.clientX-dragStart.x,y:e.clientY-dragStart.y});};
  const onMU=()=>setDragging(false);

  const zoomBrazil=()=>{setZoom(2.6);setPan({x:-470,y:-620});};
  const resetView=()=>{setZoom(1);setPan({x:0,y:0});setSelected(null);};

  const selectCountry=(geoName,e)=>{
    e.stopPropagation();
    const ptBR=PAIS_PT[geoName]||geoName;
    const d=byPais[ptBR]||byPais[geoName]||null;
    if(selected?.name===geoName){resetView();return;}
    setSelected({type:"country",name:geoName,namePT:ptBR,data:d});
    if(geoName==="Brazil")zoomBrazil();
    else{setZoom(1.5);setPan({x:0,y:0});}
  };
  const selectState=(nome,e)=>{
    e.stopPropagation();
    const d=byEstado[nome]||null;
    setSelected(s=>s?.name===nome?{...s,type:"country",name:"Brazil"}:{type:"state",name:nome,data:d});
  };

  /* ── ADD ENTRY ── */
  const inp={background:C.s1,border:"1px solid "+C.b1,borderRadius:8,padding:"7px 10px",color:C.tx,fontSize:12,outline:"none",width:"100%",boxSizing:"border-box",fontFamily:"inherit"};
  const addEntry=()=>{
    if(!form.cidade.trim())return;
    saveEntries([...entries,{...form,id:Date.now(),vendas:+form.vendas||0,valor:+form.valor||0,lat:+form.lat||0,lng:+form.lng||0}]);
    setForm({client:"",pais:"Brasil",estado:"",cidade:"",lat:"",lng:"",vendas:"",valor:"",semana:""});
    setShowAdd(false);
  };

  const totalV=filtered.reduce((s,e)=>s+e.vendas,0);
  const totalR=filtered.reduce((s,e)=>s+e.valor,0);
  const cities=Object.values(byEstado).flatMap(e=>e.cidades.filter(c=>c.lat&&c.lng));
  const maxCV=Math.max(...cities.map(c=>c.valor),1);

  return(<div style={{display:"flex",flexDirection:"column",gap:16}}>
    <style>{MAP_CSS}</style>

    {/* ── HEADER ── */}
    <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:12,flexWrap:"wrap"}}>
      <div>
        <div style={{color:C.tx,fontWeight:900,fontSize:20,letterSpacing:-.5}}>Mapeamento de Vendas</div>
        <div style={{color:C.td,fontSize:11,marginTop:3}}>América do Sul · vendas geradas pelo tráfego pago</div>
      </div>
      <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
        <select value={filterClient} onChange={e=>setFilterClient(e.target.value)} style={{...inp,width:"auto"}}>
          <option value="todos">Todos os clientes</option>
          {CLIENTS.map(cl=><option key={cl.id} value={cl.id}>{cl.name}</option>)}
        </select>
        <button onClick={()=>setShowAdd(true)}
          style={{background:`linear-gradient(135deg,${C.a},${C.aD})`,color:"#fff",border:"none",borderRadius:10,padding:"8px 16px",fontWeight:700,fontSize:12,cursor:"pointer",whiteSpace:"nowrap"}}>
          + Registrar venda
        </button>
      </div>
    </div>

    {/* ── KPIs ── */}
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:10}}>
      {[
        {l:"Vendas totais",v:totalV.toLocaleString("pt-BR"),c:"#15803d"},
        {l:"Receita total", v:"R$"+(totalR/1000).toFixed(0)+"k",c:C.gr},
        {l:"Países ativos", v:Object.keys(byPais).length,c:C.a},
        {l:"Cidades",       v:cities.length,c:"#7c3aed"},
      ].map((k,i)=>(
        <div key={i} style={{background:C.card,borderRadius:12,padding:"12px 14px",border:"1px solid "+C.b1,borderLeft:"3px solid "+k.c}}>
          <div style={{color:C.td,fontSize:9,fontWeight:700,textTransform:"uppercase",letterSpacing:.7,marginBottom:5}}>{k.l}</div>
          <div style={{color:k.c,fontWeight:900,fontSize:22,letterSpacing:-1}}>{k.v}</div>
        </div>
      ))}
    </div>

    {/* ── ADD FORM ── */}
    {showAdd&&(
      <div style={{background:C.card,borderRadius:14,border:"2px solid "+C.a+"44",padding:"16px 18px"}}>
        <div style={{color:C.a,fontWeight:700,fontSize:13,marginBottom:10}}>Registrar vendas</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:8}}>
          <div><div style={{color:C.td,fontSize:10,marginBottom:3}}>Cliente</div>
            <select value={form.client} onChange={e=>setForm(p=>({...p,client:e.target.value}))} style={inp}>
              <option value="">Selecionar...</option>
              {CLIENTS.map(cl=><option key={cl.id} value={cl.id}>{cl.name}</option>)}
            </select>
          </div>
          {MAPA_FORM_FIELDS.map(f=>(
            <div key={f.k}><div style={{color:C.td,fontSize:10,marginBottom:3}}>{f.p}</div>
              <input value={form[f.k]} onChange={e=>setForm(p=>({...p,[f.k]:e.target.value}))} style={inp}/>
            </div>
          ))}
        </div>
        <div style={{color:C.td,fontSize:10,marginTop:6}}>Ex lat/lng: Chapecó -27.10,-52.62 · Goiânia -16.69,-49.26 · B.Aires -34.61,-58.43</div>
        <div style={{display:"flex",gap:8,justifyContent:"flex-end",marginTop:10}}>
          <button onClick={()=>setShowAdd(false)} style={{background:C.s1,border:"1px solid "+C.b1,borderRadius:8,padding:"7px 14px",color:C.ts,fontSize:12,cursor:"pointer"}}>Cancelar</button>
          <button onClick={addEntry} style={{background:C.a,color:"#fff",border:"none",borderRadius:8,padding:"7px 18px",fontWeight:700,fontSize:12,cursor:"pointer"}}>Salvar</button>
        </div>
      </div>
    )}

    {/* ── MAP + PANEL ── */}
    <div style={{display:"grid",gridTemplateColumns:selected?"1fr 320px":"1fr",gap:14,alignItems:"start"}}>

      {/* MAP CARD */}
      <div style={{background:C.card,borderRadius:18,border:"1px solid "+C.b1,overflow:"hidden"}}>

        {/* Toolbar */}
        <div style={{padding:"11px 16px",borderBottom:"1px solid "+C.b1,display:"flex",alignItems:"center",gap:10,flexWrap:"wrap"}}>
          {/* Breadcrumb */}
          <div style={{display:"flex",alignItems:"center",gap:5,flex:1,minWidth:0,flexWrap:"wrap"}}>
            <button onClick={resetView} style={{background:"none",border:"none",color:selected?C.a:C.td,fontSize:12,cursor:"pointer",padding:0,fontWeight:selected?600:400}}>América do Sul</button>
            {selected&&<><span style={{color:C.td,fontSize:12}}>/</span>
              <span style={{color:C.tx,fontSize:12,fontWeight:700}}>{PAIS_PT[selected.name]||selected.namePT||selected.name}</span></>}
          </div>
          {/* Controls */}
          <div style={{display:"flex",gap:6,alignItems:"center",flexShrink:0}}>
            <span style={{color:C.td,fontSize:10}}>{Math.round(zoom*100)}%</span>
            {[["−",()=>setZoom(z=>Math.max(.7,z*.8))],["+",()=>setZoom(z=>Math.min(10,z*1.25))]].map(([l,fn])=>(
              <button key={l} onClick={fn} style={{background:C.s1,border:"1px solid "+C.b1,borderRadius:8,width:30,height:30,cursor:"pointer",color:C.tx,fontWeight:900,fontSize:15,display:"flex",alignItems:"center",justifyContent:"center"}}>
                {l}
              </button>
            ))}
            {(zoom!==1||pan.x||pan.y||selected)&&(
              <button onClick={resetView} style={{background:C.s1,border:"1px solid "+C.b1,borderRadius:8,padding:"0 10px",height:30,cursor:"pointer",color:C.ts,fontSize:10,fontWeight:600,whiteSpace:"nowrap"}}>Resetar</button>
            )}
            {!selected&&(
              <button onClick={()=>{setSelected({type:"country",name:"Brazil",namePT:"Brasil",data:byPais["Brasil"]||null});zoomBrazil();}}
                style={{background:"#dcfce7",border:"1px solid #86efac",borderRadius:8,padding:"0 10px",height:30,cursor:"pointer",color:"#15803d",fontSize:10,fontWeight:700,whiteSpace:"nowrap"}}>
                🇧🇷 Ver Brasil
              </button>
            )}
          </div>
        </div>

        {/* SVG container */}
        <div onWheel={handleWheel} onMouseDown={onMD} onMouseMove={onMM} onMouseUp={onMU} onMouseLeave={onMU}
          style={{position:"relative",overflow:"hidden",background:"#f0f9ff",height:560,cursor:dragging?"grabbing":"grab"}}
          onClick={()=>{if(!dragging)resetView();}}>

          {loading&&(
            <div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:10,background:"#f0f9ff"}}>
              <div style={{width:36,height:36,borderRadius:"50%",border:"3px solid #22c55e44",borderTop:"3px solid #22c55e",animation:"spin .9s linear infinite"}}/>
              <span style={{color:C.td,fontSize:12}}>Carregando América do Sul…</span>
              <style>{"@keyframes spin{to{transform:rotate(360deg)}}"}</style>
            </div>
          )}

          {countries&&(
            <svg width="100%" height="100%" viewBox={`0 0 ${MAP_W} ${MAP_H}`} style={{display:"block",userSelect:"none"}}>
              <defs>
                <filter id="sel-shadow"><feDropShadow dx="0" dy="2" stdDeviation="3" floodOpacity=".2"/></filter>
              </defs>
              {/* Ocean */}
              <rect width={MAP_W} height={MAP_H} fill="#e0f2fe"/>

              <g transform={`translate(${pan.x},${pan.y}) scale(${zoom})`} style={{transformOrigin:"0 0"}}>

                {/* Countries */}
                {countries.map((f,i)=>{
                  const name=f.properties.NAME||f.properties.ADMIN||"";
                  const ptBR=PAIS_PT[name]||name;
                  const isSel=selected?.name===name;
                  const fill=isSel?"#dcfce7":paisColor(name);
                  const stroke=isSel?"#15803d":"#cbd5e1";
                  const sw=(isSel?1.2:.4)/zoom;

                  // Brazil: show states when selected
                  if(name==="Brazil"&&brStates&&isSel){
                    return(<g key={i}>
                      <path d={geomPath(f.geometry)} fill="#f0fdf4" stroke="#86efac" strokeWidth={.3/zoom}/>
                      {brStates.map((sf,si)=>{
                        const sname=sf.properties.name||sf.properties.sigla||"";
                        const sSel=selected?.name===sname&&selected?.type==="state";
                        const sFill=sSel?"#15803d":estadoColor(sname);
                        const sStroke=sSel?"#15803d":"#86efac";
                        // centroid label
                        let cx=null,cy=null;
                        try{
                          const coords=sf.geometry.type==="Polygon"?sf.geometry.coordinates[0]:sf.geometry.coordinates[0][0];
                          cx=coords.reduce((s,c)=>s+c[0],0)/coords.length;
                          cy=coords.reduce((s,c)=>s+c[1],0)/coords.length;
                        }catch(e){}
                        const pt=cx?project([cx,cy]):null;
                        return(<g key={si}
                          className="feat"
                          onClick={e=>selectState(sname,e)}
                          onMouseEnter={e=>{setHoverId("br-"+sname);setTooltip({name:sname,data:byEstado[sname],x:e.clientX,y:e.clientY});}}
                          onMouseLeave={()=>{setHoverId(null);setTooltip(null);}}>
                          <path d={geomPath(sf.geometry)} fill={hoverId==="br-"+sname?"#bbf7d0":sFill}
                            stroke={sStroke} strokeWidth={(sSel?1:.5)/zoom} filter={sSel?"url(#sel-shadow)":"none"}/>
                          {pt&&<text x={pt[0]} y={pt[1]} textAnchor="middle" dominantBaseline="middle"
                            fontSize={9/zoom} fontWeight="700" fill={sSel?"#fff":"#15803d"} style={{pointerEvents:"none"}}>
                            {sf.properties.sigla||sname.slice(0,2).toUpperCase()}
                          </text>}
                        </g>);
                      })}
                    </g>);
                  }

                  return(<g key={i}
                    className="feat"
                    onClick={e=>selectCountry(name,e)}
                    onMouseEnter={e=>{setHoverId(name);setTooltip({name:ptBR,data:byPais[ptBR]||byPais[name],x:e.clientX,y:e.clientY});}}
                    onMouseLeave={()=>{setHoverId(null);setTooltip(null);}}>
                    <path d={geomPath(f.geometry)}
                      fill={hoverId===name&&!isSel?"#bbf7d0":fill}
                      stroke={stroke} strokeWidth={sw}
                      filter={isSel?"url(#sel-shadow)":"none"}/>
                    {/* Country abbreviation */}
                    {(()=>{try{
                      const coords=f.geometry.type==="Polygon"?f.geometry.coordinates[0]:f.geometry.coordinates[0][0];
                      const cx=coords.reduce((s,c)=>s+c[0],0)/coords.length;
                      const cy=coords.reduce((s,c)=>s+c[1],0)/coords.length;
                      const p=project([cx,cy]);
                      const abbr=COUNTRY_ABBR[name]||name.slice(0,2).toUpperCase();
                      const hasD=byPais[ptBR]||byPais[name];
                      return(<text x={p[0]} y={p[1]} textAnchor="middle" dominantBaseline="middle"
                        fontSize={Math.max(5,11/zoom)} fontWeight="700"
                        fill={isSel?"#15803d":hasD?"#15803d":"#94a3b8"} style={{pointerEvents:"none"}}>
                        {abbr}
                      </text>);
                    }catch(e){return null;}})()}
                  </g>);
                })}

                {/* City dots */}
                {cities.map((c,i)=>{
                  const pt=project([c.lng,c.lat]);
                  const r=Math.max(3,Math.min(9,3+(c.valor/maxCV)*6));
                  const cl=CLIENTS.find(x=>entries.some(e=>e.cidade===c.cidade&&e.client===x.id));
                  return(<g key={i} style={{cursor:"pointer"}}
                    onMouseEnter={e=>setTooltip({name:c.cidade,data:{vendas:c.vendas,valor:c.valor},x:e.clientX,y:e.clientY})}
                    onMouseLeave={()=>setTooltip(null)}>
                    <circle cx={pt[0]} cy={pt[1]} r={r+2} fill="white" opacity=".85"/>
                    <circle className="city-dot" cx={pt[0]} cy={pt[1]} r={r} fill={cl?.color||"#15803d"}/>
                    <text x={pt[0]} y={pt[1]-r-3} textAnchor="middle"
                      fontSize={Math.max(4.5,7/zoom)} fontWeight="600" fill="#0f172a" style={{pointerEvents:"none"}}>
                      {c.cidade}
                    </text>
                  </g>);
                })}
              </g>

              {/* Legend */}
              <g transform={`translate(10,${MAP_H-58})`}>
                <rect width="140" height="46" rx="6" fill="rgba(255,255,255,.92)" stroke="#e2e8f0" strokeWidth="1"/>
                <text x="8" y="13" fontSize="7" fontWeight="700" fill="#64748b">VOLUME DE VENDAS</text>
                {MAP_LEGEND_COLORS.map((c,i)=>(
                  <rect key={i} x={8+i*30} y="18" width="26" height="9" rx="2" fill={c}/>
                ))}
                <text x="8" y="40" fontSize="7" fill="#64748b">Baixo</text>
                <text x="115" y="40" fontSize="7" fill="#64748b" textAnchor="end">Alto</text>
              </g>
            </svg>
          )}

          {/* Scroll hint */}
          <div style={{position:"absolute",bottom:10,right:14,background:"rgba(0,0,0,.35)",color:"#fff",borderRadius:20,padding:"4px 12px",fontSize:9,pointerEvents:"none"}}>
            Scroll = zoom · Arrastar = mover
          </div>

          {/* Tooltip */}
          {tooltip&&(
            <div style={{position:"fixed",left:tooltip.x+14,top:tooltip.y-52,zIndex:9999,pointerEvents:"none",
              background:"#fff",border:"1px solid #e2e8f0",borderRadius:10,padding:"10px 14px",
              boxShadow:"0 6px 24px rgba(0,0,0,.12)",minWidth:160}}>
              <div style={{color:"#0f172a",fontWeight:700,fontSize:13}}>{tooltip.name}</div>
              {tooltip.data?.valor>0?(
                <div style={{display:"flex",gap:16,marginTop:6}}>
                  <div><div style={{color:"#15803d",fontWeight:800,fontSize:15}}>{(tooltip.data.vendas||0).toLocaleString("pt-BR")}</div><div style={{color:"#94a3b8",fontSize:9,marginTop:1}}>VENDAS</div></div>
                  <div><div style={{color:C.gr,fontWeight:800,fontSize:15}}>R${((tooltip.data.valor||0)/1000).toFixed(0)}k</div><div style={{color:"#94a3b8",fontSize:9,marginTop:1}}>RECEITA</div></div>
                </div>
              ):<div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>Sem dados registrados</div>}
            </div>
          )}
        </div>
      </div>

      {/* ── DETAIL PANEL ── */}
      {selected&&(
        <div style={{background:C.card,borderRadius:18,border:"1px solid "+C.b1,overflow:"hidden",display:"flex",flexDirection:"column"}}>

          {/* Panel header */}
          <div style={{padding:"14px 18px",borderBottom:"1px solid "+C.b1,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
            <div>
              <div style={{color:C.tx,fontWeight:800,fontSize:15}}>{selected.namePT||PAIS_PT[selected.name]||selected.name}</div>
              <div style={{color:C.td,fontSize:11,marginTop:2}}>{selected.type==="state"?"Estado · Brasil":"País · América do Sul"}</div>
            </div>
            <button onClick={resetView} style={{background:"none",border:"none",color:C.td,cursor:"pointer",fontSize:20,padding:4,lineHeight:1}}
              onMouseEnter={e=>e.currentTarget.style.color=C.rd} onMouseLeave={e=>e.currentTarget.style.color=C.td}>×</button>
          </div>

          <div style={{padding:"16px 18px",overflowY:"auto",flex:1}}>
            {selected.data?(
              <>
                {/* KPIs */}
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:18}}>
                  {[
                    {l:"Vendas",v:(selected.data.vendas||0).toLocaleString("pt-BR"),c:"#15803d"},
                    {l:"Receita",v:"R$"+((selected.data.valor||0)/1000).toFixed(0)+"k",c:C.gr},
                  ].map((k,i)=>(
                    <div key={i} style={{background:C.s1,borderRadius:10,padding:"12px 14px",textAlign:"center"}}>
                      <div style={{color:k.c,fontWeight:900,fontSize:20}}>{k.v}</div>
                      <div style={{color:C.td,fontSize:9,marginTop:2,textTransform:"uppercase",letterSpacing:.6}}>{k.l}</div>
                    </div>
                  ))}
                </div>

                {/* Chart: by estado (if country) or by cidade (if state) */}
                {selected.type==="country"&&selected.name==="Brazil"&&(
                  <>
                    <div style={{color:C.tx,fontWeight:700,fontSize:13,marginBottom:10}}>Receita por Estado</div>
                    <BarChartV items={Object.values(byEstado).filter(e=>e.pais==="Brasil")} colorKey="valor"/>
                  </>
                )}
                {selected.type==="country"&&selected.name!=="Brazil"&&(
                  <>
                    <div style={{color:C.tx,fontWeight:700,fontSize:13,marginBottom:10}}>Cidades</div>
                    <BarChartV items={selected.data.cidades||[]} colorKey="valor"/>
                  </>
                )}
                {selected.type==="state"&&(
                  <>
                    <div style={{color:C.tx,fontWeight:700,fontSize:13,marginBottom:10}}>Receita por Cidade</div>
                    <BarChartV items={selected.data.cidades||[]} colorKey="valor"/>
                    <div style={{color:C.tx,fontWeight:700,fontSize:13,marginTop:16,marginBottom:10}}>Vendas por Cidade</div>
                    <BarChartV items={selected.data.cidades||[]} colorKey="vendas"/>
                  </>
                )}
              </>
            ):(
              <div style={{textAlign:"center",padding:"32px 0"}}>
                <div style={{fontSize:32,marginBottom:8}}>📊</div>
                <div style={{color:C.ts,fontSize:13}}>Sem dados registrados</div>
                <div style={{color:C.td,fontSize:11,marginTop:4}}>Registre vendas para este local</div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>

    {/* ── RANKING TABLE ── */}
    {Object.keys(byPais).length>0&&(
      <div style={{background:C.card,borderRadius:16,border:"1px solid "+C.b1,overflow:"hidden"}}>
        <div style={{padding:"12px 18px",borderBottom:"1px solid "+C.b1,color:C.tx,fontWeight:700,fontSize:13}}>Ranking Completo — País → Estado → Cidade</div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
            <thead><tr style={{background:C.s1}}>
              {RANKING_TABLE_HEADERS.map((h,i)=>(
                <th key={i} style={{padding:"9px 14px",textAlign:"left",color:C.td,fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.6,borderBottom:"1px solid "+C.b1,whiteSpace:"nowrap"}}>{h}</th>
              ))}
            </tr></thead>
            <tbody>
              {filtered.sort((a,b)=>b.valor-a.valor).map((e,i)=>{
                const cl=CLIENTS.find(c=>c.id===e.client);
                return(<tr key={e.id||i} style={{borderBottom:"1px solid "+C.b1+"22",background:i%2?"transparent":C.s1+"55"}}
                  onMouseEnter={ev=>ev.currentTarget.style.background=C.s1} onMouseLeave={ev=>ev.currentTarget.style.background=i%2?"transparent":C.s1+"55"}>
                  <td style={{padding:"8px 14px",color:C.ts,fontSize:11}}>{e.pais}</td>
                  <td style={{padding:"8px 14px",fontWeight:600,color:C.tx}}>{e.estado}</td>
                  <td style={{padding:"8px 14px",color:C.tx}}>{e.cidade}</td>
                  <td style={{padding:"8px 14px",textAlign:"center"}}><span style={{color:"#15803d",fontWeight:800}}>{e.vendas}</span></td>
                  <td style={{padding:"8px 14px"}}><span style={{color:C.gr,fontWeight:700}}>R${(+e.valor/1000).toFixed(0)}k</span></td>
                  <td style={{padding:"8px 14px"}}>
                    {cl&&<span style={{background:cl.color+"18",color:cl.color,borderRadius:6,padding:"1px 7px",fontSize:10,fontWeight:700}}>{cl.name}</span>}
                    <button onClick={()=>saveEntries(entries.filter(x=>x.id!==e.id))} style={{background:"none",border:"none",color:C.td,cursor:"pointer",fontSize:13,marginLeft:6,padding:"0 2px"}}
                      onMouseEnter={ev=>ev.currentTarget.style.color=C.rd} onMouseLeave={ev=>ev.currentTarget.style.color=C.td}>×</button>
                  </td>
                </tr>);
              })}
            </tbody>
          </table>
        </div>
      </div>
    )}
  </div>);
}

function PagePontuacao({tasks}){
  const safeTasks = tasks || [];
  const [view, setView] = useState("ranking"); // ranking | timeline | detalhes
  const [selected, setSelected] = useState(null);
  const [animated, setAnimated] = useState(false);

  const animTimer=useRef(null);
  useEffect(()=>{
    animTimer.current=setTimeout(()=>setAnimated(true), 100);
    return ()=>clearTimeout(animTimer.current);
  },[]);

  // ─── Scoring engine ──────────────────────────────
  const calcScore = (uid) => {
    const mt = safeTasks.filter(t=>t.assignee===uid&&!t.deletedAt);
    const done = mt.filter(t=>t.status==="aprovado");
    const active = mt.filter(t=>t.status!=="aprovado"&&t.status!=="pausado");
    const late = active.filter(t=>{
      if(!t.deadline) return false;
      return Math.ceil((new Date(t.deadline)-new Date())/(1000*60*60*24))<0;
    });
    // Rework: tasks that have been in "alteracao" status (indicated by timeline entries)
    const rework = mt.filter(t=>(t.timeline||[]).some(e=>e.to==="alteracao")).length;
    // Avg score
    const scored = done.filter(t=>t.score!=null);
    const avgScore = scored.length>0 ? scored.reduce((s,t)=>s+(t.score||0),0)/scored.length : 0;
    // On time: completed before/on deadline
    const onTime = done.filter(t=>{
      if(!t.deadline||!t.completedAt) return true;
      return new Date(t.completedAt)<=new Date(t.deadline);
    }).length;
    // Avg time per card (days from startDate to completedAt)
    const times = done.filter(t=>t.startDate&&t.completedAt).map(t=>
      Math.ceil((new Date(t.completedAt)-new Date(t.startDate))/(1000*60*60*24))
    );
    const avgDays = times.length>0 ? (times.reduce((a,b)=>a+b,0)/times.length).toFixed(1) : "—";

    // Points
    const entregaPts = done.length>0 ? Math.min(40,Math.round((onTime/done.length)*40)) : 0;
    const qualPts = Math.min(30,Math.round((avgScore/10)*30));
    const volumePts = Math.min(20,done.length*2);
    const atrasoPts = Math.max(0,10-(late.length*2));
    // Penalty: -100 per task that needed reorganization (late + rework combo)
    const reorganizados = mt.filter(t=>
      (t.timeline||[]).some(e=>e.to==="alteracao") &&
      t.deadline && Math.ceil((new Date(t.deadline)-new Date())/(1000*60*60*24))<0
    ).length;
    const penalty = reorganizados * 100;

    const base = Math.min(100, entregaPts+qualPts+volumePts+atrasoPts);
    const total = Math.max(0, base - penalty);

    return {
      entrega:entregaPts, qualidade:qualPts, volume:volumePts, atraso:atrasoPts,
      penalty, reorganizados, rework, base, total,
      done:done.length, late:late.length, active:active.length,
      avgScore:avgScore.toFixed(1), avgDays, totalTasks:mt.length,
      onTime, scored:scored.length,
      history: done.map(t=>({
        id:t.id, title:t.title, client:t.client,
        score:t.score||null,
        startDate:t.startDate, completedAt:t.completedAt,
        deadline:t.deadline,
        days:t.startDate&&t.completedAt?Math.ceil((new Date(t.completedAt)-new Date(t.startDate))/(1000*60*60*24)):null,
        onTime:t.deadline&&t.completedAt?new Date(t.completedAt)<=new Date(t.deadline):true,
        rework:(t.timeline||[]).filter(e=>e.to==="alteracao").length,
      })).sort((a,b)=>new Date(b.completedAt)-new Date(a.completedAt)),
    };
  };

  const members = TEAM.map(u=>({...u, score:calcScore(u.id)}))
    .sort((a,b)=>b.score.total-a.score.total);

  const sel = selected ? members.find(m=>m.id===selected) : null;

  return(<div style={{display:"flex",flexDirection:"column",gap:0,minHeight:"100%"}}>
    <style>{CSS_ANIM}</style>

    {/* ── HERO HEADER ── */}
    <div style={{background:`linear-gradient(135deg,${C.a}18,${C.aD}08)`,borderRadius:20,border:`1px solid ${C.a}33`,padding:"20px 24px",marginBottom:20,position:"relative",overflow:"hidden"}}>
      <div style={{position:"absolute",top:-40,right:-40,width:160,height:160,borderRadius:"50%",background:C.a+"08"}}/>
      <div style={{position:"absolute",bottom:-30,left:60,width:100,height:100,borderRadius:"50%",background:C.a+"06"}}/>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:12}}>
        <div>
          <div style={{color:C.tx,fontWeight:900,fontSize:22,letterSpacing:-.5,display:"flex",alignItems:"center",gap:10}}>
            <span style={{fontSize:28}} className="medal-float">🏆</span>
            Ecossistema de Desempenho
          </div>
          <div style={{color:C.td,fontSize:12,marginTop:4}}>Performance em tempo real · Baseado em entregas, qualidade e comportamento</div>
        </div>
        {/* Top performer highlight */}
        {members[0]&&(<div style={{display:"flex",alignItems:"center",gap:12,background:"rgba(255,255,255,0.08)",borderRadius:14,padding:"10px 16px",border:`1px solid ${C.a}22`}}>
          <div style={{textAlign:"center"}}>
            <div style={{color:C.td,fontSize:9,fontWeight:700,textTransform:"uppercase",letterSpacing:1,marginBottom:3}}>Destaque do Mês</div>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <div style={{width:36,height:36,borderRadius:12,background:members[0].color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:900,fontSize:16}}>
                {members[0].av}
              </div>
              <div>
                <div style={{color:C.tx,fontWeight:700,fontSize:13}}>{members[0].name}</div>
                <div style={{color:scoreColor(members[0].score.total),fontWeight:900,fontSize:18}}>{members[0].score.total} pts</div>
              </div>
            </div>
          </div>
        </div>)}
      </div>

      {/* View switcher */}
      <div style={{display:"flex",gap:4,marginTop:16,background:"rgba(0,0,0,0.08)",borderRadius:12,padding:3,width:"fit-content"}}>
        {VIEWS.map(v=>(
          <button key={v.id} onClick={()=>setView(v.id)}
            style={{background:view===v.id?C.a:"transparent",color:view===v.id?"#fff":C.ts,border:"none",borderRadius:9,padding:"7px 16px",fontSize:12,fontWeight:view===v.id?700:400,cursor:"pointer",transition:"all .2s",whiteSpace:"nowrap"}}>
            {v.label}
          </button>
        ))}
      </div>
    </div>

    {/* ── RANKING VIEW ── */}
    {view==="ranking"&&(<div style={{display:"grid",gridTemplateColumns:sel?"1fr 360px":"1fr",gap:16,alignItems:"start"}}>

      <div style={{background:C.card,borderRadius:18,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
        {/* Table header */}
        <div style={{display:"grid",gridTemplateColumns:"48px 1fr 90px 90px 100px",padding:"10px 20px",background:C.s1,borderBottom:`1px solid ${C.b1}`,gap:8}}>
          {SCORE_TABLE_HEADERS.map((h,i)=>(
            <div key={i} style={{color:C.td,fontSize:9,fontWeight:700,textTransform:"uppercase",letterSpacing:.8,textAlign:i>=2?"center":"left"}}>{h}</div>
          ))}
        </div>

        {members.map((m,rank)=>{
          const s=m.score;
          const col=scoreColor(s.total);
          const isSel=selected===m.id;
          const delay=rank*80;
          return(<div key={m.id}
            className="score-row"
            style={{animationDelay:delay+"ms",display:"grid",gridTemplateColumns:"48px 1fr 90px 90px 100px",padding:"14px 20px",borderBottom:`1px solid ${C.b1}44`,cursor:"pointer",background:isSel?C.a+"0a":"transparent",transition:"background .15s",gap:8,alignItems:"center"}}
            onClick={()=>setSelected(isSel?null:m.id)}
            onMouseEnter={e=>e.currentTarget.style.background=isSel?C.a+"0a":C.s1}
            onMouseLeave={e=>e.currentTarget.style.background=isSel?C.a+"0a":"transparent"}>

            {/* Rank */}
            <div className={rank<3?"badge-pop":""} style={{textAlign:"center",fontSize:rank<3?22:14,lineHeight:1,animationDelay:(delay+200)+"ms"}}>
              {medal(rank)}
            </div>

            {/* Member info */}
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <div style={{width:40,height:40,borderRadius:13,background:m.color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:900,fontSize:17,flexShrink:0,boxShadow:isSel?`0 0 0 3px ${m.color}44`:"none",transition:"box-shadow .2s"}}>
                {m.av}
              </div>
              <div>
                <div style={{color:C.tx,fontWeight:700,fontSize:13}}>{m.name}</div>
                <div style={{display:"flex",gap:6,marginTop:2,flexWrap:"wrap"}}>
                  <span style={{color:C.td,fontSize:10}}>{m.role}</span>
                  {s.late>0&&<span style={{background:C.rd+"18",color:C.rd,borderRadius:99,padding:"0 5px",fontSize:9,fontWeight:700}}>🔥 {s.late} atrasadas</span>}
                  {s.rework>0&&<span style={{background:"#f9731618",color:"#f97316",borderRadius:99,padding:"0 5px",fontSize:9,fontWeight:700}}>🔄 {s.rework} retrabalhos</span>}
                  {s.penalty>0&&<span style={{background:C.rd+"22",color:C.rd,borderRadius:99,padding:"0 5px",fontSize:9,fontWeight:800}}>-{s.penalty}pts penalidade</span>}
                </div>
              </div>
            </div>

            {/* Done */}
            <div style={{textAlign:"center"}}>
              <div style={{color:C.gr,fontWeight:800,fontSize:16}}>{s.done}</div>
              <div style={{color:C.td,fontSize:9}}>aprovadas</div>
            </div>

            {/* Rework */}
            <div style={{textAlign:"center"}}>
              <div style={{color:s.rework>0?C.rd:C.gr,fontWeight:800,fontSize:16}}>{s.rework}</div>
              <div style={{color:C.td,fontSize:9}}>{s.rework===0?"sem retrabalho":"retrabalho(s)"}</div>
            </div>

            {/* Score */}
            <div>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                <span style={{color:col,fontSize:10,fontWeight:700}}>{scoreLabel(s.total)}</span>
                <span style={{color:col,fontWeight:900,fontSize:15}}>{s.total}</span>
              </div>
              <div style={{background:C.b1,borderRadius:99,height:5,overflow:"hidden"}}>
                <div style={{
                  width:animated?s.total+"%":"0%",height:"100%",
                  background:`linear-gradient(90deg,${col},${col}99)`,
                  borderRadius:99,transition:"width 1s cubic-bezier(.22,1,.36,1) "+delay+"ms"
                }}/>
              </div>
            </div>
          </div>);
        })}
      </div>

      {/* ── Detail sidebar ── */}
      {sel&&(<div style={{display:"flex",flexDirection:"column",gap:12,position:"sticky",top:0}}>

        {/* Header */}
        <div style={{background:C.card,borderRadius:18,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
          <div style={{padding:"16px 18px",background:`linear-gradient(135deg,${sel.color}18,${sel.color}08)`,borderBottom:`1px solid ${C.b1}`}}>
            <div style={{display:"flex",alignItems:"center",gap:12}}>
              <div style={{width:50,height:50,borderRadius:16,background:sel.color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:900,fontSize:22,boxShadow:`0 4px 16px ${sel.color}44`}}>
                {sel.av}
              </div>
              <div style={{flex:1}}>
                <div style={{color:C.tx,fontWeight:800,fontSize:16}}>{sel.name}</div>
                <div style={{color:C.td,fontSize:11}}>{sel.role}</div>
              </div>
              <button onClick={()=>setSelected(null)} style={{background:"none",border:"none",color:C.td,cursor:"pointer",fontSize:20,padding:4,lineHeight:1}}>×</button>
            </div>
          </div>

          {/* Big score */}
          <div style={{padding:"20px 18px",textAlign:"center",background:scoreColor(sel.score.total)+"08"}}>
            <div style={{color:scoreColor(sel.score.total),fontWeight:900,fontSize:56,lineHeight:1,letterSpacing:-2}}>{sel.score.total}</div>
            <div style={{color:scoreColor(sel.score.total),fontSize:13,fontWeight:700,marginTop:4}}>{scoreLabel(sel.score.total)}</div>
            {sel.score.penalty>0&&<div style={{marginTop:8,background:C.rd+"18",border:`1px solid ${C.rd}33`,borderRadius:10,padding:"6px 12px",display:"inline-block"}}>
              <span style={{color:C.rd,fontSize:11,fontWeight:700}}>⚠ -{sel.score.penalty}pts penalidade por reorganização</span>
            </div>}
          </div>

          {/* Breakdown bars */}
          <div style={{padding:"14px 18px",display:"flex",flexDirection:"column",gap:10}}>
            {[
              {l:"Entregas no prazo",v:sel.score.entrega,max:40,icon:"✅"},
              {l:"Qualidade",v:sel.score.qualidade,max:30,icon:"⭐"},
              {l:"Volume",v:sel.score.volume,max:20,icon:"📦"},
              {l:"Penalidade atrasos",v:sel.score.atraso,max:10,icon:"⏱"},
            ].map(item=>{
              const pct=Math.round((item.v/item.max)*100);
              const col=pct>=75?C.gr:pct>=50?C.yw:C.rd;
              return(<div key={item.l}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                  <span style={{color:C.tx,fontSize:11,display:"flex",alignItems:"center",gap:4}}>{item.icon} {item.l}</span>
                  <span style={{color:C.a,fontSize:11,fontWeight:700}}>{item.v}/{item.max}</span>
                </div>
                <div style={{background:C.b1,borderRadius:99,height:5,overflow:"hidden"}}>
                  <div style={{width:animated?pct+"%":"0%",height:"100%",background:col,borderRadius:99,transition:"width .9s cubic-bezier(.22,1,.36,1)"}}/>
                </div>
              </div>);
            })}
          </div>

          {/* Stats grid */}
          <div style={{padding:"0 18px 16px",display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:8}}>
            {[
              {l:"Total demandas",v:sel.score.totalTasks,c:C.tx},
              {l:"Aprovadas",v:sel.score.done,c:C.gr},
              {l:"Atrasadas",v:sel.score.late,c:sel.score.late>0?C.rd:C.gr},
              {l:"Retrabalhos",v:sel.score.rework,c:sel.score.rework>0?C.rd:C.gr},
              {l:"Score médio",v:sel.score.avgScore+"/10",c:C.a},
              {l:"Tempo médio",v:sel.score.avgDays+"d",c:C.bl},
            ].map(item=>(
              <div key={item.l} style={{background:C.s1,borderRadius:10,padding:"10px 12px",textAlign:"center"}}>
                <div style={{color:item.c,fontWeight:900,fontSize:18}}>{item.v}</div>
                <div style={{color:C.td,fontSize:9,marginTop:2}}>{item.l}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Recent tasks */}
        {sel.score.history.length>0&&(<div style={{background:C.card,borderRadius:18,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
          <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.b1}`,color:C.tx,fontWeight:700,fontSize:13}}>Últimas entregas</div>
          <div style={{maxHeight:220,overflowY:"auto"}}>
            {sel.score.history.slice(0,6).map((t,i)=>{
              const cl=CLIENTS.find(c=>c.id===t.client);
              return(<div key={t.id} style={{padding:"9px 16px",borderBottom:i<sel.score.history.length-1?`1px solid ${C.b1}33`:"none",display:"flex",gap:10,alignItems:"flex-start"}}>
                <div style={{width:6,height:6,borderRadius:"50%",background:t.onTime?C.gr:C.rd,marginTop:4,flexShrink:0}}/>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{color:C.tx,fontSize:11,fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.title}</div>
                  <div style={{display:"flex",gap:6,marginTop:2,flexWrap:"wrap"}}>
                    {cl&&<span style={{color:C.td,fontSize:9}}>{cl.name}</span>}
                    {t.days&&<span style={{color:C.td,fontSize:9}}>· {t.days}d</span>}
                    {t.rework>0&&<span style={{color:C.rd,fontSize:9}}>· {t.rework}x retrabalho</span>}
                  </div>
                </div>
                {t.score!=null&&<span style={{color:C.a,fontSize:11,fontWeight:800,flexShrink:0}}>{t.score}/10</span>}
              </div>);
            })}
          </div>
        </div>)}
      </div>)}
    </div>)}

    {/* ── TIMELINE / HISTÓRICO VIEW ── */}
    {view==="timeline"&&(<div style={{display:"flex",flexDirection:"column",gap:12}}>
      <div style={{background:C.card,borderRadius:18,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
        <div style={{padding:"14px 20px",borderBottom:`1px solid ${C.b1}`,color:C.tx,fontWeight:700,fontSize:14}}>Histórico de Entregas — Todos os colaboradores</div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
            <thead>
              <tr style={{background:C.s1}}>
                {TIMELINE_TABLE_HEADERS.map(h=>(
                  <th key={h} style={{padding:"10px 14px",textAlign:"left",color:C.td,fontWeight:700,fontSize:10,textTransform:"uppercase",letterSpacing:.6,borderBottom:`1px solid ${C.b1}`,whiteSpace:"nowrap"}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {safeTasks.filter(t=>t.status==="aprovado"&&!t.deletedAt)
                .sort((a,b)=>new Date(b.completedAt)-new Date(a.completedAt))
                .map((t,i)=>{
                  const u=TEAM.find(u=>u.id===t.assignee);
                  const cl=CLIENTS.find(c=>c.id===t.client);
                  const days=t.startDate&&t.completedAt?Math.ceil((new Date(t.completedAt)-new Date(t.startDate))/(1000*60*60*24)):null;
                  const onTime=t.deadline&&t.completedAt?new Date(t.completedAt)<=new Date(t.deadline):true;
                  const rework=(t.timeline||[]).filter(e=>e.to==="alteracao").length;
                  return(<tr key={t.id} style={{borderBottom:`1px solid ${C.b1}22`,background:i%2===0?"transparent":C.s1+"44"}}>
                    <td style={{padding:"9px 14px",color:C.tx,fontWeight:500,maxWidth:200}}>
                      <div style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{t.title}</div>
                    </td>
                    <td style={{padding:"9px 14px"}}>
                      {cl&&<span style={{background:cl.color+"18",color:cl.color,borderRadius:6,padding:"1px 7px",fontSize:10,fontWeight:700}}>{cl.name}</span>}
                    </td>
                    <td style={{padding:"9px 14px"}}>
                      {u&&<div style={{display:"flex",alignItems:"center",gap:5}}>
                        <div style={{width:20,height:20,borderRadius:"50%",background:u.color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontSize:9,fontWeight:900}}>{u.av}</div>
                        <span style={{color:C.tx,fontSize:11}}>{u.name}</span>
                      </div>}
                    </td>
                    <td style={{padding:"9px 14px",color:C.td,fontSize:10,whiteSpace:"nowrap"}}>{t.startDate?new Date(t.startDate).toLocaleDateString("pt-BR"):"—"}</td>
                    <td style={{padding:"9px 14px",color:C.td,fontSize:10,whiteSpace:"nowrap"}}>{t.deadline?new Date(t.deadline).toLocaleDateString("pt-BR"):"—"}</td>
                    <td style={{padding:"9px 14px",color:C.td,fontSize:10,whiteSpace:"nowrap"}}>{t.completedAt?new Date(t.completedAt).toLocaleDateString("pt-BR"):"—"}</td>
                    <td style={{padding:"9px 14px",textAlign:"center"}}>
                      <span style={{color:days!=null?(days<=3?C.gr:days<=7?C.yw:C.rd):C.td,fontWeight:700,fontSize:12}}>{days!=null?days+"d":"—"}</span>
                    </td>
                    <td style={{padding:"9px 14px",textAlign:"center"}}>
                      <span style={{color:rework>0?C.rd:C.gr,fontWeight:700,fontSize:12}}>{rework>0?"🔄 "+rework:"—"}</span>
                    </td>
                    <td style={{padding:"9px 14px",textAlign:"center"}}>
                      <span style={{color:C.a,fontWeight:800,fontSize:12}}>{t.score!=null?t.score+"/10":"—"}</span>
                    </td>
                    <td style={{padding:"9px 14px",textAlign:"center"}}>
                      <span style={{background:onTime?C.gr+"18":C.rd+"18",color:onTime?C.gr:C.rd,borderRadius:6,padding:"2px 8px",fontSize:9,fontWeight:700}}>
                        {onTime?"No prazo":"Atrasado"}
                      </span>
                    </td>
                  </tr>);
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>)}

    {/* ── INSIGHTS VIEW ── */}
    {view==="insights"&&(<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:16}}>

      {/* Avg delivery time per member */}
      <div style={{background:C.card,borderRadius:16,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
        <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.b1}`,color:C.tx,fontWeight:700,fontSize:13}}>⏱ Tempo médio de entrega</div>
        <div style={{padding:"12px 16px",display:"flex",flexDirection:"column",gap:10}}>
          {members.filter(m=>m.score.avgDays!=="—").sort((a,b)=>parseFloat(a.score.avgDays)-parseFloat(b.score.avgDays)).map(m=>(
            <div key={m.id} style={{display:"flex",alignItems:"center",gap:8}}>
              <div style={{width:24,height:24,borderRadius:8,background:m.color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontSize:10,fontWeight:900,flexShrink:0}}>{m.av}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                  <span style={{color:C.tx,fontSize:11}}>{m.name}</span>
                  <span style={{color:C.bl,fontWeight:700,fontSize:11}}>{m.score.avgDays}d</span>
                </div>
                <div style={{background:C.b1,borderRadius:99,height:4,overflow:"hidden"}}>
                  <div style={{width:animated?Math.min(100,(parseFloat(m.score.avgDays)||0)/14*100)+"%":"0%",height:"100%",background:C.bl,borderRadius:99,transition:"width .8s ease"}}/>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Rework ranking */}
      <div style={{background:C.card,borderRadius:16,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
        <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.b1}`,color:C.tx,fontWeight:700,fontSize:13}}>🔄 Retrabalhos por colaborador</div>
        <div style={{padding:"12px 16px",display:"flex",flexDirection:"column",gap:10}}>
          {members.map(m=>(
            <div key={m.id} style={{display:"flex",alignItems:"center",gap:8}}>
              <div style={{width:24,height:24,borderRadius:8,background:m.color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontSize:10,fontWeight:900,flexShrink:0}}>{m.av}</div>
              <div style={{flex:1}}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                  <span style={{color:C.tx,fontSize:11}}>{m.name}</span>
                  <span style={{color:m.score.rework>0?C.rd:C.gr,fontWeight:700,fontSize:11}}>{m.score.rework>0?m.score.rework+"x":"✓"}</span>
                </div>
                <div style={{background:C.b1,borderRadius:99,height:4,overflow:"hidden"}}>
                  <div style={{width:animated?Math.min(100,(m.score.rework/Math.max(1,Math.max(...members.map(x=>x.score.rework))))*100)+"%":"0%",height:"100%",background:m.score.rework>0?C.rd:C.gr,borderRadius:99,transition:"width .8s ease"}}/>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Score distribution */}
      <div style={{background:C.card,borderRadius:16,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
        <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.b1}`,color:C.tx,fontWeight:700,fontSize:13}}>📊 Distribuição de scores</div>
        <div style={{padding:"16px",display:"flex",flexDirection:"column",gap:12}}>
          {SCORE_BANDS.map(band=>{
            const count=members.filter(m=>m.score.total>=band.min&&m.score.total<=band.max).length;
            const pct=Math.round((count/members.length)*100);
            return(<div key={band.l}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                <span style={{color:band.c,fontSize:11,fontWeight:700}}>{band.l} ({band.min}-{band.max}pts)</span>
                <span style={{color:C.td,fontSize:11}}>{count} pessoa(s)</span>
              </div>
              <div style={{background:C.b1,borderRadius:99,height:6,overflow:"hidden"}}>
                <div style={{width:animated?pct+"%":"0%",height:"100%",background:band.c,borderRadius:99,transition:"width .8s ease"}}/>
              </div>
            </div>);
          })}
        </div>
      </div>

      {/* Penalty summary */}
      <div style={{background:C.card,borderRadius:16,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
        <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.b1}`,display:"flex",alignItems:"center",gap:6}}>
          <span style={{fontSize:14}}>⚠</span>
          <span style={{color:C.tx,fontWeight:700,fontSize:13}}>Penalidades aplicadas</span>
        </div>
        <div style={{padding:"12px 16px",display:"flex",flexDirection:"column",gap:8}}>
          {members.filter(m=>m.score.penalty>0).length===0?(
            <div style={{color:C.gr,fontSize:12,textAlign:"center",padding:"16px",display:"flex",flexDirection:"column",alignItems:"center",gap:6}}>
              <span style={{fontSize:28}}>🎉</span>
              Nenhuma penalidade este mês!
            </div>
          ):members.filter(m=>m.score.penalty>0).map(m=>(
            <div key={m.id} style={{background:C.rd+"08",border:`1px solid ${C.rd}22`,borderRadius:10,padding:"10px 12px",display:"flex",alignItems:"center",gap:10}}>
              <div style={{width:30,height:30,borderRadius:10,background:m.color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:900,fontSize:14,flexShrink:0}}>{m.av}</div>
              <div style={{flex:1}}>
                <div style={{color:C.tx,fontWeight:600,fontSize:12}}>{m.name}</div>
                <div style={{color:C.td,fontSize:10}}>{m.score.reorganizados} demanda(s) com reorganização</div>
              </div>
              <div style={{color:C.rd,fontWeight:900,fontSize:15}}>-{m.score.penalty}</div>
            </div>
          ))}
          <div style={{background:C.s1,borderRadius:10,padding:"10px 12px",marginTop:4}}>
            <div style={{color:C.td,fontSize:10,fontWeight:700,marginBottom:4}}>Regra de penalidade</div>
            <div style={{color:C.ts,fontSize:11,lineHeight:1.5}}>-100 pontos por demanda que precisou de reorganização (combinação de retrabalho + atraso). Incentiva qualidade desde o início.</div>
          </div>
        </div>
      </div>
    </div>)}

    {/* ── ROI VIEW ── */}
    {view==="roi"&&(<div style={{display:"flex",flexDirection:"column",gap:16}}>
      <div style={{background:C.a+"12",border:"1px solid "+C.a+"33",borderRadius:14,padding:"14px 18px",display:"flex",alignItems:"center",gap:10}}>
        <div>
          <div style={{color:C.tx,fontWeight:700,fontSize:13}}>Custo vs Producao</div>
          <div style={{color:C.td,fontSize:11,marginTop:2}}>Compare o salario de cada colaborador com o valor estimado que esta produzindo. Referencia: R$80/hora de producao criativa.</div>
        </div>
      </div>
      {members.map((m,rank)=>{
        const s=m.score;
        const valorProduzido = s.done * VALOR_POR_TAREFA;
        const salario = SALARIOS[m.id] || 3000;
        const roiNum = salario > 0 ? parseFloat(((valorProduzido - salario) / salario * 100).toFixed(0)) : 0;
        const roiColor = roiNum >= 50 ? C.gr : roiNum >= 0 ? C.yw : C.rd;
        const roiLabel = roiNum >= 100 ? "Excelente ROI" : roiNum >= 50 ? "Bom ROI" : roiNum >= 0 ? "ROI neutro" : "ROI negativo";
        const pctProd = Math.min(100, Math.round((valorProduzido/Math.max(salario,1))*50));
        const sinal = valorProduzido >= salario ? "+" : "-";
        const resultadoStr = sinal + "R$" + Math.abs(valorProduzido - salario).toLocaleString("pt-BR");
        return(<div key={m.id} style={{background:C.card,borderRadius:16,border:"1px solid "+(roiNum<0?C.rd+"44":C.b1),overflow:"hidden",marginBottom:12}}>
          <div style={{padding:"14px 18px",borderBottom:"1px solid "+C.b1,display:"flex",alignItems:"center",gap:12,background:roiNum<0?C.rd+"08":"transparent"}}>
            <div style={{width:42,height:42,borderRadius:13,background:m.color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:900,fontSize:18,flexShrink:0}}>{m.av}</div>
            <div style={{flex:1}}>
              <div style={{color:C.tx,fontWeight:700,fontSize:14}}>{m.name}</div>
              <div style={{color:C.td,fontSize:11}}>{m.role} · #{rank+1} no ranking</div>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{color:roiColor,fontWeight:900,fontSize:20}}>{roiNum>0?"+":""}{roiNum}%</div>
              <div style={{color:roiColor,fontSize:11,fontWeight:600}}>{roiLabel}</div>
            </div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",borderBottom:"1px solid "+C.b1}}>
            {[
              {l:"Salario Mensal",v:"R$"+salario.toLocaleString("pt-BR"),c:C.rd},
              {l:"Producao Estimada",v:"R$"+valorProduzido.toLocaleString("pt-BR"),c:C.gr},
              {l:"Resultado",v:resultadoStr,c:roiColor},
            ].map((item,idx)=>(
              <div key={idx} style={{padding:"14px 18px",borderRight:idx<2?"1px solid "+C.b1:"none",textAlign:"center"}}>
                <div style={{color:item.c,fontWeight:900,fontSize:18}}>{item.v}</div>
                <div style={{color:C.td,fontSize:10,marginTop:3}}>{item.l}</div>
              </div>
            ))}
          </div>
          <div style={{padding:"12px 18px"}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
              <span style={{color:C.td,fontSize:11}}>Producao vs Salario</span>
              <span style={{color:C.td,fontSize:11}}>{s.done} demandas x R${VALOR_POR_TAREFA}</span>
            </div>
            <div style={{background:C.b1,borderRadius:99,height:8,overflow:"hidden"}}>
              <div style={{width:pctProd+"%",height:"100%",background:roiColor,borderRadius:99,transition:"width .8s ease"}}/>
            </div>
            <div style={{display:"flex",justifyContent:"space-between",marginTop:3}}>
              <span style={{color:C.td,fontSize:9}}>Custo: R${salario.toLocaleString("pt-BR")}</span>
              <span style={{color:roiColor,fontSize:9,fontWeight:700}}>Produz: R${valorProduzido.toLocaleString("pt-BR")}</span>
            </div>
          </div>
        </div>);
      })}
    </div>)}

    {/* ── USO DO APP — ranking de minutos/horas (gamificação) ── */}
    {view==="uso"&&<UsoDoAppView/>}

  </div>);
}

/* ─── USO DO APP — ranking gamificado de tempo no app ─── */
function UsoDoAppView(){
  const sb=window._sb;
  const [activity,setActivity]=useState([]);
  const [presence,setPresence]=useState({});
  const [loading,setLoading]=useState(true);
  const [error,setError]=useState(null);
  const [refreshing,setRefreshing]=useState(false);
  const [lastFetch,setLastFetch]=useState(null);

  const fetchData=async()=>{
    if(!sb){setError("Supabase não disponível");setLoading(false);return;}
    setRefreshing(true);
    try{
      const [actRes,presRes]=await Promise.all([
        sb.from("user_activity_daily").select("*"),
        sb.from("user_presence").select("*"),
      ]);
      if(actRes.error)throw actRes.error;
      setActivity(actRes.data||[]);
      const pmap={};
      (presRes.data||[]).forEach(r=>{pmap[r.user_id]=r;});
      setPresence(pmap);
      setError(null);
      setLastFetch(new Date());
    }catch(e){setError(e?.message||"Erro ao carregar atividade");}
    setLoading(false);
    setRefreshing(false);
  };

  useEffect(()=>{
    fetchData();
    // Auto-refresh a cada 60s pra ver os minutos da equipe atualizando em tempo real
    const i=setInterval(fetchData,60000);
    return()=>clearInterval(i);
  },[]);

  if(loading)return<div style={{padding:40,textAlign:"center",color:C.td,fontSize:12}}>Carregando ranking de uso...</div>;
  if(error)return<div style={{padding:20,background:"#fef2f2",border:"0.5px solid #fecaca",borderRadius:12,color:"#991b1b",fontSize:12}}>
    <strong>Tabela ainda não criada no Supabase.</strong><br/>Rode o SQL pra criar <code>user_activity_daily</code>. Erro: {error}
  </div>;

  // Datas de referência
  const today=new Date();today.setHours(0,0,0,0);
  const todayStr=today.toISOString().split("T")[0];
  const weekStart=new Date(today);weekStart.setDate(today.getDate()-6); // últimos 7 dias incluindo hoje
  const monthStart=new Date(today);monthStart.setDate(today.getDate()-29); // últimos 30 dias

  // Calcula stats por usuário
  const stats=TEAM.map(m=>{
    const rows=activity.filter(a=>a.user_id===m.id);
    const today_min=rows.find(a=>a.day===todayStr)?.minutes_active||0;
    const week_min=rows.filter(a=>{const d=new Date(a.day+"T00:00:00");return d>=weekStart&&d<=today;}).reduce((s,a)=>s+(a.minutes_active||0),0);
    const month_min=rows.filter(a=>{const d=new Date(a.day+"T00:00:00");return d>=monthStart&&d<=today;}).reduce((s,a)=>s+(a.minutes_active||0),0);
    const total_min=rows.reduce((s,a)=>s+(a.minutes_active||0),0);
    // Streak: dias seguidos com atividade (a partir de hoje pra trás)
    const days=new Set(rows.filter(a=>(a.minutes_active||0)>0).map(a=>a.day));
    let streak=0;
    for(let i=0;i<365;i++){
      const d=new Date(today);d.setDate(today.getDate()-i);
      const ds=d.toISOString().split("T")[0];
      if(days.has(ds))streak++;
      else if(i>0)break; // permite que hoje ainda esteja zerado mas streak conta de ontem pra trás
    }
    const lastSeen=presence[m.id]?.last_seen_at;
    const ps=getPresenceStatus(lastSeen);
    return{user:m,today_min,week_min,month_min,total_min,streak,ps,lastSeen};
  });

  // Ranking ordenado por mês (principal), desempate por total
  const ranked=[...stats].sort((a,b)=>b.month_min-a.month_min||b.total_min-a.total_min);
  const totalEquipe=stats.reduce((s,x)=>s+x.month_min,0);
  const maxMonth=Math.max(1,...stats.map(x=>x.month_min));

  const fmtTime=(min)=>{
    if(min<60)return min+"min";
    const h=Math.floor(min/60);
    const m=min%60;
    if(m===0)return h+"h";
    return h+"h"+String(m).padStart(2,"0");
  };

  // Classificação de engajamento (média diária do mês)
  const tier=(monthMin)=>{
    const avgDay=monthMin/30;
    if(avgDay>=180)return{label:"Power User",color:"#a140ff",emoji:"🔥"};
    if(avgDay>=60)return{label:"Engajado",color:"#16a34a",emoji:"💚"};
    if(avgDay>=30)return{label:"Frequência ok",color:"#eab308",emoji:"👍"};
    if(avgDay>0)return{label:"Pouco uso",color:"#f97316",emoji:"📉"};
    return{label:"Sem registro",color:"#94a3b8",emoji:"💤"};
  };

  return(
    <div style={{display:"flex",flexDirection:"column",gap:16}}>
      {/* Header com totalizador */}
      <div style={{background:"linear-gradient(135deg,#a140ff10,#a140ff05)",border:"0.5px solid #e9d5ff",borderRadius:14,padding:"16px 20px",display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:12}}>
        <div>
          <div style={{color:"#a140ff",fontSize:11,fontWeight:600,textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>Engajamento da equipe</div>
          <div style={{color:C.tx,fontWeight:600,fontSize:18}}>{fmtTime(totalEquipe)} de uso nos últimos 30 dias</div>
          <div style={{color:C.td,fontSize:12,marginTop:2}}>Quanto mais tempo no app, mais engajamento — quem aparece pouco precisa de check-in.</div>
        </div>
        <div style={{textAlign:"right"}}>
          <div style={{color:"#a140ff",fontSize:32,fontWeight:600,lineHeight:1}}>{stats.filter(s=>s.month_min>0).length}<span style={{color:C.td,fontSize:14,fontWeight:400}}>/{TEAM.length}</span></div>
          <div style={{color:C.td,fontSize:11,marginTop:2}}>ativos este mês</div>
        </div>
      </div>

      {/* Ranking */}
      <div style={{background:C.card,borderRadius:14,border:"0.5px solid "+C.b1,overflow:"hidden"}}>
        <div style={{padding:"14px 20px",borderBottom:"0.5px solid "+C.b1,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div>
            <div style={{color:C.tx,fontWeight:600,fontSize:14}}>Ranking · 30 dias</div>
            <div style={{color:C.td,fontSize:11,marginTop:2}}>
              Ordenado por tempo de uso no mês
              {lastFetch&&<span style={{marginLeft:8,color:"#a140ff"}}>· atualizado às {lastFetch.toLocaleTimeString("pt-BR",{hour:"2-digit",minute:"2-digit",second:"2-digit"})}</span>}
            </div>
          </div>
          <button onClick={fetchData} disabled={refreshing}
            style={{background:refreshing?"#e5e7eb":"#a140ff",color:refreshing?"#94a3b8":"#fff",border:"none",borderRadius:8,padding:"7px 14px",fontSize:11,fontWeight:500,cursor:refreshing?"wait":"pointer",display:"flex",alignItems:"center",gap:6}}>
            {refreshing?"Atualizando...":"↻ Atualizar agora"}
          </button>
        </div>
        {ranked.map((s,rank)=>{
          const t=tier(s.month_min);
          const pct=Math.round((s.month_min/maxMonth)*100);
          const isTop3=rank<3;
          const med=rank===0?"🥇":rank===1?"🥈":rank===2?"🥉":"";
          return(
            <div key={s.user.id} style={{display:"grid",gridTemplateColumns:"50px 1fr 100px 100px 100px 110px",gap:10,padding:"14px 20px",borderBottom:rank<ranked.length-1?"0.5px solid "+C.b1:"none",alignItems:"center",background:isTop3?"#a140ff05":"transparent",transition:"background .15s"}}>
              {/* Posição/medalha */}
              <div style={{textAlign:"center"}}>
                {med?<span style={{fontSize:22}}>{med}</span>:<span style={{color:C.td,fontWeight:500,fontSize:13}}>#{rank+1}</span>}
              </div>
              {/* Avatar + nome + status */}
              <div style={{display:"flex",alignItems:"center",gap:10,minWidth:0}}>
                <div style={{position:"relative",flexShrink:0}}>
                  <div style={{width:34,height:34,borderRadius:"50%",background:s.user.color,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:600,fontSize:13}}>{s.user.av}</div>
                  <div style={{position:"absolute",bottom:-1,right:-1,width:11,height:11,borderRadius:"50%",background:s.ps.color,border:`2px solid ${C.card}`}}/>
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{color:C.tx,fontWeight:500,fontSize:13,lineHeight:1.2}}>{s.user.name}</div>
                  <div style={{color:t.color,fontSize:10,fontWeight:500,marginTop:2}}>{t.emoji} {t.label}</div>
                </div>
              </div>
              {/* Hoje */}
              <div style={{textAlign:"center"}}>
                <div style={{color:s.today_min>0?C.tx:C.td,fontSize:14,fontWeight:s.today_min>0?500:400}}>{s.today_min>0?fmtTime(s.today_min):"—"}</div>
                <div style={{color:C.td,fontSize:9,marginTop:2}}>hoje</div>
              </div>
              {/* Semana */}
              <div style={{textAlign:"center"}}>
                <div style={{color:s.week_min>0?C.tx:C.td,fontSize:14,fontWeight:s.week_min>0?500:400}}>{s.week_min>0?fmtTime(s.week_min):"—"}</div>
                <div style={{color:C.td,fontSize:9,marginTop:2}}>7 dias</div>
              </div>
              {/* Mês — destaque */}
              <div style={{textAlign:"center"}}>
                <div style={{color:s.month_min>0?"#a140ff":C.td,fontSize:18,fontWeight:600,lineHeight:1.1}}>{s.month_min>0?fmtTime(s.month_min):"—"}</div>
                <div style={{height:4,background:C.b1,borderRadius:99,overflow:"hidden",marginTop:5}}>
                  <div style={{width:pct+"%",height:"100%",background:"#a140ff",borderRadius:99,transition:"width .6s ease"}}/>
                </div>
              </div>
              {/* Streak */}
              <div style={{textAlign:"center"}}>
                <div style={{color:s.streak>0?"#f97316":C.td,fontSize:14,fontWeight:s.streak>=7?600:500}}>
                  {s.streak>0?<>🔥 {s.streak}d</>:"—"}
                </div>
                <div style={{color:C.td,fontSize:9,marginTop:2}}>{s.streak>=7?"streak":"dias seguidos"}</div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Legenda + nota técnica */}
      <div style={{background:C.s1,border:"0.5px solid "+C.b1,borderRadius:12,padding:"12px 16px",display:"flex",flexDirection:"column",gap:8}}>
        <div style={{color:C.td,fontSize:11,fontWeight:600,textTransform:"uppercase",letterSpacing:.5}}>Como funciona</div>
        <div style={{color:C.ts,fontSize:11,lineHeight:1.6}}>
          A cada minuto que a pessoa está com a aba do app aberta e ativa, contamos +1 minuto. Aba em segundo plano não conta.
          Streak é o número de dias seguidos com pelo menos 1 minuto de uso (rompe se ficar 1 dia inteiro sem abrir).
        </div>
      </div>
    </div>
  );
}

/* ─── PAGE CONTAGEM DA EQUIPE — visão admin (sócio) ─────────── */
function PageContagemEquipe({isMob}){
  const [items,setItems]=useState([]);
  const [loading,setLoading]=useState(true);
  const [drillUserId,setDrillUserId]=useState(null);
  const [month,setMonth]=useState(()=>{
    const d=new Date();
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`;
  });

  useEffect(()=>{
    let active=true;
    setLoading(true);
    const sb=window._sb;
    if(!sb){setLoading(false);return;}
    const [y,m]=month.split("-").map(Number);
    const start=new Date(y,m-1,1).toISOString();
    const end=new Date(y,m,1).toISOString();
    sb.from("demand_history")
      .select("*")
      .gte("approved_at",start)
      .lt("approved_at",end)
      .order("approved_at",{ascending:false})
      .then(({data,error})=>{
        if(!active)return;
        if(error){console.warn("[contagem-equipe] fetch:",error.message);setLoading(false);return;}
        setItems(data||[]);
        setLoading(false);
      });
    return()=>{active=false;};
  },[month]);

  const prevMonth=()=>{
    const [y,m]=month.split("-").map(Number);
    const d=new Date(y,m-2,1);
    setMonth(`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`);
  };
  const nextMonth=()=>{
    const [y,m]=month.split("-").map(Number);
    const d=new Date(y,m,1);
    setMonth(`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`);
  };
  const monthLabel=(()=>{
    const [y,m]=month.split("-").map(Number);
    const lbl=new Date(y,m-1,1).toLocaleDateString("pt-BR",{month:"long",year:"numeric"});
    return lbl.charAt(0).toUpperCase()+lbl.slice(1);
  })();

  // Equipe que recebe por demanda
  const equipe=TEAM.filter(u=>u.pagamentoPorDemanda);
  // Agrega por colaborador
  const stats=equipe.map(u=>{
    const userItems=items.filter(i=>i.assignee_id===u.id);
    const cliente=userItems.filter(i=>i.approval_type==="cliente").length;
    const interna=userItems.filter(i=>i.approval_type==="interna").length;
    return {user:u,items:userItems,total:userItems.length,cliente,interna};
  });
  const totalAgencia=stats.reduce((a,s)=>a+s.total,0);

  // Drill-down view
  if(drillUserId){
    const drill=stats.find(s=>s.user.id===drillUserId);
    if(!drill)return null;
    return <div style={{display:"flex",flexDirection:"column",gap:14,maxWidth:860,margin:"0 auto",width:"100%"}}>
      <button onClick={()=>setDrillUserId(null)} style={{alignSelf:"flex-start",background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:8,padding:"6px 12px",cursor:"pointer",fontSize:12,color:"#64748b"}}>← voltar</button>
      <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"14px 18px"}}>
        <div style={{fontSize:18,fontWeight:600,color:"#0f172a"}}>{drill.user.name}</div>
        <div style={{fontSize:12,color:"#94a3b8",marginTop:2}}>{drill.user.role} · {monthLabel}</div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
        <div style={{background:"#f8fafc",border:"0.5px solid #e5e7eb",borderRadius:10,padding:"14px 16px"}}>
          <div style={{fontSize:10,color:"#64748b",fontWeight:500,textTransform:"uppercase",letterSpacing:.4,marginBottom:6}}>Total</div>
          <div style={{fontSize:28,fontWeight:600,color:"#0f172a"}}>{drill.total}</div>
        </div>
        <div style={{background:"#f0fdf4",border:"0.5px solid #bbf7d0",borderRadius:10,padding:"14px 16px"}}>
          <div style={{fontSize:10,color:"#15803d",fontWeight:500,textTransform:"uppercase",letterSpacing:.4,marginBottom:6}}>Cliente</div>
          <div style={{fontSize:28,fontWeight:600,color:"#15803d"}}>{drill.cliente}</div>
        </div>
        <div style={{background:"#faf5ff",border:"0.5px solid #e9d5ff",borderRadius:10,padding:"14px 16px"}}>
          <div style={{fontSize:10,color:"#7c3aed",fontWeight:500,textTransform:"uppercase",letterSpacing:.4,marginBottom:6}}>Interna</div>
          <div style={{fontSize:28,fontWeight:600,color:"#7c3aed"}}>{drill.interna}</div>
        </div>
      </div>
      {drill.items.length===0?(
        <div style={{textAlign:"center",padding:40,color:"#94a3b8",fontSize:13,background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12}}>Sem demandas aprovadas neste mês.</div>
      ):(
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {drill.items.map(it=>(
            <div key={it.id} style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:8,padding:"11px 14px"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:10,marginBottom:5}}>
                <div style={{fontSize:13,fontWeight:500,minWidth:0,flex:1,color:"#0f172a"}}>{it.task_title||"(sem título)"}</div>
                <span style={{background:it.approval_type==="cliente"?"#dcfce7":"#ede9fe",color:it.approval_type==="cliente"?"#15803d":"#7c3aed",fontSize:9,fontWeight:600,padding:"2px 7px",borderRadius:4,whiteSpace:"nowrap",textTransform:"uppercase",letterSpacing:.4}}>{it.approval_type==="cliente"?"Cliente":"Interna"}</span>
              </div>
              {it.task_description&&<div style={{fontSize:11,color:"#64748b",lineHeight:1.5,marginBottom:6,whiteSpace:"pre-wrap",wordBreak:"break-word"}}>{it.task_description.length>240?it.task_description.slice(0,240)+"…":it.task_description}</div>}
              <div style={{display:"flex",gap:8,fontSize:10,color:"#94a3b8",flexWrap:"wrap",alignItems:"center"}}>
                {it.client_name&&<><span style={{fontWeight:500}}>{it.client_name}</span><span>·</span></>}
                <span>Aprovado em {new Date(it.approved_at).toLocaleDateString("pt-BR")}</span>
                {it.approved_by&&<><span>·</span><span>por {it.approved_by}</span></>}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>;
  }

  // Consolidated view
  return <div style={{display:"flex",flexDirection:"column",gap:14,maxWidth:860,margin:"0 auto",width:"100%"}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,padding:"12px 14px",flexWrap:"wrap",gap:8}}>
      <div>
        <div style={{fontSize:16,fontWeight:600,color:"#0f172a"}}>Contagem da equipe — {monthLabel}</div>
        <div style={{fontSize:11,color:"#94a3b8",marginTop:2}}>Total da agência: <span style={{color:"#a140ff",fontWeight:600}}>{totalAgencia}</span> demandas aprovadas</div>
      </div>
      <div style={{display:"flex",gap:6}}>
        <button onClick={prevMonth} style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:6,padding:"5px 12px",cursor:"pointer",fontSize:12,color:"#64748b"}}>‹ anterior</button>
        <button onClick={()=>{const d=new Date();setMonth(`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`);}} style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:6,padding:"5px 12px",cursor:"pointer",fontSize:12,color:"#64748b"}}>Hoje</button>
        <button onClick={nextMonth} style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:6,padding:"5px 12px",cursor:"pointer",fontSize:12,color:"#64748b"}}>próximo ›</button>
      </div>
    </div>

    {loading?(
      <div style={{textAlign:"center",padding:40,color:"#94a3b8",fontSize:13,background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12}}>Carregando histórico...</div>
    ):(
      <div style={{background:"#fff",border:"0.5px solid #e5e7eb",borderRadius:12,overflow:"hidden"}}>
        <div style={{padding:"10px 14px",borderBottom:"0.5px solid #e5e7eb",display:"grid",gridTemplateColumns:"1fr 80px 80px 80px 32px",gap:10,fontSize:10,fontWeight:600,color:"#94a3b8",textTransform:"uppercase",letterSpacing:.4}}>
          <span>Colaborador</span>
          <span>Cliente</span>
          <span>Interna</span>
          <span style={{textAlign:"right"}}>Total</span>
          <span></span>
        </div>
        {stats.map(s=>(
          <div key={s.user.id} onClick={()=>setDrillUserId(s.user.id)} style={{padding:"12px 14px",display:"grid",gridTemplateColumns:"1fr 80px 80px 80px 32px",gap:10,alignItems:"center",borderBottom:"0.5px solid #f1f5f9",cursor:"pointer",transition:"background .15s"}} onMouseEnter={e=>e.currentTarget.style.background="#f8fafc"} onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
            <div style={{display:"flex",alignItems:"center",gap:9,minWidth:0}}>
              <div style={{width:26,height:26,borderRadius:"50%",background:s.user.color,color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:600,fontSize:11,flexShrink:0}}>{s.user.av}</div>
              <div style={{minWidth:0}}>
                <div style={{fontSize:13,fontWeight:500,color:"#0f172a"}}>{s.user.name}</div>
                <div style={{fontSize:10,color:"#94a3b8"}}>{s.user.role}</div>
              </div>
            </div>
            <span style={{fontSize:12,color:"#15803d",fontWeight:500}}>{s.cliente}</span>
            <span style={{fontSize:12,color:"#7c3aed",fontWeight:500}}>{s.interna}</span>
            <span style={{fontSize:14,fontWeight:600,color:"#0f172a",textAlign:"right"}}>{s.total}</span>
            <span style={{color:"#cbd5e1",fontSize:14,textAlign:"center"}}>›</span>
          </div>
        ))}
      </div>
    )}
  </div>;
}


/* ═══════════════════════════════════════════════════════════════════
   PAGE SPRINT CONFIG — admin pra editar regras globais de sprint
═══════════════════════════════════════════════════════════════════ */
function PageSprintConfig({isMob}){
  const [cfg,setCfg]=useState(null);
  const [loading,setLoading]=useState(true);
  const [saving,setSaving]=useState(false);
  const [sprintPreview,setSprintPreview]=useState(null);

  // Carrega config do Supabase
  useEffect(function(){
    let active=true;
    (async function(){
      try{
        if(window._sb){
          const {data,error}=await window._sb.from("sprint_config").select("*").eq("id",1).single();
          if(!active)return;
          if(error||!data){
            setCfg({...SPRINT_CONFIG_DEFAULT});
          }else{
            setCfg(data);
          }
        }else{
          setCfg({...SPRINT_CONFIG_DEFAULT});
        }
      }catch(e){
        if(active)setCfg({...SPRINT_CONFIG_DEFAULT});
      }
      if(active)setLoading(false);
    })();
    return function(){active=false;};
  },[]);

  // Calcula preview da sprint atual + da sprint da próxima demanda
  useEffect(function(){
    if(!cfg)return;
    setSprintPreview({
      atual: sprintAtual(cfg),
      proxima_demanda: sprintParaDemanda(new Date(),cfg),
    });
  },[cfg]);

  const _set=function(field,value){setCfg(function(prev){return Object.assign({},prev,{[field]:value});});};

  const handleSave=async function(){
    if(!cfg||saving)return;
    setSaving(true);
    try{
      if(window._sb){
        const payload={
          dia_inicio:cfg.dia_inicio,
          dia_limite:cfg.dia_limite,
          horario_limite:cfg.horario_limite,
          prazo_padrao_dias:cfg.prazo_padrao_dias,
          texto_cliente:cfg.texto_cliente,
          texto_aguardando:cfg.texto_aguardando,
          texto_urgente:cfg.texto_urgente,
          updated_at:new Date().toISOString(),
        };
        const {error}=await window._sb.from("sprint_config").update(payload).eq("id",1);
        if(error)throw error;
        if(typeof invalidateSprintConfigCache==="function")invalidateSprintConfigCache();
        if(typeof pixelsToast!=="undefined")pixelsToast.success("Configuração de sprint salva!",3000);
      }
    }catch(e){
      if(typeof pixelsToast!=="undefined")pixelsToast.error("Erro ao salvar: "+(e.message||e),5000);
    }finally{
      setSaving(false);
    }
  };

  if(loading){
    return <div style={{padding:"40px 20px",textAlign:"center",color:"#94a3b8"}}>Carregando configuração...</div>;
  }
  if(!cfg)return <div style={{padding:"40px 20px",color:"#dc2626"}}>Não foi possível carregar a configuração.</div>;

  const diasSemana=[
    {v:0,l:"Domingo"},{v:1,l:"Segunda"},{v:2,l:"Terça"},{v:3,l:"Quarta"},
    {v:4,l:"Quinta"},{v:5,l:"Sexta"},{v:6,l:"Sábado"},
  ];

  const _ddmmStr=function(s){if(!s)return "";const d=new Date(s+"T12:00:00");return String(d.getDate()).padStart(2,"0")+"/"+String(d.getMonth()+1).padStart(2,"0");};

  return <div style={{display:"flex",flexDirection:"column",gap:18,maxWidth:920,margin:"0 auto",fontFamily:"'Inter',system-ui,sans-serif"}}>
    {/* Header */}
    <div>
      <div style={{color:"#0f172a",fontWeight:800,fontSize:22,letterSpacing:-.5}}>Configuração de Sprints</div>
      <div style={{color:"#64748b",fontSize:13,marginTop:4}}>Regras globais usadas pra calcular automaticamente a previsão de entrega das demandas avulsas.</div>
    </div>

    {/* Preview da sprint atual */}
    {sprintPreview&&<div style={{background:"linear-gradient(135deg,#f0fdf4,#dcfce7)",border:"1px solid #bbf7d0",borderRadius:12,padding:"14px 18px",display:"flex",flexWrap:"wrap",gap:18}}>
      <div style={{flex:1,minWidth:200}}>
        <div style={{color:"#166534",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>Sprint atual</div>
        <div style={{color:"#0f172a",fontWeight:800,fontSize:16,fontFeatureSettings:"'tnum'"}}>{sprintPreview.atual.id}</div>
        <div style={{color:"#475569",fontSize:12,marginTop:2}}>{_ddmmStr(sprintPreview.atual.data_inicio)} → {_ddmmStr(sprintPreview.atual.data_fim)}</div>
      </div>
      <div style={{flex:1,minWidth:200}}>
        <div style={{color:"#166534",fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:.5,marginBottom:4}}>Próxima demanda iria pra</div>
        <div style={{color:"#0f172a",fontWeight:800,fontSize:16,fontFeatureSettings:"'tnum'"}}>{sprintPreview.proxima_demanda.id}{sprintPreview.proxima_demanda.cutoff_passou?" (após cutoff)":""}</div>
        <div style={{color:"#475569",fontSize:12,marginTop:2}}>Previsão: <strong>{_ddmmStr(sprintPreview.proxima_demanda.data_fim)}</strong></div>
      </div>
    </div>}

    {/* Form principal */}
    <div style={{background:"#fff",border:"1px solid #e2e8f0",borderRadius:12,padding:"20px 22px",display:"flex",flexDirection:"column",gap:18}}>
      {/* Dia de início + dia limite */}
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"1fr 1fr",gap:14}}>
        <div>
          <div style={{color:"#475569",fontSize:11,fontWeight:700,marginBottom:6,textTransform:"uppercase",letterSpacing:.4}}>Dia de início da sprint</div>
          <select value={cfg.dia_inicio} onChange={function(e){_set("dia_inicio",parseInt(e.target.value,10));}}
            style={{width:"100%",border:"1px solid #cbd5e1",borderRadius:8,padding:"9px 12px",fontSize:13,fontFamily:"inherit",background:"#fff",outline:"none"}}>
            {diasSemana.map(function(d){return <option key={d.v} value={d.v}>{d.l}</option>;})}
          </select>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>Sprint começa nesse dia da semana toda semana.</div>
        </div>
        <div>
          <div style={{color:"#475569",fontSize:11,fontWeight:700,marginBottom:6,textTransform:"uppercase",letterSpacing:.4}}>Dia limite (cutoff)</div>
          <select value={cfg.dia_limite} onChange={function(e){_set("dia_limite",parseInt(e.target.value,10));}}
            style={{width:"100%",border:"1px solid #cbd5e1",borderRadius:8,padding:"9px 12px",fontSize:13,fontFamily:"inherit",background:"#fff",outline:"none"}}>
            {diasSemana.map(function(d){return <option key={d.v} value={d.v}>{d.l}</option>;})}
          </select>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>Depois desse dia, demandas vão pra próxima sprint.</div>
        </div>
      </div>

      {/* Horário limite + prazo padrão */}
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"1fr 1fr",gap:14}}>
        <div>
          <div style={{color:"#475569",fontSize:11,fontWeight:700,marginBottom:6,textTransform:"uppercase",letterSpacing:.4}}>Horário limite</div>
          <input type="time" value={cfg.horario_limite} onChange={function(e){_set("horario_limite",e.target.value);}}
            style={{width:"100%",border:"1px solid #cbd5e1",borderRadius:8,padding:"9px 12px",fontSize:13,fontFamily:"inherit",background:"#fff",outline:"none"}}/>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>No dia limite, depois desse horário também é cutoff.</div>
        </div>
        <div>
          <div style={{color:"#475569",fontSize:11,fontWeight:700,marginBottom:6,textTransform:"uppercase",letterSpacing:.4}}>Prazo padrão (dias úteis)</div>
          <input type="number" min="1" max="30" value={cfg.prazo_padrao_dias} onChange={function(e){_set("prazo_padrao_dias",parseInt(e.target.value,10)||1);}}
            style={{width:"100%",border:"1px solid #cbd5e1",borderRadius:8,padding:"9px 12px",fontSize:13,fontFamily:"inherit",background:"#fff",outline:"none",fontFeatureSettings:"'tnum'"}}/>
          <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>Quantos dias úteis a sprint dura (pula sáb/dom).</div>
        </div>
      </div>

      {/* Textos */}
      <div>
        <div style={{color:"#475569",fontSize:11,fontWeight:700,marginBottom:6,textTransform:"uppercase",letterSpacing:.4}}>Texto exibido ao cliente</div>
        <textarea value={cfg.texto_cliente} onChange={function(e){_set("texto_cliente",e.target.value);}}
          rows={2}
          style={{width:"100%",border:"1px solid #cbd5e1",borderRadius:8,padding:"9px 12px",fontSize:13,fontFamily:"inherit",background:"#fff",outline:"none",resize:"vertical",boxSizing:"border-box"}}/>
        <div style={{color:"#94a3b8",fontSize:11,marginTop:4}}>Use <code style={{background:"#f1f5f9",padding:"1px 5px",borderRadius:4}}>{"{inicio}"}</code> e <code style={{background:"#f1f5f9",padding:"1px 5px",borderRadius:4}}>{"{fim}"}</code> como placeholders das datas.</div>
      </div>

      <div>
        <div style={{color:"#475569",fontSize:11,fontWeight:700,marginBottom:6,textTransform:"uppercase",letterSpacing:.4}}>Texto pra demanda aguardando informações</div>
        <textarea value={cfg.texto_aguardando} onChange={function(e){_set("texto_aguardando",e.target.value);}}
          rows={2}
          style={{width:"100%",border:"1px solid #cbd5e1",borderRadius:8,padding:"9px 12px",fontSize:13,fontFamily:"inherit",background:"#fff",outline:"none",resize:"vertical",boxSizing:"border-box"}}/>
      </div>

      <div>
        <div style={{color:"#475569",fontSize:11,fontWeight:700,marginBottom:6,textTransform:"uppercase",letterSpacing:.4}}>Texto pra demanda urgente em análise</div>
        <textarea value={cfg.texto_urgente} onChange={function(e){_set("texto_urgente",e.target.value);}}
          rows={2}
          style={{width:"100%",border:"1px solid #cbd5e1",borderRadius:8,padding:"9px 12px",fontSize:13,fontFamily:"inherit",background:"#fff",outline:"none",resize:"vertical",boxSizing:"border-box"}}/>
      </div>

      {/* Botão salvar */}
      <div style={{display:"flex",justifyContent:"flex-end",gap:8,borderTop:"1px solid #f1f5f9",paddingTop:14,marginTop:4}}>
        <button onClick={handleSave} disabled={saving}
          style={{background:saving?"#94a3b8":"#0f172a",color:"#fff",border:"none",borderRadius:10,padding:"10px 22px",fontWeight:700,fontSize:13,cursor:saving?"not-allowed":"pointer",fontFamily:"inherit",letterSpacing:-.1,display:"inline-flex",alignItems:"center",gap:7}}>
          {saving?"Salvando...":<><Ico n="check" size={14}/> Salvar configuração</>}
        </button>
      </div>
    </div>
  </div>;
}

const RADAR_ORIGENS = {
  interno:             { label:"Interna",      icon:"🔵", color:"#6366f1" },
  solicitacao_cliente: { label:"Solicitação",  icon:"🟡", color:"#f59e0b" },
  portal:              { label:"Portal",       icon:"🟢", color:"#22c55e" },
};

function getMonthKey(date){ return `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,"0")}`; }

const FLUXO_COLS = [
  {id:"demanda",   label:"Demandas",                  color:"#a140ff"},
  {id:"recebida",  label:"Recebidas",                 color:"#ff6eb4"},
  {id:"execucao",  label:"Em execução",               color:"#ffd000"},
  {id:"avaliacao", label:"Concluídas para avaliação", color:"#ff7200"},
  {id:"aprovado",  label:"Aprovadas",                 color:"#00e5a0"},
  {id:"agendado",  label:"Agendadas",                 color:"#4db8ff"},
  {id:"publicado", label:"Publicadas",                color:"#a78bfa"},
];

const INTERNAS_COLS_RADAR = [
  {id:"interno_demanda",   label:"Demandas",               color:"#6366f1"},
  {id:"interno_execucao",  label:"Em execução",            color:"#f97316"},
  {id:"interno_avaliacao", label:"Aguardando aprovação",   color:"#eab308"},
  {id:"interno_aprovado",  label:"Aprovadas",              color:"#22c55e"},
  {id:"interno_executado", label:"Executadas",             color:"#8b5cf6"},
];

const PERIODO_OPTS = [
  {id:"7d",    label:"7d",    full:"Última semana"},
  {id:"14d",   label:"14d",   full:"14 dias"},
  {id:"21d",   label:"21d",   full:"21 dias"},
  {id:"30d",   label:"30d",   full:"30 dias"},
  {id:"60d",   label:"60d",   full:"60 dias"},
  {id:"90d",   label:"90d",   full:"90 dias"},
  {id:"mes",   label:"Mês",   full:"Mês atual"},
  {id:"custom",label:"Datas", full:"Personalizado"},
];

function PageRadarEntrega({ tasks, isMob }) {
  const now = new Date();
  const [clienteId,  setClienteId]  = useState("");
  const [bioterUnit, setBioterUnit] = useState("");
  const [periodoId,  setPeriodoId]  = useState("30d");
  const [customIni,  setCustomIni]  = useState("");
  const [customFim,  setCustomFim]  = useState("");
  const [copiado,    setCopiado]    = useState(false);

  // ── Período ──
  const { periodoInicio, periodoFim } = (() => {
    const hoje = new Date(); hoje.setHours(23,59,59,999);
    if(periodoId==="mes"){
      return { periodoInicio:new Date(hoje.getFullYear(),hoje.getMonth(),1), periodoFim:hoje };
    }
    if(periodoId==="custom"){
      const ini = customIni ? new Date(customIni+"T00:00:00") : new Date(hoje.getFullYear(),hoje.getMonth(),1);
      const fim = customFim ? new Date(customFim+"T23:59:59") : hoje;
      return { periodoInicio:ini, periodoFim:fim };
    }
    const dias = parseInt(periodoId);
    const ini = new Date(hoje); ini.setDate(ini.getDate()-dias); ini.setHours(0,0,0,0);
    return { periodoInicio:ini, periodoFim:hoje };
  })();

  const durDias = Math.round((periodoFim-periodoInicio)/86400000);
  const duracao  = periodoFim-periodoInicio;
  const antFim   = new Date(periodoInicio.getTime()-1);
  const antIni   = new Date(antFim.getTime()-duracao); antIni.setHours(0,0,0,0);

  // ── Helpers ──
  // Melhoria 1: fallback createdAt → colEnteredAt → publishDate
  const parseData = (s) => {
    if(!s) return null;
    // Tenta ISO primeiro (ex: "2026-04-08T14:30:00.000Z") — Demandas Internas
    let d = new Date(s);
    if(!isNaN(d)) return d;
    // Tenta formato pt-BR "08/04/2026" ou "08/04/2026 às 14:30" — Fluxo de Demandas
    const match = s.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
    if(match) return new Date(`${match[3]}-${match[2]}-${match[1]}T00:00:00`);
    return null;
  };

  const dataEntrada = (t) => {
    return parseData(t.createdAt)
        || parseData(t.colEnteredAt)
        || (t.publishDate ? new Date(t.publishDate+"T00:00:00") : null);
  };

  const passaCliente = (t) => {
    if(clienteId && t.client!==clienteId) return false;
    if(clienteId==="bioter"&&bioterUnit&&t.bioterUnit!==bioterUnit) return false;
    return true;
  };

  const noPeriodo = (t) => { const d=dataEntrada(t); return d&&d>=periodoInicio&&d<=periodoFim; };
  const noAnt     = (t) => { const d=dataEntrada(t); return d&&d>=antIni&&d<=antFim; };

  // ── Dados ──
  const publicacoes = (tasks||[]).filter(t=>!t.deletedAt&&FLUXO_COLS.find(c=>c.id===t.status)&&passaCliente(t)&&noPeriodo(t));
  const extras      = (tasks||[]).filter(t=>!t.deletedAt&&INTERNAS_COLS_RADAR.find(c=>c.id===t.status)&&t.client&&t.client!=="interno"&&passaCliente(t)&&noPeriodo(t));
  const total       = publicacoes.length + extras.length;

  const publAnt    = (tasks||[]).filter(t=>!t.deletedAt&&FLUXO_COLS.find(c=>c.id===t.status)&&passaCliente(t)&&noAnt(t)).length;
  const extrasAnt  = (tasks||[]).filter(t=>!t.deletedAt&&INTERNAS_COLS_RADAR.find(c=>c.id===t.status)&&t.client&&t.client!=="interno"&&passaCliente(t)&&noAnt(t)).length;
  const totalAnt   = publAnt+extrasAnt;

  const _diffPubl  = publAnt>0   ? Math.round(((publicacoes.length-publAnt)/publAnt)*100)   : null;
  const _diffExtra = extrasAnt>0 ? Math.round(((extras.length-extrasAnt)/extrasAnt)*100)     : null;
  const _diffTotal = totalAnt>0  ? Math.round(((total-totalAnt)/totalAnt)*100)               : null;

  const calcTempo = (t) => {
    const ini=parseData(t.createdAt);
    const fim=t.completedAt?new Date(t.completedAt):null;
    if(!ini||!fim||isNaN(ini)||isNaN(fim))return null;
    const d=Math.round((fim-ini)/86400000);
    return d>=0?d:null;
  };
  const temposPubl  = publicacoes.map(calcTempo).filter(d=>d!==null);
  const temposExtra = extras.map(calcTempo).filter(d=>d!==null);
  const mediaPubl   = temposPubl.length  ? (temposPubl.reduce((a,b)=>a+b,0)/temposPubl.length).toFixed(1)  : null;
  const mediaExtra  = temposExtra.length ? (temposExtra.reduce((a,b)=>a+b,0)/temposExtra.length).toFixed(1) : null;

  const todasFluxo    = (tasks||[]).filter(t=>!t.deletedAt&&FLUXO_COLS.find(c=>c.id===t.status)&&passaCliente(t));
  const todasInternas = (tasks||[]).filter(t=>!t.deletedAt&&INTERNAS_COLS_RADAR.find(c=>c.id===t.status)&&t.client&&t.client!=="interno"&&passaCliente(t));

  // Melhoria 3: subtítulo com dias
  const fmtData2 = (d) => d.toLocaleDateString("pt-BR",{day:"2-digit",month:"2-digit",year:"2-digit"});
  const subtitulo = `${fmtData2(periodoInicio)} → ${fmtData2(periodoFim)}  ·  ${durDias} dia${durDias!==1?"s":""}`;

  // Melhoria 5: exportar resumo
  const exportarResumo = () => {
    const cl   = clienteId ? CLIENTS.find(c=>c.id===clienteId)?.name||clienteId : "Todos os clientes";
    const unit = bioterUnit ? " — "+BIOTER_UNITS.find(u=>u.id===bioterUnit)?.label : "";
    const per  = PERIODO_OPTS.find(p=>p.id===periodoId)?.full||periodoId;
    const txt = [
      `📊 Radar de Entrega — ${cl}${unit}`,
      `📅 ${per} (${fmtData2(periodoInicio)} → ${fmtData2(periodoFim)})`,
      ``,
      `📋 Publicações / Conteúdos: ${publicacoes.length}${mediaPubl?" (média "+mediaPubl+"d)":""}`,
      `⚡ Extras / Solicitações: ${extras.length}${mediaExtra?" (média "+mediaExtra+"d)":""}`,
      `📦 Total: ${total} entrega${total!==1?"s":""}`,
      ``,
      `— Gerado pelo Pixels Agency OS`,
    ].join("\n");
    try{ navigator.clipboard.writeText(txt); }catch(e){}
    setCopiado(true);
    setTimeout(()=>setCopiado(false),3000);
  };

  const DiffBadge = ({diff})=>{
    if(diff===null)return null;
    const up=diff>=0;
    return <span style={{background:up?C.gr+"20":C.rd+"20",color:up?C.gr:C.rd,borderRadius:6,padding:"2px 7px",fontSize:10,fontWeight:700,marginLeft:6}}>{up?"▲":"▼"} {Math.abs(diff)}%</span>;
  };

  const fmtDataCard = (t) => {
    const opts = {day:"2-digit",month:"2-digit"};
    const d = t.completedAt   ? new Date(t.completedAt)
            : t.publishDate   ? new Date(t.publishDate+"T00:00:00")
            : t.colEnteredAt  ? new Date(t.colEnteredAt)
            : parseData(t.createdAt); // usa parseData para suportar formato pt-BR
    return d&&!isNaN(d) ? d.toLocaleDateString("pt-BR",opts) : "—";
  };

  // Melhoria 4: ItemRow com badge de origem e cliente
  const ItemRow = ({t, showOrigem})=>{
    const cl   = CLIENTS.find(c=>c.id===t.client);
    const tempo= calcTempo(t);
    const orig = t.origem&&t.origem!=="interno" ? RADAR_ORIGENS[t.origem] : null;
    const col  = [...FLUXO_COLS,...INTERNAS_COLS_RADAR].find(c=>c.id===t.status);
    return(
      <div style={{display:"flex",alignItems:"center",gap:10,padding:"8px 12px",borderRadius:10,background:C.s1,border:`1px solid ${C.b1}`}}>
        <div style={{flex:1,minWidth:0}}>
          <div style={{color:C.tx,fontSize:12,fontWeight:600,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{t.title}</div>
          {t.caption&&<div style={{color:C.td,fontSize:10,marginTop:2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{t.caption.slice(0,80)}{t.caption.length>80?"...":""}</div>}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:5,flexShrink:0}}>
          {col&&<span style={{background:col.color+"20",color:col.color,borderRadius:6,padding:"1px 6px",fontSize:9,fontWeight:700}}>{col.label}</span>}
          {orig&&<span style={{background:orig.color+"20",color:orig.color,borderRadius:6,padding:"1px 6px",fontSize:9,fontWeight:700}}>{orig.icon} {orig.label}</span>}
          {!clienteId&&cl&&<span style={{background:cl.color+"18",color:cl.color,borderRadius:6,padding:"1px 6px",fontSize:9,fontWeight:700}}>{cl.abbr}</span>}
          {tempo!==null&&<span style={{color:C.td,fontSize:10}}>{tempo}d</span>}
          <span style={{color:C.td,fontSize:10,minWidth:30,textAlign:"right"}}>{fmtDataCard(t)}</span>
        </div>
      </div>
    );
  };

  const ColCounter = ({cols, tasksArr, title})=>(
    <div style={{background:C.card,borderRadius:14,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
      <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.b1}`}}>
        <span style={{color:C.tx,fontWeight:700,fontSize:12}}>{title}</span>
      </div>
      <div style={{display:"flex",overflowX:"auto",padding:"10px 12px",gap:8}}>
        {cols.map(col=>{
          const cnt=tasksArr.filter(t=>t.status===col.id).length;
          return(
            <div key={col.id} style={{flexShrink:0,textAlign:"center",minWidth:80,background:C.s1,borderRadius:10,padding:"10px 12px",borderTop:`3px solid ${col.color}`}}>
              <div style={{color:col.color,fontWeight:900,fontSize:22,lineHeight:1}}>{cnt}</div>
              <div style={{color:C.td,fontSize:9,fontWeight:600,marginTop:4,lineHeight:1.3}}>{col.label}</div>
            </div>
          );
        })}
      </div>
    </div>
  );

  return(
    <div style={{display:"flex",flexDirection:"column",gap:20}}>

      {/* Header */}
      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",flexWrap:"wrap",gap:12}}>
        <div>
          <div style={{color:C.tx,fontWeight:800,fontSize:18}}>📡 Radar de Entrega</div>
          <div style={{color:C.td,fontSize:11,marginTop:3}}>{subtitulo}</div>
        </div>
        {/* Melhoria 5: botão exportar */}
        <button onClick={exportarResumo}
          style={{background:copiado?C.gr:C.s1,border:`1px solid ${copiado?C.gr:C.b1}`,borderRadius:10,padding:"8px 16px",color:copiado?"#fff":C.ts,fontSize:11,fontWeight:700,cursor:"pointer",transition:"all .2s",flexShrink:0}}>
          {copiado?"✅ Copiado!":"📋 Copiar resumo"}
        </button>
      </div>

      {/* Filtros */}
      <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
        {/* Cliente */}
        <select value={clienteId} onChange={e=>{setClienteId(e.target.value);setBioterUnit("");}}
          style={{background:C.s1,border:`1px solid ${C.b1}`,borderRadius:10,padding:"7px 12px",color:clienteId?C.tx:C.td,fontSize:12,outline:"none",cursor:"pointer"}}>
          <option value="">Todos os clientes</option>
          {CLIENTS.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
        </select>

        {/* Bioter unidades */}
        {clienteId==="bioter"&&(
          <select value={bioterUnit} onChange={e=>setBioterUnit(e.target.value)}
            style={{background:C.s1,border:`1px solid ${C.b1}`,borderRadius:10,padding:"7px 12px",color:bioterUnit?C.tx:C.td,fontSize:12,outline:"none",cursor:"pointer"}}>
            <option value="">Todas as unidades</option>
            {BIOTER_UNITS.map(u=><option key={u.id} value={u.id}>{u.label}</option>)}
          </select>
        )}

        {/* Melhoria 2: botões de período */}
        <div style={{display:"flex",background:C.s1,border:`1px solid ${C.b1}`,borderRadius:10,overflow:"hidden",flexShrink:0}}>
          {PERIODO_OPTS.map(opt=>(
            <button key={opt.id} onClick={()=>setPeriodoId(opt.id)} title={opt.full}
              style={{background:periodoId===opt.id?C.a:"transparent",border:"none",padding:"7px 12px",color:periodoId===opt.id?"#fff":C.ts,fontSize:11,fontWeight:periodoId===opt.id?700:400,cursor:"pointer",whiteSpace:"nowrap",transition:"all .12s"}}>
              {opt.label}
            </button>
          ))}
        </div>

        {/* Datas personalizadas */}
        {periodoId==="custom"&&(
          <div style={{display:"flex",alignItems:"center",gap:6}}>
            <input type="date" value={customIni} onChange={e=>setCustomIni(e.target.value)}
              style={{background:C.s1,border:`1px solid ${C.b1}`,borderRadius:10,padding:"7px 10px",color:C.tx,fontSize:12,outline:"none"}}/>
            <span style={{color:C.td,fontSize:12}}>→</span>
            <input type="date" value={customFim} onChange={e=>setCustomFim(e.target.value)}
              style={{background:C.s1,border:`1px solid ${C.b1}`,borderRadius:10,padding:"7px 10px",color:C.tx,fontSize:12,outline:"none"}}/>
          </div>
        )}
      </div>

      {/* 3 cards do topo */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1.5fr",gap:10}}>
        <div style={{background:C.card,borderRadius:14,border:`1px solid ${C.b1}`,padding:"16px 18px",position:"relative",overflow:"hidden"}}>
          <div style={{position:"absolute",top:0,left:0,right:0,height:3,background:"#6366f1"}}/>
          <div style={{color:C.td,fontSize:9,fontWeight:700,textTransform:"uppercase",letterSpacing:.7,marginBottom:6}}>Publicações / Conteúdos</div>
          <div style={{display:"flex",alignItems:"baseline",gap:4}}>
            <span style={{color:"#6366f1",fontWeight:900,fontSize:28,letterSpacing:-1}}>{publicacoes.length}</span>
            <DiffBadge diff={_diffPubl}/>
          </div>
          {mediaPubl&&<div style={{color:C.td,fontSize:10,marginTop:3}}>{mediaPubl}d médio</div>}
        </div>

        <div style={{background:C.card,borderRadius:14,border:`1px solid ${C.b1}`,padding:"16px 18px",position:"relative",overflow:"hidden"}}>
          <div style={{position:"absolute",top:0,left:0,right:0,height:3,background:"#f59e0b"}}/>
          <div style={{color:C.td,fontSize:9,fontWeight:700,textTransform:"uppercase",letterSpacing:.7,marginBottom:6}}>Extras</div>
          <div style={{display:"flex",alignItems:"baseline",gap:4}}>
            <span style={{color:"#f59e0b",fontWeight:900,fontSize:28,letterSpacing:-1}}>{extras.length}</span>
            <DiffBadge diff={_diffExtra}/>
          </div>
          {mediaExtra&&<div style={{color:C.td,fontSize:10,marginTop:3}}>{mediaExtra}d médio</div>}
        </div>

        <div style={{background:`linear-gradient(135deg,${C.a}18,${C.a}08)`,borderRadius:14,border:`2px solid ${C.a}44`,padding:"16px 18px",position:"relative",overflow:"hidden"}}>
          <div style={{position:"absolute",top:0,left:0,right:0,height:4,background:C.a}}/>
          <div style={{color:C.a,fontSize:9,fontWeight:800,textTransform:"uppercase",letterSpacing:.7,marginBottom:6}}>Total no Período</div>
          <div style={{display:"flex",alignItems:"baseline",gap:8}}>
            <span style={{color:C.a,fontWeight:900,fontSize:38,letterSpacing:-2,lineHeight:1}}>{total}</span>
            <DiffBadge diff={_diffTotal}/>
          </div>
          <div style={{color:C.ts,fontSize:10,marginTop:6}}>{publicacoes.length} publ. + {extras.length} extras</div>
        </div>
      </div>

      {/* Situação atual — Fluxo */}
      <ColCounter cols={FLUXO_COLS} tasksArr={todasFluxo} title="📋 Fluxo de Demandas — situação atual"/>

      {/* Situação atual — Internas */}
      <ColCounter cols={INTERNAS_COLS_RADAR} tasksArr={todasInternas} title="⚡ Demandas Internas — situação atual"/>

      {/* Lista publicações */}
      <div style={{background:C.card,borderRadius:14,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
        <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.b1}`,display:"flex",alignItems:"center",gap:8}}>
          <span style={{color:C.tx,fontWeight:700,fontSize:13}}>📋 Publicações / Conteúdos do período</span>
          <span style={{background:"#6366f120",color:"#6366f1",borderRadius:99,padding:"1px 8px",fontSize:11,fontWeight:700}}>{publicacoes.length}</span>
        </div>
        <div style={{padding:"10px 12px",display:"flex",flexDirection:"column",gap:6,maxHeight:280,overflowY:"auto"}}>
          {publicacoes.length===0
            ? <div style={{color:C.td,fontSize:12,textAlign:"center",padding:"20px 0"}}>Nenhuma publicação no período</div>
            : publicacoes.map(t=><ItemRow key={t.id} t={t}/>)
          }
        </div>
      </div>

      {/* Lista extras */}
      <div style={{background:C.card,borderRadius:14,border:`1px solid ${C.b1}`,overflow:"hidden"}}>
        <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.b1}`,display:"flex",alignItems:"center",gap:8}}>
          <span style={{color:C.tx,fontWeight:700,fontSize:13}}>⚡ Extras / Solicitações do período</span>
          <span style={{background:"#f59e0b20",color:"#f59e0b",borderRadius:99,padding:"1px 8px",fontSize:11,fontWeight:700}}>{extras.length}</span>
        </div>
        <div style={{padding:"10px 12px",display:"flex",flexDirection:"column",gap:6,maxHeight:280,overflowY:"auto"}}>
          {extras.length===0
            ? <div style={{color:C.td,fontSize:12,textAlign:"center",padding:"20px 0"}}>Nenhuma demanda extra no período</div>
            : extras.map(t=><ItemRow key={t.id} t={t}/>)
          }
        </div>
      </div>

      {/* Comparativo */}
      {(_diffTotal!==null||_diffPubl!==null||_diffExtra!==null)&&(
        <div style={{background:C.card,borderRadius:14,border:`1px solid ${C.b1}`,padding:"16px 18px"}}>
          <div style={{color:C.tx,fontWeight:700,fontSize:13,marginBottom:4}}>📈 Comparativo vs período anterior</div>
          <div style={{color:C.td,fontSize:10,marginBottom:12}}>{fmtData2(antIni)} → {fmtData2(antFim)}</div>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {[
              {label:"Total",       atual:total,              ant:totalAnt,  color:C.a},
              {label:"Publicadas", atual:publicacoes.length, ant:publAnt,   color:"#6366f1"},
              {label:"Extras",      atual:extras.length,      ant:extrasAnt, color:"#f59e0b"},
            ].map((row,i)=>{
              const max=Math.max(row.atual,row.ant,1);
              const diff=row.ant>0?Math.round(((row.atual-row.ant)/row.ant)*100):null;
              const up=diff!==null&&diff>=0;
              return(
                <div key={i}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:4}}>
                    <span style={{color:C.ts,fontSize:11,fontWeight:600}}>{row.label}</span>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <span style={{color:C.td,fontSize:10}}>Ant: {row.ant}</span>
                      <span style={{color:C.tx,fontSize:12,fontWeight:700}}>Atual: {row.atual}</span>
                      {diff!==null&&<span style={{color:up?C.gr:C.rd,fontSize:11,fontWeight:700}}>{up?"▲":"▼"}{Math.abs(diff)}%</span>}
                    </div>
                  </div>
                  <div style={{display:"flex",gap:4}}>
                    <div style={{flex:1,height:5,background:C.b1,borderRadius:99,overflow:"hidden"}}>
                      <div style={{height:"100%",width:`${Math.round(row.ant/max*100)}%`,background:C.b2,borderRadius:99}}/>
                    </div>
                    <div style={{flex:1,height:5,background:C.b1,borderRadius:99,overflow:"hidden"}}>
                      <div style={{height:"100%",width:`${Math.round(row.atual/max*100)}%`,background:row.color,borderRadius:99}}/>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

function RichToolbar({elRef}){
  const exec=(cmd,val)=>{
    if(elRef.current){elRef.current.focus();}
    try{document.execCommand(cmd,false,val||null);}catch(e){}
  };
  const btn=(content,cmd,val,title)=>(
    <button type="button" title={title}
      onMouseDown={e=>{e.preventDefault();exec(cmd,val);}}
      style={{background:"none",border:"1px solid #e2e8f0",borderRadius:6,padding:"3px 8px",cursor:"pointer",color:"#475569",fontSize:12,fontWeight:700,lineHeight:1.4,minWidth:28}}
      onMouseEnter={e=>e.currentTarget.style.background="#f1f5f9"}
      onMouseLeave={e=>e.currentTarget.style.background="none"}>
      {content}
    </button>
  );
  return <div style={{display:"flex",gap:4,padding:"6px 10px",background:"#f8fafc",borderRadius:"8px 8px 0 0",borderBottom:"1px solid #e2e8f0",flexWrap:"wrap",alignItems:"center",position:"sticky",top:0,zIndex:5}}>
    {btn(<b style={{fontWeight:900}}>N</b>,"bold",null,"Negrito")}
    {btn(<i>I</i>,"italic",null,"Itálico")}
    {btn(<u>S</u>,"underline",null,"Sublinhado")}
    <div style={{width:1,background:"#e2e8f0",margin:"0 2px",height:16}}/>
    {btn("• ","insertUnorderedList",null,"Lista")}
    {btn("1.","insertOrderedList",null,"Numerada")}
  </div>;
}

