// Total de items (incluindo subs) — pra contagem do progresso
function _onbCountAllItems(){
  let n=0;
  ONBOARDING_BLOCKS.forEach(function(b){
    b.items.forEach(function(it){
      n++;
      if(it.sub) n += it.sub.length;
    });
  });
  return n;
}
const ONBOARDING_TOTAL = _onbCountAllItems();

/* ─── SEED do Onboarding ──────────────────────────────────────────
   Quando um cliente é cadastrado, monta items prévios com:
   - id estável (mesmo padrão dos blocks)
   - due (data) calculada em dias úteis a partir de hoje
   - resp default (sócios) que pode ser ajustado depois pela equipe
   - done:false
   E persiste em client_onboarding.items (JSONB)
─────────────────────────────────────────────────────────────── */
// Avança N dias úteis a partir de uma base (pula sáb/dom)
function _onbAddBusinessDays(baseDate, n){
  const d = new Date(baseDate.getTime());
  let added = 0;
  while(added < n){
    d.setDate(d.getDate()+1);
    const dow = d.getDay();
    if(dow!==0 && dow!==6) added++;
  }
  return d;
}
function _onbIsoDate(d){
  return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0");
}
// Offset (em dias úteis) por bloco — espelha o "Dia N" do checklist
const _ONB_BLOCK_OFFSETS = {
  inicial: 0,   // "Antes do dia 1" → cair pra hoje
  dia1:    1,
  dia2:    2,
  dia3:    3,
  dia3_7:  7,
  dia7:    7,
  dia14:  14,
  dia31:  31,  // 31 dias corridos no caso, mas usar úteis aproxima 6 semanas — ok pra MVP
};
// Responsáveis default por bloco (sócios cuidam do setup; equipe operacional entra depois)
const _ONB_DEFAULT_RESP = {
  inicial: ["vinicius","gustavo"],
  dia1:    ["vinicius","gustavo"],
  dia2:    ["gustavo","ellen"],
  dia3:    ["vinicius","gustavo","ellen"],
  dia3_7:  ["gustavo","ellen","erick"],
  dia7:    ["ellen","erick"],
  dia14:   ["erick","gustavo"],
  dia31:   ["vinicius","gustavo"],
};

// Constrói os items default pra um cliente novo
function _onbBuildSeedItems(){
  const base = new Date();
  base.setHours(0,0,0,0);
  const out = {};
  ONBOARDING_BLOCKS.forEach(function(b){
    const offset = _ONB_BLOCK_OFFSETS[b.id] || 0;
    const due = _onbIsoDate(_onbAddBusinessDays(base, offset));
    const resp = _ONB_DEFAULT_RESP[b.id] || ["vinicius","gustavo"];
    b.items.forEach(function(it){
      out[it.id] = {done:false, due:due, resp:resp};
      if(it.sub){
        it.sub.forEach(function(sub){
          out[sub.id] = {done:false, due:due, resp:resp};
        });
      }
    });
  });
  return out;
}

// Persiste o seed no Supabase. Idempotente: se já tiver items, NÃO sobrescreve
// (evita perder progresso caso o usuário cadastre o mesmo cliente 2x sem querer).
async function seedClientOnboarding(clientId){
  if(!clientId) return;
  if(typeof window==="undefined" || !window._sb) return;
  try{
    const existing = await window._sb.from("client_onboarding")
      .select("items").eq("client_id",clientId).maybeSingle();
    if(existing && existing.data && existing.data.items && Object.keys(existing.data.items).length > 0){
      // Já tem onboarding — não mexe
      return;
    }
    const items = _onbBuildSeedItems();
    const{error} = await window._sb.from("client_onboarding")
      .upsert({client_id:clientId, items:items}, {onConflict:"client_id"});
    if(error){
      console.warn("[seedClientOnboarding] upsert err:", error);
      return;
    }
    // Limpa cache local pra forçar re-fetch nas próximas renders
    try{
      const key = (typeof _onbCacheKey==="function") ? _onbCacheKey(clientId) : ("pixels-onb-"+clientId);
      localStorage.removeItem(key);
    }catch(_){}
    // Dispara evento global pra UIs atualizarem
    try{ window.dispatchEvent(new CustomEvent("pixels:onb-seeded",{detail:{clientId:clientId}})); }catch(_){}
  }catch(e){
    console.warn("[seedClientOnboarding] exc:", e);
  }
}

/* ─── HOOK: useClientMeta ─────────────────────────────────────── */
function useClientMeta(clientId){
  const [meta, setMeta] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(function(){
    if(!clientId||!window._sb){setLoading(false);return;}
    setLoading(true);
    window._sb.from("client_meta").select("*").eq("client_id",clientId).maybeSingle().then(function(r){
      if(r.data){ setMeta(r.data); }
      else { setMeta({client_id:clientId, status:"ativo", saude:"verde", mrr:0, score:0, alertas:[]}); }
      setLoading(false);
    });
  }, [clientId]);

  function save(patch){
    const next = Object.assign({}, meta||{client_id:clientId}, patch);
    setMeta(next);
    if(!window._sb)return Promise.resolve();
    return window._sb.from("client_meta").upsert(next, {onConflict:"client_id"});
  }
  return { meta, setMeta, save, loading };
}

/* ─── HOOK: useClientOnboarding ──────────────────────────────── */
// Cache local com TTL — evita que fetch do Supabase sobrescreva um clique recente
// quando o usuário troca de aba e volta antes do upsert completar
const _ONB_CACHE_TTL_MS = 60*1000; // 60s — janela confortável pra trocar abas
function _onbCacheKey(clientId){ return "pixels-onb-"+clientId; }
function _onbCacheLoad(clientId){
  try{
    const s=localStorage.getItem(_onbCacheKey(clientId));
    if(!s) return null;
    const obj=JSON.parse(s);
    if(!obj||!obj.items) return null;
    return obj; // {items, v: timestamp}
  }catch(e){ return null; }
}
function _onbCacheSave(clientId, items){
  try{ localStorage.setItem(_onbCacheKey(clientId), JSON.stringify({items:items, v:Date.now()})); }catch(e){}
}

function useClientOnboarding(clientId){
  const [items, setItems] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(function(){
    if(!clientId){setLoading(false);return;}
    // 1) Cache local primeiro — resposta instantânea
    const cached = _onbCacheLoad(clientId);
    const cacheFresh = cached && (Date.now()-cached.v) < _ONB_CACHE_TTL_MS;
    if(cached){
      setItems(cached.items);
      setLoading(false);
    }
    // Cache fresco vence — pula fetch pra não sobrescrever clique recente
    if(cacheFresh) return;
    // 2) Fetch do Supabase
    if(!window._sb){setLoading(false);return;}
    let canceled=false;
    window._sb.from("client_onboarding").select("*").eq("client_id",clientId).maybeSingle().then(function(r){
      if(canceled) return;
      if(r&&r.data&&r.data.items){
        setItems(r.data.items);
        _onbCacheSave(clientId, r.data.items);
      } else if(!cached){
        setItems({});
      }
      setLoading(false);
    }).catch(function(e){
      console.warn("[onboarding load]", e&&e.message||e);
      setLoading(false);
    });
    return function(){canceled=true;};
  }, [clientId]);

  function _persist(next){
    setItems(next);
    // Cache local imediato — vence sobre fetch nas próximas 60s
    _onbCacheSave(clientId, next);
    if(window._sb){
      window._sb.from("client_onboarding").upsert({client_id:clientId, items:next}, {onConflict:"client_id"})
        .then(function(r){ if(r&&r.error) console.warn("[onboarding persist]", r.error.message); });
    }
  }
  function toggle(itemId, currentUserId){
    const cur = items[itemId];
    const isDone = cur&&cur.done;
    let next;
    if(isDone){
      // Desmarcar — SEM confirmação (usuário pediu)
      const prev = Object.assign({}, items[itemId]||{});
      delete prev.done;
      delete prev.completed_at;
      delete prev.completed_by;
      // Mantém resp/due se já existiam
      if(prev.resp||prev.due){
        next = Object.assign({}, items, {[itemId]: prev});
      }else{
        next = Object.assign({}, items);
        delete next[itemId];
      }
    }else{
      next = Object.assign({}, items, {
        [itemId]: Object.assign({}, items[itemId]||{}, { done:true, completed_at:new Date().toISOString(), completed_by:currentUserId||"" })
      });
    }
    _persist(next);
  }
  function setResp(itemId, respVal){
    // Aceita string (legado: 1 responsável) OU array (novo: vários)
    const arr = Array.isArray(respVal) ? respVal.filter(Boolean) : (respVal ? [respVal] : []);
    const next = Object.assign({}, items, {
      [itemId]: Object.assign({}, items[itemId]||{}, { resp: arr })
    });
    _persist(next);
  }
  function setDue(itemId, due){
    const next = Object.assign({}, items, {
      [itemId]: Object.assign({}, items[itemId]||{}, { due: due||"" })
    });
    _persist(next);
  }

  const doneCount = Object.keys(items).filter(function(k){return k!=="__finalizado__" && items[k] && items[k].done;}).length;
  const finalizado = !!items.__finalizado__;
  function setFinalizado(value){
    const next = Object.assign({}, items);
    if(value){
      next.__finalizado__ = true;
    }else{
      delete next.__finalizado__;
    }
    _persist(next);
  }
  return { items, toggle, setResp, setDue, doneCount, loading, finalizado, setFinalizado };
}

/* ─── COMPONENTE: ClientMetricsCards (visão geral) ───────────── */
